import { PublicCard } from '../../../types';

export const chemistryCards: PublicCard[] = [
  { id: 'dc-chemistry-0001', deck_id: 'deck-chemistry', sort_order: 1, front: "Hydrogen (H)", back: "Atomic number 1, atomic mass 1.008 u. The lightest and most abundant element in the universe. Forms H₂ gas and is a key component of water and organic molecules." , front_translations: {"es":"Hidrógeno (H)","de":"Wasserstoff (H)","fr":"Hydrogène (H)","tr":"Hidrojen (H)","nl":"Waterstof (H)","ru":"Водород (H)","zh":"氢 (H)","pt_BR":"Hidrogênio (H)","pt_PT":"Hidrogénio (H)"}, back_translations: {"es":"Número atómico 1, masa atómica 1,008 u. El elemento más ligero y más abundante del universo. Forma el gas H₂ y es componente fundamental de la agua y de las moléculas organicas.","de":"Ordnungszahl 1, Atommasse 1,008 u. Das leichteste und häufigste Element im Universum. Bildet H₂-Gas und ist ein wesentlicher Bestandteil von Wasser und organischen Molekülen.","fr":"Numéro atomique 1, masse atomique 1,008 u. L'élément le plus léger et le plus abondant de l'univers. Forme le gaz H₂ et est un composant clé de l'eau et des molécules organiques.","tr":"Atom numarası 1, atom kütlesi 1,008 u. Evrende en hafif ve en bol bulunan element. H₂ gazı oluşturur ve su ile organik moleküllerin temel bileşenidir.","nl":"Atoomnummer 1, atoommassa 1,008 u. Het lichtste en meest voorkomende element in het heelal. Vormt H₂-gas en is een belangrijk bestanddeel van water en organische moleculen.","ru":"Порядковый номер 1, атомная масса 1,008 у. Самый лёгкий и наиболее распространённый элемент во Вселенной. Образует газ H₂ и является ключевым компонентом воды и органических молекул.","zh":"原子序数1，原子量1.008 u。宇宙中最轻且最丰富的元素。形成H₂气体，是水和有机分子的关键组成部分。","pt_BR":"Número atômico 1, massa atômica 1,008 u. O elemento mais leve e mais abundante do universo. Forma o gás H₂ e é componente fundamental da água e das moléculas orgânicas.","pt_PT":"Número atómico 1, massa atómica 1,008 u. O elemento mais leve e mais abundante do universo. Forma o gás H₂ e é um componente essencial da água e das moléculas orgânicas."}},
  { id: 'dc-chemistry-0002', deck_id: 'deck-chemistry', sort_order: 2, front: "Helium (He)", back: "Atomic number 2, atomic mass 4.003 u. Noble gas; second most abundant element in the universe. Completely unreactive due to full outer shell. Used in balloons and cryogenics." , front_translations: {"es":"Hélio (He)","de":"Helium (He)","fr":"Hélium (He)","tr":"Helyum (He)","nl":"Helium (He)","ru":"Гелий (He)","zh":"氦 (He)","pt_BR":"Hélio (He)","pt_PT":"Hélio (He)"}, back_translations: {"es":"Número atómico 2, masa atómica 4,003 u. Gas nobre; según elemento más abundante del universo. Completamente inerte debido a la capa externa completa. Usado en balões y criogenia.","de":"Ordnungszahl 2, Atommasse 4,003 u. Edelgas; zweithäufigstes Element im Universum. Völlig unreaktiv aufgrund der vollständig besetzten Außenschale. Verwendet in Ballons und Kryotechnik.","fr":"Numéro atomique 2, masse atomique 4,003 u. Gaz noble ; deuxième élément le plus abondant de l'univers. Totalement inerte en raison de sa couche externe complète. Utilisé dans les ballons et la cryogénie.","tr":"Atom numarası 2, atom kütlesi 4,003 u. Soy gaz; evrende ikinci en bol element. Dolu dış kabuğu nedeniyle tamamen reaktif değildir. Balonlarda ve kriyojenikte kullanılır.","nl":"Atoomnummer 2, atoommassa 4,003 u. Edelgas; het op één na meest voorkomende element in het heelal. Volledig inert door de gevulde buitenste schil. Gebruikt in ballonnen en cryogene toepassingen.","ru":"Порядковый номер 2, атомная масса 4,003 у. Благородный газ; второй по распространённости элемент во Вселенной. Полностью инертен из-за заполненной внешней оболочки. Применяется в аэростатах и криогенике.","zh":"原子序数2，原子量4.003 u。稀有气体；宇宙中丰度第二的元素。由于外层电子壳全满而完全不活泼。用于气球和低温技术。","pt_BR":"Número atômico 2, massa atômica 4,003 u. Gás nobre; segundo elemento mais abundante do universo. Completamente inerte devido à camada externa completa. Usado em balões e criogenia.","pt_PT":"Número atómico 2, massa atómica 4,003 u. Gás nobre; segundo elemento mais abundante do universo. Completamente inerte devido à camada externa completa. Usado em balões e criogenia."}},
  { id: 'dc-chemistry-0003', deck_id: 'deck-chemistry', sort_order: 3, front: "Lithium (Li)", back: "Atomic number 3, atomic mass 6.941 u. Lightest metal; highly reactive alkali metal. Stores charge well, making it key in rechargeable batteries. Reacts vigorously with water." , front_translations: {"es":"Lítio (Li)","de":"Lithium (Li)","fr":"Lithium (Li)","tr":"Lityum (Li)","nl":"Lithium (Li)","ru":"Литий (Li)","zh":"锂 (Li)","pt_BR":"Lítio (Li)","pt_PT":"Lítio (Li)"}, back_translations: {"es":"Número atómico 3, masa atómica 6,941 u. Metal más ligero; metal alcalino altamente reativo. Almacena carga bem, tornando-el esencial en baterias recarregables. Reage vigorosamente con a agua.","de":"Ordnungszahl 3, Atommasse 6,941 u. Leichtestes Metall; hochreaktives Alkalimetall. Speichert Ladung gut, was es zu einem wichtigen Bestandteil von Akkumulatoren macht. Reagiert heftig mit Wasser.","fr":"Numéro atomique 3, masse atomique 6,941 u. Métal le plus léger ; métal alcalin très réactif. Stocke bien l'énergie, ce qui en fait un élément clé des batteries rechargeables. Réagit vigoureusement avec l'eau.","tr":"Atom numarası 3, atom kütlesi 6,941 u. En hafif metal; yüksek reaktifli alkali metal. Yükü iyi depolayarak şarj edilebilir pillerin temel bileşeni olur. Su ile şiddetli reaksiyon verir.","nl":"Atoomnummer 3, atoommassa 6,941 u. Lichtste metaal; zeer reactief alkalimetaal. Slaat goed lading op, waardoor het een sleutelcomponent is in oplaadbare batterijen. Reageert heftig met water.","ru":"Порядковый номер 3, атомная масса 6,941 у. Самый лёгкий металл; высокореакционный щелочной металл. Хорошо накапливает заряд, что делает его ключевым компонентом аккумуляторов. Бурно реагирует с водой.","zh":"原子序数3，原子量6.941 u。最轻的金属；高活性碱金属。储电性能好，是充电电池的关键成分。与水剧烈反应。","pt_BR":"Número atômico 3, massa atômica 6,941 u. Metal mais leve; metal alcalino altamente reativo. Armazena carga bem, tornando-o essencial em baterias recarregáveis. Reage vigorosamente com a água.","pt_PT":"Número atómico 3, massa atómica 6,941 u. Metal mais leve; metal alcalino altamente reativo. Armazena carga bem, tornando-o essencial em baterias recarregáveis. Reage vigorosamente com a água."}},
  { id: 'dc-chemistry-0004', deck_id: 'deck-chemistry', sort_order: 4, front: "Beryllium (Be)", back: "Atomic number 4, atomic mass 9.012 u. Alkaline earth metal; hard, light, and stiff. Toxic if inhaled. Used in aerospace alloys and nuclear reactors as a neutron reflector." , front_translations: {"es":"Berílio (Be)","de":"Beryllium (Be)","fr":"Béryllium (Be)","tr":"Berilyum (Be)","nl":"Beryllium (Be)","ru":"Бериллий (Be)","zh":"铍 (Be)","pt_BR":"Berílio (Be)","pt_PT":"Berílio (Be)"}, back_translations: {"es":"Número atómico 4, masa atómica 9,012 u. Metal alcalino-terroso; duro, ligero y rígido. Tóxico se inalado. Usado en ligas aeroespaciais y en reatores nucleares como refletor de neutrones.","de":"Ordnungszahl 4, Atommasse 9,012 u. Erdalkalimetall; hart, leicht und steif. Giftig beim Einatmen. Verwendet in Luft- und Raumfahrtlegierungen sowie als Neutronenreflektor in Kernreaktoren.","fr":"Numéro atomique 4, masse atomique 9,012 u. Métal alcalino-terreux ; dur, léger et rigide. Toxique si inhalé. Utilisé dans les alliages aérospatiaux et les réacteurs nucléaires comme réflecteur de neutrons.","tr":"Atom numarası 4, atom kütlesi 9,012 u. Toprak alkali metal; sert, hafif ve rijit. Solunması durumunda toksiktir. Havacılık alaşımlarında ve nükleer reaktörlerde nötron yansıtıcısı olarak kullanılır.","nl":"Atoomnummer 4, atoommassa 9,012 u. Aardalkalimetaal; hard, licht en stijf. Giftig bij inademing. Gebruikt in luchtvaartlegeringen en kernreactoren als neutronenreflector.","ru":"Порядковый номер 4, атомная масса 9,012 у. Щёлочноземельный металл; твёрдый, лёгкий и жёсткий. Токсичен при вдыхании. Применяется в авиакосмических сплавах и в ядерных реакторах в качестве отражателя нейтронов.","zh":"原子序数4，原子量9.012 u。碱土金属；坚硬、轻质且刚性。吸入有毒。用于航空航天合金和核反应堆中的中子反射体。","pt_BR":"Número atômico 4, massa atômica 9,012 u. Metal alcalino-terroso; duro, leve e rígido. Tóxico se inalado. Usado em ligas aeroespaciais e em reatores nucleares como refletor de nêutrons.","pt_PT":"Número atómico 4, massa atómica 9,012 u. Metal alcalino-terroso; duro, leve e rígido. Tóxico se inalado. Usado em ligas aeroespaciais e em reatores nucleares como refletor de neutrões."}},
  { id: 'dc-chemistry-0005', deck_id: 'deck-chemistry', sort_order: 5, front: "Boron (B)", back: "Atomic number 5, atomic mass 10.811 u. Metalloid; essential micronutrient for plants. Forms borate glass (borosilicate). Used in semiconductors, detergents (borax), and rocket fuel." , front_translations: {"es":"Boro (B)","de":"Bor (B)","fr":"Bore (B)","tr":"Bor (B)","nl":"Boor (B)","ru":"Бор (B)","zh":"硼 (B)","pt_BR":"Boro (B)","pt_PT":"Boro (B)"}, back_translations: {"es":"Número atómico 5, masa atómica 10,811 u. Metalóide; micronutriente esencial para plantas. Forma vidro borato (borossilicato). Usado en semicondutores, detergentes (bórax) y combustible de foguetes.","de":"Ordnungszahl 5, Atommasse 10,811 u. Halbmetall; essenzielles Mikronährstoff für Pflanzen. Bildet Boratglas (Borosilikat). Verwendet in Halbleitern, Waschmitteln (Borax) und Raketentreibstoff.","fr":"Numéro atomique 5, masse atomique 10,811 u. Métalloïde ; micronutriment essentiel pour les plantes. Forme le verre borate (borosilicate). Utilisé dans les semi-conducteurs, les détergents (borax) et le carburant de fusée.","tr":"Atom numarası 5, atom kütlesi 10,811 u. Yarı metal; bitkiler için temel bir mikro besin. Borat camı (borosilikat) oluşturur. Yarı iletkenler, deterjanlar (boraks) ve roket yakıtında kullanılır.","nl":"Atoomnummer 5, atoommassa 10,811 u. Metalloïde; essentieel micronutriënt voor planten. Vormt boraatglas (borosilicaat). Gebruikt in halfgeleiders, wasmiddelen (borax) en raketbrandstof.","ru":"Порядковый номер 5, атомная масса 10,811 у. Металлоид; незаменимый микроэлемент для растений. Образует боратное стекло (боросиликат). Применяется в полупроводниках, моющих средствах (бура) и ракетном топливе.","zh":"原子序数5，原子量10.811 u。类金属；植物必需的微量营养素。形成硼酸盐玻璃（硼硅酸盐）。用于半导体、洗涤剂（硼砂）和火箭燃料。","pt_BR":"Número atômico 5, massa atômica 10,811 u. Metalóide; micronutriente essencial para plantas. Forma vidro borato (borossilicato). Usado em semicondutores, detergentes (bórax) e combustível de foguetes.","pt_PT":"Número atómico 5, massa atómica 10,811 u. Metalóide; micronutriente essencial para plantas. Forma vidro borato (borossilicato). Usado em semicondutores, detergentes (bórax) e combustível de foguetes."}},
  { id: 'dc-chemistry-0006', deck_id: 'deck-chemistry', sort_order: 6, front: "Carbon (C)", back: "Atomic number 6, atomic mass 12.011 u. The basis of organic chemistry; can form four covalent bonds, enabling the vast diversity of organic molecules. Occurs as graphite, diamond, and fullerenes." , front_translations: {"es":"Carbono (C)","de":"Kohlenstoff (C)","fr":"Carbone (C)","tr":"Karbon (C)","nl":"Koolstof (C)","ru":"Углерод (C)","zh":"碳 (C)","pt_BR":"Carbono (C)","pt_PT":"Carbono (C)"}, back_translations: {"es":"Número atómico 6, masa atómica 12,011 u. La base de la química orgánica; puede formar cuatro enlaces covalentes, possibilitando a enorme diversidad de moléculas organicas. Ocurre como grafite, diamante y fulerenos.","de":"Ordnungszahl 6, Atommasse 12,011 u. Die Grundlage der organischen Chemie; kann vier kovalente Bindungen eingehen und ermöglicht so die enorme Vielfalt organischer Moleküle. Kommt als Graphit, Diamant und Fullerene vor.","fr":"Numéro atomique 6, masse atomique 12,011 u. La base de la chimie organique ; peut former quatre liaisons covalentes, permettant une immense diversité de molécules organiques. Se présente sous forme de graphite, de diamant et de fullerènes.","tr":"Atom numarası 6, atom kütlesi 12,011 u. Organik kimyanın temeli; dört kovalent bağ oluşturabilir ve bu sayede organik moleküllerin büyük çeşitliliğini mümkün kılar. Grafit, elmas ve fuleren olarak bulunur.","nl":"Atoomnummer 6, atoommassa 12,011 u. De basis van de organische chemie; kan vier covalente bindingen vormen, wat de enorme diversiteit aan organische moleculen mogelijk maakt. Komt voor als grafiet, diamant en fullerenen.","ru":"Порядковый номер 6, атомная масса 12,011 у. Основа органической химии; может образовывать четыре ковалентные связи, обеспечивая огромное разнообразие органических молекул. Существует в виде графита, алмаза и фуллеренов.","zh":"原子序数6，原子量12.011 u。有机化学的基础；能形成四个共价键，赋予有机分子极大的多样性。以石墨、金刚石和富勒烯形式存在。","pt_BR":"Número atômico 6, massa atômica 12,011 u. A base da química orgânica; pode formar quatro ligações covalentes, possibilitando a enorme diversidade de moléculas orgânicas. Ocorre como grafite, diamante e fulerenos.","pt_PT":"Número atómico 6, massa atómica 12,011 u. A base da química orgânica; pode formar quatro ligações covalentes, possibilitando a enorme diversidade de moléculas orgânicas. Ocorre como grafite, diamante e fulerenos."}},
  { id: 'dc-chemistry-0007', deck_id: 'deck-chemistry', sort_order: 7, front: "Nitrogen (N)", back: "Atomic number 7, atomic mass 14.007 u. Makes up 78% of Earth's atmosphere as N₂. Essential component of amino acids and DNA. Forms many important compounds including NH₃, HNO₃." , front_translations: {"es":"Nitrógeno (N)","de":"Stickstoff (N)","fr":"Azote (N)","tr":"Azot (N)","nl":"Stikstof (N)","ru":"Азот (N)","zh":"氮 (N)","pt_BR":"Nitrogênio (N)","pt_PT":"Azoto (N)"}, back_translations: {"es":"Número atómico 7, masa atómica 14,007 u. Compõe 78% de la atmosfera terrestre como N₂. Componente esencial de aminoácidos y DNA. Forma muchos compuestos importantes, incluyendo NH₃ y HNO₃.","de":"Ordnungszahl 7, Atommasse 14,007 u. Macht 78 % der Erdatmosphäre als N₂ aus. Wesentlicher Bestandteil von Aminosäuren und DNA. Bildet viele wichtige Verbindungen, darunter NH₃ und HNO₃.","fr":"Numéro atomique 7, masse atomique 14,007 u. Constitue 78 % de l'atmosphère terrestre sous forme de N₂. Composant essentiel des acides aminés et de l'ADN. Forme de nombreux composés importants dont NH₃ et HNO₃.","tr":"Atom numarası 7, atom kütlesi 14,007 u. Dünya atmosferinin %78'ini N₂ olarak oluşturur. Amino asitlerin ve DNA'nın temel bileşenidir. NH₃ ve HNO₃ dahil birçok önemli bileşik oluşturur.","nl":"Atoomnummer 7, atoommassa 14,007 u. Maakt 78% uit van de aardatmosfeer als N₂. Essentieel bestanddeel van aminozuren en DNA. Vormt vele belangrijke verbindingen waaronder NH₃ en HNO₃.","ru":"Порядковый номер 7, атомная масса 14,007 у. Составляет 78% атмосферы Земли в виде N₂. Незаменимый компонент аминокислот и ДНК. Образует множество важных соединений, в том числе NH₃ и HNO₃.","zh":"原子序数7，原子量14.007 u。以N₂形式占地球大气的78%。氨基酸和DNA的基本组成元素。形成NH₃、HNO₃等许多重要化合物。","pt_BR":"Número atômico 7, massa atômica 14,007 u. Compõe 78% da atmosfera terrestre como N₂. Componente essencial de aminoácidos e DNA. Forma muitos compostos importantes, incluindo NH₃ e HNO₃.","pt_PT":"Número atómico 7, massa atómica 14,007 u. Constitui 78% da atmosfera terrestre como N₂. Componente essencial de aminoácidos e DNA. Forma muitos compostos importantes, incluindo NH₃ e HNO₃."}},
  { id: 'dc-chemistry-0008', deck_id: 'deck-chemistry', sort_order: 8, front: "Oxygen (O)", back: "Atomic number 8, atomic mass 15.999 u. Makes up 21% of Earth's atmosphere. Highly electronegative; essential for aerobic respiration. Forms oxides with most elements." , front_translations: {"es":"Oxígeno (El)","de":"Sauerstoff (O)","fr":"Oxygène (O)","tr":"Oksijen (O)","nl":"Zuurstof (O)","ru":"Кислород (O)","zh":"氧 (O)","pt_BR":"Oxigênio (O)","pt_PT":"Oxigénio (O)"}, back_translations: {"es":"Número atómico 8, masa atómica 15,999 u. Compõe 21% de la atmosfera terrestre. Altamente eletronegativo; esencial para a respiración aeróbica. Forma óxidos con a maioria de los elementos.","de":"Ordnungszahl 8, Atommasse 15,999 u. Macht 21 % der Erdatmosphäre aus. Hoch elektronegativ; unentbehrlich für die aerobe Atmung. Bildet Oxide mit den meisten Elementen.","fr":"Numéro atomique 8, masse atomique 15,999 u. Constitue 21 % de l'atmosphère terrestre. Très électronégatif ; essentiel à la respiration aérobie. Forme des oxydes avec la plupart des éléments.","tr":"Atom numarası 8, atom kütlesi 15,999 u. Dünya atmosferinin %21'ini oluşturur. Yüksek elektronegatifliğe sahiptir; aerobik solunum için zorunludur. Çoğu elementle oksit oluşturur.","nl":"Atoomnummer 8, atoommassa 15,999 u. Maakt 21% uit van de aardatmosfeer. Sterk elektronegatief; essentieel voor aerobe ademhaling. Vormt oxiden met de meeste elementen.","ru":"Порядковый номер 8, атомная масса 15,999 у. Составляет 21% атмосферы Земли. Высокая электроотрицательность; необходим для аэробного дыхания. Образует оксиды с большинством элементов.","zh":"原子序数8，原子量15.999 u。占地球大气的21%。电负性极强；有氧呼吸所必需。与大多数元素形成氧化物。","pt_BR":"Número atômico 8, massa atômica 15,999 u. Compõe 21% da atmosfera terrestre. Altamente eletronegativo; essencial para a respiração aeróbica. Forma óxidos com a maioria dos elementos.","pt_PT":"Número atómico 8, massa atómica 15,999 u. Constitui 21% da atmosfera terrestre. Altamente eletronegativo; essencial para a respiração aeróbica. Forma óxidos com a maioria dos elementos."}},
  { id: 'dc-chemistry-0009', deck_id: 'deck-chemistry', sort_order: 9, front: "Fluorine (F)", back: "Atomic number 9, atomic mass 18.998 u. Most electronegative element; pale yellow gas. Extremely reactive. Used in toothpaste (fluoride), Teflon, and refrigerants (CFCs/HFCs)." , front_translations: {"es":"Flúor (F)","de":"Fluor (F)","fr":"Fluor (F)","tr":"Flor (F)","nl":"Fluor (F)","ru":"Фтор (F)","zh":"氟 (F)","pt_BR":"Flúor (F)","pt_PT":"Flúor (F)"}, back_translations: {"es":"Número atómico 9, masa atómica 18,998 u. Elemento más eletronegativo; gas amarelo-pálido. Extremamente reativo. Usado en pasta de dente (fluoreto), Teflon y refrigerantes (CFCs/HFCs).","de":"Ordnungszahl 9, Atommasse 18,998 u. Elektronegativstes Element; blassgelbliches Gas. Äußerst reaktiv. Verwendet in Zahnpasta (Fluorid), Teflon und Kühlmitteln (FCKW/H-FCKW).","fr":"Numéro atomique 9, masse atomique 18,998 u. L'élément le plus électronégatif ; gaz jaune pâle. Extrêmement réactif. Utilisé dans le dentifrice (fluorure), le Téflon et les réfrigérants (CFC/HFC).","tr":"Atom numarası 9, atom kütlesi 18,998 u. En elektronegatif element; soluk sarı gaz. Son derece reaktiftir. Diş macununda (florür), Teflon'da ve soğutucularda (CFC/HFC) kullanılır.","nl":"Atoomnummer 9, atoommassa 18,998 u. Meest elektronegatief element; bleekgeel gas. Uiterst reactief. Gebruikt in tandpasta (fluoride), teflon en koelmiddelen (CFK's/HFK's).","ru":"Порядковый номер 9, атомная масса 18,998 у. Наиболее электроотрицательный элемент; бледно-жёлтый газ. Чрезвычайно реакционноспособен. Применяется в зубной пасте (фторид), тефлоне и хладагентах (ХФУ/ГФУ).","zh":"原子序数9，原子量18.998 u。电负性最强的元素；淡黄色气体。极具反应性。用于牙膏（氟化物）、特氟龙和制冷剂（氯氟烃/氢氟烃）。","pt_BR":"Número atômico 9, massa atômica 18,998 u. Elemento mais eletronegativo; gás amarelo-pálido. Extremamente reativo. Usado em pasta de dente (fluoreto), Teflon e refrigerantes (CFCs/HFCs).","pt_PT":"Número atómico 9, massa atómica 18,998 u. Elemento mais eletronegativo; gás amarelo-pálido. Extremamente reativo. Usado em pasta dentífrica (fluoreto), Teflon e refrigerantes (CFCs/HFCs)."}},
  { id: 'dc-chemistry-0010', deck_id: 'deck-chemistry', sort_order: 10, front: "Neon (Ne)", back: "Atomic number 10, atomic mass 20.180 u. Noble gas; unreactive. Emits red-orange light when excited electrically, used in neon signs. Obtained by fractional distillation of liquid air." , front_translations: {"es":"Neonio (Ne)","de":"Neon (Ne)","fr":"Néon (Ne)","tr":"Neon (Ne)","nl":"Neon (Ne)","ru":"Неон (Ne)","zh":"氖 (Ne)","pt_BR":"Neônio (Ne)","pt_PT":"Néon (Ne)"}, back_translations: {"es":"Número atómico 10, masa atómica 20,180 u. Gas nobre; inerte. Emite luz rojo-alaranjada cuando excitado eletricamente, usado en letreros de néon. Obtenido por destilación fracionada del aire líquido.","de":"Ordnungszahl 10, Atommasse 20,180 u. Edelgas; reaktionsträge. Emittiert rotoranges Licht bei elektrischer Anregung, verwendet in Leuchtreklamen. Gewonnen durch fraktionierte Destillation von flüssiger Luft.","fr":"Numéro atomique 10, masse atomique 20,180 u. Gaz noble ; non réactif. Émet une lumière rouge-orangé quand il est excité électriquement, utilisé dans les enseignes au néon. Obtenu par distillation fractionnée de l'air liquide.","tr":"Atom numarası 10, atom kütlesi 20,180 u. Soy gaz; tepkisiz. Elektriksel olarak uyarıldığında kırmızı-turuncu ışık yayar, neon tabelalarında kullanılır. Sıvı havanın fraksiyonel damıtılmasıyla elde edilir.","nl":"Atoomnummer 10, atoommassa 20,180 u. Edelgas; inert. Zendt rood-oranje licht uit bij elektrische opwinding, gebruikt in neonreclames. Verkregen door fractionele destillatie van vloeibare lucht.","ru":"Порядковый номер 10, атомная масса 20,180 у. Благородный газ; инертен. При электрическом возбуждении испускает красно-оранжевый свет; используется в неоновых вывесках. Получают фракционной перегонкой жидкого воздуха.","zh":"原子序数10，原子量20.180 u。稀有气体；不活泼。受电激发时发出红橙色光，用于霓虹灯。通过液态空气分馏获得。","pt_BR":"Número atômico 10, massa atômica 20,180 u. Gás nobre; inerte. Emite luz vermelho-alaranjada quando excitado eletricamente, usado em letreiros de néon. Obtido por destilação fracionada do ar líquido.","pt_PT":"Número atómico 10, massa atómica 20,180 u. Gás nobre; inerte. Emite luz vermelho-alaranjada quando excitado eletricamente, usado em insígnias de néon. Obtido por destilação fracionada do ar líquido."}},
  { id: 'dc-chemistry-0011', deck_id: 'deck-chemistry', sort_order: 11, front: "Sodium (Na)", back: "Atomic number 11, atomic mass 22.990 u. Reactive alkali metal; stored under oil. Critical electrolyte in biological systems. NaCl (table salt) is its most common compound." , front_translations: {"es":"Sódio (Na)","de":"Natrium (Na)","fr":"Sodium (Na)","tr":"Sodyum (Na)","nl":"Natrium (Na)","ru":"Натрий (Na)","zh":"钠 (Na)","pt_BR":"Sódio (Na)","pt_PT":"Sódio (Na)"}, back_translations: {"es":"Número atómico 11, masa atómica 22,990 u. Metal alcalino reativo; almacenado sob óleo. Eletrólito esencial en los sistemas biológicos. NaCl (sal de cozinha) es su compuesto más comum.","de":"Ordnungszahl 11, Atommasse 22,990 u. Reaktives Alkalimetall; wird unter Öl aufbewahrt. Kritisches Elektrolyt in biologischen Systemen. NaCl (Kochsalz) ist seine häufigste Verbindung.","fr":"Numéro atomique 11, masse atomique 22,990 u. Métal alcalin réactif ; conservé sous huile. Électrolyte critique dans les systèmes biologiques. NaCl (sel de table) est son composé le plus courant.","tr":"Atom numarası 11, atom kütlesi 22,990 u. Reaktif alkali metal; yağ altında saklanır. Biyolojik sistemlerde kritik elektrolittir. NaCl (sofra tuzu) en yaygın bileşiğidir.","nl":"Atoomnummer 11, atoommassa 22,990 u. Reactief alkalimetaal; bewaard onder olie. Kritisch elektrolyt in biologische systemen. NaCl (keukenzout) is zijn meest voorkomende verbinding.","ru":"Порядковый номер 11, атомная масса 22,990 у. Реакционноспособный щелочной металл; хранится под маслом. Важнейший электролит в биологических системах. NaCl (поваренная соль) — его наиболее распространённое соединение.","zh":"原子序数11，原子量22.990 u。活泼碱金属；储存于油中。生物系统中的关键电解质。NaCl（食盐）是其最常见的化合物。","pt_BR":"Número atômico 11, massa atômica 22,990 u. Metal alcalino reativo; armazenado sob óleo. Eletrólito essencial nos sistemas biológicos. NaCl (sal de cozinha) é seu composto mais comum.","pt_PT":"Número atómico 11, massa atómica 22,990 u. Metal alcalino reativo; armazenado sob óleo. Eletrólito essencial nos sistemas biológicos. NaCl (sal de cozinha) é o seu composto mais comum."}},
  { id: 'dc-chemistry-0012', deck_id: 'deck-chemistry', sort_order: 12, front: "Magnesium (Mg)", back: "Atomic number 12, atomic mass 24.305 u. Alkaline earth metal; burns brilliantly in air with white flame. Essential in chlorophyll and many enzymes. Used in lightweight alloys." , front_translations: {"es":"Magnésio (Mg)","de":"Magnesium (Mg)","fr":"Magnésium (Mg)","tr":"Magnezyum (Mg)","nl":"Magnesium (Mg)","ru":"Магний (Mg)","zh":"镁 (Mg)","pt_BR":"Magnésio (Mg)","pt_PT":"Magnésio (Mg)"}, back_translations: {"es":"Número atómico 12, masa atómica 24,305 u. Metal alcalino-terroso; queima brilhantemente en el aire con chama branca. Esencial en la clorofila y en muchas enzimas. Usado en ligas leves.","de":"Ordnungszahl 12, Atommasse 24,305 u. Erdalkalimetall; brennt in der Luft mit heller weißer Flamme. Unentbehrlich in Chlorophyll und vielen Enzymen. Verwendet in Leichtbaulegierungen.","fr":"Numéro atomique 12, masse atomique 24,305 u. Métal alcalino-terreux ; brûle brillamment dans l'air avec une flamme blanche. Essentiel dans la chlorophylle et de nombreuses enzymes. Utilisé dans les alliages légers.","tr":"Atom numarası 12, atom kütlesi 24,305 u. Toprak alkali metal; havada parlak beyaz alevle yanar. Klorofil ve birçok enzimde zorunludur. Hafif alaşımlarda kullanılır.","nl":"Atoomnummer 12, atoommassa 24,305 u. Aardalkalimetaal; verbrandt schitterend in lucht met een witte vlam. Essentieel in chlorofyl en veel enzymen. Gebruikt in lichte legeringen.","ru":"Порядковый номер 12, атомная масса 24,305 у. Щёлочноземельный металл; ярко горит в воздухе белым пламенем. Незаменим в хлорофилле и многих ферментах. Применяется в лёгких сплавах.","zh":"原子序数12，原子量24.305 u。碱土金属；在空气中燃烧发出耀眼的白色火焰。叶绿素和许多酶中不可缺少。用于轻质合金。","pt_BR":"Número atômico 12, massa atômica 24,305 u. Metal alcalino-terroso; queima brilhantemente no ar com chama branca. Essencial na clorofila e em muitas enzimas. Usado em ligas leves.","pt_PT":"Número atómico 12, massa atómica 24,305 u. Metal alcalino-terroso; queima brilhantemente no ar com chama branca. Essencial na clorofila e em muitas enzimas. Usado em ligas leves."}},
  { id: 'dc-chemistry-0013', deck_id: 'deck-chemistry', sort_order: 13, front: "Aluminum (Al)", back: "Atomic number 13, atomic mass 26.982 u. Most abundant metal in Earth's crust. Lightweight, corrosion-resistant (forms Al₂O₃ layer). Widely used in packaging, transportation, construction." , front_translations: {"es":"Alumínio (Al)","de":"Aluminium (Al)","fr":"Aluminium (Al)","tr":"Alüminyum (Al)","nl":"Aluminium (Al)","ru":"Алюминий (Al)","zh":"铝 (Al)","pt_BR":"Alumínio (Al)","pt_PT":"Alumínio (Al)"}, back_translations: {"es":"Número atómico 13, masa atómica 26,982 u. Metal más abundante en la crosta terrestre. Ligero, resistente a la corrosión (forma capa de Al₂El₃). Amplamente usado en embalajes, transporte y construcción.","de":"Ordnungszahl 13, Atommasse 26,982 u. Häufigstes Metall in der Erdkruste. Leicht, korrosionsbeständig (bildet Al₂O₃-Schicht). Weit verbreitet in Verpackungen, Transport und Bauwesen.","fr":"Numéro atomique 13, masse atomique 26,982 u. Métal le plus abondant dans la croûte terrestre. Léger, résistant à la corrosion (forme une couche d'Al₂O₃). Largement utilisé dans l'emballage, le transport et la construction.","tr":"Atom numarası 13, atom kütlesi 26,982 u. Dünya kabuğundaki en bol metal. Hafif, korozyona dayanıklı (Al₂O₃ tabakası oluşturur). Ambalaj, ulaşım ve inşaatta yaygın olarak kullanılır.","nl":"Atoomnummer 13, atoommassa 26,982 u. Meest voorkomend metaal in de aardkorst. Licht, corrosiebestendig (vormt een Al₂O₃-laag). Veel gebruikt in verpakkingen, transport en bouw.","ru":"Порядковый номер 13, атомная масса 26,982 у. Наиболее распространённый металл в земной коре. Лёгкий, коррозионностойкий (образует слой Al₂O₃). Широко применяется в упаковке, транспорте и строительстве.","zh":"原子序数13，原子量26.982 u。地壳中含量最丰富的金属。轻质、耐腐蚀（形成Al₂O₃保护层）。广泛用于包装、交通和建筑。","pt_BR":"Número atômico 13, massa atômica 26,982 u. Metal mais abundante na crosta terrestre. Leve, resistente à corrosão (forma camada de Al₂O₃). Amplamente usado em embalagens, transporte e construção.","pt_PT":"Número atómico 13, massa atómica 26,982 u. Metal mais abundante na crosta terrestre. Leve, resistente à corrosão (forma camada de Al₂O₃). Amplamente usado em embalagens, transporte e construção."}},
  { id: 'dc-chemistry-0014', deck_id: 'deck-chemistry', sort_order: 14, front: "Silicon (Si)", back: "Atomic number 14, atomic mass 28.086 u. Second most abundant element in Earth's crust after oxygen. Semiconductor; basis of modern electronics and solar cells. Forms SiO₂ (quartz, glass)." , front_translations: {"es":"Silício (Si)","de":"Silizium (Si)","fr":"Silicium (Si)","tr":"Silisyum (Si)","nl":"Silicium (Si)","ru":"Кремний (Si)","zh":"硅 (Si)","pt_BR":"Silício (Si)","pt_PT":"Silício (Si)"}, back_translations: {"es":"Número atómico 14, masa atómica 28,086 u. Según elemento más abundante en la crosta terrestre, após el oxígeno. Semicondutor; base de la electrónica moderna y células solares. Forma SiO₂ (quartzo, vidro).","de":"Ordnungszahl 14, Atommasse 28,086 u. Zweithäufigstes Element in der Erdkruste nach Sauerstoff. Halbleiter; Grundlage der modernen Elektronik und Solarzellen. Bildet SiO₂ (Quarz, Glas).","fr":"Numéro atomique 14, masse atomique 28,086 u. Deuxième élément le plus abondant dans la croûte terrestre après l'oxygène. Semi-conducteur ; base de l'électronique moderne et des cellules solaires. Forme SiO₂ (quartz, verre).","tr":"Atom numarası 14, atom kütlesi 28,086 u. Dünya kabuğunda oksijenden sonra ikinci en bol element. Yarı iletken; modern elektroniğin ve güneş pillerinin temelidir. SiO₂ (kuvars, cam) oluşturur.","nl":"Atoomnummer 14, atoommassa 28,086 u. Op één na meest voorkomend element in de aardkorst na zuurstof. Halfgeleider; basis van moderne elektronica en zonnecellen. Vormt SiO₂ (kwarts, glas).","ru":"Порядковый номер 14, атомная масса 28,086 у. Второй по распространённости элемент в земной коре после кислорода. Полупроводник; основа современной электроники и солнечных батарей. Образует SiO₂ (кварц, стекло).","zh":"原子序数14，原子量28.086 u。地壳中丰度仅次于氧的元素。半导体；现代电子和太阳能电池的基础。形成SiO₂（石英、玻璃）。","pt_BR":"Número atômico 14, massa atômica 28,086 u. Segundo elemento mais abundante na crosta terrestre, após o oxigênio. Semicondutor; base da eletrônica moderna e células solares. Forma SiO₂ (quartzo, vidro).","pt_PT":"Número atómico 14, massa atómica 28,086 u. Segundo elemento mais abundante na crosta terrestre, após o oxigénio. Semicondutor; base da eletrónica moderna e células solares. Forma SiO₂ (quartzo, vidro)."}},
  { id: 'dc-chemistry-0015', deck_id: 'deck-chemistry', sort_order: 15, front: "Phosphorus (P)", back: "Atomic number 15, atomic mass 30.974 u. Essential for DNA, RNA, and ATP. Exists as white (reactive) and red (stable) allotropes. Used in fertilizers, matches, and detergents." , front_translations: {"es":"Fósforo (P)","de":"Phosphor (P)","fr":"Phosphore (P)","tr":"Fosfor (P)","nl":"Fosfor (P)","ru":"Фосфор (P)","zh":"磷 (P)","pt_BR":"Fósforo (P)","pt_PT":"Fósforo (P)"}, back_translations: {"es":"Número atómico 15, masa atómica 30,974 u. Esencial para DNA, RNA y ATP. Existe como alótropos branco (reativo) y rojo (estable). Usado en fertilizantes, fósforos y detergentes.","de":"Ordnungszahl 15, Atommasse 30,974 u. Unentbehrlich für DNA, RNA und ATP. Existiert als weiße (reaktive) und rote (stabile) Allotrope. Verwendet in Düngemitteln, Streichhölzern und Waschmitteln.","fr":"Numéro atomique 15, masse atomique 30,974 u. Essentiel pour l'ADN, l'ARN et l'ATP. Existe sous forme d'allotropes blanc (réactif) et rouge (stable). Utilisé dans les engrais, les allumettes et les détergents.","tr":"Atom numarası 15, atom kütlesi 30,974 u. DNA, RNA ve ATP için zorunludur. Beyaz (reaktif) ve kırmızı (kararlı) allotrop olarak bulunur. Gübreler, kibritler ve deterjanlarda kullanılır.","nl":"Atoomnummer 15, atoommassa 30,974 u. Essentieel voor DNA, RNA en ATP. Bestaat als witte (reactieve) en rode (stabiele) allotropen. Gebruikt in meststoffen, lucifers en wasmiddelen.","ru":"Порядковый номер 15, атомная масса 30,974 у. Незаменим для ДНК, РНК и АТФ. Существует в виде белой (реакционной) и красной (стабильной) аллотропных форм. Применяется в удобрениях, спичках и моющих средствах.","zh":"原子序数15，原子量30.974 u。DNA、RNA和ATP不可缺少。以白磷（活泼）和红磷（稳定）同素异形体存在。用于化肥、火柴和洗涤剂。","pt_BR":"Número atômico 15, massa atômica 30,974 u. Essencial para DNA, RNA e ATP. Existe como alótropos branco (reativo) e vermelho (estável). Usado em fertilizantes, fósforos e detergentes.","pt_PT":"Número atómico 15, massa atómica 30,974 u. Essencial para DNA, RNA e ATP. Existe como alótropos branco (reativo) e vermelho (estável). Usado em fertilizantes, fósforos e detergentes."}},
  { id: 'dc-chemistry-0016', deck_id: 'deck-chemistry', sort_order: 16, front: "Sulfur (S)", back: "Atomic number 16, atomic mass 32.065 u. Yellow solid; found near volcanoes. Essential in amino acids (cysteine, methionine). Used to make H₂SO₄, the most produced chemical worldwide." , front_translations: {"es":"Enxofre (S)","de":"Schwefel (S)","fr":"Soufre (S)","tr":"Kükürt (S)","nl":"Zwavel (S)","ru":"Сера (S)","zh":"硫 (S)","pt_BR":"Enxofre (S)","pt_PT":"Enxofre (S)"}, back_translations: {"es":"Número atómico 16, masa atómica 32,065 u. Sólido amarelo; encontrado perto de vulcões. Esencial en aminoácidos (cisteína, metionina). Usado para produzir H₂SO₄, el producto químico más producido en el mundo.","de":"Ordnungszahl 16, Atommasse 32,065 u. Gelber Feststoff; kommt in der Nähe von Vulkanen vor. Unentbehrlich in Aminosäuren (Cystein, Methionin). Verwendet zur Herstellung von H₂SO₄, dem weltweit meistproduzierten Chemikalie.","fr":"Numéro atomique 16, masse atomique 32,065 u. Solide jaune ; présent près des volcans. Essentiel dans les acides aminés (cystéine, méthionine). Utilisé pour fabriquer H₂SO₄, le produit chimique le plus produit au monde.","tr":"Atom numarası 16, atom kütlesi 32,065 u. Sarı katı; volkanların yakınında bulunur. Amino asitlerde (sistein, metiyonin) zorunludur. Dünyada en çok üretilen kimyasal olan H₂SO₄ yapımında kullanılır.","nl":"Atoomnummer 16, atoommassa 32,065 u. Gele vaste stof; gevonden in de buurt van vulkanen. Essentieel in aminozuren (cysteïne, methionine). Gebruikt om H₂SO₄ te maken, de wereldwijd meest geproduceerde chemische stof.","ru":"Порядковый номер 16, атомная масса 32,065 у. Жёлтое твёрдое вещество; встречается вблизи вулканов. Незаменима в аминокислотах (цистеин, метионин). Применяется для производства H₂SO₄ — наиболее производимого химического вещества в мире.","zh":"原子序数16，原子量32.065 u。黄色固体；常见于火山附近。氨基酸（半胱氨酸、蛋氨酸）中不可缺少。用于制造全球产量最大的化学品H₂SO₄。","pt_BR":"Número atômico 16, massa atômica 32,065 u. Sólido amarelo; encontrado perto de vulcões. Essencial em aminoácidos (cisteína, metionina). Usado para produzir H₂SO₄, o produto químico mais produzido no mundo.","pt_PT":"Número atómico 16, massa atómica 32,065 u. Sólido amarelo; encontrado perto de vulcões. Essencial em aminoácidos (cisteína, metionina). Usado para produzir H₂SO₄, o produto químico mais produzido no mundo."}},
  { id: 'dc-chemistry-0017', deck_id: 'deck-chemistry', sort_order: 17, front: "Chlorine (Cl)", back: "Atomic number 17, atomic mass 35.453 u. Halogen; greenish-yellow toxic gas. Used as a disinfectant in water treatment. Forms ionic NaCl and covalent HCl (hydrochloric acid)." , front_translations: {"es":"Cloro (Cl)","de":"Chlor (Cl)","fr":"Chlore (Cl)","tr":"Klor (Cl)","nl":"Chloor (Cl)","ru":"Хлор (Cl)","zh":"氯 (Cl)","pt_BR":"Cloro (Cl)","pt_PT":"Cloro (Cl)"}, back_translations: {"es":"Número atómico 17, masa atómica 35,453 u. Halogenio; gas amarelo-esverdeado tóxico. Usado como desinfetante en el tratamiento de agua. Forma NaCl ionico y HCl covalente (ácido clorídrico).","de":"Ordnungszahl 17, Atommasse 35,453 u. Halogen; gelblich-grünes Giftgas. Als Desinfektionsmittel bei der Wasseraufbereitung eingesetzt. Bildet ionisches NaCl und kovalentes HCl (Salzsäure).","fr":"Numéro atomique 17, masse atomique 35,453 u. Halogène ; gaz jaune-verdâtre toxique. Utilisé comme désinfectant dans le traitement de l'eau. Forme NaCl ionique et HCl covalent (acide chlorhydrique).","tr":"Atom numarası 17, atom kütlesi 35,453 u. Halojen; yeşilimsi sarı zehirli gaz. Su arıtmada dezenfektan olarak kullanılır. İyonik NaCl ve kovalent HCl (hidroklorik asit) oluşturur.","nl":"Atoomnummer 17, atoommassa 35,453 u. Halogeen; geelgroen giftig gas. Gebruikt als desinfectant bij waterbehandeling. Vormt ionisch NaCl en covalent HCl (zoutzuur).","ru":"Порядковый номер 17, атомная масса 35,453 у. Галоген; жёлто-зелёный ядовитый газ. Применяется как дезинфектант при водоподготовке. Образует ионный NaCl и ковалентный HCl (соляная кислота).","zh":"原子序数17，原子量35.453 u。卤素；黄绿色有毒气体。用作水处理中的消毒剂。形成离子型NaCl和共价型HCl（盐酸）。","pt_BR":"Número atômico 17, massa atômica 35,453 u. Halogênio; gás amarelo-esverdeado tóxico. Usado como desinfetante no tratamento de água. Forma NaCl iônico e HCl covalente (ácido clorídrico).","pt_PT":"Número atómico 17, massa atómica 35,453 u. Halogénio; gás amarelo-esverdeado tóxico. Usado como desinfetante no tratamento de água. Forma NaCl iónico e HCl covalente (ácido clorídrico)."}},
  { id: 'dc-chemistry-0018', deck_id: 'deck-chemistry', sort_order: 18, front: "Argon (Ar)", back: "Atomic number 18, atomic mass 39.948 u. Noble gas; makes up ~0.93% of Earth's atmosphere. Used as an inert atmosphere for welding, incandescent bulbs, and laboratory work." , front_translations: {"es":"Argonio (Aire)","de":"Argon (Ar)","fr":"Argon (Ar)","tr":"Argon (Ar)","nl":"Argon (Ar)","ru":"Аргон (Ar)","zh":"氩 (Ar)","pt_BR":"Argônio (Ar)","pt_PT":"Árgon (Ar)"}, back_translations: {"es":"Número atómico 18, masa atómica 39,948 u. Gas nobre; compõe ~0,93% de la atmosfera terrestre. Usado como atmosfera inerte en soldaje, lampadas incandescentes y trabajos de laboratório.","de":"Ordnungszahl 18, Atommasse 39,948 u. Edelgas; macht ~0,93 % der Erdatmosphäre aus. Wird als Inertgasatmosphäre beim Schweißen, in Glühlampen und für Laborarbeiten verwendet.","fr":"Numéro atomique 18, masse atomique 39,948 u. Gaz noble ; représente environ 0,93 % de l'atmosphère terrestre. Utilisé comme atmosphère inerte pour le soudage, les ampoules à incandescence et les travaux de laboratoire.","tr":"Atom numarası 18, atom kütlesi 39,948 u. Soy gaz; Dünya atmosferinin yaklaşık %0,93'ünü oluşturur. Kaynak işlemi, akkor lambalar ve laboratuvar çalışmalarında inert atmosfer olarak kullanılır.","nl":"Atoomnummer 18, atoommassa 39,948 u. Edelgas; maakt ~0,93% uit van de aardatmosfeer. Gebruikt als inerte atmosfeer voor lassen, gloeilampen en laboratoriumwerk.","ru":"Порядковый номер 18, атомная масса 39,948 у. Благородный газ; составляет ~0,93% атмосферы Земли. Применяется в качестве инертной атмосферы при сварке, в лампах накаливания и в лабораторных работах.","zh":"原子序数18，原子量39.948 u。稀有气体；约占地球大气的0.93%。用作焊接、白炽灯和实验室工作的惰性气氛。","pt_BR":"Número atômico 18, massa atômica 39,948 u. Gás nobre; compõe ~0,93% da atmosfera terrestre. Usado como atmosfera inerte em soldagem, lâmpadas incandescentes e trabalhos de laboratório.","pt_PT":"Número atómico 18, massa atómica 39,948 u. Gás nobre; constitui ~0,93% da atmosfera terrestre. Usado como atmosfera inerte em soldadura, lâmpadas incandescentes e trabalhos laboratoriais."}},
  { id: 'dc-chemistry-0019', deck_id: 'deck-chemistry', sort_order: 19, front: "Potassium (K)", back: "Atomic number 19, atomic mass 39.098 u. Alkali metal; critical intracellular cation in biology. Highly reactive with water. Used in fertilizers (potash) and gunpowder." , front_translations: {"es":"Potássio (K)","de":"Kalium (K)","fr":"Potassium (K)","tr":"Potasyum (K)","nl":"Kalium (K)","ru":"Калий (K)","zh":"钾 (K)","pt_BR":"Potássio (K)","pt_PT":"Potássio (K)"}, back_translations: {"es":"Número atómico 19, masa atómica 39,098 u. Metal alcalino; cátion intracelular esencial en la biologia. Reage vigorosamente con a agua. Usado en fertilizantes (potassa) y pólvora.","de":"Ordnungszahl 19, Atommasse 39,098 u. Alkalimetall; wichtiges intrazelluläres Kation in der Biologie. Reagiert heftig mit Wasser. Verwendet in Düngemitteln (Kali) und Schießpulver.","fr":"Numéro atomique 19, masse atomique 39,098 u. Métal alcalin ; cation intracellulaire essentiel en biologie. Très réactif avec l'eau. Utilisé dans les engrais (potasse) et la poudre à canon.","tr":"Atom numarası 19, atom kütlesi 39,098 u. Alkali metal; biyolojide kritik hücre içi katyon. Su ile şiddetli reaksiyon verir. Gübreler (potas) ve barutda kullanılır.","nl":"Atoomnummer 19, atoommassa 39,098 u. Alkalimetaal; kritisch intracellulair kation in de biologie. Reageert heftig met water. Gebruikt in meststoffen (kali) en buskruit.","ru":"Порядковый номер 19, атомная масса 39,098 у. Щелочной металл; важнейший внутриклеточный катион в биологии. Бурно реагирует с водой. Применяется в удобрениях (поташ) и порохе.","zh":"原子序数19，原子量39.098 u。碱金属；生物学中关键的胞内阳离子。与水剧烈反应。用于化肥（钾肥）和火药。","pt_BR":"Número atômico 19, massa atômica 39,098 u. Metal alcalino; cátion intracelular essencial na biologia. Reage vigorosamente com a água. Usado em fertilizantes (potassa) e pólvora.","pt_PT":"Número atómico 19, massa atómica 39,098 u. Metal alcalino; catião intracelular essencial na biologia. Reage vigorosamente com a água. Usado em fertilizantes (potassa) e pólvora."}},
  { id: 'dc-chemistry-0020', deck_id: 'deck-chemistry', sort_order: 20, front: "Calcium (Ca)", back: "Atomic number 20, atomic mass 40.078 u. Alkaline earth metal; the fifth most abundant element in Earth's crust. Essential for bones, teeth, and cell signaling. Found in limestone (CaCO₃)." , front_translations: {"es":"Cálcio (Ca)","de":"Calcium (Ca)","fr":"Calcium (Ca)","tr":"Kalsiyum (Ca)","nl":"Calcium (Ca)","ru":"Кальций (Ca)","zh":"钙 (Ca)","pt_BR":"Cálcio (Ca)","pt_PT":"Cálcio (Ca)"}, back_translations: {"es":"Número atómico 20, masa atómica 40,078 u. Metal alcalino-terroso; quinto elemento más abundante en la crosta terrestre. Esencial para huesos, dentes y sinalización celular. Encontrado en el calcário (CaCO₃).","de":"Ordnungszahl 20, Atommasse 40,078 u. Erdalkalimetall; das fünfthäufigste Element in der Erdkruste. Unentbehrlich für Knochen, Zähne und Zellsignalisierung. Vorkommt in Kalkstein (CaCO₃).","fr":"Numéro atomique 20, masse atomique 40,078 u. Métal alcalino-terreux ; cinquième élément le plus abondant dans la croûte terrestre. Essentiel pour les os, les dents et la signalisation cellulaire. Présent dans le calcaire (CaCO₃).","tr":"Atom numarası 20, atom kütlesi 40,078 u. Toprak alkali metal; Dünya kabuğundaki beşinci en bol element. Kemikler, dişler ve hücre sinyalizasyonu için zorunludur. Kireçtaşında (CaCO₃) bulunur.","nl":"Atoomnummer 20, atoommassa 40,078 u. Aardalkalimetaal; het vijfde meest voorkomende element in de aardkorst. Essentieel voor botten, tanden en celsignalering. Gevonden in kalksteen (CaCO₃).","ru":"Порядковый номер 20, атомная масса 40,078 у. Щёлочноземельный металл; пятый по распространённости элемент в земной коре. Незаменим для костей, зубов и клеточной сигнализации. Встречается в известняке (CaCO₃).","zh":"原子序数20，原子量40.078 u。碱土金属；地壳中第五丰富的元素。骨骼、牙齿和细胞信号传导不可缺少。存在于石灰石（CaCO₃）中。","pt_BR":"Número atômico 20, massa atômica 40,078 u. Metal alcalino-terroso; quinto elemento mais abundante na crosta terrestre. Essencial para ossos, dentes e sinalização celular. Encontrado no calcário (CaCO₃).","pt_PT":"Número atómico 20, massa atómica 40,078 u. Metal alcalino-terroso; quinto elemento mais abundante na crosta terrestre. Essencial para ossos, dentes e sinalização celular. Encontrado na calcário (CaCO₃)."}},
  { id: 'dc-chemistry-0021', deck_id: 'deck-chemistry', sort_order: 21, front: "Scandium (Sc)", back: "Atomic number 21, atomic mass 44.956 u. First transition metal; silvery-white. Used in aluminum alloys for aerospace and in metal-halide lamps. Relatively rare in pure form." , front_translations: {"es":"Escandio (Sc)","de":"Scandium (Sc)","fr":"Scandium (Sc)","tr":"Skandiyum (Sc)","nl":"Scandium (Sc)","ru":"Скандий (Sc)","zh":"钪 (Sc)","pt_BR":"Escândio (Sc)","pt_PT":"Escândio (Sc)"}, back_translations: {"es":"Número atómico 21, masa atómica 44,956 u. Primero metal de transición; branco-prateado. Usado en ligas de alumínio para aeroespacial y en lampadas de haleto metálico. Relativamente raro en la forma pura.","de":"Ordnungszahl 21, Atommasse 44,956 u. Erstes Übergangsmetall; silbrig-weiß. Verwendet in Aluminiumlegierungen für die Luft- und Raumfahrt sowie in Metallhalogenidlampen. In reiner Form relativ selten.","fr":"Numéro atomique 21, masse atomique 44,956 u. Premier métal de transition ; blanc argenté. Utilisé dans les alliages d'aluminium pour l'aérospatiale et dans les lampes à halogénures métalliques. Relativement rare sous forme pure.","tr":"Atom numarası 21, atom kütlesi 44,956 u. İlk geçiş metali; gümüşi beyaz. Havacılık alüminyum alaşımlarında ve metal-halojenür lambalarda kullanılır. Saf hâlde görece nadirdir.","nl":"Atoomnummer 21, atoommassa 44,956 u. Eerste overgangsmetaal; zilverachtig wit. Gebruikt in aluminiumlegeringen voor de luchtvaart en in metaalhalogenidelampen. Relatief zeldzaam in pure vorm.","ru":"Порядковый номер 21, атомная масса 44,956 у. Первый переходный металл; серебристо-белый. Применяется в алюминиевых сплавах для аэрокосмической промышленности и в металлогалогенных лампах. В чистом виде встречается редко.","zh":"原子序数21，原子量44.956 u。第一种过渡金属；银白色。用于航空航天铝合金和金属卤化物灯。纯态下相对稀少。","pt_BR":"Número atômico 21, massa atômica 44,956 u. Primeiro metal de transição; branco-prateado. Usado em ligas de alumínio para aeroespacial e em lâmpadas de haleto metálico. Relativamente raro na forma pura.","pt_PT":"Número atómico 21, massa atómica 44,956 u. Primeiro metal de transição; branco-prateado. Usado em ligas de alumínio para aeroespacial e em lâmpadas de haleto metálico. Relativamente raro na forma pura."}},
  { id: 'dc-chemistry-0022', deck_id: 'deck-chemistry', sort_order: 22, front: "Titanium (Ti)", back: "Atomic number 22, atomic mass 47.867 u. Transition metal; strong, lightweight, corrosion-resistant. Used in aerospace, medical implants, and pigments (TiO₂ in white paint)." , front_translations: {"es":"Titanio (Ti)","de":"Titan (Ti)","fr":"Titane (Ti)","tr":"Titanyum (Ti)","nl":"Titanium (Ti)","ru":"Титан (Ti)","zh":"钛 (Ti)","pt_BR":"Titânio (Ti)","pt_PT":"Titânio (Ti)"}, back_translations: {"es":"Número atómico 22, masa atómica 47,867 u. Metal de transición; resistente, ligero, resistente a la corrosión. Usado en aeroespacial, implantes médicos y pigmentos (TiO₂ en tinta branca).","de":"Ordnungszahl 22, Atommasse 47,867 u. Übergangsmetall; stark, leicht, korrosionsbeständig. Verwendet in der Luft- und Raumfahrt, medizinischen Implantaten und Pigmenten (TiO₂ in weißer Farbe).","fr":"Numéro atomique 22, masse atomique 47,867 u. Métal de transition ; solide, léger, résistant à la corrosion. Utilisé dans l'aérospatiale, les implants médicaux et les pigments (TiO₂ dans la peinture blanche).","tr":"Atom numarası 22, atom kütlesi 47,867 u. Geçiş metali; sağlam, hafif, korozyona dayanıklı. Havacılık, tıbbi implantlar ve pigmentlerde (beyaz boyada TiO₂) kullanılır.","nl":"Atoomnummer 22, atoommassa 47,867 u. Overgangsmetaal; sterk, licht, corrosiebestendig. Gebruikt in de luchtvaart, medische implantaten en pigmenten (TiO₂ in witte verf).","ru":"Порядковый номер 22, атомная масса 47,867 у. Переходный металл; прочный, лёгкий, коррозионностойкий. Применяется в аэрокосмической промышленности, медицинских имплантатах и пигментах (TiO₂ в белой краске).","zh":"原子序数22，原子量47.867 u。过渡金属；强度高、重量轻、耐腐蚀。用于航空航天、医疗植入物和颜料（白色涂料中的TiO₂）。","pt_BR":"Número atômico 22, massa atômica 47,867 u. Metal de transição; resistente, leve, resistente à corrosão. Usado em aeroespacial, implantes médicos e pigmentos (TiO₂ em tinta branca).","pt_PT":"Número atómico 22, massa atómica 47,867 u. Metal de transição; resistente, leve, resistente à corrosão. Usado em aeroespacial, implantes médicos e pigmentos (TiO₂ em tinta branca)."}},
  { id: 'dc-chemistry-0023', deck_id: 'deck-chemistry', sort_order: 23, front: "Vanadium (V)", back: "Atomic number 23, atomic mass 50.942 u. Transition metal added to steel to increase strength. Exhibits multiple oxidation states (+2 to +5). Used in large-scale energy storage batteries." , front_translations: {"es":"Vanádio (V)","de":"Vanadium (V)","fr":"Vanadium (V)","tr":"Vanadyum (V)","nl":"Vanadium (V)","ru":"Ванадий (V)","zh":"钒 (V)","pt_BR":"Vanádio (V)","pt_PT":"Vanádio (V)"}, back_translations: {"es":"Número atómico 23, masa atómica 50,942 u. Metal de transición adicionado al aço para aumentar a resistencia. Exibe múltiplos estados de oxidación (+2 a +5). Usado en baterias de almacenamiento de energía en ancha escala.","de":"Ordnungszahl 23, Atommasse 50,942 u. Übergangsmetall, das Stahl zugefügt wird, um die Festigkeit zu erhöhen. Zeigt mehrere Oxidationsstufen (+2 bis +5). Verwendet in großmaßstäblichen Energiespeicherbatterien.","fr":"Numéro atomique 23, masse atomique 50,942 u. Métal de transition ajouté à l'acier pour augmenter sa résistance. Présente plusieurs états d'oxydation (+2 à +5). Utilisé dans les batteries de stockage d'énergie à grande échelle.","tr":"Atom numarası 23, atom kütlesi 50,942 u. Çeliğe dayanıklılık artırmak için eklenen geçiş metali. +2'den +5'e kadar birden fazla oksidasyon durumu sergiler. Büyük ölçekli enerji depolama pillerinde kullanılır.","nl":"Atoomnummer 23, atoommassa 50,942 u. Overgangsmetaal dat aan staal wordt toegevoegd om de sterkte te verhogen. Vertoont meerdere oxidatietoestanden (+2 tot +5). Gebruikt in grootschalige energieopslagbatterijen.","ru":"Порядковый номер 23, атомная масса 50,942 у. Переходный металл, добавляемый в сталь для повышения прочности. Проявляет несколько степеней окисления (от +2 до +5). Применяется в крупномасштабных аккумуляторах.","zh":"原子序数23，原子量50.942 u。加入钢中以提高强度的过渡金属。表现出多种氧化态（+2至+5）。用于大规模储能电池。","pt_BR":"Número atômico 23, massa atômica 50,942 u. Metal de transição adicionado ao aço para aumentar a resistência. Exibe múltiplos estados de oxidação (+2 a +5). Usado em baterias de armazenamento de energia em larga escala.","pt_PT":"Número atómico 23, massa atómica 50,942 u. Metal de transição adicionado ao aço para aumentar a resistência. Exibe múltiplos estados de oxidação (+2 a +5). Usado em baterias de armazenamento de energia em larga escala."}},
  { id: 'dc-chemistry-0024', deck_id: 'deck-chemistry', sort_order: 24, front: "Chromium (Cr)", back: "Atomic number 24, atomic mass 51.996 u. Hard, shiny transition metal. Key component of stainless steel. Cr³⁺ is a required trace nutrient; Cr⁶⁺ is highly toxic and carcinogenic." , front_translations: {"es":"Cromo (Cr)","de":"Chrom (Cr)","fr":"Chrome (Cr)","tr":"Krom (Cr)","nl":"Chroom (Cr)","ru":"Хром (Cr)","zh":"铬 (Cr)","pt_BR":"Cromo (Cr)","pt_PT":"Crómio (Cr)"}, back_translations: {"es":"Número atómico 24, masa atómica 51,996 u. Metal de transición duro y brilhante. Componente esencial del aço inoxidable. Cr³⁺ es un micronutriente esencial; Cr⁶⁺ es altamente tóxico y cancerígeno.","de":"Ordnungszahl 24, Atommasse 51,996 u. Hartes, glänzendes Übergangsmetall. Schlüsselkomponente von rostfreiem Stahl. Cr³⁺ ist ein erforderliches Spurenelement; Cr⁶⁺ ist hochgiftig und krebserregend.","fr":"Numéro atomique 24, masse atomique 51,996 u. Métal de transition dur et brillant. Composant clé de l'acier inoxydable. Cr³⁺ est un oligo-élément requis ; Cr⁶⁺ est hautement toxique et cancérigène.","tr":"Atom numarası 24, atom kütlesi 51,996 u. Sert, parlak geçiş metali. Paslanmaz çeliğin temel bileşeni. Cr³⁺ gerekli bir iz besindir; Cr⁶⁺ son derece toksik ve kanserojendir.","nl":"Atoomnummer 24, atoommassa 51,996 u. Hard, glanzend overgangsmetaal. Sleutelcomponent van roestvrij staal. Cr³⁺ is een vereist sporenelement; Cr⁶⁺ is zeer giftig en kankerverwekkend.","ru":"Порядковый номер 24, атомная масса 51,996 у. Твёрдый, блестящий переходный металл. Ключевой компонент нержавеющей стали. Cr³⁺ — необходимый микроэлемент; Cr⁶⁺ — высокотоксичен и канцерогенен.","zh":"原子序数24，原子量51.996 u。坚硬光亮的过渡金属。不锈钢的关键成分。Cr³⁺是必需的微量营养素；Cr⁶⁺具有高度毒性和致癌性。","pt_BR":"Número atômico 24, massa atômica 51,996 u. Metal de transição duro e brilhante. Componente essencial do aço inoxidável. Cr³⁺ é um micronutriente essencial; Cr⁶⁺ é altamente tóxico e cancerígeno.","pt_PT":"Número atómico 24, massa atómica 51,996 u. Metal de transição duro e brilhante. Componente essencial do aço inoxidável. Cr³⁺ é um micronutriente essencial; Cr⁶⁺ é altamente tóxico e cancerígeno."}},
  { id: 'dc-chemistry-0025', deck_id: 'deck-chemistry', sort_order: 25, front: "Manganese (Mn)", back: "Atomic number 25, atomic mass 54.938 u. Transition metal essential to steel production (prevents brittleness). Important cofactor in enzymes and vital for photosynthesis (oxygen evolution)." , front_translations: {"es":"Manganes (Mn)","de":"Mangan (Mn)","fr":"Manganèse (Mn)","tr":"Mangan (Mn)","nl":"Mangaan (Mn)","ru":"Марганец (Mn)","zh":"锰 (Mn)","pt_BR":"Manganês (Mn)","pt_PT":"Manganês (Mn)"}, back_translations: {"es":"Número atómico 25, masa atómica 54,938 u. Metal de transición esencial para a producción de aço (previene a fragilidad). Importante cofator en enzimas y vital para a fotossíntese (evolución del oxígeno).","de":"Ordnungszahl 25, Atommasse 54,938 u. Übergangsmetall, das für die Stahlproduktion unentbehrlich ist (verhindert Sprödigkeit). Wichtiger Kofaktor in Enzymen und wesentlich für die Photosynthese (Sauerstoffentwicklung).","fr":"Numéro atomique 25, masse atomique 54,938 u. Métal de transition essentiel à la production d'acier (prévient la fragilité). Important cofacteur dans les enzymes et vital pour la photosynthèse (dégagement d'oxygène).","tr":"Atom numarası 25, atom kütlesi 54,938 u. Çelik üretimi için temel geçiş metali (kırılganlığı önler). Enzimlerde önemli bir kofaktördür ve fotosentez için (oksijen gelişimi) yaşamsaldır.","nl":"Atoomnummer 25, atoommassa 54,938 u. Overgangsmetaal essentieel voor staalproductie (voorkomt broosheid). Belangrijke cofactor in enzymen en van vitaal belang voor fotosynthese (zuurstofevolutie).","ru":"Порядковый номер 25, атомная масса 54,938 у. Переходный металл, незаменимый для производства стали (предотвращает хрупкость). Важный кофактор в ферментах и необходим для фотосинтеза (выделение кислорода).","zh":"原子序数25，原子量54.938 u。钢铁生产不可缺少的过渡金属（防止脆性）。酶的重要辅因子，对光合作用（释放氧气）至关重要。","pt_BR":"Número atômico 25, massa atômica 54,938 u. Metal de transição essencial para a produção de aço (previne a fragilidade). Importante cofator em enzimas e vital para a fotossíntese (evolução do oxigênio).","pt_PT":"Número atómico 25, massa atómica 54,938 u. Metal de transição essencial para a produção de aço (previne a fragilidade). Importante cofator em enzimas e vital para a fotossíntese (evolução do oxigénio)."}},
  { id: 'dc-chemistry-0026', deck_id: 'deck-chemistry', sort_order: 26, front: "Iron (Fe)", back: "Atomic number 26, atomic mass 55.845 u. Most used metal; core of Earth is largely iron-nickel. Carries oxygen in hemoglobin (Fe²⁺). Rusts in the presence of O₂ and H₂O." , front_translations: {"es":"Ferro (Fe)","de":"Eisen (Fe)","fr":"Fer (Fe)","tr":"Demir (Fe)","nl":"IJzer (Fe)","ru":"Железо (Fe)","zh":"铁 (Fe)","pt_BR":"Ferro (Fe)","pt_PT":"Ferro (Fe)"}, back_translations: {"es":"Número atómico 26, masa atómica 55,845 u. Metal más utilizado; el núcleo de la Tierra es en grande parte formado por ferro-níquel. Transporta oxígeno en la hemoglobina (Fe²⁺). Enferruja en la presencia de El₂ y H₂El.","de":"Ordnungszahl 26, Atommasse 55,845 u. Meistgenutztes Metall; der Erdkern besteht größtenteils aus Eisen-Nickel. Transportiert Sauerstoff im Hämoglobin (Fe²⁺). Rostet in Anwesenheit von O₂ und H₂O.","fr":"Numéro atomique 26, masse atomique 55,845 u. Métal le plus utilisé ; le noyau terrestre est en grande partie composé de fer-nickel. Transporte l'oxygène dans l'hémoglobine (Fe²⁺). Rouille en présence de O₂ et H₂O.","tr":"Atom numarası 26, atom kütlesi 55,845 u. En çok kullanılan metal; Dünya'nın çekirdeği büyük ölçüde demir-nikeldan oluşur. Hemoglobinde oksijen taşır (Fe²⁺). O₂ ve H₂O varlığında paslanır.","nl":"Atoomnummer 26, atoommassa 55,845 u. Meest gebruikte metaal; de kern van de Aarde bestaat grotendeels uit ijzer-nikkel. Draagt zuurstof in hemoglobine (Fe²⁺). Roest bij aanwezigheid van O₂ en H₂O.","ru":"Атомный номер 26, атомная масса 55,845 а.е.м. Наиболее используемый металл; ядро Земли в основном состоит из железо-никелевого сплава. Переносит кислород в гемоглобине (Fe²⁺). Ржавеет в присутствии O₂ и H₂O.","zh":"原子序数26，原子质量55.845 u。使用最广泛的金属；地球核心主要由铁镍组成。在血红蛋白中携带氧气（Fe²⁺）。在O₂和H₂O存在下生锈。","pt_BR":"Número atômico 26, massa atômica 55,845 u. Metal mais utilizado; o núcleo da Terra é em grande parte formado por ferro-níquel. Transporta oxigênio na hemoglobina (Fe²⁺). Enferruja na presença de O₂ e H₂O.","pt_PT":"Número atómico 26, massa atómica 55,845 u. Metal mais utilizado; o núcleo da Terra é em grande parte formado por ferro-níquel. Transporta oxigénio na hemoglobina (Fe²⁺). Enferruja na presença de O₂ e H₂O."}},
  { id: 'dc-chemistry-0027', deck_id: 'deck-chemistry', sort_order: 27, front: "Cobalt (Co)", back: "Atomic number 27, atomic mass 58.933 u. Hard, lustrous transition metal. Central atom in vitamin B₁₂ (cobalamin). Used in superalloys, magnets, and lithium-ion battery cathodes." , front_translations: {"es":"Cobalto (Co)","de":"Kobalt (Co)","fr":"Cobalt (Co)","tr":"Kobalt (Co)","nl":"Kobalt (Co)","ru":"Кобальт (Co)","zh":"钴 (Co)","pt_BR":"Cobalto (Co)","pt_PT":"Cobalto (Co)"}, back_translations: {"es":"Número atómico 27, masa atómica 58,933 u. Metal de transición duro y brilhante. Átomo central en la vitamina B₁₂ (cobalamina). Usado en superligas, ímãs y cátodos de baterias de lítio-ion.","de":"Ordnungszahl 27, Atommasse 58,933 u. Hartes, glänzendes Übergangsmetall. Zentralatom in Vitamin B₁₂ (Cobalamin). Wird in Superlegierungen, Magneten und Kathoden von Lithium-Ionen-Batterien verwendet.","fr":"Numéro atomique 27, masse atomique 58,933 u. Métal de transition dur et lustré. Atome central dans la vitamine B₁₂ (cobalamine). Utilisé dans les superalliages, les aimants et les cathodes de batteries lithium-ion.","tr":"Atom numarası 27, atom kütlesi 58,933 u. Sert, parlak geçiş metali. Vitamin B₁₂'nin (kobalamin) merkez atomu. Süper alaşımlarda, mıknatıslarda ve lityum-iyon pil katotlarında kullanılır.","nl":"Atoomnummer 27, atoommassa 58,933 u. Hard, glanzend overgangsmetaal. Centraal atoom in vitamine B₁₂ (cobalamine). Gebruikt in superlegeringen, magneten en kathodes van lithium-ionbatterijen.","ru":"Атомный номер 27, атомная масса 58,933 а.е.м. Твёрдый блестящий переходный металл. Центральный атом в витамине B₁₂ (кобаламин). Используется в жаропрочных сплавах, магнитах и катодах литий-ионных аккумуляторов.","zh":"原子序数27，原子质量58.933 u。坚硬有光泽的过渡金属。维生素B₁₂（钴胺素）的中心原子。用于高温合金、磁铁和锂离子电池正极。","pt_BR":"Número atômico 27, massa atômica 58,933 u. Metal de transição duro e brilhante. Átomo central na vitamina B₁₂ (cobalamina). Usado em superligas, ímãs e cátodos de baterias de lítio-íon.","pt_PT":"Número atómico 27, massa atómica 58,933 u. Metal de transição duro e brilhante. Átomo central na vitamina B₁₂ (cobalamina). Usado em superligas, ímanes e cátodos de baterias de lítio-ião."}},
  { id: 'dc-chemistry-0028', deck_id: 'deck-chemistry', sort_order: 28, front: "Nickel (Ni)", back: "Atomic number 28, atomic mass 58.693 u. Corrosion-resistant transition metal. Used in stainless steel, coins, rechargeable batteries, and as a catalyst for hydrogenation reactions." , front_translations: {"es":"Níquel (Ni)","de":"Nickel (Ni)","fr":"Nickel (Ni)","tr":"Nikel (Ni)","nl":"Nikkel (Ni)","ru":"Никель (Ni)","zh":"镍 (Ni)","pt_BR":"Níquel (Ni)","pt_PT":"Níquel (Ni)"}, back_translations: {"es":"Número atómico 28, masa atómica 58,693 u. Metal de transición resistente a la corrosión. Usado en aço inoxidable, moedas, baterias recarregables y como catalizador en reacciones de hidrogenación.","de":"Ordnungszahl 28, Atommasse 58,693 u. Korrosionsbeständiges Übergangsmetall. Verwendet in Edelstahl, Münzen, wiederaufladbaren Batterien und als Katalysator für Hydrierungsreaktionen.","fr":"Numéro atomique 28, masse atomique 58,693 u. Métal de transition résistant à la corrosion. Utilisé dans l'acier inoxydable, les pièces de monnaie, les batteries rechargeables et comme catalyseur pour les réactions d'hydrogénation.","tr":"Atom numarası 28, atom kütlesi 58,693 u. Korozyona dayanıklı geçiş metali. Paslanmaz çelikte, madeni paralarda, şarj edilebilir pillerde ve hidrojenasyon reaksiyonları için katalizör olarak kullanılır.","nl":"Atoomnummer 28, atoommassa 58,693 u. Corrosiebestendig overgangsmetaal. Gebruikt in roestvast staal, munten, oplaadbare batterijen en als katalysator voor hydrogenatiereacties.","ru":"Атомный номер 28, атомная масса 58,693 а.е.м. Коррозионностойкий переходный металл. Используется в нержавеющей стали, монетах, перезаряжаемых аккумуляторах и в качестве катализатора реакций гидрирования.","zh":"原子序数28，原子质量58.693 u。耐腐蚀的过渡金属。用于不锈钢、硬币、可充电电池以及氢化反应的催化剂。","pt_BR":"Número atômico 28, massa atômica 58,693 u. Metal de transição resistente à corrosão. Usado em aço inoxidável, moedas, baterias recarregáveis e como catalisador em reações de hidrogenação.","pt_PT":"Número atómico 28, massa atómica 58,693 u. Metal de transição resistente à corrosão. Usado em aço inoxidável, moedas, baterias recarregáveis e como catalisador em reações de hidrogenação."}},
  { id: 'dc-chemistry-0029', deck_id: 'deck-chemistry', sort_order: 29, front: "Copper (Cu)", back: "Atomic number 29, atomic mass 63.546 u. Excellent electrical and thermal conductor. First metal used by humans. Key component of bronze (Cu+Sn) and brass (Cu+Zn). Essential trace nutrient." , front_translations: {"es":"Cobre (Cu)","de":"Kupfer (Cu)","fr":"Cuivre (Cu)","tr":"Bakır (Cu)","nl":"Koper (Cu)","ru":"Медь (Cu)","zh":"铜 (Cu)","pt_BR":"Cobre (Cu)","pt_PT":"Cobre (Cu)"}, back_translations: {"es":"Número atómico 29, masa atómica 63,546 u. Excelente condutor eléctrico y térmico. Primero metal utilizado por los humanos. Componente-chave del bronze (Cu+Sn) y del latão (Cu+Zn). Micronutriente esencial.","de":"Ordnungszahl 29, Atommasse 63,546 u. Hervorragender elektrischer und thermischer Leiter. Erstes vom Menschen genutztes Metall. Hauptbestandteil von Bronze (Cu+Sn) und Messing (Cu+Zn). Essenzielles Spurenelement.","fr":"Numéro atomique 29, masse atomique 63,546 u. Excellent conducteur électrique et thermique. Premier métal utilisé par les humains. Composant clé du bronze (Cu+Sn) et du laiton (Cu+Zn). Oligo-élément essentiel.","tr":"Atom numarası 29, atom kütlesi 63,546 u. Mükemmel elektrik ve ısı iletken. İnsanlar tarafından kullanılan ilk metal. Bronzun (Cu+Sn) ve pirincin (Cu+Zn) temel bileşeni. Temel eser element.","nl":"Atoomnummer 29, atoommassa 63,546 u. Uitstekende elektrische en warmtegeleider. Eerste metaal dat door mensen werd gebruikt. Sleutelcomponent van brons (Cu+Sn) en messing (Cu+Zn). Essentieel sporenelement.","ru":"Атомный номер 29, атомная масса 63,546 а.е.м. Превосходный электрический и тепловой проводник. Первый металл, использованный человеком. Ключевой компонент бронзы (Cu+Sn) и латуни (Cu+Zn). Незаменимый микроэлемент.","zh":"原子序数29，原子质量63.546 u。出色的导电和导热体。人类使用的第一种金属。青铜（Cu+Sn）和黄铜（Cu+Zn）的关键成分。必需微量元素。","pt_BR":"Número atômico 29, massa atômica 63,546 u. Excelente condutor elétrico e térmico. Primeiro metal utilizado pelos humanos. Componente-chave do bronze (Cu+Sn) e do latão (Cu+Zn). Micronutriente essencial.","pt_PT":"Número atómico 29, massa atómica 63,546 u. Excelente condutor elétrico e térmico. Primeiro metal utilizado pelos humanos. Componente-chave do bronze (Cu+Sn) e do latão (Cu+Zn). Micronutriente essencial."}},
  { id: 'dc-chemistry-0030', deck_id: 'deck-chemistry', sort_order: 30, front: "Zinc (Zn)", back: "Atomic number 30, atomic mass 65.38 u. Bluish-white transition metal. Essential trace element; important in immune function and enzyme activity. Used to galvanize steel and in brass alloys." , front_translations: {"es":"Zinco (Zn)","de":"Zink (Zn)","fr":"Zinc (Zn)","tr":"Çinko (Zn)","nl":"Zink (Zn)","ru":"Цинк (Zn)","zh":"锌 (Zn)","pt_BR":"Zinco (Zn)","pt_PT":"Zinco (Zn)"}, back_translations: {"es":"Número atómico 30, masa atómica 65,38 u. Metal de transición branco-azulado. Microelemento esencial; importante para a función imunológica y a atividad enzimática. Usado para galvanizar el aço y en ligas de latão.","de":"Ordnungszahl 30, Atommasse 65,38 u. Blauweißes Übergangsmetall. Essenzielles Spurenelement; wichtig für Immunfunktion und Enzymaktivität. Wird zur Verzinkung von Stahl und in Messinglegierungen verwendet.","fr":"Numéro atomique 30, masse atomique 65,38 u. Métal de transition blanc bleuté. Oligo-élément essentiel ; important pour la fonction immunitaire et l'activité enzymatique. Utilisé pour galvaniser l'acier et dans les alliages de laiton.","tr":"Atom numarası 30, atom kütlesi 65,38 u. Mavimsi-beyaz geçiş metali. Temel eser element; bağışıklık işlevi ve enzim aktivitesinde önemlidir. Çeliği galvanizlemek ve pirinç alaşımlarında kullanılır.","nl":"Atoomnummer 30, atoommassa 65,38 u. Blauwwit overgangsmetaal. Essentieel sporenelement; belangrijk voor immuunfunctie en enzymactiviteit. Gebruikt om staal te galvaniseren en in messinglegeringen.","ru":"Атомный номер 30, атомная масса 65,38 а.е.м. Голубовато-белый переходный металл. Незаменимый микроэлемент; важен для иммунной функции и активности ферментов. Используется для оцинковки стали и в латунных сплавах.","zh":"原子序数30，原子质量65.38 u。蓝白色过渡金属。必需微量元素；对免疫功能和酶活性至关重要。用于钢铁镀锌和黄铜合金。","pt_BR":"Número atômico 30, massa atômica 65,38 u. Metal de transição branco-azulado. Microelemento essencial; importante para a função imunológica e a atividade enzimática. Usado para galvanizar o aço e em ligas de latão.","pt_PT":"Número atómico 30, massa atómica 65,38 u. Metal de transição branco-azulado. Microelemento essencial; importante para a função imunológica e a atividade enzimática. Usado para galvanizar o aço e em ligas de latão."}},
  { id: 'dc-chemistry-0031', deck_id: 'deck-chemistry', sort_order: 31, front: "Ionic Bonding", back: "A chemical bond formed by the electrostatic attraction between a positively charged cation and a negatively charged anion. Typically occurs between a metal and a nonmetal. E.g., NaCl." , front_translations: {"es":"Enlace Ionica","de":"Ionische Bindung","fr":"Liaison ionique","tr":"İyonik Bağ","nl":"Ionische binding","ru":"Ионная связь","zh":"离子键","pt_BR":"Ligação Iônica","pt_PT":"Ligação Iónica"}, back_translations: {"es":"Una enlace químico formada por la atración eletrostática entre un cátion con carga positiva y un anion con carga negativa. Ocurre típicamente entre un metal y un no metal. Ex.: NaCl.","de":"Eine chemische Bindung, die durch elektrostatische Anziehung zwischen einem positiv geladenen Kation und einem negativ geladenen Anion gebildet wird. Tritt typischerweise zwischen einem Metall und einem Nichtmetall auf. Z.B. NaCl.","fr":"Une liaison chimique formée par l'attraction électrostatique entre un cation chargé positivement et un anion chargé négativement. Se produit généralement entre un métal et un non-métal. Ex. : NaCl.","tr":"Pozitif yüklü bir katyon ile negatif yüklü bir anyon arasındaki elektrostatik çekim kuvvetiyle oluşan kimyasal bağ. Genellikle bir metal ile ametal arasında oluşur. Örn. NaCl.","nl":"Een chemische binding gevormd door elektrostatische aantrekking tussen een positief geladen kation en een negatief geladen anion. Treedt typisch op tussen een metaal en een niet-metaal. Bijv. NaCl.","ru":"Химическая связь, образованная электростатическим притяжением между положительно заряженным катионом и отрицательно заряженным анионом. Обычно возникает между металлом и неметаллом. Напр., NaCl.","zh":"由带正电的阳离子和带负电的阴离子之间的静电吸引力形成的化学键。通常发生在金属和非金属之间。例如NaCl。","pt_BR":"Uma ligação química formada pela atração eletrostática entre um cátion com carga positiva e um ânion com carga negativa. Ocorre tipicamente entre um metal e um não metal. Ex.: NaCl.","pt_PT":"Uma ligação química formada pela atração eletrostática entre um catião com carga positiva e um anião com carga negativa. Ocorre tipicamente entre um metal e um não metal. Ex.: NaCl."}},
  { id: 'dc-chemistry-0032', deck_id: 'deck-chemistry', sort_order: 32, front: "Covalent Bonding", back: "A chemical bond formed when two atoms share one or more pairs of electrons. Occurs between nonmetals. Can be single (2 e⁻), double (4 e⁻), or triple (6 e⁻) bonds." , front_translations: {"es":"Enlace Covalente","de":"Kovalente Bindung","fr":"Liaison covalente","tr":"Kovalent Bağ","nl":"Covalente binding","ru":"Ковалентная связь","zh":"共价键","pt_BR":"Ligação Covalente","pt_PT":"Ligação Covalente"}, back_translations: {"es":"Una enlace químico formada cuando de los átomos compartilham uno el más pares de electrones. Ocurre entre no metais. Puede ser simples (2 y⁻), dupla (4 y⁻) o tripla (6 y⁻).","de":"Eine chemische Bindung, die entsteht, wenn zwei Atome ein oder mehrere Elektronenpaare teilen. Tritt zwischen Nichtmetallen auf. Kann Einfachbindungen (2 e⁻), Doppelbindungen (4 e⁻) oder Dreifachbindungen (6 e⁻) sein.","fr":"Une liaison chimique formée lorsque deux atomes partagent une ou plusieurs paires d'électrons. Se produit entre des non-métaux. Peut être simple (2 e⁻), double (4 e⁻) ou triple (6 e⁻).","tr":"İki atomun bir veya daha fazla elektron çiftini paylaştığında oluşan kimyasal bağ. Ametaller arasında oluşur. Tek (2 e⁻), çift (4 e⁻) veya üçlü (6 e⁻) bağ olabilir.","nl":"Een chemische binding die ontstaat wanneer twee atomen één of meer paren elektronen delen. Treedt op tussen niet-metalen. Kan enkelvoudig (2 e⁻), dubbel (4 e⁻) of drievoudig (6 e⁻) zijn.","ru":"Химическая связь, возникающая, когда два атома совместно используют одну или несколько пар электронов. Встречается между неметаллами. Может быть одинарной (2 e⁻), двойной (4 e⁻) или тройной (6 e⁻).","zh":"当两个原子共享一对或多对电子时形成的化学键。发生在非金属之间。可以是单键（2 e⁻）、双键（4 e⁻）或三键（6 e⁻）。","pt_BR":"Uma ligação química formada quando dois átomos compartilham um ou mais pares de elétrons. Ocorre entre não metais. Pode ser simples (2 e⁻), dupla (4 e⁻) ou tripla (6 e⁻).","pt_PT":"Uma ligação química formada quando dois átomos partilham um ou mais pares de eletrões. Ocorre entre não metais. Pode ser simples (2 e⁻), dupla (4 e⁻) ou tripla (6 e⁻)."}},
  { id: 'dc-chemistry-0033', deck_id: 'deck-chemistry', sort_order: 33, front: "Polar Covalent Bond", back: "A covalent bond in which electrons are shared unequally due to a difference in electronegativity. The more electronegative atom carries a partial negative charge (δ−). E.g., H–O in water." , front_translations: {"es":"Enlace Covalente Polar","de":"Polare kovalente Bindung","fr":"Liaison covalente polaire","tr":"Polar Kovalent Bağ","nl":"Polaire covalente binding","ru":"Полярная ковалентная связь","zh":"极性共价键","pt_BR":"Ligação Covalente Polar","pt_PT":"Ligação Covalente Polar"}, back_translations: {"es":"Una enlace covalente en que los electrones son compartilhados de forma desigual debido a una diferencia de eletronegatividad. El átomo más eletronegativo carrega una carga parcialmente negativa (δ−). Ex.: H–El en la agua.","de":"Eine kovalente Bindung, bei der Elektronen aufgrund eines Unterschieds in der Elektronegativität ungleich geteilt werden. Das elektronegativere Atom trägt eine partielle negative Ladung (δ−). Z.B. H–O im Wasser.","fr":"Une liaison covalente dans laquelle les électrons sont partagés inégalement en raison d'une différence d'électronégativité. L'atome le plus électronégatif porte une charge négative partielle (δ−). Ex. : H–O dans l'eau.","tr":"Elektronegatiflik farkı nedeniyle elektronların eşit olmayan şekilde paylaşıldığı bir kovalent bağ. Daha elektronegatif atom kısmi negatif yük taşır (δ−). Örn. sudaki H–O.","nl":"Een covalente binding waarbij elektronen ongelijk worden gedeeld vanwege een verschil in elektronegativiteit. Het meer elektronegatieve atoom draagt een gedeeltelijk negatieve lading (δ−). Bijv. H–O in water.","ru":"Ковалентная связь, в которой электроны распределены неравномерно из-за разницы в электроотрицательности. Более электроотрицательный атом несёт частичный отрицательный заряд (δ−). Напр., H–O в воде.","zh":"由于电负性差异导致电子不均等共享的共价键。电负性更强的原子带有部分负电荷（δ−）。例如水中的H–O。","pt_BR":"Uma ligação covalente em que os elétrons são compartilhados de forma desigual devido a uma diferença de eletronegatividade. O átomo mais eletronegativo carrega uma carga parcialmente negativa (δ−). Ex.: H–O na água.","pt_PT":"Uma ligação covalente em que os eletrões são partilhados de forma desigual devido a uma diferença de eletronegatividade. O átomo mais eletronegativo carrega uma carga parcialmente negativa (δ−). Ex.: H–O na água."}},
  { id: 'dc-chemistry-0034', deck_id: 'deck-chemistry', sort_order: 34, front: "Hydrogen Bond", back: "A relatively strong intermolecular force between an H atom bonded to N, O, or F and a lone pair on N, O, or F of a neighboring molecule. Responsible for water's high boiling point." , front_translations: {"es":"Enlace de Hidrógeno","de":"Wasserstoffbrückenbindung","fr":"Liaison hydrogène","tr":"Hidrojen Bağı","nl":"Waterstofbrug","ru":"Водородная связь","zh":"氢键","pt_BR":"Ligação de Hidrogênio","pt_PT":"Ligação de Hidrogénio"}, back_translations: {"es":"Una fuerza intermolecular relativamente fuerte entre un átomo H ligado a N, El o F y un par isolado en N, El o F de una molécula vizinha. Responsable por el alto punto de ebullición de la agua.","de":"Eine relativ starke zwischenmolekulare Kraft zwischen einem H-Atom, das an N, O oder F gebunden ist, und einem freien Elektronenpaar an N, O oder F eines benachbarten Moleküls. Verantwortlich für den hohen Siedepunkt von Wasser.","fr":"Une force intermoléculaire relativement forte entre un atome H lié à N, O ou F et un doublet libre sur N, O ou F d'une molécule voisine. Responsable du point d'ébullition élevé de l'eau.","tr":"N, O veya F'ye bağlı bir H atomu ile komşu bir molekülün N, O veya F üzerindeki yalnız elektron çifti arasındaki görece güçlü bir moleküller arası kuvvet. Suyun yüksek kaynama noktasından sorumludur.","nl":"Een relatief sterke intermoleculaire kracht tussen een H-atoom gebonden aan N, O of F en een vrij elektronenpaar op N, O of F van een naburig molecuul. Verantwoordelijk voor het hoge kookpunt van water.","ru":"Относительно сильная межмолекулярная сила между атомом H, связанным с N, O или F, и неподелённой электронной парой на N, O или F соседней молекулы. Обусловливает высокую температуру кипения воды.","zh":"与N、O或F相连的H原子与相邻分子上N、O或F的孤电子对之间相对较强的分子间作用力。是水具有高沸点的原因。","pt_BR":"Uma força intermolecular relativamente forte entre um átomo H ligado a N, O ou F e um par isolado em N, O ou F de uma molécula vizinha. Responsável pelo alto ponto de ebulição da água.","pt_PT":"Uma força intermolecular relativamente forte entre um átomo H ligado a N, O ou F e um par isolado em N, O ou F de uma molécula vizinha. Responsável pelo alto ponto de ebulição da água."}},
  { id: 'dc-chemistry-0035', deck_id: 'deck-chemistry', sort_order: 35, front: "Electronegativity", back: "A measure of an atom's tendency to attract shared electrons in a bond (Pauling scale). Increases across periods and up groups. Fluorine is the most electronegative element (4.0)." , front_translations: {"es":"Eletronegatividad","de":"Elektronegativität","fr":"Électronégativité","tr":"Elektronegatiflik","nl":"Elektronegativiteit","ru":"Электроотрицательность","zh":"电负性","pt_BR":"Eletronegatividade","pt_PT":"Eletronegatividade"}, back_translations: {"es":"Una medida de la tendencia de un átomo de atrair electrones compartilhados en una enlace (escala de Pauling). Aumenta al ancho de los períodos y para cima en los grupos. El flúor es el elemento más eletronegativo (4,0).","de":"Ein Maß für die Tendenz eines Atoms, gemeinsame Elektronen in einer Bindung anzuziehen (Pauling-Skala). Nimmt über Perioden und in Gruppen nach oben zu. Fluor ist das elektronegativste Element (4,0).","fr":"Une mesure de la tendance d'un atome à attirer les électrons partagés dans une liaison (échelle de Pauling). Augmente à travers les périodes et vers le haut des groupes. Le fluor est l'élément le plus électronégatif (4,0).","tr":"Bir atomun bir bağdaki paylaşılan elektronları çekme eğiliminin ölçüsü (Pauling ölçeği). Periyotlar boyunca ve gruplarda yukarı doğru artar. Flor en elektronegatif elementtir (4,0).","nl":"Een maat voor de neiging van een atoom om gedeelde elektronen in een binding aan te trekken (Pauling-schaal). Neemt toe over perioden en omhoog in groepen. Fluor is het meest elektronegatieve element (4,0).","ru":"Мера способности атома притягивать общие электроны в химической связи (шкала Полинга). Возрастает по периодам и вверх по группам. Фтор — наиболее электроотрицательный элемент (4,0).","zh":"衡量原子吸引共用电子能力的量度（鲍林标度）。沿周期增大，在族中向上增大。氟是电负性最强的元素（4.0）。","pt_BR":"Uma medida da tendência de um átomo de atrair elétrons compartilhados em uma ligação (escala de Pauling). Aumenta ao longo dos períodos e para cima nos grupos. O flúor é o elemento mais eletronegativo (4,0).","pt_PT":"Uma medida da tendência de um átomo de atrair eletrões partilhados numa ligação (escala de Pauling). Aumenta ao longo dos períodos e para cima nos grupos. O flúor é o elemento mais eletronegativo (4,0)."}},
  { id: 'dc-chemistry-0036', deck_id: 'deck-chemistry', sort_order: 36, front: "VSEPR Theory", back: "Valence Shell Electron Pair Repulsion. Electron pairs around a central atom arrange themselves to minimize repulsion. Lone pairs repel more than bonding pairs, affecting molecular geometry." , front_translations: {"es":"Teoría VSEPR","de":"VSEPR-Theorie","fr":"Théorie VSEPR","tr":"VSEPR Teorisi","nl":"VSEPR-theorie","ru":"Теория VSEPR","zh":"价层电子对互斥理论（VSEPR）","pt_BR":"Teoria VSEPR","pt_PT":"Teoria VSEPR"}, back_translations: {"es":"Repulsão de los Pares de Electrones de la Capa de Valencia. Los pares de electrones alrededor de un átomo central se organizam para minimizar a repulsão. Pares isolados repelem más del que pares de enlace, afectando a geometría molecular.","de":"Valence Shell Electron Pair Repulsion (Valenzschalen-Elektronenpaar-Abstoßung). Elektronenpaare um ein Zentralatom ordnen sich an, um die Abstoßung zu minimieren. Freie Elektronenpaare stoßen stärker ab als bindende Paare, was die Molekülgeometrie beeinflusst.","fr":"Répulsion des paires d'électrons de la couche de valence. Les paires d'électrons autour d'un atome central s'arrangent pour minimiser la répulsion. Les paires libres repoussent plus que les paires liantes, affectant la géométrie moléculaire.","tr":"Değerlik Kabuğu Elektron Çifti İtilmesi. Bir merkez atomu etrafındaki elektron çiftleri itilmeyi en aza indirecek şekilde düzenlenir. Yalnız çiftler, bağ çiftlerinden daha fazla iter ve moleküler geometriyi etkiler.","nl":"Afstoting van elektronenparen in de valentielaag. Elektronenparen rond een centraal atoom schikken zich om afstoting te minimaliseren. Vrije paren stoten meer af dan bindingsparen, wat de moleculaire geometrie beïnvloedt.","ru":"Отталкивание электронных пар валентного слоя. Электронные пары вокруг центрального атома располагаются так, чтобы минимизировать отталкивание. Неподелённые пары отталкивают сильнее, чем связывающие, влияя на геометрию молекулы.","zh":"价层电子对互斥理论。中心原子周围的电子对排列以最小化排斥力。孤电子对比成键电子对有更大的排斥力，影响分子几何构型。","pt_BR":"Repulsão dos Pares de Elétrons da Camada de Valência. Os pares de elétrons ao redor de um átomo central se organizam para minimizar a repulsão. Pares isolados repelem mais do que pares de ligação, afetando a geometria molecular.","pt_PT":"Repulsão dos Pares de Eletrões da Camada de Valência. Os pares de eletrões em torno de um átomo central organizam-se para minimizar a repulsão. Pares isolados repelem mais do que pares de ligação, afetando a geometria molecular."}},
  { id: 'dc-chemistry-0037', deck_id: 'deck-chemistry', sort_order: 37, front: "Molecular Geometry: Tetrahedral", back: "Four bonding pairs, no lone pairs around central atom. Bond angles of 109.5°. Example: CH₄ (methane). Lone pairs compress bond angles: NH₃ (107°), H₂O (104.5°)." , front_translations: {"es":"Geometría Molecular: Tetraédrica","de":"Molekülgeometrie: Tetraeder","fr":"Géométrie moléculaire : tétraèdre","tr":"Moleküler Geometri: Tetrahedron","nl":"Moleculaire geometrie: tetraëder","ru":"Молекулярная геометрия: тетраэдр","zh":"分子几何构型：四面体形","pt_BR":"Geometria Molecular: Tetraédrica","pt_PT":"Geometria Molecular: Tetraédrica"}, back_translations: {"es":"Cuatro pares de enlace, sin pares isolados alrededor del átomo central. Ángulos de enlace de 109,5°. Ejemplo: CH₄ (metano). Pares isolados comprimem los ángulos de enlace: NH₃ (107°), H₂El (104,5°).","de":"Vier bindende Paare, keine freien Paare um das Zentralatom. Bindungswinkel von 109,5°. Beispiel: CH₄ (Methan). Freie Elektronenpaare komprimieren die Bindungswinkel: NH₃ (107°), H₂O (104,5°).","fr":"Quatre paires liantes, aucune paire libre autour de l'atome central. Angles de liaison de 109,5°. Exemple : CH₄ (méthane). Les paires libres compriment les angles de liaison : NH₃ (107°), H₂O (104,5°).","tr":"Merkez atom etrafında dört bağ çifti, serbest çift yok. Bağ açıları 109,5°. Örnek: CH₄ (metan). Yalnız çiftler bağ açılarını daraltır: NH₃ (107°), H₂O (104,5°).","nl":"Vier bindingsparen, geen vrije paren rond het centrale atoom. Bindingshoeken van 109,5°. Voorbeeld: CH₄ (methaan). Vrije paren verkleinen bindingshoeken: NH₃ (107°), H₂O (104,5°).","ru":"Четыре связывающие пары, нет неподелённых пар вокруг центрального атома. Углы связей 109,5°. Пример: CH₄ (метан). Неподелённые пары сжимают углы связей: NH₃ (107°), H₂O (104,5°).","zh":"中心原子周围有四个成键电子对，无孤电子对。键角109.5°。示例：CH₄（甲烷）。孤电子对压缩键角：NH₃（107°），H₂O（104.5°）。","pt_BR":"Quatro pares de ligação, sem pares isolados ao redor do átomo central. Ângulos de ligação de 109,5°. Exemplo: CH₄ (metano). Pares isolados comprimem os ângulos de ligação: NH₃ (107°), H₂O (104,5°).","pt_PT":"Quatro pares de ligação, sem pares isolados em torno do átomo central. Ângulos de ligação de 109,5°. Exemplo: CH₄ (metano). Pares isolados comprimem os ângulos de ligação: NH₃ (107°), H₂O (104,5°)."}},
  { id: 'dc-chemistry-0038', deck_id: 'deck-chemistry', sort_order: 38, front: "Oxidation State", back: "A bookkeeping concept representing the hypothetical charge an atom would have if all bonds were fully ionic. Used to track electron transfer in redox reactions. Increases in oxidation = oxidation." , front_translations: {"es":"Estado de Oxidación","de":"Oxidationsstufe","fr":"Degré d'oxydation","tr":"Yükseltgenme Basamağı","nl":"Oxidatietoestand","ru":"Степень окисления","zh":"氧化态","pt_BR":"Estado de Oxidação","pt_PT":"Estado de Oxidação"}, back_translations: {"es":"Un concepto contábil que representa a carga hipotética que un átomo teria se todas las enlaces fossem completamente ionicas. Usado para rastrear a transferencia de electrones en reacciones redox. Aumento en el estado de oxidación = oxidación.","de":"Ein Buchführungskonzept, das die hypothetische Ladung darstellt, die ein Atom hätte, wenn alle Bindungen vollständig ionisch wären. Dient zur Verfolgung des Elektronentransfers bei Redoxreaktionen. Zunahme der Oxidationsstufe = Oxidation.","fr":"Un concept comptable représentant la charge hypothétique qu'aurait un atome si toutes les liaisons étaient entièrement ioniques. Utilisé pour suivre le transfert d'électrons dans les réactions rédox. Une augmentation du degré d'oxydation = oxydation.","tr":"Tüm bağlar tam iyonik olsaydı bir atomun sahip olacağı varsayımsal yükü temsil eden bir muhasebe kavramı. Redoks reaksiyonlarında elektron transferini izlemek için kullanılır. Yükseltgenme basamağının artması = yükseltgenme.","nl":"Een boekhoudkundig concept dat de hypothetische lading voorstelt die een atoom zou hebben als alle bindingen volledig ionisch waren. Gebruikt om elektronenoverdracht in redoxreacties bij te houden. Toename in oxidatietoestand = oxidatie.","ru":"Бухгалтерская концепция, представляющая гипотетический заряд, который имел бы атом, если бы все связи были полностью ионными. Используется для отслеживания переноса электронов в окислительно-восстановительных реакциях. Увеличение степени окисления = окисление.","zh":"一种核算概念，表示假设所有键都完全是离子键时原子所具有的假想电荷。用于追踪氧化还原反应中的电子转移。氧化态升高 = 氧化。","pt_BR":"Um conceito contábil que representa a carga hipotética que um átomo teria se todas as ligações fossem completamente iônicas. Usado para rastrear a transferência de elétrons em reações redox. Aumento no estado de oxidação = oxidação.","pt_PT":"Um conceito contabilístico que representa a carga hipotética que um átomo teria se todas as ligações fossem completamente iónicas. Usado para rastrear a transferência de eletrões em reações redox. Aumento no estado de oxidação = oxidação."}},
  { id: 'dc-chemistry-0039', deck_id: 'deck-chemistry', sort_order: 39, front: "Oxidation-Reduction (Redox) Reaction", back: "A reaction involving transfer of electrons. OIL RIG: Oxidation Is Loss of electrons; Reduction Is Gain of electrons. The oxidizing agent gains electrons; the reducing agent loses them." , front_translations: {"es":"Reacción de Oxidación-Reducción (Redox)","de":"Oxidations-Reduktions-Reaktion (Redox)","fr":"Réaction d'oxydoréduction (Redox)","tr":"Yükseltgenme-İndirgenme (Redoks) Tepkimesi","nl":"Oxidatie-reductiereactie (Redox)","ru":"Окислительно-восстановительная реакция (Редокс)","zh":"氧化还原反应（Redox）","pt_BR":"Reação de Oxidação-Redução (Redox)","pt_PT":"Reação de Oxidação-Redução (Redox)"}, back_translations: {"es":"Una reacción que involucra transferencia de electrones. OIL RIG: Oxidación es Perda (Loss) de electrones; Reducción es Ganho (Gain) de electrones. El agente oxidante ganha electrones; el agente redutor los perde.","de":"Eine Reaktion mit Elektronentransfer. OIL RIG: Oxidation ist Verlust (Loss) von Elektronen; Reduktion ist Gewinn (Gain) von Elektronen. Das Oxidationsmittel nimmt Elektronen auf; das Reduktionsmittel gibt sie ab.","fr":"Une réaction impliquant un transfert d'électrons. OIL RIG : l'Oxydation est une perte (Loss) d'électrons ; la Réduction est un gain (Gain) d'électrons. L'agent oxydant gagne des électrons ; l'agent réducteur les perd.","tr":"Elektron transferini içeren bir tepkime. OIL RIG: Yükseltgenme elektron kaybıdır (Loss); İndirgenme elektron kazanımıdır (Gain). Yükseltgen elektron kazanır; indirgen elektron kaybeder.","nl":"Een reactie waarbij overdracht van elektronen plaatsvindt. OIL RIG: Oxidatie is verlies (Loss) van elektronen; Reductie is winst (Gain) van elektronen. Het oxidatiemiddel wint elektronen; het reductiemiddel verliest ze.","ru":"Реакция, включающая перенос электронов. OIL RIG: Окисление — это Потеря (Loss) электронов; Восстановление — это Приобретение (Gain) электронов. Окислитель принимает электроны; восстановитель их отдаёт.","zh":"涉及电子转移的反应。OIL RIG口诀：氧化（Oxidation）是失去（Loss）电子；还原（Reduction）是得到（Gain）电子。氧化剂得到电子；还原剂失去电子。","pt_BR":"Uma reação que envolve transferência de elétrons. OIL RIG: Oxidação é Perda (Loss) de elétrons; Redução é Ganho (Gain) de elétrons. O agente oxidante ganha elétrons; o agente redutor os perde.","pt_PT":"Uma reação que envolve transferência de eletrões. OIL RIG: Oxidação é Perda (Loss) de eletrões; Redução é Ganho (Gain) de eletrões. O agente oxidante ganha eletrões; o agente redutor perde-os."}},
  { id: 'dc-chemistry-0040', deck_id: 'deck-chemistry', sort_order: 40, front: "Acid-Base Reaction (Arrhenius)", back: "An acid produces H⁺ ions in aqueous solution; a base produces OH⁻ ions. They neutralize each other to form water and a salt: HCl + NaOH → NaCl + H₂O." , front_translations: {"es":"Reacción Ácido-Base (Arrhenius)","de":"Säure-Base-Reaktion (Arrhenius)","fr":"Réaction acide-base (Arrhenius)","tr":"Asit-Baz Tepkimesi (Arrhenius)","nl":"Zuur-basereactie (Arrhenius)","ru":"Кислотно-основная реакция (Аррениус)","zh":"酸碱反应（阿伦尼乌斯理论）","pt_BR":"Reação Ácido-Base (Arrhenius)","pt_PT":"Reação Ácido-Base (Arrhenius)"}, back_translations: {"es":"Un ácido produce iones H⁺ en solución aquosa; una base produce iones OH⁻. Eles se neutralizam formando agua y un sal: HCl + NaOH → NaCl + H₂El.","de":"Eine Säure erzeugt H⁺-Ionen in wässriger Lösung; eine Base erzeugt OH⁻-Ionen. Sie neutralisieren sich gegenseitig zu Wasser und einem Salz: HCl + NaOH → NaCl + H₂O.","fr":"Un acide produit des ions H⁺ en solution aqueuse ; une base produit des ions OH⁻. Ils se neutralisent mutuellement pour former de l'eau et un sel : HCl + NaOH → NaCl + H₂O.","tr":"Bir asit sulu çözeltide H⁺ iyonları üretir; bir baz OH⁻ iyonları üretir. Birbirini nötralize ederek su ve tuz oluştururlar: HCl + NaOH → NaCl + H₂O.","nl":"Een zuur produceert H⁺-ionen in waterige oplossing; een base produceert OH⁻-ionen. Ze neutraliseren elkaar tot water en een zout: HCl + NaOH → NaCl + H₂O.","ru":"Кислота производит ионы H⁺ в водном растворе; основание производит ионы OH⁻. Они нейтрализуют друг друга с образованием воды и соли: HCl + NaOH → NaCl + H₂O.","zh":"酸在水溶液中产生H⁺离子；碱产生OH⁻离子。它们相互中和生成水和盐：HCl + NaOH → NaCl + H₂O。","pt_BR":"Um ácido produz íons H⁺ em solução aquosa; uma base produz íons OH⁻. Eles se neutralizam formando água e um sal: HCl + NaOH → NaCl + H₂O.","pt_PT":"Um ácido produz iões H⁺ em solução aquosa; uma base produz iões OH⁻. Eles neutralizam-se mutuamente formando água e um sal: HCl + NaOH → NaCl + H₂O."}},
  { id: 'dc-chemistry-0041', deck_id: 'deck-chemistry', sort_order: 41, front: "Brønsted-Lowry Acid-Base Theory", back: "An acid is a proton (H⁺) donor; a base is a proton acceptor. Extends acid-base chemistry to non-aqueous solvents. Every acid has a conjugate base and vice versa." , front_translations: {"es":"Teoría Ácido-Base de Brønsted-Lowry","de":"Brønsted-Lowry-Säure-Base-Theorie","fr":"Théorie acide-base de Brønsted-Lowry","tr":"Brønsted-Lowry Asit-Baz Teorisi","nl":"Brønsted-Lowry-zuur-basetheorie","ru":"Теория кислот и оснований Бренстеда-Лоури","zh":"布朗斯特-劳里酸碱理论","pt_BR":"Teoria Ácido-Base de Brønsted-Lowry","pt_PT":"Teoria Ácido-Base de Brønsted-Lowry"}, back_translations: {"es":"Un ácido es un doador de protón (H⁺); una base es un receptor de protón. Estende a química ácido-base a disolventes no aquosos. Todo ácido tiene una base conjugada y vice-versa.","de":"Eine Säure ist ein Protonendonor (H⁺); eine Base ist ein Protonenakzeptor. Erweitert die Säure-Base-Chemie auf nicht-wässrige Lösungsmittel. Jede Säure hat eine konjugierte Base und umgekehrt.","fr":"Un acide est un donneur de proton (H⁺) ; une base est un accepteur de proton. Étend la chimie acide-base aux solvants non aqueux. Chaque acide a une base conjuguée et vice versa.","tr":"Asit, proton (H⁺) vericisidir; baz, proton alıcısıdır. Asit-baz kimyasını sulu olmayan çözücülere genişletir. Her asidin bir konjuge bazı ve her bazın bir konjuge asidi vardır.","nl":"Een zuur is een protondonor (H⁺); een base is een protonacceptor. Breidt de zuur-basechemie uit naar niet-waterige oplosmiddelen. Elk zuur heeft een geconjugeerde base en vice versa.","ru":"Кислота — донор протона (H⁺); основание — акцептор протона. Расширяет кислотно-основную химию на неводные растворители. Каждая кислота имеет сопряжённое основание и наоборот.","zh":"酸是质子（H⁺）的供体；碱是质子的受体。将酸碱化学扩展到非水溶剂中。每种酸都有其共轭碱，反之亦然。","pt_BR":"Um ácido é um doador de próton (H⁺); uma base é um receptor de próton. Estende a química ácido-base a solventes não aquosos. Todo ácido tem uma base conjugada e vice-versa.","pt_PT":"Um ácido é um dador de protão (H⁺); uma base é um aceitador de protão. Estende a química ácido-base a solventes não aquosos. Todo ácido tem uma base conjugada e vice-versa."}},
  { id: 'dc-chemistry-0042', deck_id: 'deck-chemistry', sort_order: 42, front: "Lewis Acid-Base Theory", back: "A Lewis acid is an electron-pair acceptor; a Lewis base is an electron-pair donor. Broader than Brønsted-Lowry; explains reactions like BF₃ + NH₃ → F₃B-NH₃ without proton transfer." , front_translations: {"es":"Teoría Ácido-Base de Lewis","de":"Lewis-Säure-Base-Theorie","fr":"Théorie acide-base de Lewis","tr":"Lewis Asit-Baz Teorisi","nl":"Lewis-zuur-basetheorie","ru":"Теория кислот и оснований Льюиса","zh":"路易斯酸碱理论","pt_BR":"Teoria Ácido-Base de Lewis","pt_PT":"Teoria Ácido-Base de Lewis"}, back_translations: {"es":"Un ácido de Lewis es un aceitador de par de electrones; una base de Lewis es un doador de par de electrones. Más amplo que Brønsted-Lowry; explica reacciones como BF₃ + NH₃ → F₃B-NH₃ sin transferencia de protón.","de":"Eine Lewis-Säure ist ein Elektronenpaarakzeptor; eine Lewis-Base ist ein Elektronenpaardonor. Breiter als Brønsted-Lowry; erklärt Reaktionen wie BF₃ + NH₃ → F₃B-NH₃ ohne Protonentransfer.","fr":"Un acide de Lewis est un accepteur de paire d'électrons ; une base de Lewis est un donneur de paire d'électrons. Plus large que Brønsted-Lowry ; explique des réactions comme BF₃ + NH₃ → F₃B-NH₃ sans transfert de proton.","tr":"Lewis asidi, elektron çifti alıcısıdır; Lewis bazı, elektron çifti vericisidir. Brønsted-Lowry'den daha geniş; BF₃ + NH₃ → F₃B-NH₃ gibi proton transferi olmaksızın gerçekleşen tepkimeleri açıklar.","nl":"Een Lewis-zuur is een elektronenpaaracceptor; een Lewis-base is een elektronenpaardonor. Breder dan Brønsted-Lowry; verklaart reacties zoals BF₃ + NH₃ → F₃B-NH₃ zonder protonenoverdracht.","ru":"Кислота Льюиса — акцептор электронной пары; основание Льюиса — донор электронной пары. Шире, чем концепция Бренстеда-Лоури; объясняет реакции типа BF₃ + NH₃ → F₃B-NH₃ без переноса протона.","zh":"路易斯酸是电子对的受体；路易斯碱是电子对的供体。比布朗斯特-劳里理论更广泛；解释了BF₃ + NH₃ → F₃B-NH₃等无质子转移的反应。","pt_BR":"Um ácido de Lewis é um aceitador de par de elétrons; uma base de Lewis é um doador de par de elétrons. Mais amplo que Brønsted-Lowry; explica reações como BF₃ + NH₃ → F₃B-NH₃ sem transferência de próton.","pt_PT":"Um ácido de Lewis é um aceitador de par de eletrões; uma base de Lewis é um dador de par de eletrões. Mais amplo que Brønsted-Lowry; explica reações como BF₃ + NH₃ → F₃B-NH₃ sem transferência de protão."}},
  { id: 'dc-chemistry-0043', deck_id: 'deck-chemistry', sort_order: 43, front: "pH Scale", back: "pH = -log[H⁺]. Measures acidity on a logarithmic scale from 0 (most acidic) to 14 (most basic). pH 7 is neutral. Each unit change represents a 10-fold change in [H⁺]." , front_translations: {"es":"Escala de pH","de":"pH-Skala","fr":"Échelle pH","tr":"pH Ölçeği","nl":"pH-schaal","ru":"Шкала pH","zh":"pH值标度","pt_BR":"Escala de pH","pt_PT":"Escala de pH"}, back_translations: {"es":"pH = -log[H⁺]. Mide a acidez en una escala logarítmica de 0 (más ácido) a 14 (más básico). pH 7 es neutro. Cada cambio de unidad representa una cambio de 10 veces en [H⁺].","de":"pH = -log[H⁺]. Misst den Säuregehalt auf einer logarithmischen Skala von 0 (am sauersten) bis 14 (am basischsten). pH 7 ist neutral. Jede Einheitenänderung entspricht einer 10-fachen Änderung von [H⁺].","fr":"pH = -log[H⁺]. Mesure l'acidité sur une échelle logarithmique de 0 (plus acide) à 14 (plus basique). pH 7 est neutre. Chaque unité de changement représente un changement de 10 fois la concentration en [H⁺].","tr":"pH = -log[H⁺]. Asitliği 0 (en asidik) ile 14 (en bazik) arasında logaritmik bir ölçekte ölçer. pH 7 nötrdür. Her birim değişim, [H⁺] konsantrasyonunda 10 katlık bir değişimi temsil eder.","nl":"pH = -log[H⁺]. Meet zuurgraad op een logaritmische schaal van 0 (meest zuur) tot 14 (meest basisch). pH 7 is neutraal. Elke eenheidverandering vertegenwoordigt een 10-voudige verandering in [H⁺].","ru":"pH = -log[H⁺]. Измеряет кислотность по логарифмической шкале от 0 (наиболее кислая) до 14 (наиболее щелочная). pH 7 — нейтральный. Каждое изменение на единицу соответствует 10-кратному изменению [H⁺].","zh":"pH = -log[H⁺]。以对数标度测量酸度，范围从0（最酸）到14（最碱）。pH 7为中性。每单位变化代表[H⁺]浓度10倍的变化。","pt_BR":"pH = -log[H⁺]. Mede a acidez em uma escala logarítmica de 0 (mais ácido) a 14 (mais básico). pH 7 é neutro. Cada mudança de unidade representa uma mudança de 10 vezes em [H⁺].","pt_PT":"pH = -log[H⁺]. Mede a acidez numa escala logarítmica de 0 (mais ácido) a 14 (mais básico). pH 7 é neutro. Cada mudança de unidade representa uma mudança de 10 vezes em [H⁺]."}},
  { id: 'dc-chemistry-0044', deck_id: 'deck-chemistry', sort_order: 44, front: "pKa", back: "pKa = -log(Ka). The negative logarithm of the acid dissociation constant. Lower pKa = stronger acid. At pH = pKa, the acid is exactly half-dissociated." , front_translations: {"es":"pKa","de":"pKa","fr":"pKa","tr":"pKa","nl":"pKa","ru":"pKa","zh":"pKa","pt_BR":"pKa","pt_PT":"pKa"}, back_translations: {"es":"pKa = -log(Ka). El logaritmo negativo de la constante de dissociación ácida. Menor pKa = ácido más fuerte. En pH = pKa, el ácido está exatamente con metade dissociada.","de":"pKa = -log(Ka). Der negative Logarithmus der Säuredissoziationskonstante. Kleinerer pKa = stärkere Säure. Bei pH = pKa ist die Säure genau zur Hälfte dissoziiert.","fr":"pKa = -log(Ka). Le logarithme négatif de la constante de dissociation acide. Un pKa plus faible = un acide plus fort. Au pH = pKa, l'acide est exactement à moitié dissocié.","tr":"pKa = -log(Ka). Asit ayrışma sabitinin negatif logaritması. Daha düşük pKa = daha güçlü asit. pH = pKa'da asit tam olarak yarı yarıya ayrışmıştır.","nl":"pKa = -log(Ka). De negatieve logaritme van de zuurverdisociatieconstante. Lagere pKa = sterker zuur. Bij pH = pKa is het zuur precies voor de helft gedissocieerd.","ru":"pKa = -log(Ka). Отрицательный логарифм константы диссоциации кислоты. Меньший pKa = более сильная кислота. При pH = pKa кислота диссоциирована ровно наполовину.","zh":"pKa = -log(Ka)。酸解离常数的负对数。pKa越小 = 酸性越强。当pH = pKa时，酸恰好半解离。","pt_BR":"pKa = -log(Ka). O logaritmo negativo da constante de dissociação ácida. Menor pKa = ácido mais forte. Em pH = pKa, o ácido está exatamente com metade dissociada.","pt_PT":"pKa = -log(Ka). O logaritmo negativo da constante de dissociação ácida. Menor pKa = ácido mais forte. Em pH = pKa, o ácido está exatamente com metade dissociada."}},
  { id: 'dc-chemistry-0045', deck_id: 'deck-chemistry', sort_order: 45, front: "Buffer Solution", back: "A solution that resists changes in pH when small amounts of acid or base are added. Composed of a weak acid and its conjugate base. Effective within ±1 pH unit of the pKa." , front_translations: {"es":"Solución Tampão","de":"Pufferlösung","fr":"Solution tampon","tr":"Tampon Çözelti","nl":"Bufferoplossing","ru":"Буферный раствор","zh":"缓冲溶液","pt_BR":"Solução Tampão","pt_PT":"Solução Tampão"}, back_translations: {"es":"Una solución que resiste a cambios de pH cuando pequeñas quantidades de ácido o base son adicionadas. Compuesta de un ácido débil y su base conjugada. Eficaz dentro de ±1 unidad de pH del pKa.","de":"Eine Lösung, die pH-Änderungen widersteht, wenn kleine Mengen Säure oder Base hinzugefügt werden. Besteht aus einer schwachen Säure und ihrer konjugierten Base. Wirksam innerhalb von ±1 pH-Einheit vom pKa.","fr":"Une solution qui résiste aux changements de pH lors de l'ajout de petites quantités d'acide ou de base. Composée d'un acide faible et de sa base conjuguée. Efficace dans un intervalle de ±1 unité pH autour du pKa.","tr":"Küçük miktarda asit veya baz eklenmesine karşın pH değişimine direnen çözelti. Zayıf bir asit ve konjuge bazından oluşur. pKa'nın ±1 pH birimi içinde etkilidir.","nl":"Een oplossing die veranderingen in pH weerstaat bij toevoeging van kleine hoeveelheden zuur of base. Bestaat uit een zwak zuur en zijn geconjugeerde base. Effectief binnen ±1 pH-eenheid van de pKa.","ru":"Раствор, устойчивый к изменениям pH при добавлении небольших количеств кислоты или основания. Состоит из слабой кислоты и её сопряжённого основания. Эффективен в пределах ±1 единицы pH от значения pKa.","zh":"加入少量酸或碱时能抵抗pH变化的溶液。由弱酸及其共轭碱组成。在pKa ±1 pH单位范围内有效。","pt_BR":"Uma solução que resiste a mudanças de pH quando pequenas quantidades de ácido ou base são adicionadas. Composta de um ácido fraco e sua base conjugada. Eficaz dentro de ±1 unidade de pH do pKa.","pt_PT":"Uma solução que resiste a mudanças de pH quando pequenas quantidades de ácido ou base são adicionadas. Composta por um ácido fraco e a sua base conjugada. Eficaz dentro de ±1 unidade de pH do pKa."}},
  { id: 'dc-chemistry-0046', deck_id: 'deck-chemistry', sort_order: 46, front: "Le Chatelier's Principle", back: "If a system at equilibrium is disturbed by a change in concentration, temperature, or pressure, the system shifts to counteract the disturbance and re-establish equilibrium." , front_translations: {"es":"Principio de Le Chatelier","de":"Le Chatelier'sches Prinzip","fr":"Principe de Le Chatelier","tr":"Le Chatelier İlkesi","nl":"Principe van Le Chatelier","ru":"Принцип Ле Шателье","zh":"勒夏特列原理","pt_BR":"Princípio de Le Chatelier","pt_PT":"Princípio de Le Chatelier"}, back_translations: {"es":"Se un sistema en equilíbrio for perturbado por una cambio en la concentración, temperatura o presión, el sistema se desloca para contrabalançar a perturbación y restabelecer el equilíbrio.","de":"Wenn ein System im Gleichgewicht durch eine Änderung der Konzentration, Temperatur oder des Drucks gestört wird, verschiebt sich das System, um der Störung entgegenzuwirken und das Gleichgewicht wiederherzustellen.","fr":"Si un système à l'équilibre est perturbé par un changement de concentration, de température ou de pression, le système se déplace pour contrecarrer la perturbation et rétablir l'équilibre.","tr":"Denge halindeki bir sistem konsantrasyon, sıcaklık veya basınç değişikliğiyle bozulduğunda, sistem bu bozulmayı dengelemek ve dengeyi yeniden sağlamak için kayar.","nl":"Als een systeem in evenwicht wordt verstoord door een verandering in concentratie, temperatuur of druk, verschuift het systeem om de verstoring tegen te gaan en het evenwicht te herstellen.","ru":"Если система, находящаяся в равновесии, нарушается изменением концентрации, температуры или давления, она смещается, чтобы противодействовать возмущению и восстановить равновесие.","zh":"若处于平衡状态的体系受到浓度、温度或压力变化的扰动，体系会向抵消该扰动、重新建立平衡的方向移动。","pt_BR":"Se um sistema em equilíbrio for perturbado por uma mudança na concentração, temperatura ou pressão, o sistema se desloca para contrabalançar a perturbação e restabelecer o equilíbrio.","pt_PT":"Se um sistema em equilíbrio for perturbado por uma mudança na concentração, temperatura ou pressão, o sistema desloca-se para contrabalançar a perturbação e restabelecer o equilíbrio."}},
  { id: 'dc-chemistry-0047', deck_id: 'deck-chemistry', sort_order: 47, front: "Equilibrium Constant (Kc)", back: "Kc = [products]^coeff / [reactants]^coeff. A dimensionless ratio expressing the relative concentrations of products and reactants at equilibrium. K > 1 favors products; K < 1 favors reactants." , front_translations: {"es":"Constante de Equilíbrio (Kc)","de":"Gleichgewichtskonstante (Kc)","fr":"Constante d'équilibre (Kc)","tr":"Denge Sabiti (Kc)","nl":"Evenwichtsconstante (Kc)","ru":"Константа равновесия (Kc)","zh":"平衡常数（Kc）","pt_BR":"Constante de Equilíbrio (Kc)","pt_PT":"Constante de Equilíbrio (Kc)"}, back_translations: {"es":"Kc = [productos]^coef / [reactivos]^coef. Una razão adimensional que expressa las concentraciones relativas de productos y reactivos en el equilíbrio. K > 1 favorece los productos; K < 1 favorece los reactivos.","de":"Kc = [Produkte]^Koeff / [Edukte]^Koeff. Ein dimensionsloses Verhältnis, das die relativen Konzentrationen von Produkten und Edukten im Gleichgewicht ausdrückt. K > 1 begünstigt Produkte; K < 1 begünstigt Edukte.","fr":"Kc = [produits]^coeff / [réactifs]^coeff. Un rapport sans dimension exprimant les concentrations relatives des produits et des réactifs à l'équilibre. K > 1 favorise les produits ; K < 1 favorise les réactifs.","tr":"Kc = [ürünler]^katsayı / [reaktifler]^katsayı. Denge anındaki ürünlerin ve reaktiflerin göreli konsantrasyonlarını ifade eden boyutsuz bir oran. K > 1 ürünleri destekler; K < 1 reaktifleri destekler.","nl":"Kc = [producten]^coëff / [reactanten]^coëff. Een dimensieloze verhouding die de relatieve concentraties van producten en reactanten in evenwicht uitdrukt. K > 1 begunstigt producten; K < 1 begunstigt reactanten.","ru":"Kc = [продукты]^коэфф / [реагенты]^коэфф. Безразмерное отношение, выражающее относительные концентрации продуктов и реагентов в состоянии равновесия. K > 1 — равновесие смещено в сторону продуктов; K < 1 — в сторону реагентов.","zh":"Kc = [产物]^系数 / [反应物]^系数。表示平衡时产物与反应物相对浓度的无量纲比值。K > 1有利于产物；K < 1有利于反应物。","pt_BR":"Kc = [produtos]^coef / [reagentes]^coef. Uma razão adimensional que expressa as concentrações relativas de produtos e reagentes no equilíbrio. K > 1 favorece os produtos; K < 1 favorece os reagentes.","pt_PT":"Kc = [produtos]^coef / [reagentes]^coef. Uma razão adimensional que expressa as concentrações relativas de produtos e reagentes no equilíbrio. K > 1 favorece os produtos; K < 1 favorece os reagentes."}},
  { id: 'dc-chemistry-0048', deck_id: 'deck-chemistry', sort_order: 48, front: "Solubility Product (Ksp)", back: "The equilibrium constant for the dissolution of a sparingly soluble ionic compound. Ksp = [cation]^m[anion]^n. Used to predict whether a precipitate will form." , front_translations: {"es":"Producto de Solubilidad (Ksp)","de":"Löslichkeitsprodukt (Ksp)","fr":"Produit de solubilité (Ksp)","tr":"Çözünürlük Çarpımı (Ksp)","nl":"Oplosbaarheidsproduct (Ksp)","ru":"Произведение растворимости (Ksp)","zh":"溶度积（Ksp）","pt_BR":"Produto de Solubilidade (Ksp)","pt_PT":"Produto de Solubilidade (Ksp)"}, back_translations: {"es":"La constante de equilíbrio para a disolución de un compuesto ionico pouco soluble. Ksp = [cátion]^m[anion]^n. Usado para prever se un precipitado se formará.","de":"Die Gleichgewichtskonstante für die Auflösung einer schwer löslichen Ionenverbindung. Ksp = [Kation]^m[Anion]^n. Wird verwendet, um vorherzusagen, ob ein Niederschlag entsteht.","fr":"La constante d'équilibre pour la dissolution d'un composé ionique peu soluble. Ksp = [cation]^m[anion]^n. Utilisé pour prédire si un précipité se formera.","tr":"Az çözünür bir iyonik bileşiğin çözünmesi için denge sabiti. Ksp = [katyon]^m[anyon]^n. Çökelti oluşup oluşmayacağını tahmin etmek için kullanılır.","nl":"De evenwichtsconstante voor het oplossen van een weinig oplosbare ionische verbinding. Ksp = [kation]^m[anion]^n. Gebruikt om te voorspellen of een neerslag zal vormen.","ru":"Константа равновесия для растворения малорастворимого ионного соединения. Ksp = [катион]^m[анион]^n. Используется для прогнозирования образования осадка.","zh":"难溶离子化合物溶解的平衡常数。Ksp = [阳离子]^m[阴离子]^n。用于预测是否会生成沉淀。","pt_BR":"A constante de equilíbrio para a dissolução de um composto iônico pouco solúvel. Ksp = [cátion]^m[ânion]^n. Usado para prever se um precipitado se formará.","pt_PT":"A constante de equilíbrio para a dissolução de um composto iónico pouco solúvel. Ksp = [catião]^m[anião]^n. Usado para prever se um precipitado se formará."}},
  { id: 'dc-chemistry-0049', deck_id: 'deck-chemistry', sort_order: 49, front: "Common Ion Effect", back: "Adding an ion already present in a sparingly soluble salt's solution decreases the salt's solubility (shifts equilibrium left, per Le Chatelier's Principle). E.g., adding NaCl reduces AgCl solubility." , front_translations: {"es":"Efecto del Ion Comum","de":"Gemeinsamer-Ionen-Effekt","fr":"Effet d'ion commun","tr":"Ortak İyon Etkisi","nl":"Gemeenschappelijk-ion-effect","ru":"Эффект общего иона","zh":"同离子效应","pt_BR":"Efeito do Íon Comum","pt_PT":"Efeito do Ião Comum"}, back_translations: {"es":"Adicionar un ion ya presente en la solución de un sal pouco soluble disminuye a solubilidad del sal (desloca el equilíbrio para a esquerda, por el Principio de Le Chatelier). Ex.: adicionar NaCl reduce a solubilidad de AgCl.","de":"Das Hinzufügen eines bereits in der Lösung eines schwer löslichen Salzes vorhandenen Ions verringert die Löslichkeit des Salzes (verschiebt das Gleichgewicht nach links, gemäß dem Le Chatelier'schen Prinzip). Z.B. vermindert NaCl-Zugabe die AgCl-Löslichkeit.","fr":"L'ajout d'un ion déjà présent dans la solution d'un sel peu soluble diminue la solubilité du sel (déplace l'équilibre vers la gauche, selon le principe de Le Chatelier). Ex. : l'ajout de NaCl réduit la solubilité de AgCl.","tr":"Az çözünür bir tuzun çözeltisinde zaten mevcut olan bir iyonun eklenmesi, tuzun çözünürlüğünü azaltır (Le Chatelier İlkesi'ne göre dengeyi sola kaydırır). Örn. NaCl eklenmesi AgCl çözünürlüğünü azaltır.","nl":"Het toevoegen van een ion dat al aanwezig is in de oplossing van een weinig oplosbaar zout vermindert de oplosbaarheid van het zout (verschuift het evenwicht naar links, volgens het principe van Le Chatelier). Bijv. toevoegen van NaCl vermindert de oplosbaarheid van AgCl.","ru":"Добавление иона, уже присутствующего в растворе малорастворимой соли, уменьшает растворимость соли (смещает равновесие влево согласно принципу Ле Шателье). Напр., добавление NaCl снижает растворимость AgCl.","zh":"向难溶盐的溶液中加入已存在的离子会降低该盐的溶解度（根据勒夏特列原理使平衡向左移动）。例如，加入NaCl会降低AgCl的溶解度。","pt_BR":"Adicionar um íon já presente na solução de um sal pouco solúvel diminui a solubilidade do sal (desloca o equilíbrio para a esquerda, pelo Princípio de Le Chatelier). Ex.: adicionar NaCl reduz a solubilidade de AgCl.","pt_PT":"Adicionar um ião já presente na solução de um sal pouco solúvel diminui a solubilidade do sal (desloca o equilíbrio para a esquerda, pelo Princípio de Le Chatelier). Ex.: adicionar NaCl reduz a solubilidade de AgCl."}},
  { id: 'dc-chemistry-0050', deck_id: 'deck-chemistry', sort_order: 50, front: "Stoichiometry", back: "The calculation of relative quantities of reactants and products in chemical reactions using mole ratios from a balanced equation. The mole is the central unit (1 mol = 6.022×10²³ particles)." , front_translations: {"es":"Estequiometria","de":"Stöchiometrie","fr":"Stœchiométrie","tr":"Stokiyometri","nl":"Stoichiometrie","ru":"Стехиометрия","zh":"化学计量学","pt_BR":"Estequiometria","pt_PT":"Estequiometria"}, back_translations: {"es":"El cálculo de las quantidades relativas de reactivos y productos en reacciones químicas usando razões molares de una ecuación balanceada. El mol es a unidad central (1 mol = 6,022×10²³ partículas).","de":"Die Berechnung der relativen Mengen von Edukten und Produkten in chemischen Reaktionen anhand von Molverhältnissen aus einer ausgeglichenen Gleichung. Das Mol ist die zentrale Einheit (1 mol = 6,022×10²³ Teilchen).","fr":"Le calcul des quantités relatives de réactifs et de produits dans des réactions chimiques en utilisant des rapports molaires issus d'une équation équilibrée. La mole est l'unité centrale (1 mol = 6,022×10²³ particules).","tr":"Dengelenmiş bir denklemden mol oranlarını kullanarak kimyasal reaksiyonlardaki reaktif ve ürünlerin göreli miktarlarının hesaplanması. Mol temel birimdir (1 mol = 6,022×10²³ parçacık).","nl":"De berekening van relatieve hoeveelheden reactanten en producten in chemische reacties met behulp van molverhoudhoudingen uit een gebalanceerde vergelijking. De mol is de centrale eenheid (1 mol = 6,022×10²³ deeltjes).","ru":"Расчёт относительных количеств реагентов и продуктов в химических реакциях с использованием молярных соотношений из сбалансированного уравнения. Моль является центральной единицей (1 моль = 6,022×10²³ частиц).","zh":"利用平衡方程式中的摩尔比计算化学反应中反应物和产物相对数量的方法。摩尔是核心单位（1 mol = 6.022×10²³个粒子）。","pt_BR":"O cálculo das quantidades relativas de reagentes e produtos em reações químicas usando razões molares de uma equação balanceada. O mol é a unidade central (1 mol = 6,022×10²³ partículas).","pt_PT":"O cálculo das quantidades relativas de reagentes e produtos em reações químicas usando razões molares de uma equação balanceada. O mol é a unidade central (1 mol = 6,022×10²³ partículas)."}},
  { id: 'dc-chemistry-0051', deck_id: 'deck-chemistry', sort_order: 51, front: "Limiting Reagent", back: "The reactant that is completely consumed first in a chemical reaction, determining the maximum amount of product that can form. Excess reactants remain after the reaction ends." , front_translations: {"es":"Reactivo limitante","de":"Begrenzender Reaktant","fr":"Réactif limitant","tr":"Sınırlayıcı Reaktif","nl":"Beperkend reagens","ru":"Ограничивающий реагент","zh":"限量试剂","pt_BR":"Reagente limitante","pt_PT":"Reagente limitante"}, back_translations: {"es":"El reactivo que es completamente consumido primero en una reacción química, determinando a cantidad máxima de producto que puede ser formada. Los reactivos en exceso permanecen após el término de la reacción.","de":"Der Reaktant, der in einer chemischen Reaktion zuerst vollständig verbraucht wird und die maximale Menge an Produkt bestimmt, die entstehen kann. Überschüssige Reaktanten verbleiben nach Ende der Reaktion.","fr":"Le réactif entièrement consommé en premier lors d'une réaction chimique, déterminant la quantité maximale de produit pouvant se former. Les réactifs en excès demeurent après la fin de la réaction.","tr":"Bir kimyasal reaksiyonda ilk olarak tamamen tüketilen ve oluşabilecek maksimum ürün miktarını belirleyen reaktif. Fazla reaktifler reaksiyon sona erdikten sonra kalır.","nl":"Het reagens dat als eerste volledig wordt verbruikt in een chemische reactie, waardoor de maximale hoeveelheid product wordt bepaald. Overtollige reagentia blijven over na afloop van de reactie.","ru":"Реагент, который полностью расходуется первым в химической реакции, определяя максимальное количество продукта, которое может образоваться. Избыточные реагенты остаются после окончания реакции.","zh":"在化学反应中最先被完全消耗的反应物，决定了能够生成的最大产品量。反应结束后，过量反应物仍然存在。","pt_BR":"O reagente que é completamente consumido primeiro em uma reação química, determinando a quantidade máxima de produto que pode ser formada. Os reagentes em excesso permanecem após o término da reação.","pt_PT":"O reagente que é completamente consumido primeiro numa reação química, determinando a quantidade máxima de produto que pode ser formada. Os reagentes em excesso permanecem após o fim da reação."}},
  { id: 'dc-chemistry-0052', deck_id: 'deck-chemistry', sort_order: 52, front: "Percent Yield", back: "% yield = (actual yield / theoretical yield) × 100%. Actual yield comes from the experiment; theoretical yield is calculated from stoichiometry assuming 100% conversion." , front_translations: {"es":"Rendimento percentual","de":"Prozentuale Ausbeute","fr":"Rendement en pourcentage","tr":"Yüzde Verim","nl":"Procentuele opbrengst","ru":"Процентный выход","zh":"百分产率","pt_BR":"Rendimento percentual","pt_PT":"Rendimento percentual"}, back_translations: {"es":"% rendimento = (rendimento real / rendimento teórico) × 100 %. El rendimento real vem del experimento; el rendimento teórico es calculado por la estequiometria assumindo 100% de conversão.","de":"% Ausbeute = (tatsächliche Ausbeute / theoretische Ausbeute) × 100 %. Die tatsächliche Ausbeute stammt aus dem Experiment; die theoretische Ausbeute wird aus der Stöchiometrie unter Annahme einer vollständigen Umsetzung berechnet.","fr":"% rendement = (rendement réel / rendement théorique) × 100 %. Le rendement réel provient de l'expérience ; le rendement théorique est calculé par stœchiométrie en supposant une conversion à 100 %.","tr":"% verim = (gerçek verim / teorik verim) × 100 %. Gerçek verim deneyden elde edilir; teorik verim, %100 dönüşüm varsayılarak stokiyometriden hesaplanır.","nl":"% opbrengst = (werkelijke opbrengst / theoretische opbrengst) × 100 %. De werkelijke opbrengst komt uit het experiment; de theoretische opbrengst wordt berekend via stoichiometrie bij aanname van 100 % omzetting.","ru":"% выход = (фактический выход / теоретический выход) × 100 %. Фактический выход получают из эксперимента; теоретический выход рассчитывается из стехиометрии при допущении 100 % превращения.","zh":"百分产率 = （实际产量 / 理论产量）× 100 %。实际产量来自实验；理论产量根据化学计量假设100%转化率计算得出。","pt_BR":"% rendimento = (rendimento real / rendimento teórico) × 100 %. O rendimento real vem do experimento; o rendimento teórico é calculado pela estequiometria assumindo 100% de conversão.","pt_PT":"% rendimento = (rendimento real / rendimento teórico) × 100 %. O rendimento real provém da experiência; o rendimento teórico é calculado pela estequiometria assumindo 100 % de conversão."}},
  { id: 'dc-chemistry-0053', deck_id: 'deck-chemistry', sort_order: 53, front: "Molar Mass", back: "The mass in grams of one mole of a substance, numerically equal to the atomic/molecular weight in u. Used to convert between grams and moles: n = m/M." , front_translations: {"es":"Masa molar","de":"Molmasse","fr":"Masse molaire","tr":"Molar Kütle","nl":"Molaire massa","ru":"Молярная масса","zh":"摩尔质量","pt_BR":"Massa molar","pt_PT":"Massa molar"}, back_translations: {"es":"La masa en gramas de un mol de una sustancia, numericamente igual a la masa atómica/molecular en u. Usada para converter entre gramas y moles: n = m/M.","de":"Die Masse in Gramm eines Mols einer Substanz, numerisch gleich dem Atom-/Molekulargewicht in u. Wird zur Umrechnung zwischen Gramm und Mol verwendet: n = m/M.","fr":"La masse en grammes d'une mole d'une substance, numériquement égale à la masse atomique/moléculaire en u. Utilisée pour convertir entre grammes et moles : n = m/M.","tr":"Bir mol maddenin gram cinsinden kütlesi; u cinsinden atom/molekül ağırlığına sayısal olarak eşittir. Gram ile mol arasında dönüşüm için kullanılır: n = m/M.","nl":"De massa in gram van één mol van een stof, numeriek gelijk aan het atoom-/molecuulgewicht in u. Gebruikt om te converteren tussen gram en mol: n = m/M.","ru":"Масса в граммах одного моля вещества, численно равная атомной/молекулярной массе в а.е.м. Используется для перевода между граммами и молями: n = m/M.","zh":"一摩尔物质的克质量，在数值上等于以u为单位的原子/分子量。用于克与摩尔之间的换算：n = m/M。","pt_BR":"A massa em gramas de um mol de uma substância, numericamente igual à massa atômica/molecular em u. Usada para converter entre gramas e moles: n = m/M.","pt_PT":"A massa em gramas de um mol de uma substância, numericamente igual à massa atómica/molecular em u. Utilizada para converter entre gramas e moles: n = m/M."}},
  { id: 'dc-chemistry-0054', deck_id: 'deck-chemistry', sort_order: 54, front: "Molarity", back: "M = moles of solute / liters of solution. The most common unit of concentration in solution chemistry. A 1 M NaCl solution contains 58.44 g of NaCl per liter of solution." , front_translations: {"es":"Molaridad","de":"Molarität","fr":"Molarité","tr":"Molarite","nl":"Molariteit","ru":"Молярность","zh":"摩尔浓度","pt_BR":"Molaridade","pt_PT":"Molaridade"}, back_translations: {"es":"M = moles de soluto / litros de solución. La unidad de concentración más comum en química de soluciones. Una solución 1 M de NaCl contiene 58,44 g de NaCl por litro de solución.","de":"M = Mol des gelösten Stoffs / Liter der Lösung. Die gebräuchlichste Konzentrationseinheit in der Lösungschemie. Eine 1 M NaCl-Lösung enthält 58,44 g NaCl pro Liter Lösung.","fr":"M = moles de soluté / litres de solution. L'unité de concentration la plus courante en chimie des solutions. Une solution de NaCl à 1 M contient 58,44 g de NaCl par litre de solution.","tr":"M = çözünen maddenin molü / çözeltinin litresi. Çözelti kimyasında en yaygın konsantrasyon birimi. 1 M NaCl çözeltisi, litre çözelti başına 58,44 g NaCl içerir.","nl":"M = mol opgeloste stof / liter oplossing. De meest gebruikte concentratie-eenheid in de oplossingchemie. Een 1 M NaCl-oplossing bevat 58,44 g NaCl per liter oplossing.","ru":"М = моли растворённого вещества / литры раствора. Наиболее распространённая единица концентрации в химии растворов. 1 М раствор NaCl содержит 58,44 г NaCl на литр раствора.","zh":"M = 溶质的摩尔数 / 溶液的升数。溶液化学中最常用的浓度单位。1 M NaCl溶液每升溶液含有58.44 g NaCl。","pt_BR":"M = moles de soluto / litros de solução. A unidade de concentração mais comum em química de soluções. Uma solução 1 M de NaCl contém 58,44 g de NaCl por litro de solução.","pt_PT":"M = moles de soluto / litros de solução. A unidade de concentração mais comum em química de soluções. Uma solução 1 M de NaCl contém 58,44 g de NaCl por litro de solução."}},
  { id: 'dc-chemistry-0055', deck_id: 'deck-chemistry', sort_order: 55, front: "Enthalpy (ΔH)", back: "The heat exchanged in a reaction at constant pressure. ΔH < 0 is exothermic (heat released); ΔH > 0 is endothermic (heat absorbed). Measured by calorimetry." , front_translations: {"es":"Entalpia (ΔH)","de":"Enthalpie (ΔH)","fr":"Enthalpie (ΔH)","tr":"Entalpi (ΔH)","nl":"Enthalpie (ΔH)","ru":"Энтальпия (ΔH)","zh":"焓（ΔH）","pt_BR":"Entalpia (ΔH)","pt_PT":"Entalpia (ΔH)"}, back_translations: {"es":"El calor trocado en una reacción a presión constante. ΔH < 0 es exotérmico (calor liberado); ΔH > 0 es endotérmico (calor absorbido). Medido por calorimetria.","de":"Die bei konstantem Druck in einer Reaktion ausgetauschte Wärme. ΔH < 0 ist exotherm (Wärme wird abgegeben); ΔH > 0 ist endotherm (Wärme wird aufgenommen). Gemessen durch Kalorimetrie.","fr":"La chaleur échangée lors d'une réaction à pression constante. ΔH < 0 est exothermique (chaleur libérée) ; ΔH > 0 est endothermique (chaleur absorbée). Mesuré par calorimétrie.","tr":"Sabit basınçta bir reaksiyonda alışverişi yapılan ısı. ΔH < 0 ekzotermik (ısı salınır); ΔH > 0 endotermik (ısı emilir). Kalorimetri ile ölçülür.","nl":"De warmte die wordt uitgewisseld in een reactie bij constante druk. ΔH < 0 is exotherm (warmte vrijgegeven); ΔH > 0 is endotherm (warmte geabsorbeerd). Gemeten door calorimetrie.","ru":"Теплота, обмениваемая в реакции при постоянном давлении. ΔH < 0 — экзотермическая реакция (тепло выделяется); ΔH > 0 — эндотермическая (тепло поглощается). Измеряется калориметрией.","zh":"在恒压条件下反应中交换的热量。ΔH < 0 为放热反应（释放热量）；ΔH > 0 为吸热反应（吸收热量）。通过量热法测量。","pt_BR":"O calor trocado em uma reação a pressão constante. ΔH < 0 é exotérmico (calor liberado); ΔH > 0 é endotérmico (calor absorvido). Medido por calorimetria.","pt_PT":"O calor trocado numa reação a pressão constante. ΔH < 0 é exotérmico (calor libertado); ΔH > 0 é endotérmico (calor absorvido). Medido por calorimetria."}},
  { id: 'dc-chemistry-0056', deck_id: 'deck-chemistry', sort_order: 56, front: "Hess's Law", back: "The enthalpy change of a reaction is the same regardless of the path taken. Allows calculation of ΔH for reactions that are hard to measure directly by combining known equations." , front_translations: {"es":"Ley de Hess","de":"Hessscher Satz","fr":"Loi de Hess","tr":"Hess Yasası","nl":"Wet van Hess","ru":"Закон Гесса","zh":"赫斯定律","pt_BR":"Lei de Hess","pt_PT":"Lei de Hess"}, back_translations: {"es":"La variación de entalpia de una reacción es a misma independentemente del caminho percorrido. Permite calcular ΔH para reacciones difíceis de medir directamente, combinando ecuaciones conocidas.","de":"Die Enthalpieänderung einer Reaktion ist unabhängig vom gewählten Weg. Ermöglicht die Berechnung von ΔH für schwer direkt messbare Reaktionen durch Kombination bekannter Gleichungen.","fr":"La variation d'enthalpie d'une réaction est la même quel que soit le chemin emprunté. Permet de calculer ΔH pour des réactions difficiles à mesurer directement en combinant des équations connues.","tr":"Bir reaksiyonun entalpi değişimi, izlenen yoldan bağımsız olarak aynıdır. Bilinen denklemleri birleştirerek doğrudan ölçülmesi zor olan reaksiyonlar için ΔH hesaplanmasına olanak tanır.","nl":"De enthalpiewijziging van een reactie is dezelfde, ongeacht de gevolgde weg. Maakt berekening van ΔH mogelijk voor reacties die moeilijk direct te meten zijn, door bekende vergelijkingen te combineren.","ru":"Изменение энтальпии реакции одинаково независимо от пути. Позволяет рассчитывать ΔH для трудноизмеримых реакций путём комбинирования известных уравнений.","zh":"反应的焓变与所经历的路径无关。通过组合已知方程，可以计算难以直接测量的反应的ΔH。","pt_BR":"A variação de entalpia de uma reação é a mesma independentemente do caminho percorrido. Permite calcular ΔH para reações difíceis de medir diretamente, combinando equações conhecidas.","pt_PT":"A variação de entalpia de uma reação é a mesma independentemente do caminho percorrido. Permite calcular ΔH para reações difíceis de medir diretamente, combinando equações conhecidas."}},
  { id: 'dc-chemistry-0057', deck_id: 'deck-chemistry', sort_order: 57, front: "Bond Enthalpy", back: "The energy required to break one mole of a bond in the gas phase. ΔH_rxn ≈ Σ(bonds broken) - Σ(bonds formed). Breaking bonds requires energy; forming bonds releases it." , front_translations: {"es":"Entalpia de enlace","de":"Bindungsenthalpie","fr":"Enthalpie de liaison","tr":"Bağ Entalpisi","nl":"Bindingsenthalpie","ru":"Энергия связи","zh":"键焓","pt_BR":"Entalpia de ligação","pt_PT":"Entalpia de ligação"}, back_translations: {"es":"La energía necesaria para romper un mol de una enlace en la fase gaseosa. ΔH_rxn ≈ Σ(enlaces rompidas) − Σ(enlaces formadas). Romper enlaces requiere energía; formar enlaces libera energía.","de":"Die Energie, die erforderlich ist, um ein Mol einer Bindung in der Gasphase zu brechen. ΔH_rxn ≈ Σ(gebrochene Bindungen) − Σ(gebildete Bindungen). Bindungen zu brechen erfordert Energie; Bindungen zu bilden setzt sie frei.","fr":"L'énergie nécessaire pour rompre une mole de liaisons en phase gazeuse. ΔH_rxn ≈ Σ(liaisons rompues) − Σ(liaisons formées). Rompre des liaisons requiert de l'énergie ; en former en libère.","tr":"Gaz fazında bir mol bağı kırmak için gereken enerji. ΔH_rxn ≈ Σ(kırılan bağlar) − Σ(oluşan bağlar). Bağların kırılması enerji gerektirir; bağların oluşması enerji serbest bırakır.","nl":"De energie die nodig is om één mol bindingen in de gasfase te verbreken. ΔH_rxn ≈ Σ(verbroken bindingen) − Σ(gevormde bindingen). Bindingen verbreken vereist energie; bindingen vormen geeft energie vrij.","ru":"Энергия, необходимая для разрыва одного моля связей в газовой фазе. ΔH_rxn ≈ Σ(разорванные связи) − Σ(образованные связи). Разрыв связей требует энергии; образование связей её выделяет.","zh":"在气相中断裂一摩尔键所需的能量。ΔH_rxn ≈ Σ（断裂的键）− Σ（形成的键）。断键需要能量；成键释放能量。","pt_BR":"A energia necessária para romper um mol de uma ligação na fase gasosa. ΔH_rxn ≈ Σ(ligações rompidas) − Σ(ligações formadas). Romper ligações requer energia; formar ligações libera energia.","pt_PT":"A energia necessária para romper um mol de uma ligação na fase gasosa. ΔH_rxn ≈ Σ(ligações rompidas) − Σ(ligações formadas). Romper ligações requer energia; formar ligações liberta energia."}},
  { id: 'dc-chemistry-0058', deck_id: 'deck-chemistry', sort_order: 58, front: "Entropy (ΔS)", back: "A measure of the dispersal of energy and matter in a system. Increases with temperature, dissolving, gas production, and increased particle number. Unit: J/(mol·K)." , front_translations: {"es":"Entropia (ΔS)","de":"Entropie (ΔS)","fr":"Entropie (ΔS)","tr":"Entropi (ΔS)","nl":"Entropie (ΔS)","ru":"Энтропия (ΔS)","zh":"熵（ΔS）","pt_BR":"Entropia (ΔS)","pt_PT":"Entropia (ΔS)"}, back_translations: {"es":"Una medida de la dispersão de energía y materia en un sistema. Aumenta con a temperatura, disolución, producción de gas y aumento del número de partículas. Unidad: J/(mol·K).","de":"Ein Maß für die Verteilung von Energie und Materie in einem System. Nimmt mit Temperatur, Lösen, Gaserzeugung und Zunahme der Teilchenzahl zu. Einheit: J/(mol·K).","fr":"Une mesure de la dispersion de l'énergie et de la matière dans un système. Augmente avec la température, la dissolution, la production de gaz et l'augmentation du nombre de particules. Unité : J/(mol·K).","tr":"Bir sistemdeki enerji ve maddenin dağılımının ölçüsü. Sıcaklık, çözünme, gaz üretimi ve parçacık sayısındaki artışla birlikte artar. Birimi: J/(mol·K).","nl":"Een maatstaf voor de verspreiding van energie en materie in een systeem. Neemt toe met temperatuur, oplossen, gasproductie en toename van het aantal deeltjes. Eenheid: J/(mol·K).","ru":"Мера рассеяния энергии и вещества в системе. Увеличивается с температурой, растворением, выделением газа и увеличением числа частиц. Единица: Дж/(моль·К).","zh":"衡量系统中能量和物质分散程度的量。随温度升高、溶解、产生气体和粒子数增加而增大。单位：J/(mol·K)。","pt_BR":"Uma medida da dispersão de energia e matéria em um sistema. Aumenta com a temperatura, dissolução, produção de gás e aumento do número de partículas. Unidade: J/(mol·K).","pt_PT":"Uma medida da dispersão de energia e matéria num sistema. Aumenta com a temperatura, dissolução, produção de gás e aumento do número de partículas. Unidade: J/(mol·K)."}},
  { id: 'dc-chemistry-0059', deck_id: 'deck-chemistry', sort_order: 59, front: "Gibbs Free Energy", back: "ΔG = ΔH - TΔS. If ΔG < 0, a reaction is spontaneous; if ΔG > 0, it is non-spontaneous. Combines enthalpy and entropy to predict reaction favorability." , front_translations: {"es":"Energía livre de Gibbs","de":"Gibbs-Freie Energie","fr":"Énergie libre de Gibbs","tr":"Gibbs Serbest Enerjisi","nl":"Gibbs vrije energie","ru":"Энергия Гиббса","zh":"吉布斯自由能","pt_BR":"Energia livre de Gibbs","pt_PT":"Energia livre de Gibbs"}, back_translations: {"es":"ΔG = ΔH − TΔS. Se ΔG < 0, una reacción es espontanea; se ΔG > 0, es no espontanea. Combina entalpia y entropia para prever a favorabilidad de la reacción.","de":"ΔG = ΔH − TΔS. Wenn ΔG < 0, ist eine Reaktion spontan; wenn ΔG > 0, ist sie nicht spontan. Kombiniert Enthalpie und Entropie, um die Reaktionsgünstigkeit vorherzusagen.","fr":"ΔG = ΔH − TΔS. Si ΔG < 0, une réaction est spontanée ; si ΔG > 0, elle est non spontanée. Combine l'enthalpie et l'entropie pour prédire la favorabilité d'une réaction.","tr":"ΔG = ΔH − TΔS. ΔG < 0 ise reaksiyon kendiliğinden gerçekleşir; ΔG > 0 ise kendiliğinden gerçekleşmez. Reaksiyonun uygunluğunu tahmin etmek için entalpiyi ve entropiyi birleştirir.","nl":"ΔG = ΔH − TΔS. Als ΔG < 0, is een reactie spontaan; als ΔG > 0, is ze niet-spontaan. Combineert enthalpie en entropie om de gunstigheid van een reactie te voorspellen.","ru":"ΔG = ΔH − TΔS. Если ΔG < 0, реакция самопроизвольна; если ΔG > 0 — несамопроизвольна. Объединяет энтальпию и энтропию для предсказания термодинамической выгодности реакции.","zh":"ΔG = ΔH − TΔS。若ΔG < 0，反应是自发的；若ΔG > 0，则不自发。结合焓和熵来预测反应的热力学可行性。","pt_BR":"ΔG = ΔH − TΔS. Se ΔG < 0, uma reação é espontânea; se ΔG > 0, é não espontânea. Combina entalpia e entropia para prever a favorabilidade da reação.","pt_PT":"ΔG = ΔH − TΔS. Se ΔG < 0, uma reação é espontânea; se ΔG > 0, é não espontânea. Combina entalpia e entropia para prever a favorabilidade da reação."}},
  { id: 'dc-chemistry-0060', deck_id: 'deck-chemistry', sort_order: 60, front: "Standard Free Energy and Equilibrium", back: "ΔG° = -RT·ln(K). The standard free energy change is related to the equilibrium constant. If K > 1, ΔG° < 0 (products favored); if K < 1, ΔG° > 0 (reactants favored)." , front_translations: {"es":"Energía livre padrão y equilíbrio","de":"Standardfreie Energie und Gleichgewicht","fr":"Énergie libre standard et équilibre","tr":"Standart Serbest Enerji ve Denge","nl":"Standaard vrije energie en evenwicht","ru":"Стандартная свободная энергия и равновесие","zh":"标准自由能与平衡","pt_BR":"Energia livre padrão e equilíbrio","pt_PT":"Energia livre padrão e equilíbrio"}, back_translations: {"es":"ΔG° = −RT·ln(K). La variación de energía livre padrão está relacionada a la constante de equilíbrio. Se K > 1, ΔG° < 0 (productos favorecidos); se K < 1, ΔG° > 0 (reactivos favorecidos).","de":"ΔG° = −RT·ln(K). Die Standard-Freie-Energie-Änderung ist mit der Gleichgewichtskonstante verknüpft. Wenn K > 1, ist ΔG° < 0 (Produkte bevorzugt); wenn K < 1, ist ΔG° > 0 (Edukte bevorzugt).","fr":"ΔG° = −RT·ln(K). La variation d'énergie libre standard est liée à la constante d'équilibre. Si K > 1, ΔG° < 0 (produits favorisés) ; si K < 1, ΔG° > 0 (réactifs favorisés).","tr":"ΔG° = −RT·ln(K). Standart serbest enerji değişimi denge sabitiyle ilişkilidir. K > 1 ise ΔG° < 0 (ürünler tercih edilir); K < 1 ise ΔG° > 0 (reaktifler tercih edilir).","nl":"ΔG° = −RT·ln(K). De standaard vrije-energiewijziging is gerelateerd aan de evenwichtsconstante. Als K > 1, is ΔG° < 0 (producten begunstigd); als K < 1, is ΔG° > 0 (reactanten begunstigd).","ru":"ΔG° = −RT·ln(K). Стандартное изменение свободной энергии связано с константой равновесия. Если K > 1, ΔG° < 0 (продукты предпочтительны); если K < 1, ΔG° > 0 (реагенты предпочтительны).","zh":"ΔG° = −RT·ln(K)。标准自由能变与平衡常数相关。若K > 1，则ΔG° < 0（有利于产物）；若K < 1，则ΔG° > 0（有利于反应物）。","pt_BR":"ΔG° = −RT·ln(K). A variação de energia livre padrão está relacionada à constante de equilíbrio. Se K > 1, ΔG° < 0 (produtos favorecidos); se K < 1, ΔG° > 0 (reagentes favorecidos).","pt_PT":"ΔG° = −RT·ln(K). A variação de energia livre padrão está relacionada com a constante de equilíbrio. Se K > 1, ΔG° < 0 (produtos favorecidos); se K < 1, ΔG° > 0 (reagentes favorecidos)."}},
  { id: 'dc-chemistry-0061', deck_id: 'deck-chemistry', sort_order: 61, front: "Reaction Rate", back: "The change in concentration of a reactant or product per unit time. Rate = Δ[concentration]/Δtime. Influenced by temperature, concentration, catalysts, and surface area." , front_translations: {"es":"Taxa de reacción","de":"Reaktionsgeschwindigkeit","fr":"Vitesse de réaction","tr":"Tepkime Hızı","nl":"Reactiesnelheid","ru":"Скорость реакции","zh":"反应速率","pt_BR":"Taxa de reação","pt_PT":"Taxa de reação"}, back_translations: {"es":"La variación de concentración de un reactivo o producto por unidad de tiempo. Taxa = Δ[concentración]/Δt. Influenciada por temperatura, concentración, catalizadores y área de superficie.","de":"Die Konzentrationsänderung eines Reaktanten oder Produkts pro Zeiteinheit. Rate = Δ[Konzentration]/Δt. Wird beeinflusst durch Temperatur, Konzentration, Katalysatoren und Oberfläche.","fr":"La variation de concentration d'un réactif ou d'un produit par unité de temps. Vitesse = Δ[concentration]/Δt. Influencée par la température, la concentration, les catalyseurs et la surface de contact.","tr":"Bir reaktif veya ürünün birim zamandaki konsantrasyon değişimi. Hız = Δ[konsantrasyon]/Δt. Sıcaklık, konsantrasyon, katalizörler ve yüzey alanı tarafından etkilenir.","nl":"De verandering in concentratie van een reactant of product per tijdseenheid. Snelheid = Δ[concentratie]/Δt. Beïnvloed door temperatuur, concentratie, katalysatoren en oppervlakte.","ru":"Изменение концентрации реагента или продукта в единицу времени. Скорость = Δ[концентрация]/Δt. Зависит от температуры, концентрации, катализаторов и площади поверхности.","zh":"单位时间内反应物或产物浓度的变化。速率 = Δ[浓度]/Δt。受温度、浓度、催化剂和表面积的影响。","pt_BR":"A variação de concentração de um reagente ou produto por unidade de tempo. Taxa = Δ[concentração]/Δt. Influenciada por temperatura, concentração, catalisadores e área de superfície.","pt_PT":"A variação de concentração de um reagente ou produto por unidade de tempo. Taxa = Δ[concentração]/Δt. Influenciada pela temperatura, concentração, catalisadores e área de superfície."}},
  { id: 'dc-chemistry-0062', deck_id: 'deck-chemistry', sort_order: 62, front: "Rate Law", back: "Rate = k[A]^m[B]^n. The rate of a reaction depends on the rate constant k and the concentrations of reactants raised to their orders m and n. Orders must be determined experimentally." , front_translations: {"es":"Ley de velocidad","de":"Geschwindigkeitsgesetz","fr":"Loi de vitesse","tr":"Hız Yasası","nl":"Snelheidswet","ru":"Уравнение скорости реакции","zh":"速率方程","pt_BR":"Lei de velocidade","pt_PT":"Lei de velocidade"}, back_translations: {"es":"Taxa = k[A]^m[B]^n. La velocidad de una reacción depende de la constante de velocidad k y de las concentraciones de los reactivos elevadas a las sus ordens m y n. As ordens devem ser determinadas experimentalmente.","de":"Rate = k[A]^m[B]^n. Die Reaktionsgeschwindigkeit hängt von der Geschwindigkeitskonstante k und den Konzentrationen der Reaktanten ab, potenziert mit ihren Ordnungen m und n. Ordnungen müssen experimentell bestimmt werden.","fr":"Vitesse = k[A]^m[B]^n. La vitesse de réaction dépend de la constante de vitesse k et des concentrations des réactifs élevées à leurs ordres m et n. Les ordres doivent être déterminés expérimentalement.","tr":"Hız = k[A]^m[B]^n. Reaksiyonun hızı, hız sabiti k'ya ve reaktiflerin m ile n kuvvetlerine yükseltilmiş konsantrasyonlarına bağlıdır. Dereceler deneysel olarak belirlenmek zorundadır.","nl":"Snelheid = k[A]^m[B]^n. De reactiesnelheid hangt af van de snelheidsconstante k en de concentraties van reactanten verheven tot hun orden m en n. Orden moeten experimenteel worden bepaald.","ru":"Скорость = k[A]^m[B]^n. Скорость реакции зависит от константы скорости k и концентраций реагентов, возведённых в степени m и n. Порядки реакции определяются экспериментально.","zh":"速率 = k[A]^m[B]^n。反应速率取决于速率常数k以及反应物浓度的m次方和n次方。反应级数必须通过实验确定。","pt_BR":"Taxa = k[A]^m[B]^n. A velocidade de uma reação depende da constante de velocidade k e das concentrações dos reagentes elevadas às suas ordens m e n. As ordens devem ser determinadas experimentalmente.","pt_PT":"Taxa = k[A]^m[B]^n. A velocidade de uma reação depende da constante de velocidade k e das concentrações dos reagentes elevadas às suas ordens m e n. As ordens têm de ser determinadas experimentalmente."}},
  { id: 'dc-chemistry-0063', deck_id: 'deck-chemistry', sort_order: 63, front: "Activation Energy (Ea)", back: "The minimum energy required for reactants to transform into products. Reactions with high Ea are slow; catalysts lower Ea, increasing reaction rate without being consumed." , front_translations: {"es":"Energía de ativación (Ea)","de":"Aktivierungsenergie (Ea)","fr":"Énergie d'activation (Ea)","tr":"Aktivasyon Enerjisi (Ea)","nl":"Activeringsenergie (Ea)","ru":"Энергия активации (Ea)","zh":"活化能（Ea）","pt_BR":"Energia de ativação (Ea)","pt_PT":"Energia de ativação (Ea)"}, back_translations: {"es":"La energía mínima necesaria para que los reactivos se transformem en productos. Reacciones con Ea alta son lentas; catalizadores disminuyen Ea, aumentando a taxa de reacción sin serem consumidos.","de":"Die Mindestenergie, die erforderlich ist, damit Reaktanten zu Produkten umgewandelt werden. Reaktionen mit hoher Ea sind langsam; Katalysatoren senken Ea, erhöhen die Reaktionsgeschwindigkeit ohne verbraucht zu werden.","fr":"L'énergie minimale requise pour que les réactifs se transforment en produits. Les réactions à Ea élevée sont lentes ; les catalyseurs abaissent Ea, augmentant la vitesse de réaction sans être consommés.","tr":"Reaktiflerin ürünlere dönüşmesi için gereken minimum enerji. Yüksek Ea'ya sahip reaksiyonlar yavaştır; katalizörler Ea'yı düşürerek tüketilmeden reaksiyon hızını artırır.","nl":"De minimale energie die vereist is voor reactanten om om te zetten in producten. Reacties met een hoge Ea zijn traag; katalysatoren verlagen Ea, waardoor de reactiesnelheid toeneemt zonder te worden verbruikt.","ru":"Минимальная энергия, необходимая для превращения реагентов в продукты. Реакции с высокой Ea протекают медленно; катализаторы снижают Ea, увеличивая скорость реакции без собственного расходования.","zh":"将反应物转化为产物所需的最低能量。Ea高的反应速度慢；催化剂降低Ea，在不被消耗的情况下提高反应速率。","pt_BR":"A energia mínima necessária para que os reagentes se transformem em produtos. Reações com Ea alta são lentas; catalisadores diminuem Ea, aumentando a taxa de reação sem serem consumidos.","pt_PT":"A energia mínima necessária para que os reagentes se transformem em produtos. Reações com Ea alta são lentas; catalisadores diminuem Ea, aumentando a taxa de reação sem serem consumidos."}},
  { id: 'dc-chemistry-0064', deck_id: 'deck-chemistry', sort_order: 64, front: "Arrhenius Equation", back: "k = Ae^(-Ea/RT). The rate constant k increases exponentially with temperature. A is the frequency factor; Ea is activation energy; R = 8.314 J/mol·K; T is temperature in K." , front_translations: {"es":"Ecuación de Arrhenius","de":"Arrhenius-Gleichung","fr":"Équation d'Arrhenius","tr":"Arrhenius Denklemi","nl":"Vergelijking van Arrhenius","ru":"Уравнение Аррениуса","zh":"阿伦尼乌斯方程","pt_BR":"Equação de Arrhenius","pt_PT":"Equação de Arrhenius"}, back_translations: {"es":"k = Ae^(−Ea/RT). La constante de velocidad k aumenta exponencialmente con a temperatura. La es el fator de frecuencia; Ea es a energía de ativación; R = 8,314 J/mol·K; T es a temperatura en K.","de":"k = Ae^(−Ea/RT). Die Geschwindigkeitskonstante k steigt exponentiell mit der Temperatur. A ist der Frequenzfaktor; Ea ist die Aktivierungsenergie; R = 8,314 J/mol·K; T ist die Temperatur in K.","fr":"k = Ae^(−Ea/RT). La constante de vitesse k augmente de manière exponentielle avec la température. A est le facteur de fréquence ; Ea est l'énergie d'activation ; R = 8,314 J/mol·K ; T est la température en K.","tr":"k = Ae^(−Ea/RT). Hız sabiti k, sıcaklıkla üstel olarak artar. A frekans faktörüdür; Ea aktivasyon enerjisidir; R = 8,314 J/mol·K; T Kelvin cinsinden sıcaklıktır.","nl":"k = Ae^(−Ea/RT). De snelheidsconstante k neemt exponentieel toe met de temperatuur. A is de frequentiefactor; Ea is de activeringsenergie; R = 8,314 J/mol·K; T is de temperatuur in K.","ru":"k = Ae^(−Ea/RT). Константа скорости k экспоненциально возрастает с температурой. A — предэкспоненциальный множитель; Ea — энергия активации; R = 8,314 Дж/моль·К; T — температура в К.","zh":"k = Ae^(−Ea/RT)。速率常数k随温度呈指数增长。A为频率因子；Ea为活化能；R = 8.314 J/mol·K；T为开尔文温度。","pt_BR":"k = Ae^(−Ea/RT). A constante de velocidade k aumenta exponencialmente com a temperatura. A é o fator de frequência; Ea é a energia de ativação; R = 8,314 J/mol·K; T é a temperatura em K.","pt_PT":"k = Ae^(−Ea/RT). A constante de velocidade k aumenta exponencialmente com a temperatura. A é o fator de frequência; Ea é a energia de ativação; R = 8,314 J/mol·K; T é a temperatura em K."}},
  { id: 'dc-chemistry-0065', deck_id: 'deck-chemistry', sort_order: 65, front: "Catalyst", back: "A substance that increases reaction rate by providing an alternative pathway with lower activation energy. It is not consumed in the reaction and does not shift equilibrium position." , front_translations: {"es":"Catalizador","de":"Katalysator","fr":"Catalyseur","tr":"Katalizör","nl":"Katalysator","ru":"Катализатор","zh":"催化剂","pt_BR":"Catalisador","pt_PT":"Catalisador"}, back_translations: {"es":"Una sustancia que aumenta a taxa de reacción proporcionando una via alternativa con menor energía de ativación. No es consumida en la reacción y no desloca a posición de equilíbrio.","de":"Eine Substanz, die die Reaktionsgeschwindigkeit erhöht, indem sie einen alternativen Reaktionspfad mit niedrigerer Aktivierungsenergie bereitstellt. Sie wird in der Reaktion nicht verbraucht und verschiebt nicht die Gleichgewichtsposition.","fr":"Une substance qui augmente la vitesse de réaction en fournissant une voie alternative avec une énergie d'activation plus faible. Elle n'est pas consommée dans la réaction et ne déplace pas la position d'équilibre.","tr":"Daha düşük aktivasyon enerjisine sahip alternatif bir yol sağlayarak reaksiyon hızını artıran bir madde. Reaksiyonda tüketilmez ve denge konumunu değiştirmez.","nl":"Een stof die de reactiesnelheid verhoogt door een alternatieve weg te bieden met een lagere activeringsenergie. Het wordt niet verbruikt in de reactie en verschuift de evenwichtspositie niet.","ru":"Вещество, увеличивающее скорость реакции за счёт предоставления альтернативного пути с меньшей энергией активации. Оно не расходуется в реакции и не смещает положение равновесия.","zh":"通过提供活化能更低的替代路径来提高反应速率的物质。它在反应中不被消耗，也不会改变平衡位置。","pt_BR":"Uma substância que aumenta a taxa de reação fornecendo uma via alternativa com menor energia de ativação. Não é consumida na reação e não desloca a posição de equilíbrio.","pt_PT":"Uma substância que aumenta a taxa de reação fornecendo uma via alternativa com menor energia de ativação. Não é consumida na reação e não desloca a posição de equilíbrio."}},
  { id: 'dc-chemistry-0066', deck_id: 'deck-chemistry', sort_order: 66, front: "Reaction Order", back: "Describes how the rate depends on reactant concentrations. Zero order: rate is constant. First order: rate ∝ [A]. Second order: rate ∝ [A]² or [A][B]. Determined experimentally." , front_translations: {"es":"Ordem de reacción","de":"Reaktionsordnung","fr":"Ordre de réaction","tr":"Reaksiyon Derecesi","nl":"Reactieorde","ru":"Порядок реакции","zh":"反应级数","pt_BR":"Ordem de reação","pt_PT":"Ordem de reação"}, back_translations: {"es":"Descreve como a taxa depende de las concentraciones de los reactivos. Ordem zero: taxa constante. Primera ordem: taxa ∝ [A]. Segunda ordem: taxa ∝ [A]² o [A][B]. Determinada experimentalmente.","de":"Beschreibt, wie die Geschwindigkeit von den Reaktantenkonzentrationen abhängt. Nullter Ordnung: Geschwindigkeit konstant. Erster Ordnung: Rate ∝ [A]. Zweiter Ordnung: Rate ∝ [A]² oder [A][B]. Experimentell bestimmt.","fr":"Décrit comment la vitesse dépend des concentrations des réactifs. Ordre zéro : vitesse constante. Premier ordre : vitesse ∝ [A]. Deuxième ordre : vitesse ∝ [A]² ou [A][B]. Déterminé expérimentalement.","tr":"Hızın reaktif konsantrasyonlarına nasıl bağlı olduğunu açıklar. Sıfırıncı derece: hız sabittir. Birinci derece: hız ∝ [A]. İkinci derece: hız ∝ [A]² veya [A][B]. Deneysel olarak belirlenir.","nl":"Beschrijft hoe de snelheid afhangt van de concentraties van de reactanten. Nulde orde: snelheid is constant. Eerste orde: snelheid ∝ [A]. Tweede orde: snelheid ∝ [A]² of [A][B]. Experimenteel bepaald.","ru":"Описывает, как скорость зависит от концентраций реагентов. Нулевой порядок: скорость постоянна. Первый порядок: скорость ∝ [A]. Второй порядок: скорость ∝ [A]² или [A][B]. Определяется экспериментально.","zh":"描述反应速率如何依赖于反应物浓度。零级：速率恒定。一级：速率 ∝ [A]。二级：速率 ∝ [A]² 或 [A][B]。通过实验确定。","pt_BR":"Descreve como a taxa depende das concentrações dos reagentes. Ordem zero: taxa constante. Primeira ordem: taxa ∝ [A]. Segunda ordem: taxa ∝ [A]² ou [A][B]. Determinada experimentalmente.","pt_PT":"Descreve como a taxa depende das concentrações dos reagentes. Ordem zero: taxa constante. Primeira ordem: taxa ∝ [A]. Segunda ordem: taxa ∝ [A]² ou [A][B]. Determinada experimentalmente."}},
  { id: 'dc-chemistry-0067', deck_id: 'deck-chemistry', sort_order: 67, front: "Half-Life of First-Order Reaction", back: "t½ = ln2/k = 0.693/k. For a first-order reaction, the half-life is constant and independent of initial concentration. Applies to radioactive decay and many drug elimination kinetics." , front_translations: {"es":"Media-vida de una reacción de primera ordem","de":"Halbwertszeit einer Reaktion erster Ordnung","fr":"Demi-vie d'une réaction du premier ordre","tr":"Birinci Dereceden Reaksiyonun Yarı Ömrü","nl":"Halveringstijd van een eersteorde-reactie","ru":"Период полупревращения реакции первого порядка","zh":"一级反应的半衰期","pt_BR":"Meia-vida de uma reação de primeira ordem","pt_PT":"Meia-vida de uma reação de primeira ordem"}, back_translations: {"es":"t½ = ln2/k = 0,693/k. Para una reacción de primera ordem, a media-vida es constante y independente de la concentración inicial. Se aplica al decaimento radioativo y a la cinética de eliminación de muchos fármacos.","de":"t½ = ln2/k = 0,693/k. Bei einer Reaktion erster Ordnung ist die Halbwertszeit konstant und unabhängig von der Anfangskonzentration. Gilt für radioaktiven Zerfall und viele Arzneimittel-Eliminationskinetiken.","fr":"t½ = ln2/k = 0,693/k. Pour une réaction de premier ordre, la demi-vie est constante et indépendante de la concentration initiale. S'applique à la désintégration radioactive et à la cinétique d'élimination de nombreux médicaments.","tr":"t½ = ln2/k = 0,693/k. Birinci dereceden reaksiyonda yarı ömür sabittir ve başlangıç konsantrasyonundan bağımsızdır. Radyoaktif bozunma ve pek çok ilaç eliminasyon kinetiğine uygulanır.","nl":"t½ = ln2/k = 0,693/k. Voor een eersteorde-reactie is de halveringstijd constant en onafhankelijk van de beginconcentratie. Van toepassing op radioactief verval en de eliminatiekinetiek van veel geneesmiddelen.","ru":"t½ = ln2/k = 0,693/k. Для реакции первого порядка период полупревращения постоянен и не зависит от начальной концентрации. Применяется к радиоактивному распаду и кинетике элиминации многих лекарств.","zh":"t½ = ln2/k = 0.693/k。对于一级反应，半衰期是恒定的，与初始浓度无关。适用于放射性衰变和许多药物的消除动力学。","pt_BR":"t½ = ln2/k = 0,693/k. Para uma reação de primeira ordem, a meia-vida é constante e independente da concentração inicial. Aplica-se ao decaimento radioativo e à cinética de eliminação de muitos fármacos.","pt_PT":"t½ = ln2/k = 0,693/k. Para uma reação de primeira ordem, a meia-vida é constante e independente da concentração inicial. Aplica-se ao decaimento radioativo e à cinética de eliminação de muitos fármacos."}},
  { id: 'dc-chemistry-0068', deck_id: 'deck-chemistry', sort_order: 68, front: "Electrochemistry: Galvanic Cell", back: "Converts chemical energy to electrical energy via a spontaneous redox reaction. Electrons flow from the anode (oxidation) through the external circuit to the cathode (reduction)." , front_translations: {"es":"Eletroquímica: Célula galvanica","de":"Elektrochemie: Galvanische Zelle","fr":"Électrochimie : Pile galvanique","tr":"Elektrokimya: Galvanik Hücre","nl":"Elektrochemie: Galvanische cel","ru":"Электрохимия: гальванический элемент","zh":"电化学：原电池","pt_BR":"Eletroquímica: Célula galvânica","pt_PT":"Eletroquímica: Célula galvânica"}, back_translations: {"es":"Convierte energía química en energía eléctrica por medio de una reacción redox espontanea. Los electrones fluem del anodo (oxidación) por el circuito externo hasta el cátodo (reducción).","de":"Wandelt chemische Energie durch eine spontane Redoxreaktion in elektrische Energie um. Elektronen fließen von der Anode (Oxidation) durch den externen Stromkreis zur Kathode (Reduktion).","fr":"Convertit l'énergie chimique en énergie électrique via une réaction rédox spontanée. Les électrons circulent de l'anode (oxydation) à travers le circuit externe vers la cathode (réduction).","tr":"Spontan bir redoks reaksiyonu yoluyla kimyasal enerjiyi elektrik enerjisine dönüştürür. Elektronlar anoddan (oksidasyon) dış devre aracılığıyla katoda (indirgenme) akar.","nl":"Zet chemische energie om in elektrische energie via een spontane redoxreactie. Elektronen stromen van de anode (oxidatie) door het externe circuit naar de kathode (reductie).","ru":"Преобразует химическую энергию в электрическую посредством самопроизвольной окислительно-восстановительной реакции. Электроны текут от анода (окисление) через внешнюю цепь к катоду (восстановление).","zh":"通过自发的氧化还原反应将化学能转化为电能。电子从阳极（氧化）通过外部电路流向阴极（还原）。","pt_BR":"Converte energia química em energia elétrica por meio de uma reação redox espontânea. Os elétrons fluem do ânodo (oxidação) pelo circuito externo até o cátodo (redução).","pt_PT":"Converte energia química em energia elétrica através de uma reação redox espontânea. Os eletrões fluem do ânodo (oxidação) pelo circuito externo até ao cátodo (redução)."}},
  { id: 'dc-chemistry-0069', deck_id: 'deck-chemistry', sort_order: 69, front: "Standard Cell Potential (E°)", back: "E°cell = E°cathode - E°anode. Calculated from standard reduction potentials. A positive E°cell indicates a spontaneous reaction. Related to ΔG° by ΔG° = -nFE°." , front_translations: {"es":"Potencial de célula padrão (Y°)","de":"Standardzellpotenzial (E°)","fr":"Potentiel standard de cellule (E°)","tr":"Standart Hücre Potansiyeli (E°)","nl":"Standaard celpotentiaal (E°)","ru":"Стандартный потенциал элемента (E°)","zh":"标准电池电动势（E°）","pt_BR":"Potencial de célula padrão (E°)","pt_PT":"Potencial de célula padrão (E°)"}, back_translations: {"es":"Y°célula = Y°cátodo − Y°anodo. Calculado a partir de los potenciais padrão de reducción. Un Y°célula positivo indica una reacción espontanea. Relacionado a ΔG° por ΔG° = −nFE°.","de":"E°Zelle = E°Kathode − E°Anode. Berechnet aus Standard-Reduktionspotenzialen. Ein positives E°Zelle zeigt eine spontane Reaktion an. Mit ΔG° verbunden durch ΔG° = −nFE°.","fr":"E°pile = E°cathode − E°anode. Calculé à partir des potentiels standard de réduction. Un E°pile positif indique une réaction spontanée. Lié à ΔG° par ΔG° = −nFE°.","tr":"E°hücre = E°katot − E°anot. Standart indirgenme potansiyellerinden hesaplanır. Pozitif E°hücre spontan bir reaksiyona işaret eder. ΔG° ile ΔG° = −nFE° bağıntısıyla ilişkilidir.","nl":"E°cel = E°kathode − E°anode. Berekend uit standaard reductiepotentialen. Een positief E°cel geeft een spontane reactie aan. Gerelateerd aan ΔG° via ΔG° = −nFE°.","ru":"E°эл = E°катода − E°анода. Рассчитывается по стандартным потенциалам восстановления. Положительное E°эл свидетельствует о самопроизвольной реакции. Связано с ΔG° соотношением ΔG° = −nFE°.","zh":"E°电池 = E°阴极 − E°阳极。由标准还原电位计算得出。正的E°电池表示反应是自发的。通过ΔG° = −nFE°与ΔG°相关联。","pt_BR":"E°célula = E°cátodo − E°ânodo. Calculado a partir dos potenciais padrão de redução. Um E°célula positivo indica uma reação espontânea. Relacionado a ΔG° por ΔG° = −nFE°.","pt_PT":"E°célula = E°cátodo − E°ânodo. Calculado a partir dos potenciais padrão de redução. Um E°célula positivo indica uma reação espontânea. Relacionado com ΔG° por ΔG° = −nFE°."}},
  { id: 'dc-chemistry-0070', deck_id: 'deck-chemistry', sort_order: 70, front: "Nernst Equation", back: "E = E° - (RT/nF)ln(Q) ≈ E° - (0.0592/n)log(Q) at 25°C. Gives the cell potential under non-standard conditions. At equilibrium, E = 0 and Q = K." , front_translations: {"es":"Ecuación de Nernst","de":"Nernst-Gleichung","fr":"Équation de Nernst","tr":"Nernst Denklemi","nl":"Vergelijking van Nernst","ru":"Уравнение Нернста","zh":"能斯特方程","pt_BR":"Equação de Nernst","pt_PT":"Equação de Nernst"}, back_translations: {"es":"Y = Y° − (RT/nF)ln(Q) ≈ Y° − (0,0592/n)log(Q) a 25°C. Proporciona el potencial de célula en condiciones no padrão. No equilíbrio, Y = 0 y Q = K.","de":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) bei 25 °C. Gibt das Zellpotenzial unter nicht-standardisierten Bedingungen an. Im Gleichgewicht gilt E = 0 und Q = K.","fr":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) à 25 °C. Donne le potentiel de la pile dans des conditions non standard. À l'équilibre, E = 0 et Q = K.","tr":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) (25 °C'de). Standart dışı koşullarda hücre potansiyelini verir. Dengede E = 0 ve Q = K olur.","nl":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) bij 25 °C. Geeft het celpotentiaal onder niet-standaardomstandigheden. Bij evenwicht is E = 0 en Q = K.","ru":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) при 25 °C. Даёт потенциал элемента в нестандартных условиях. При равновесии E = 0 и Q = K.","zh":"E = E° − (RT/nF)ln(Q) ≈ E° − (0.0592/n)log(Q)（25°C下）。给出非标准条件下的电池电动势。在平衡时，E = 0，Q = K。","pt_BR":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) a 25°C. Fornece o potencial de célula em condições não padrão. No equilíbrio, E = 0 e Q = K.","pt_PT":"E = E° − (RT/nF)ln(Q) ≈ E° − (0,0592/n)log(Q) a 25°C. Fornece o potencial de célula em condições não padrão. No equilíbrio, E = 0 e Q = K."}},
  { id: 'dc-chemistry-0071', deck_id: 'deck-chemistry', sort_order: 71, front: "Electrolysis", back: "Using electrical energy to drive a non-spontaneous redox reaction. Faraday's Law: moles deposited = (current × time) / (n × F). Used in electroplating and producing metals like Al." , front_translations: {"es":"Eletrólise","de":"Elektrolyse","fr":"Électrolyse","tr":"Elektroliz","nl":"Elektrolyse","ru":"Электролиз","zh":"电解","pt_BR":"Eletrólise","pt_PT":"Eletrólise"}, back_translations: {"es":"Uso de energía eléctrica para impulsionar una reacción redox no espontanea. Ley de Faraday: moles depositados = (corrente × tiempo) / (n × F). Usada en galvanoplastia y producción de metais como Al.","de":"Verwendung elektrischer Energie, um eine nicht spontane Redoxreaktion anzutreiben. Faradaysches Gesetz: abgeschiedene Mole = (Strom × Zeit) / (n × F). Verwendet bei der Galvanik und der Herstellung von Metallen wie Al.","fr":"Utilisation de l'énergie électrique pour entraîner une réaction rédox non spontanée. Loi de Faraday : moles déposées = (courant × temps) / (n × F). Utilisée pour l'électrodéposition et la production de métaux comme l'Al.","tr":"Elektrik enerjisini kullanarak kendiliğinden gerçekleşmeyen bir redoks reaksiyonunu gerçekleştirme. Faraday Yasası: biriken mol = (akım × süre) / (n × F). Elektrokaplamada ve Al gibi metallerin üretiminde kullanılır.","nl":"Gebruik van elektrische energie om een niet-spontane redoxreactie aan te drijven. Wet van Faraday: mol afgezet = (stroom × tijd) / (n × F). Gebruikt bij galvaniseren en de productie van metalen zoals Al.","ru":"Использование электрической энергии для проведения несамопроизвольной окислительно-восстановительной реакции. Закон Фарадея: осаждённые моли = (ток × время) / (n × F). Применяется в гальванотехнике и производстве металлов, таких как Al.","zh":"利用电能驱动非自发的氧化还原反应。法拉第定律：沉积的摩尔数 = （电流 × 时间）/（n × F）。用于电镀和生产铝等金属。","pt_BR":"Uso de energia elétrica para impulsionar uma reação redox não espontânea. Lei de Faraday: moles depositados = (corrente × tempo) / (n × F). Usada em galvanoplastia e produção de metais como Al.","pt_PT":"Utilização de energia elétrica para impulsionar uma reação redox não espontânea. Lei de Faraday: moles depositados = (corrente × tempo) / (n × F). Utilizada em galvanoplastia e produção de metais como Al."}},
  { id: 'dc-chemistry-0072', deck_id: 'deck-chemistry', sort_order: 72, front: "Alkane", back: "Saturated hydrocarbon with only C–C single bonds. General formula CₙH₂ₙ₊₂. Examples: methane (CH₄), ethane (C₂H₆). Low reactivity; primarily undergo combustion and halogenation." , front_translations: {"es":"Alcano","de":"Alkan","fr":"Alcane","tr":"Alkan","nl":"Alkaan","ru":"Алкан","zh":"烷烃","pt_BR":"Alcano","pt_PT":"Alcano"}, back_translations: {"es":"Hidrocarboneto saturado con solo enlaces simples C–C. Fórmula geral CₙH₂ₙ₊₂. Ejemplos: metano (CH₄), etano (C₂H₆). Baja reatividad; sofrem principalmente combustión y halogenación.","de":"Gesättigter Kohlenwasserstoff mit ausschließlich C–C-Einfachbindungen. Allgemeine Formel CₙH₂ₙ₊₂. Beispiele: Methan (CH₄), Ethan (C₂H₆). Geringe Reaktivität; hauptsächlich Verbrennung und Halogenierung.","fr":"Hydrocarbure saturé avec uniquement des liaisons simples C–C. Formule générale CₙH₂ₙ₊₂. Exemples : méthane (CH₄), éthane (C₂H₆). Faible réactivité ; subissent principalement la combustion et l'halogénation.","tr":"Yalnızca C–C tek bağları içeren doymuş hidrokarbon. Genel formül CₙH₂ₙ₊₂. Örnekler: metan (CH₄), etan (C₂H₆). Düşük reaktivite; öncelikle yanma ve halojenasyon reaksiyonları geçirir.","nl":"Verzadigde koolwaterstof met alleen C–C enkelvoudige bindingen. Algemene formule CₙH₂ₙ₊₂. Voorbeelden: methaan (CH₄), ethaan (C₂H₆). Lage reactiviteit; ondergaan voornamelijk verbranding en halogenering.","ru":"Насыщенный углеводород, содержащий только простые связи C–C. Общая формула CₙH₂ₙ₊₂. Примеры: метан (CH₄), этан (C₂H₆). Низкая реакционная способность; преимущественно горение и галогенирование.","zh":"只含C–C单键的饱和烃。通式CₙH₂ₙ₊₂。例如：甲烷（CH₄）、乙烷（C₂H₆）。反应性低；主要发生燃烧和卤代反应。","pt_BR":"Hidrocarboneto saturado com apenas ligações simples C–C. Fórmula geral CₙH₂ₙ₊₂. Exemplos: metano (CH₄), etano (C₂H₆). Baixa reatividade; sofrem principalmente combustão e halogenação.","pt_PT":"Hidrocarboneto saturado com apenas ligações simples C–C. Fórmula geral CₙH₂ₙ₊₂. Exemplos: metano (CH₄), etano (C₂H₆). Baixa reatividade; sofrem principalmente combustão e halogenação."}},
  { id: 'dc-chemistry-0073', deck_id: 'deck-chemistry', sort_order: 73, front: "Alkene", back: "Unsaturated hydrocarbon containing at least one C=C double bond. General formula CₙH₂ₙ. Undergo addition reactions (HX, H₂O, H₂, halogens). Ethylene (C₂H₄) is the simplest example." , front_translations: {"es":"Alceno","de":"Alken","fr":"Alcène","tr":"Alken","nl":"Alkeen","ru":"Алкен","zh":"烯烃","pt_BR":"Alceno","pt_PT":"Alceno"}, back_translations: {"es":"Hidrocarboneto insaturado conteniendo por el menos una enlace dupla C=C. Fórmula geral CₙH₂ₙ. Sofrem reacciones de adición (HX, H₂El, H₂, halogenios). Etileno (C₂H₄) es el ejemplo más simples.","de":"Ungesättigter Kohlenwasserstoff mit mindestens einer C=C-Doppelbindung. Allgemeine Formel CₙH₂ₙ. Undergo Additionsreaktionen (HX, H₂O, H₂, Halogene). Ethylen (C₂H₄) ist das einfachste Beispiel.","fr":"Hydrocarbure insaturé contenant au moins une double liaison C=C. Formule générale CₙH₂ₙ. Subissent des réactions d'addition (HX, H₂O, H₂, halogènes). L'éthylène (C₂H₄) est l'exemple le plus simple.","tr":"En az bir C=C çift bağı içeren doymamış hidrokarbon. Genel formül CₙH₂ₙ. Katılma reaksiyonları geçirir (HX, H₂O, H₂, halojenler). Etilen (C₂H₄) en basit örnektir.","nl":"Onverzadigde koolwaterstof met minstens één C=C-dubbele binding. Algemene formule CₙH₂ₙ. Ondergaan additiereacties (HX, H₂O, H₂, halogenen). Ethyleen (C₂H₄) is het eenvoudigste voorbeeld.","ru":"Ненасыщенный углеводород с по меньшей мере одной двойной связью C=C. Общая формула CₙH₂ₙ. Вступают в реакции присоединения (HX, H₂O, H₂, галогены). Этилен (C₂H₄) — простейший пример.","zh":"含有至少一个C=C双键的不饱和烃。通式CₙH₂ₙ。发生加成反应（HX、H₂O、H₂、卤素）。乙烯（C₂H₄）是最简单的例子。","pt_BR":"Hidrocarboneto insaturado contendo pelo menos uma ligação dupla C=C. Fórmula geral CₙH₂ₙ. Sofrem reações de adição (HX, H₂O, H₂, halogênios). Etileno (C₂H₄) é o exemplo mais simples.","pt_PT":"Hidrocarboneto insaturado contendo pelo menos uma ligação dupla C=C. Fórmula geral CₙH₂ₙ. Sofrem reações de adição (HX, H₂O, H₂, halogénios). Etileno (C₂H₄) é o exemplo mais simples."}},
  { id: 'dc-chemistry-0074', deck_id: 'deck-chemistry', sort_order: 74, front: "Alkyne", back: "Hydrocarbon with at least one C≡C triple bond. General formula CₙH₂ₙ₋₂. More reactive than alkenes; undergo addition reactions. Acetylene (C₂H₂) is used in welding." , front_translations: {"es":"Alcino","de":"Alkin","fr":"Alcyne","tr":"Alkin","nl":"Alkyn","ru":"Алкин","zh":"炔烃","pt_BR":"Alcino","pt_PT":"Alcino"}, back_translations: {"es":"Hidrocarboneto con por el menos una enlace tripla C≡C. Fórmula geral CₙH₂ₙ₋₂. Más reativo que alcenos; sofrem reacciones de adición. Acetileno (C₂H₂) es usado en soldaje.","de":"Kohlenwasserstoff mit mindestens einer C≡C-Dreifachbindung. Allgemeine Formel CₙH₂ₙ₋₂. Reaktiver als Alkene; Additionsreaktionen. Acetylen (C₂H₂) wird beim Schweißen verwendet.","fr":"Hydrocarbure avec au moins une triple liaison C≡C. Formule générale CₙH₂ₙ₋₂. Plus réactif que les alcènes ; subit des réactions d'addition. L'acétylène (C₂H₂) est utilisé pour le soudage.","tr":"En az bir C≡C üçlü bağı içeren hidrokarbon. Genel formül CₙH₂ₙ₋₂. Alkenlerden daha reaktif; katılma reaksiyonları geçirir. Asetilen (C₂H₂) kaynakta kullanılır.","nl":"Koolwaterstof met minstens één C≡C-drievoudige binding. Algemene formule CₙH₂ₙ₋₂. Reactiever dan alkenen; ondergaan additiereacties. Acetyleen (C₂H₂) wordt gebruikt bij lassen.","ru":"Углеводород с по меньшей мере одной тройной связью C≡C. Общая формула CₙH₂ₙ₋₂. Более реакционноспособен, чем алкены; реакции присоединения. Ацетилен (C₂H₂) применяется при сварке.","zh":"含有至少一个C≡C三键的烃。通式CₙH₂ₙ₋₂。比烯烃更活泼；发生加成反应。乙炔（C₂H₂）用于焊接。","pt_BR":"Hidrocarboneto com pelo menos uma ligação tripla C≡C. Fórmula geral CₙH₂ₙ₋₂. Mais reativo que alcenos; sofrem reações de adição. Acetileno (C₂H₂) é usado em soldagem.","pt_PT":"Hidrocarboneto com pelo menos uma ligação tripla C≡C. Fórmula geral CₙH₂ₙ₋₂. Mais reativo que alcenos; sofrem reações de adição. Acetileno (C₂H₂) é usado em soldadura."}},
  { id: 'dc-chemistry-0075', deck_id: 'deck-chemistry', sort_order: 75, front: "Aromatic Compounds (Benzene)", back: "Benzene (C₆H₆) has a ring of 6 carbons with delocalized π electrons. Aromatic compounds are unusually stable. Undergo electrophilic aromatic substitution rather than addition." , front_translations: {"es":"Compuestos aromáticos (Benzeno)","de":"Aromatische Verbindungen (Benzol)","fr":"Composés aromatiques (Benzène)","tr":"Aromatik Bileşikler (Benzen)","nl":"Aromatische verbindingen (Benzeen)","ru":"Ароматические соединения (Бензол)","zh":"芳香族化合物（苯）","pt_BR":"Compostos aromáticos (Benzeno)","pt_PT":"Compostos aromáticos (Benzeno)"}, back_translations: {"es":"El benzeno (C₆H₆) tiene un anel de 6 carbonos con electrones π deslocalizados. Los compuestos aromáticos son excepcionalmente estables. Sofrem substituición aromática eletrofílica en vez de adición.","de":"Benzol (C₆H₆) hat einen Ring aus 6 Kohlenstoffen mit delokalisierten π-Elektronen. Aromatische Verbindungen sind ungewöhnlich stabil. Sie bevorzugen elektrophile aromatische Substitution statt Addition.","fr":"Le benzène (C₆H₆) possède un cycle de 6 carbones avec des électrons π délocalisés. Les composés aromatiques sont inhabituellement stables. Ils subissent une substitution aromatique électrophile plutôt qu'une addition.","tr":"Benzen (C₆H₆), delokalize π elektronu olan 6 karbonlu bir halkaya sahiptir. Aromatik bileşikler alışılmadık biçimde kararlıdır. Katılma yerine elektrofilik aromatik sübstitüsyon geçirirler.","nl":"Benzeen (C₆H₆) heeft een ring van 6 koolstofatomen met gedelokaliseerde π-elektronen. Aromatische verbindingen zijn ongewoon stabiel. Ze ondergaan elektrofiele aromatische substitutie in plaats van additie.","ru":"Бензол (C₆H₆) имеет кольцо из 6 атомов углерода с делокализованными π-электронами. Ароматические соединения необычно стабильны. Они предпочтительно вступают в реакции электрофильного ароматического замещения, а не присоединения.","zh":"苯（C₆H₆）具有6个碳组成的环，含有离域π电子。芳香族化合物异常稳定。它们发生亲电芳香取代反应而非加成反应。","pt_BR":"O benzeno (C₆H₆) tem um anel de 6 carbonos com elétrons π deslocalizados. Os compostos aromáticos são excepcionalmente estáveis. Sofrem substituição aromática eletrofílica em vez de adição.","pt_PT":"O benzeno (C₆H₆) tem um anel de 6 carbonos com eletrões π deslocalizados. Os compostos aromáticos são excecionalmente estáveis. Sofrem substituição aromática eletrofílica em vez de adição."}},
  { id: 'dc-chemistry-0076', deck_id: 'deck-chemistry', sort_order: 76, front: "Functional Group: Hydroxyl (-OH)", back: "The –OH group defines alcohols. Makes molecules polar and capable of hydrogen bonding, raising boiling points. Primary, secondary, and tertiary alcohols have different reactivity." , front_translations: {"es":"Grupo Funcional: Hidroxila (-OH)","de":"Funktionelle Gruppe: Hydroxyl (-OH)","fr":"Groupe fonctionnel : Hydroxyle (-OH)","tr":"Fonksiyonel Grup: Hidroksil (-OH)","nl":"Functionele groep: Hydroxyl (-OH)","ru":"Функциональная группа: Гидроксил (-OH)","zh":"官能团：羟基（-OH）","pt_BR":"Grupo Funcional: Hidroxila (-OH)","pt_PT":"Grupo Funcional: Hidroxilo (-OH)"}, back_translations: {"es":"El grupo –OH define los álcoois. Torna las moléculas polares y capazes de formar enlaces de hidrógeno, elevando los puntos de ebullición. Álcoois primários, secundários y terciários tienen reatividades diferentes.","de":"Die –OH-Gruppe definiert Alkohole. Macht Moleküle polar und ermöglicht Wasserstoffbrückenbindungen, was die Siedepunkte erhöht. Primäre, sekundäre und tertiäre Alkohole haben unterschiedliche Reaktivität.","fr":"Le groupe –OH définit les alcools. Rend les molécules polaires et capables de liaisons hydrogène, ce qui élève les points d'ébullition. Les alcools primaires, secondaires et tertiaires ont des réactivités différentes.","tr":"–OH grubu alkolleri tanımlar. Molekülleri polar yapar ve hidrojen bağı oluşturabilir; bu da kaynama noktalarını yükseltir. Birincil, ikincil ve üçüncül alkollerin reaktiviteleri farklıdır.","nl":"De –OH-groep definieert alcoholen. Maakt moleculen polair en in staat tot waterstofbruggen, waardoor de kookpunten stijgen. Primaire, secundaire en tertiaire alcoholen hebben verschillende reactiviteit.","ru":"Группа –OH определяет спирты. Делает молекулы полярными и способными к водородным связям, повышая температуры кипения. Первичные, вторичные и третичные спирты имеют разную реакционную способность.","zh":"–OH基团定义了醇类。使分子具有极性并能形成氢键，从而升高沸点。伯醇、仲醇和叔醇具有不同的反应活性。","pt_BR":"O grupo –OH define os álcoois. Torna as moléculas polares e capazes de formar ligações de hidrogênio, elevando os pontos de ebulição. Álcoois primários, secundários e terciários têm reatividades diferentes.","pt_PT":"O grupo –OH define os álcoois. Torna as moléculas polares e capazes de formar ligações de hidrogénio, elevando os pontos de ebulição. Álcoois primários, secundários e terciários têm reatividades diferentes."}},
  { id: 'dc-chemistry-0077', deck_id: 'deck-chemistry', sort_order: 77, front: "Functional Group: Carbonyl (C=O)", back: "A carbon-oxygen double bond. Present in aldehydes (R-CHO), ketones (R-CO-R'), carboxylic acids (R-COOH), esters (R-COO-R'), and amides (R-CO-NH₂). Central to biochemistry." , front_translations: {"es":"Grupo Funcional: Carbonila (C=El)","de":"Funktionelle Gruppe: Carbonyl (C=O)","fr":"Groupe fonctionnel : Carbonyle (C=O)","tr":"Fonksiyonel Grup: Karbonil (C=O)","nl":"Functionele groep: Carbonyl (C=O)","ru":"Функциональная группа: Карбонил (C=O)","zh":"官能团：羰基（C=O）","pt_BR":"Grupo Funcional: Carbonila (C=O)","pt_PT":"Grupo Funcional: Carbonilo (C=O)"}, back_translations: {"es":"Una enlace dupla carbono-oxígeno. Presente en aldeídos (R-CHO), cetonas (R-CO-R'), ácidos carboxílicos (R-COOH), ésteres (R-COO-R') y amidas (R-CO-NH₂). Central en la bioquímica.","de":"Eine Kohlenstoff-Sauerstoff-Doppelbindung. Vorhanden in Aldehyden (R-CHO), Ketonen (R-CO-R'), Carbonsäuren (R-COOH), Estern (R-COO-R') und Amiden (R-CO-NH₂). Zentral in der Biochemie.","fr":"Une double liaison carbone-oxygène. Présente dans les aldéhydes (R-CHO), les cétones (R-CO-R'), les acides carboxyliques (R-COOH), les esters (R-COO-R') et les amides (R-CO-NH₂). Centrale en biochimie.","tr":"Bir karbon-oksijen çift bağı. Aldehitlerde (R-CHO), ketonlarda (R-CO-R'), karboksilik asitlerde (R-COOH), esterlerde (R-COO-R') ve amitlerde (R-CO-NH₂) bulunur. Biyokimyada merkezi öneme sahiptir.","nl":"Een koolstof-zuurstof-dubbele binding. Aanwezig in aldehyden (R-CHO), ketonen (R-CO-R'), carbonzuren (R-COOH), esters (R-COO-R') en amiden (R-CO-NH₂). Centraal in de biochemie.","ru":"Двойная связь углерод-кислород. Присутствует в альдегидах (R-CHO), кетонах (R-CO-R'), карбоновых кислотах (R-COOH), эфирах (R-COO-R') и амидах (R-CO-NH₂). Центральная в биохимии.","zh":"碳氧双键。存在于醛（R-CHO）、酮（R-CO-R'）、羧酸（R-COOH）、酯（R-COO-R'）和酰胺（R-CO-NH₂）中。在生物化学中处于核心地位。","pt_BR":"Uma ligação dupla carbono-oxigênio. Presente em aldeídos (R-CHO), cetonas (R-CO-R'), ácidos carboxílicos (R-COOH), ésteres (R-COO-R') e amidas (R-CO-NH₂). Central na bioquímica.","pt_PT":"Uma ligação dupla carbono-oxigénio. Presente em aldeídos (R-CHO), cetonas (R-CO-R'), ácidos carboxílicos (R-COOH), ésteres (R-COO-R') e amidas (R-CO-NH₂). Central na bioquímica."}},
  { id: 'dc-chemistry-0078', deck_id: 'deck-chemistry', sort_order: 78, front: "Functional Group: Amine (-NH₂)", back: "An –NH₂ group attached to a carbon. Amines are weak bases. Primary amines react with carboxylic acids to form amide bonds. Essential in amino acids and nucleotides." , front_translations: {"es":"Grupo Funcional: Amina (-NH₂)","de":"Funktionelle Gruppe: Amin (-NH₂)","fr":"Groupe fonctionnel : Amine (-NH₂)","tr":"Fonksiyonel Grup: Amin (-NH₂)","nl":"Functionele groep: Amine (-NH₂)","ru":"Функциональная группа: Амин (-NH₂)","zh":"官能团：氨基（-NH₂）","pt_BR":"Grupo Funcional: Amina (-NH₂)","pt_PT":"Grupo Funcional: Amina (-NH₂)"}, back_translations: {"es":"Un grupo –NH₂ ligado a un carbono. Aminas son bases débiles. Aminas primárias reaje con ácidos carboxílicos para formar enlaces amida. Esenciales en los aminoácidos y nucleotídeos.","de":"Eine –NH₂-Gruppe, die an einen Kohlenstoff gebunden ist. Amine sind schwache Basen. Primäre Amine reagieren mit Carbonsäuren unter Bildung von Amidbindungen. Essenziell in Aminosäuren und Nukleotiden.","fr":"Un groupe –NH₂ attaché à un carbone. Les amines sont des bases faibles. Les amines primaires réagissent avec les acides carboxyliques pour former des liaisons amide. Essentielles dans les acides aminés et les nucléotides.","tr":"Bir karbona bağlı –NH₂ grubu. Aminler zayıf bazlardır. Birincil aminler karboksilik asitlerle reaksiyona girerek amid bağları oluşturur. Amino asitler ve nükleotitlerde hayati öneme sahiptir.","nl":"Een –NH₂-groep gehecht aan een koolstof. Aminen zijn zwakke basen. Primaire aminen reageren met carbonzuren tot amidebindingen. Essentieel in aminozuren en nucleotiden.","ru":"Группа –NH₂, присоединённая к углероду. Амины — слабые основания. Первичные амины реагируют с карбоновыми кислотами с образованием амидных связей. Необходимы в аминокислотах и нуклеотидах.","zh":"连接在碳上的–NH₂基团。胺是弱碱。伯胺与羧酸反应形成酰胺键。在氨基酸和核苷酸中至关重要。","pt_BR":"Um grupo –NH₂ ligado a um carbono. Aminas são bases fracas. Aminas primárias reagem com ácidos carboxílicos para formar ligações amida. Essenciais nos aminoácidos e nucleotídeos.","pt_PT":"Um grupo –NH₂ ligado a um carbono. As aminas são bases fracas. As aminas primárias reagem com ácidos carboxílicos para formar ligações amida. Essenciais nos aminoácidos e nucleótidos."}},
  { id: 'dc-chemistry-0079', deck_id: 'deck-chemistry', sort_order: 79, front: "Esterification", back: "The reaction of a carboxylic acid with an alcohol to form an ester and water: RCOOH + R'OH ⇌ RCOOR' + H₂O. Acid-catalyzed, reversible. Esters have pleasant fruity odors." , front_translations: {"es":"Esterificación","de":"Veresterung","fr":"Estérification","tr":"Esterleşme","nl":"Verestering","ru":"Этерификация","zh":"酯化反应","pt_BR":"Esterificação","pt_PT":"Esterificação"}, back_translations: {"es":"La reacción de un ácido carboxílico con un álcool para formar un éster y agua: RCOOH + R'OH ⇌ RCOOR' + H₂El. Catalisada por ácido, reversible. Los ésteres tienen odores frutados agradables.","de":"Die Reaktion einer Carbonsäure mit einem Alkohol unter Bildung eines Esters und Wasser: RCOOH + R'OH ⇌ RCOOR' + H₂O. Säurekatalysiert, reversibel. Ester haben angenehme fruchtige Gerüche.","fr":"La réaction d'un acide carboxylique avec un alcool pour former un ester et de l'eau : RCOOH + R'OH ⇌ RCOOR' + H₂O. Catalysée par un acide, réversible. Les esters ont des odeurs fruitées agréables.","tr":"Bir karboksilik asidin bir alkolle reaksiyona girerek ester ve su oluşturması: RCOOH + R'OH ⇌ RCOOR' + H₂O. Asit katalizi ile gerçekleşir, tersinirdir. Esterlerin hoş meyve kokuları vardır.","nl":"De reactie van een carbonzuur met een alcohol tot een ester en water: RCOOH + R'OH ⇌ RCOOR' + H₂O. Zuurkatalytisch, reversibel. Esters hebben aangename fruitige geuren.","ru":"Реакция карбоновой кислоты со спиртом с образованием эфира и воды: RCOOH + R'OH ⇌ RCOOR' + H₂O. Кислотный катализ, обратимая реакция. Эфиры имеют приятный фруктовый запах.","zh":"羧酸与醇反应生成酯和水：RCOOH + R'OH ⇌ RCOOR' + H₂O。酸催化，可逆反应。酯具有令人愉悦的果香气味。","pt_BR":"A reação de um ácido carboxílico com um álcool para formar um éster e água: RCOOH + R'OH ⇌ RCOOR' + H₂O. Catalisada por ácido, reversível. Os ésteres têm odores frutados agradáveis.","pt_PT":"A reação de um ácido carboxílico com um álcool para formar um éster e água: RCOOH + R'OH ⇌ RCOOR' + H₂O. Catalisada por ácido, reversível. Os ésteres têm odores frutados agradáveis."}},
  { id: 'dc-chemistry-0080', deck_id: 'deck-chemistry', sort_order: 80, front: "Saponification", back: "The base-catalyzed hydrolysis of an ester to give an alcohol and a carboxylate salt. Industrially used to make soap from animal fats (triglycerides) and NaOH." , front_translations: {"es":"Saponificación","de":"Verseifung","fr":"Saponification","tr":"Sabunlaşma","nl":"Verzeping","ru":"Омыление","zh":"皂化反应","pt_BR":"Saponificação","pt_PT":"Saponificação"}, back_translations: {"es":"La hidrólise alcalina de un éster para produzir un álcool y un sal de carboxilato. Usada industrialmente para fabricar sabão a partir de gorduras animales (triglicerídeos) y NaOH.","de":"Die basenkatalysierte Hydrolyse eines Esters zu einem Alkohol und einem Carboxylatsalz. Industriell zur Herstellung von Seife aus tierischen Fetten (Triglyceriden) und NaOH verwendet.","fr":"L'hydrolyse basique d'un ester pour donner un alcool et un sel de carboxylate. Utilisée industriellement pour fabriquer du savon à partir de graisses animales (triglycérides) et de NaOH.","tr":"Bir esterin baz katalizli hidrolizi sonucu alkol ve karboksilat tuzu oluşması. Endüstriyel olarak hayvan yağlarından (trigliseritler) ve NaOH'tan sabun üretmek için kullanılır.","nl":"De basegekatalyseerde hydrolyse van een ester tot een alcohol en een carboxylaatzout. Industrieel gebruikt om zeep te maken van dierlijke vetten (triglyceriden) en NaOH.","ru":"Щелочной гидролиз эфира с образованием спирта и карбоксилатной соли. Промышленно используется для производства мыла из животных жиров (триглицеридов) и NaOH.","zh":"酯的碱催化水解，生成醇和羧酸盐。工业上用于将动物脂肪（甘油三酯）与NaOH反应制造肥皂。","pt_BR":"A hidrólise alcalina de um éster para produzir um álcool e um sal de carboxilato. Usada industrialmente para fabricar sabão a partir de gorduras animais (triglicerídeos) e NaOH.","pt_PT":"A hidrólise básica de um éster para produzir um álcool e um sal de carboxilato. Usada industrialmente para fabricar sabão a partir de gorduras animais (triglicéridos) e NaOH."}},
  { id: 'dc-chemistry-0081', deck_id: 'deck-chemistry', sort_order: 81, front: "Addition Polymer", back: "Formed by the repeated addition of monomer units containing a double bond, without any byproduct. E.g., polyethylene from ethylene (CH₂=CH₂). The backbone is entirely carbon." , front_translations: {"es":"Polímero de Adición","de":"Additionspolymer","fr":"Polymère d'addition","tr":"Katılma Polimeri","nl":"Additiepolymeer","ru":"Полимер присоединения","zh":"加聚物","pt_BR":"Polímero de Adição","pt_PT":"Polímero de Adição"}, back_translations: {"es":"Formado por la adición repetida de unidades de monomero conteniendo una enlace dupla, sin subprodutos. Ex.: polietileno a partir del etileno (CH₂=CH₂). La cadeia principal es inteiramente de carbono.","de":"Gebildet durch wiederholte Addition von Monomereinheiten mit einer Doppelbindung, ohne Nebenprodukte. Z. B. Polyethylen aus Ethylen (CH₂=CH₂). Das Rückgrat besteht ausschließlich aus Kohlenstoff.","fr":"Formé par l'addition répétée d'unités monomères contenant une double liaison, sans sous-produit. P. ex., le polyéthylène à partir de l'éthylène (CH₂=CH₂). La chaîne principale est entièrement carbonée.","tr":"Çift bağ içeren monomer birimlerinin yan ürün oluşturmadan tekrarlı katılmasıyla oluşur. Örn. etilenden (CH₂=CH₂) polietilen. Ana zincir tamamen karbondan oluşur.","nl":"Gevormd door herhaalde additie van monomere eenheden met een dubbele binding, zonder bijproduct. Bijv. polyethyleen uit ethyleen (CH₂=CH₂). De ruggengraat bestaat volledig uit koolstof.","ru":"Образуется в результате многократного присоединения мономерных звеньев с двойной связью без побочных продуктов. Напр., полиэтилен из этилена (CH₂=CH₂). Основная цепь состоит полностью из углерода.","zh":"由含双键的单体单元反复加成形成，无副产物。例如乙烯（CH₂=CH₂）聚合成聚乙烯。主链完全由碳组成。","pt_BR":"Formado pela adição repetida de unidades de monômero contendo uma ligação dupla, sem subprodutos. Ex.: polietileno a partir do etileno (CH₂=CH₂). A cadeia principal é inteiramente de carbono.","pt_PT":"Formado pela adição repetida de unidades de monómero contendo uma ligação dupla, sem subprodutos. Ex.: polietileno a partir do etileno (CH₂=CH₂). A cadeia principal é inteiramente de carbono."}},
  { id: 'dc-chemistry-0082', deck_id: 'deck-chemistry', sort_order: 82, front: "Condensation Polymer", back: "Formed by the reaction of two different monomer types with elimination of a small molecule (often H₂O) at each junction. E.g., nylon (polyamide), polyester, protein." , front_translations: {"es":"Polímero de Condensación","de":"Kondensationspolymer","fr":"Polymère de condensation","tr":"Kondenzasyon Polimeri","nl":"Condensatiepolymeer","ru":"Конденсационный полимер","zh":"缩聚物","pt_BR":"Polímero de Condensação","pt_PT":"Polímero de Condensação"}, back_translations: {"es":"Formado por la reacción de de los tipos diferentes de monomeros con eliminación de una pequeña molécula (generalmente H₂El) en cada junción. Ex.: nylon (poliamida), poliéster, proteína.","de":"Gebildet durch die Reaktion zweier verschiedener Monomertypen unter Abspaltung eines kleinen Moleküls (oft H₂O) an jeder Verknüpfungsstelle. Z. B. Nylon (Polyamid), Polyester, Protein.","fr":"Formé par la réaction de deux types de monomères différents avec élimination d'une petite molécule (souvent H₂O) à chaque jonction. P. ex., le nylon (polyamide), le polyester, les protéines.","tr":"İki farklı monomer türünün her bağlantı noktasında küçük bir molekül (genellikle H₂O) elimine ederek reaksiyona girmesiyle oluşur. Örn. naylon (poliamit), polyester, protein.","nl":"Gevormd door de reactie van twee verschillende monomeertypes met eliminatie van een klein molecuul (vaak H₂O) bij elke verbinding. Bijv. nylon (polyamide), polyester, eiwit.","ru":"Образуется при реакции двух разных типов мономеров с выделением небольшой молекулы (часто H₂O) в каждом узле. Напр., нейлон (полиамид), полиэстер, белок.","zh":"由两种不同单体在每个连接处消除小分子（通常是H₂O）反应形成。例如尼龙（聚酰胺）、聚酯、蛋白质。","pt_BR":"Formado pela reação de dois tipos diferentes de monômeros com eliminação de uma pequena molécula (geralmente H₂O) em cada junção. Ex.: nylon (poliamida), poliéster, proteína.","pt_PT":"Formado pela reação de dois tipos diferentes de monómeros com eliminação de uma pequena molécula (geralmente H₂O) em cada junção. Ex.: nylon (poliamida), poliéster, proteína."}},
  { id: 'dc-chemistry-0083', deck_id: 'deck-chemistry', sort_order: 83, front: "Isomers", back: "Compounds with the same molecular formula but different structural arrangements. Structural isomers differ in connectivity; stereoisomers differ in spatial arrangement of atoms." , front_translations: {"es":"Isomeros","de":"Isomere","fr":"Isomères","tr":"İzomerler","nl":"Isomeren","ru":"Изомеры","zh":"同分异构体","pt_BR":"Isômeros","pt_PT":"Isómeros"}, back_translations: {"es":"Compuestos con a misma fórmula molecular, pero diferentes arranjos estruturais. Isomeros estruturais diferem en la conectividad; estereoisomeros diferem en el arranjo espacial de los átomos.","de":"Verbindungen mit gleicher Molekülformel, aber unterschiedlicher Struktur. Konstitutionsisomere unterscheiden sich in der Verknüpfung; Stereoisomere in der räumlichen Anordnung der Atome.","fr":"Composés ayant la même formule moléculaire mais des arrangements structuraux différents. Les isomères de constitution diffèrent par leur connectivité ; les stéréoisomères diffèrent par l'arrangement spatial des atomes.","tr":"Aynı molekül formülüne sahip ancak farklı yapısal düzenlemeleri olan bileşikler. Yapısal izomerler bağlanma sırasında farklılaşır; stereoisomerler atomların uzaysal düzenlemesinde farklılaşır.","nl":"Verbindingen met dezelfde molecuulformule maar verschillende structurele rangschikkingen. Structuurisomeren verschillen in connectiviteit; stereoisomeren in de ruimtelijke rangschikking van atomen.","ru":"Соединения с одинаковой молекулярной формулой, но разным структурным строением. Структурные изомеры отличаются по связности; стереоизомеры — по пространственному расположению атомов.","zh":"具有相同分子式但不同结构排列的化合物。结构异构体在连接方式上不同；立体异构体在原子的空间排列上不同。","pt_BR":"Compostos com a mesma fórmula molecular, mas diferentes arranjos estruturais. Isômeros estruturais diferem na conectividade; estereoisômeros diferem no arranjo espacial dos átomos.","pt_PT":"Compostos com a mesma fórmula molecular, mas diferentes arranjos estruturais. Isómeros estruturais diferem na conectividade; estereoisómeros diferem no arranjo espacial dos átomos."}},
  { id: 'dc-chemistry-0084', deck_id: 'deck-chemistry', sort_order: 84, front: "Enantiomers", back: "Non-superimposable mirror-image stereoisomers (chiral molecules). Differ in rotating plane-polarized light (+/– optical activity). Biologically important: one enantiomer of a drug may be active, the other inactive or harmful." , front_translations: {"es":"Enantiomeros","de":"Enantiomere","fr":"Énantiomères","tr":"Enantiyomerler","nl":"Enantiomeren","ru":"Энантиомеры","zh":"对映体","pt_BR":"Enantiômeros","pt_PT":"Enantiómeros"}, back_translations: {"es":"Estereoisomeros de imaje especular no superponibles (moléculas quirais). Diferem en la rotación de la luz plano-polarizada (+/– atividad óptica). Biologicamente importantes: un enantiomero de un fármaco puede ser ativo, el outro inativo o prejudicial.","de":"Nicht-überlagerbare Spiegelbildstereoisomere (chirale Moleküle). Unterscheiden sich darin, dass sie linear polarisiertes Licht drehen (+/– optische Aktivität). Biologisch wichtig: ein Enantiomer eines Wirkstoffs kann aktiv sein, das andere inaktiv oder schädlich.","fr":"Stéréoisomères non superposables en images miroir (molécules chirales). Diffèrent par la rotation de la lumière polarisée (+/– activité optique). Biologiquement importants : un énantiomère d'un médicament peut être actif, l'autre inactif ou nocif.","tr":"Üst üste getirilemeyen ayna görüntüsü stereoisomerleri (kiral moleküller). Düzlem polarize ışığı döndürme bakımından farklıdırlar (+/– optik aktivite). Biyolojik olarak önemlidir: bir ilacın bir enantiyomeri aktif, diğeri inaktif veya zararlı olabilir.","nl":"Niet-superimponeerbare spiegelbeeldstereoisomeren (chirale moleculen). Verschillen in het roteren van vlak-gepolariseerd licht (+/– optische activiteit). Biologisch belangrijk: één enantiomeer van een medicijn kan actief zijn, het andere inactief of schadelijk.","ru":"Несовместимые зеркальные стереоизомеры (хиральные молекулы). Отличаются по вращению плоскополяризованного света (+/– оптическая активность). Биологически важны: один энантиомер лекарства может быть активным, другой — неактивным или вредным.","zh":"不可叠加的镜像立体异构体（手性分子）。在旋转平面偏振光方面不同（+/–旋光性）。在生物学上很重要：药物的一种对映体可能有活性，另一种可能无活性或有害。","pt_BR":"Estereoisômeros de imagem especular não superponíveis (moléculas quirais). Diferem na rotação da luz plano-polarizada (+/– atividade óptica). Biologicamente importantes: um enantiômero de um fármaco pode ser ativo, o outro inativo ou prejudicial.","pt_PT":"Estereoisómeros de imagem especular não sobreponíveis (moléculas quirais). Diferem na rotação da luz plano-polarizada (+/– atividade ótica). Biologicamente importantes: um enantiómero de um fármaco pode ser ativo, o outro inativo ou prejudicial."}},
  { id: 'dc-chemistry-0085', deck_id: 'deck-chemistry', sort_order: 85, front: "Periodic Table: Periods and Groups", back: "Elements are arranged in 18 groups (columns) and 7 periods (rows). Properties repeat periodically (Mendeleev's periodic law). Groups have similar electron configurations and chemical behavior." , front_translations: {"es":"Tabela Periódica: Períodos y Grupos","de":"Periodensystem: Perioden und Gruppen","fr":"Tableau périodique : Périodes et groupes","tr":"Periyodik Tablo: Periyotlar ve Gruplar","nl":"Periodiek systeem: Perioden en groepen","ru":"Периодическая таблица: Периоды и группы","zh":"元素周期表：周期和族","pt_BR":"Tabela Periódica: Períodos e Grupos","pt_PT":"Tabela Periódica: Períodos e Grupos"}, back_translations: {"es":"Los elementos son dispostos en 18 grupos (colunas) y 7 períodos (líneas). As propiedades se repetem periodicamente (ley periódica de Mendeleev). Los grupos tienen configuraciones eletronicas y comportamientos químicos semelhantes.","de":"Elemente sind in 18 Gruppen (Spalten) und 7 Perioden (Zeilen) angeordnet. Eigenschaften wiederholen sich periodisch (Mendeleevs Periodengesetz). Gruppen haben ähnliche Elektronenkonfigurationen und chemisches Verhalten.","fr":"Les éléments sont disposés en 18 groupes (colonnes) et 7 périodes (lignes). Les propriétés se répètent périodiquement (loi périodique de Mendeleïev). Les groupes ont des configurations électroniques et des comportements chimiques similaires.","tr":"Elementler 18 grup (sütun) ve 7 periyotta (satır) düzenlenmiştir. Özellikler periyodik olarak tekrarlanır (Mendeleev'in periyodik yasası). Gruplar benzer elektron konfigürasyonlarına ve kimyasal davranışlara sahiptir.","nl":"Elementen zijn gerangschikt in 18 groepen (kolommen) en 7 perioden (rijen). Eigenschappen herhalen zich periodiek (periodieke wet van Mendelejev). Groepen hebben vergelijkbare elektronenconfiguraties en chemisch gedrag.","ru":"Элементы расположены в 18 группах (столбцах) и 7 периодах (строках). Свойства периодически повторяются (периодический закон Менделеева). Группы имеют схожие электронные конфигурации и химическое поведение.","zh":"元素排列在18个族（列）和7个周期（行）中。性质呈周期性重复（门捷列夫周期律）。同族元素具有相似的电子构型和化学行为。","pt_BR":"Os elementos são dispostos em 18 grupos (colunas) e 7 períodos (linhas). As propriedades se repetem periodicamente (lei periódica de Mendeleev). Os grupos têm configurações eletrônicas e comportamentos químicos semelhantes.","pt_PT":"Os elementos estão dispostos em 18 grupos (colunas) e 7 períodos (linhas). As propriedades repetem-se periodicamente (lei periódica de Mendeleev). Os grupos têm configurações eletrónicas e comportamentos químicos semelhantes."}},
  { id: 'dc-chemistry-0086', deck_id: 'deck-chemistry', sort_order: 86, front: "Alkali Metals (Group 1)", back: "Li, Na, K, Rb, Cs, Fr. One valence electron; very reactive. React violently with water producing H₂ and a metal hydroxide. Reactivity increases down the group." , front_translations: {"es":"Metais Alcalinos (Grupo 1)","de":"Alkalimetalle (Gruppe 1)","fr":"Métaux alcalins (groupe 1)","tr":"Alkali Metaller (Grup 1)","nl":"Alkalimetalen (groep 1)","ru":"Щелочные металлы (группа 1)","zh":"碱金属（第1族）","pt_BR":"Metais Alcalinos (Grupo 1)","pt_PT":"Metais Alcalinos (Grupo 1)"}, back_translations: {"es":"Li, Na, K, Rb, Cs, Fr. Un electrón de valencia; muy reativos. Reaje violentamente con a agua, produciendo H₂ y un hidróxido metálico. La reatividad aumenta a lo ancho del grupo.","de":"Li, Na, K, Rb, Cs, Fr. Ein Valenzelektron; sehr reaktiv. Reagieren heftig mit Wasser unter Bildung von H₂ und einem Metallhydroxid. Reaktivität nimmt in der Gruppe zu.","fr":"Li, Na, K, Rb, Cs, Fr. Un électron de valence ; très réactifs. Réagissent violemment avec l'eau en produisant H₂ et un hydroxyde métallique. La réactivité augmente dans le groupe.","tr":"Li, Na, K, Rb, Cs, Fr. Bir değerlik elektronu; çok reaktif. Su ile şiddetli reaksiyon vererek H₂ ve metal hidroksit oluşturur. Reaktivite grup boyunca aşağıya doğru artar.","nl":"Li, Na, K, Rb, Cs, Fr. Één valentie-elektron; zeer reactief. Reageren heftig met water en produceren H₂ en een metaalhydroxide. Reactiviteit neemt toe in de groep.","ru":"Li, Na, K, Rb, Cs, Fr. Один валентный электрон; очень реакционноспособны. Бурно реагируют с водой, образуя H₂ и гидроксид металла. Реакционная способность возрастает в группе.","zh":"Li、Na、K、Rb、Cs、Fr。一个价电子；非常活泼。与水剧烈反应，生成H₂和金属氢氧化物。反应活性在族中从上到下依次增强。","pt_BR":"Li, Na, K, Rb, Cs, Fr. Um elétron de valência; muito reativos. Reagem violentamente com a água, produzindo H₂ e um hidróxido metálico. A reatividade aumenta ao longo do grupo.","pt_PT":"Li, Na, K, Rb, Cs, Fr. Um eletrão de valência; muito reativos. Reagem violentamente com a água, produzindo H₂ e um hidróxido metálico. A reatividade aumenta ao longo do grupo."}},
  { id: 'dc-chemistry-0087', deck_id: 'deck-chemistry', sort_order: 87, front: "Alkaline Earth Metals (Group 2)", back: "Be, Mg, Ca, Sr, Ba, Ra. Two valence electrons. Less reactive than alkali metals. Ca²⁺ and Mg²⁺ are biologically essential. CaCO₃ (limestone) and MgSO₄ (Epsom salt) are common compounds." , front_translations: {"es":"Metais Alcalino-terrosos (Grupo 2)","de":"Erdalkalimetalle (Gruppe 2)","fr":"Métaux alcalino-terreux (groupe 2)","tr":"Toprak Alkali Metaller (Grup 2)","nl":"Aardalkalimetalen (groep 2)","ru":"Щёлочноземельные металлы (группа 2)","zh":"碱土金属（第2族）","pt_BR":"Metais Alcalino-terrosos (Grupo 2)","pt_PT":"Metais Alcalino-terrosos (Grupo 2)"}, back_translations: {"es":"Be, Mg, Ca, Sr, Ba, Ra. Dos electrones de valencia. Menos reativos que los metais alcalinos. Ca²⁺ y Mg²⁺ son biologicamente esenciales. CaCO₃ (calcário) y MgSO₄ (sal de Epsom) son compuestos comuns.","de":"Be, Mg, Ca, Sr, Ba, Ra. Zwei Valenzelektronen. Weniger reaktiv als Alkalimetalle. Ca²⁺ und Mg²⁺ sind biologisch essenziell. CaCO₃ (Kalkstein) und MgSO₄ (Bittersalz) sind häufige Verbindungen.","fr":"Be, Mg, Ca, Sr, Ba, Ra. Deux électrons de valence. Moins réactifs que les métaux alcalins. Ca²⁺ et Mg²⁺ sont biologiquement essentiels. CaCO₃ (calcaire) et MgSO₄ (sel d'Epsom) sont des composés courants.","tr":"Be, Mg, Ca, Sr, Ba, Ra. İki değerlik elektronu. Alkali metallerden daha az reaktif. Ca²⁺ ve Mg²⁺ biyolojik açıdan elzem. CaCO₃ (kireçtaşı) ve MgSO₄ (Epsom tuzu) yaygın bileşiklerdir.","nl":"Be, Mg, Ca, Sr, Ba, Ra. Twee valentie-elektronen. Minder reactief dan alkalimetalen. Ca²⁺ en Mg²⁺ zijn biologisch essentieel. CaCO₃ (kalksteen) en MgSO₄ (Epsomzout) zijn gewone verbindingen.","ru":"Be, Mg, Ca, Sr, Ba, Ra. Два валентных электрона. Менее реакционноспособны, чем щелочные металлы. Ca²⁺ и Mg²⁺ биологически необходимы. CaCO₃ (известняк) и MgSO₄ (соль Эпсома) — распространённые соединения.","zh":"Be、Mg、Ca、Sr、Ba、Ra。两个价电子。比碱金属活性低。Ca²⁺和Mg²⁺在生物学上不可或缺。CaCO₃（石灰石）和MgSO₄（泻盐）是常见化合物。","pt_BR":"Be, Mg, Ca, Sr, Ba, Ra. Dois elétrons de valência. Menos reativos que os metais alcalinos. Ca²⁺ e Mg²⁺ são biologicamente essenciais. CaCO₃ (calcário) e MgSO₄ (sal de Epsom) são compostos comuns.","pt_PT":"Be, Mg, Ca, Sr, Ba, Ra. Dois eletrões de valência. Menos reativos do que os metais alcalinos. Ca²⁺ e Mg²⁺ são biologicamente essenciais. CaCO₃ (calcário) e MgSO₄ (sal de Epsom) são compostos comuns."}},
  { id: 'dc-chemistry-0088', deck_id: 'deck-chemistry', sort_order: 88, front: "Halogens (Group 17)", back: "F, Cl, Br, I, At. Seven valence electrons; one electron away from noble gas configuration. Very reactive nonmetals that form salts with metals. Reactivity decreases down the group." , front_translations: {"es":"Halogenios (Grupo 17)","de":"Halogene (Gruppe 17)","fr":"Halogènes (groupe 17)","tr":"Halojenler (Grup 17)","nl":"Halogenen (groep 17)","ru":"Галогены (группа 17)","zh":"卤素（第17族）","pt_BR":"Halogênios (Grupo 17)","pt_PT":"Halogéneos (Grupo 17)"}, back_translations: {"es":"F, Cl, Br, I, At. Siete electrones de valencia; a un electrón de la configuración de gas nobre. No-metais muy reativos que forman sais con metais. La reatividad disminuye a lo ancho del grupo.","de":"F, Cl, Br, I, At. Sieben Valenzelektronen; ein Elektron von der Edelgaskonfiguration entfernt. Sehr reaktive Nichtmetalle, die mit Metallen Salze bilden. Reaktivität nimmt in der Gruppe ab.","fr":"F, Cl, Br, I, At. Sept électrons de valence ; un électron de la configuration des gaz nobles. Non-métaux très réactifs qui forment des sels avec les métaux. La réactivité diminue dans le groupe.","tr":"F, Cl, Br, I, At. Yedi değerlik elektronu; soy gaz konfigürasyonuna bir elektron uzaklıkta. Metallerle tuz oluşturan çok reaktif ametaller. Reaktivite grup boyunca aşağıya doğru azalır.","nl":"F, Cl, Br, I, At. Zeven valentie-elektronen; één elektron van edelgasconfiguratie. Zeer reactieve niet-metalen die zouten vormen met metalen. Reactiviteit neemt af in de groep.","ru":"F, Cl, Br, I, At. Семь валентных электронов; один электрон до конфигурации инертного газа. Очень реакционноспособные неметаллы, образующие соли с металлами. Реакционная способность убывает в группе.","zh":"F、Cl、Br、I、At。七个价电子；距稀有气体构型还差一个电子。与金属形成盐的高活性非金属。反应活性在族中从上到下依次减弱。","pt_BR":"F, Cl, Br, I, At. Sete elétrons de valência; a um elétron da configuração de gás nobre. Não-metais muito reativos que formam sais com metais. A reatividade diminui ao longo do grupo.","pt_PT":"F, Cl, Br, I, At. Sete eletrões de valência; a um eletrão da configuração de gás nobre. Não-metais muito reativos que formam sais com metais. A reatividade diminui ao longo do grupo."}},
  { id: 'dc-chemistry-0089', deck_id: 'deck-chemistry', sort_order: 89, front: "Noble Gases (Group 18)", back: "He, Ne, Ar, Kr, Xe, Rn. Full valence shells; extremely unreactive. Used where inert atmospheres are needed. Xe and Kr can form compounds with highly electronegative F and O." , front_translations: {"es":"Gases Nobres (Grupo 18)","de":"Edelgase (Gruppe 18)","fr":"Gaz nobles (groupe 18)","tr":"Soy Gazlar (Grup 18)","nl":"Edelgassen (groep 18)","ru":"Благородные газы (группа 18)","zh":"稀有气体（第18族）","pt_BR":"Gases Nobres (Grupo 18)","pt_PT":"Gases Nobres (Grupo 18)"}, back_translations: {"es":"He, Ne, Aire, Kr, Xe, Rn. Capas de valencia completas; extremamente inertes. Usados donde atmosferas inertes son necesarias. Xe y Kr pueden formar compuestos con el altamente eletronegativo F y El.","de":"He, Ne, Ar, Kr, Xe, Rn. Vollständig besetzte Valenzschalen; extrem unreaktiv. Werden verwendet, wo inerte Atmosphären benötigt werden. Xe und Kr können Verbindungen mit den stark elektronegativen Elementen F und O bilden.","fr":"He, Ne, Ar, Kr, Xe, Rn. Couches de valence complètes ; extrêmement peu réactifs. Utilisés quand des atmosphères inertes sont nécessaires. Xe et Kr peuvent former des composés avec le très électronégatif F et O.","tr":"He, Ne, Ar, Kr, Xe, Rn. Dolu değerlik kabukları; son derece reaktif değil. İnert atmosferilerin gerektiği yerlerde kullanılır. Xe ve Kr, yüksek elektronegatifliğe sahip F ve O ile bileşik oluşturabilir.","nl":"He, Ne, Ar, Kr, Xe, Rn. Volledige valentie-schillen; uiterst niet-reactief. Gebruikt waar inerte atmosferen nodig zijn. Xe en Kr kunnen verbindingen vormen met de sterk elektronegatieve F en O.","ru":"He, Ne, Ar, Kr, Xe, Rn. Полностью заполненные валентные оболочки; крайне инертны. Применяются там, где требуется инертная атмосфера. Xe и Kr могут образовывать соединения с высокоэлектроотрицательными F и O.","zh":"He、Ne、Ar、Kr、Xe、Rn。价电子层全充满；极不活泼。用于需要惰性气氛的场合。Xe和Kr能与高电负性的F和O形成化合物。","pt_BR":"He, Ne, Ar, Kr, Xe, Rn. Camadas de valência completas; extremamente inertes. Usados onde atmosferas inertes são necessárias. Xe e Kr podem formar compostos com o altamente eletronegativo F e O.","pt_PT":"He, Ne, Ar, Kr, Xe, Rn. Camadas de valência completas; extremamente inertes. Usados onde são necessárias atmosferas inertes. Xe e Kr podem formar compostos com o altamente eletronegativo F e O."}},
  { id: 'dc-chemistry-0090', deck_id: 'deck-chemistry', sort_order: 90, front: "Transition Metals", back: "Elements with partially filled d subshells (Groups 3–12). Form multiple oxidation states, colored compounds, and many are catalytically active. Include Fe, Cu, Ni, Zn, Pt, Au." , front_translations: {"es":"Metais de Transición","de":"Übergangsmetalle","fr":"Métaux de transition","tr":"Geçiş Metalleri","nl":"Overgangsmetalen","ru":"Переходные металлы","zh":"过渡金属","pt_BR":"Metais de Transição","pt_PT":"Metais de Transição"}, back_translations: {"es":"Elementos con subnible d parcialmente preenchido (grupos 3–12). Forman múltiplos estados de oxidación, compuestos coloridos y muchos son cataliticamente ativos. Incluyen Fe, Cu, Ni, Zn, Pt, Au.","de":"Elemente mit teilweise besetzten d-Unterschalen (Gruppen 3–12). Bilden mehrere Oxidationsstufen, farbige Verbindungen; viele sind katalytisch aktiv. Dazu gehören Fe, Cu, Ni, Zn, Pt, Au.","fr":"Éléments avec des sous-couches d partiellement remplies (groupes 3–12). Forment plusieurs états d'oxydation, des composés colorés et beaucoup sont catalytiquement actifs. Comprennent Fe, Cu, Ni, Zn, Pt, Au.","tr":"Kısmen dolu d alt kabukları olan elementler (Gruplar 3–12). Birden fazla oksidasyon durumu, renkli bileşikler oluştururlar ve pek çoğu katalitik olarak aktiftir. Fe, Cu, Ni, Zn, Pt, Au'yu içerir.","nl":"Elementen met gedeeltelijk gevulde d-subniveaus (groepen 3–12). Vormen meerdere oxidatietoestanden, gekleurde verbindingen en velen zijn katalytisch actief. Inclusief Fe, Cu, Ni, Zn, Pt, Au.","ru":"Элементы с частично заполненными d-подоболочками (группы 3–12). Образуют несколько степеней окисления, окрашенные соединения, многие каталитически активны. Включают Fe, Cu, Ni, Zn, Pt, Au.","zh":"具有部分填充d亚层的元素（第3–12族）。能形成多种氧化态、有色化合物，许多具有催化活性。包括Fe、Cu、Ni、Zn、Pt、Au。","pt_BR":"Elementos com subnível d parcialmente preenchido (grupos 3–12). Formam múltiplos estados de oxidação, compostos coloridos e muitos são cataliticamente ativos. Incluem Fe, Cu, Ni, Zn, Pt, Au.","pt_PT":"Elementos com subnível d parcialmente preenchido (grupos 3–12). Formam múltiplos estados de oxidação, compostos coloridos e muitos são cataliticamente ativos. Incluem Fe, Cu, Ni, Zn, Pt, Au."}},
  { id: 'dc-chemistry-0091', deck_id: 'deck-chemistry', sort_order: 91, front: "Ionization Energy", back: "The energy required to remove an electron from a gaseous atom. Increases across a period (stronger nuclear attraction) and decreases down a group (electrons farther from nucleus)." , front_translations: {"es":"Energía de Ionización","de":"Ionisierungsenergie","fr":"Énergie d'ionisation","tr":"İyonlaşma Enerjisi","nl":"Ionisatie-energie","ru":"Энергия ионизации","zh":"电离能","pt_BR":"Energia de Ionização","pt_PT":"Energia de Ionização"}, back_translations: {"es":"La energía necesaria para remover un electrón de un átomo gaseoso. Aumenta a lo ancho de un período (mayor atración nuclear) y disminuye a lo ancho de un grupo (electrones más distantes del núcleo).","de":"Die Energie, die benötigt wird, um ein Elektron aus einem gasförmigen Atom zu entfernen. Nimmt innerhalb einer Periode zu (stärkere Kernanziehung) und in einer Gruppe ab (Elektronen weiter vom Kern entfernt).","fr":"L'énergie nécessaire pour retirer un électron d'un atome gazeux. Augmente dans une période (attraction nucléaire plus forte) et diminue dans un groupe (électrons plus éloignés du noyau).","tr":"Gaz halindeki bir atomdan bir elektron uzaklaştırmak için gereken enerji. Bir periyot boyunca artar (daha güçlü çekirdek çekimi) ve bir grup boyunca azalır (elektronlar çekirdekten daha uzak).","nl":"De energie die nodig is om een elektron te verwijderen uit een gasvormig atoom. Neemt toe langs een periode (sterkere nucleaire aantrekking) en neemt af in een groep (elektronen verder van de kern).","ru":"Энергия, необходимая для удаления электрона из газообразного атома. Возрастает вдоль периода (усиление ядерного притяжения) и убывает в группе (электроны дальше от ядра).","zh":"从气态原子中移除一个电子所需的能量。在同一周期中从左到右增大（核吸引力增强），在同一族中从上到下减小（电子距核更远）。","pt_BR":"A energia necessária para remover um elétron de um átomo gasoso. Aumenta ao longo de um período (maior atração nuclear) e diminui ao longo de um grupo (elétrons mais distantes do núcleo).","pt_PT":"A energia necessária para remover um eletrão de um átomo gasoso. Aumenta ao longo de um período (maior atração nuclear) e diminui ao longo de um grupo (eletrões mais distantes do núcleo)."}},
  { id: 'dc-chemistry-0092', deck_id: 'deck-chemistry', sort_order: 92, front: "Electron Affinity", back: "The energy change when a gaseous atom gains an electron. Generally more negative (more energy released) across a period. Halogens have the highest electron affinities." , front_translations: {"es":"Afinidad Electrónica","de":"Elektronenaffinität","fr":"Affinité électronique","tr":"Elektron İlgisi","nl":"Elektronenaffiniteit","ru":"Сродство к электрону","zh":"电子亲和能","pt_BR":"Afinidade Eletrônica","pt_PT":"Afinidade Eletrónica"}, back_translations: {"es":"La variación de energía cuando un átomo gaseoso ganha un electrón. Generalmente más negativa (más energía liberada) a lo ancho de un período. Los halogenios tienen las mayores afinidades eletronicas.","de":"Die Energieänderung, wenn ein gasförmiges Atom ein Elektron aufnimmt. Wird im Allgemeinen negativer (mehr Energie freigesetzt) innerhalb einer Periode. Halogene haben die höchsten Elektronenaffinitäten.","fr":"La variation d'énergie lorsqu'un atome gazeux gagne un électron. Généralement plus négative (plus d'énergie libérée) dans une période. Les halogènes ont les affinités électroniques les plus élevées.","tr":"Gaz halindeki bir atomun bir elektron kazanmasındaki enerji değişimi. Genellikle bir periyot boyunca daha negatif olur (daha fazla enerji açığa çıkar). Halojenler en yüksek elektron ilgisine sahiptir.","nl":"De energieverandering wanneer een gasvormig atoom een elektron opneemt. Over het algemeen negatiever (meer energie vrijgegeven) langs een periode. Halogenen hebben de hoogste elektronenaffiniteiten.","ru":"Изменение энергии при присоединении электрона к газообразному атому. Как правило, становится более отрицательным (выделяется больше энергии) вдоль периода. Галогены имеют наибольшее сродство к электрону.","zh":"气态原子得到一个电子时的能量变化。在同一周期中通常变得更负（释放更多能量）。卤素具有最高的电子亲和能。","pt_BR":"A variação de energia quando um átomo gasoso ganha um elétron. Geralmente mais negativa (mais energia liberada) ao longo de um período. Os halogênios têm as maiores afinidades eletrônicas.","pt_PT":"A variação de energia quando um átomo gasoso ganha um eletrão. Geralmente mais negativa (mais energia libertada) ao longo de um período. Os halogéneos têm as maiores afinidades eletrónicas."}},
  { id: 'dc-chemistry-0093', deck_id: 'deck-chemistry', sort_order: 93, front: "Atomic Radius", back: "Decreases across a period (increasing nuclear charge pulls electrons closer) and increases down a group (additional electron shells increase size). Cations are smaller; anions are larger than parent atoms." , front_translations: {"es":"Raio Atómico","de":"Atomradius","fr":"Rayon atomique","tr":"Atom Yarıçapı","nl":"Atoomstraal","ru":"Атомный радиус","zh":"原子半径","pt_BR":"Raio Atômico","pt_PT":"Raio Atómico"}, back_translations: {"es":"Disminuye a lo ancho de un período (carga nuclear crescente atrai los electrones más próximos) y aumenta a lo ancho de un grupo (capas eletronicas adicionais aumentan el tamaño). Cátions son menores; anions son mayores que los átomos originais.","de":"Nimmt innerhalb einer Periode ab (zunehmende Kernladung zieht Elektronen näher) und nimmt in einer Gruppe zu (zusätzliche Elektronenschalen vergrößern die Größe). Kationen sind kleiner; Anionen sind größer als die Ausgangselemente.","fr":"Diminue le long d'une période (la charge nucléaire croissante attire les électrons plus près) et augmente dans un groupe (des couches électroniques supplémentaires augmentent la taille). Les cations sont plus petits ; les anions sont plus grands que les atomes parents.","tr":"Bir periyot boyunca azalır (artan çekirdek yükü elektronları daha yakın çeker) ve bir grup boyunca artar (ek elektron kabukları boyutu artırır). Katyonlar daha küçük; anyonlar ana atomlardan daha büyüktür.","nl":"Neemt af langs een periode (toenemende kernlading trekt elektronen dichter) en neemt toe in een groep (extra elektronenschillen vergroten de grootte). Kationen zijn kleiner; anionen zijn groter dan de ouderatomen.","ru":"Уменьшается вдоль периода (возрастающий заряд ядра притягивает электроны ближе) и увеличивается в группе (дополнительные электронные оболочки увеличивают размер). Катионы меньше; анионы больше, чем исходные атомы.","zh":"在同一周期中从左到右减小（核电荷增大使电子靠近），在同一族中从上到下增大（电子层数增多）。阳离子比母原子小；阴离子比母原子大。","pt_BR":"Diminui ao longo de um período (carga nuclear crescente atrai os elétrons mais próximos) e aumenta ao longo de um grupo (camadas eletrônicas adicionais aumentam o tamanho). Cátions são menores; ânions são maiores que os átomos originais.","pt_PT":"Diminui ao longo de um período (carga nuclear crescente atrai os eletrões mais próximos) e aumenta ao longo de um grupo (camadas eletrónicas adicionais aumentam o tamanho). Os catiões são mais pequenos; os aniões são maiores do que os átomos originais."}},
  { id: 'dc-chemistry-0094', deck_id: 'deck-chemistry', sort_order: 94, front: "Colligative Properties", back: "Properties that depend on the number of solute particles, not their identity: boiling point elevation (ΔTb = Kbm), freezing point depression (ΔTf = Kfm), osmotic pressure (π = MRT)." , front_translations: {"es":"Propiedades Coligativas","de":"Kolligative Eigenschaften","fr":"Propriétés colligatives","tr":"Koligatif Özellikler","nl":"Colligatieve eigenschappen","ru":"Коллигативные свойства","zh":"依数性","pt_BR":"Propriedades Coligativas","pt_PT":"Propriedades Coligativas"}, back_translations: {"es":"Propiedades que dependen del número de partículas de soluto, no de su identidad: elevación del punto de ebullición (ΔTb = Kbm), depresión del punto de congelamento (ΔTf = Kfm), presión osmótica (π = MRT).","de":"Eigenschaften, die von der Anzahl der gelösten Teilchen abhängen, nicht von ihrer Identität: Siedepunkterhöhung (ΔTb = Kbm), Gefrierpunktserniedrigung (ΔTf = Kfm), osmotischer Druck (π = MRT).","fr":"Propriétés qui dépendent du nombre de particules de soluté, pas de leur identité : élévation du point d'ébullition (ΔTb = Kbm), abaissement du point de congélation (ΔTf = Kfm), pression osmotique (π = MRT).","tr":"Çözünen partikül sayısına bağlı olan özellikler: kaynama noktası yükselmesi (ΔTb = Kbm), donma noktası düşmesi (ΔTf = Kfm), osmotik basınç (π = MRT).","nl":"Eigenschappen die afhangen van het aantal opgeloste deeltjes, niet van hun identiteit: kookpuntverhoging (ΔTb = Kbm), vriespuntsdaling (ΔTf = Kfm), osmotische druk (π = MRT).","ru":"Свойства, зависящие от числа частиц растворённого вещества, а не от их природы: повышение температуры кипения (ΔTb = Kbm), понижение температуры замерзания (ΔTf = Kfm), осмотическое давление (π = MRT).","zh":"取决于溶质粒子数而非其种类的性质：沸点升高（ΔTb = Kbm）、凝固点降低（ΔTf = Kfm）、渗透压（π = MRT）。","pt_BR":"Propriedades que dependem do número de partículas de soluto, não de sua identidade: elevação do ponto de ebulição (ΔTb = Kbm), depressão do ponto de congelamento (ΔTf = Kfm), pressão osmótica (π = MRT).","pt_PT":"Propriedades que dependem do número de partículas de soluto, não da sua identidade: elevação do ponto de ebulição (ΔTb = Kbm), depressão do ponto de congelação (ΔTf = Kfm), pressão osmótica (π = MRT)."}},
  { id: 'dc-chemistry-0095', deck_id: 'deck-chemistry', sort_order: 95, front: "Combustion Reaction", back: "A substance reacts with O₂ to produce CO₂ and H₂O (complete combustion). Highly exothermic. Complete combustion of hydrocarbons: CₙHₘ + O₂ → CO₂ + H₂O." , front_translations: {"es":"Reacción de Combustión","de":"Verbrennungsreaktion","fr":"Réaction de combustion","tr":"Yanma Tepkimesi","nl":"Verbrandingsreactie","ru":"Реакция горения","zh":"燃烧反应","pt_BR":"Reação de Combustão","pt_PT":"Reação de Combustão"}, back_translations: {"es":"Una sustancia reage con El₂ para produzir CO₂ y H₂El (combustión completa). Altamente exotérmica. Combustión completa de hidrocarbonetos: CₙHₘ + El₂ → CO₂ + H₂El.","de":"Ein Stoff reagiert mit O₂ unter Bildung von CO₂ und H₂O (vollständige Verbrennung). Stark exotherm. Vollständige Verbrennung von Kohlenwasserstoffen: CₙHₘ + O₂ → CO₂ + H₂O.","fr":"Une substance réagit avec O₂ pour produire CO₂ et H₂O (combustion complète). Très exothermique. Combustion complète des hydrocarbures : CₙHₘ + O₂ → CO₂ + H₂O.","tr":"Bir madde O₂ ile reaksiyona girerek CO₂ ve H₂O üretir (tam yanma). Güçlü ekzotermik. Hidrokarbonların tam yanması: CₙHₘ + O₂ → CO₂ + H₂O.","nl":"Een stof reageert met O₂ om CO₂ en H₂O te produceren (volledige verbranding). Sterk exotherm. Volledige verbranding van koolwaterstoffen: CₙHₘ + O₂ → CO₂ + H₂O.","ru":"Вещество реагирует с O₂ с образованием CO₂ и H₂O (полное горение). Сильно экзотермическая. Полное горение углеводородов: CₙHₘ + O₂ → CO₂ + H₂O.","zh":"物质与O₂反应生成CO₂和H₂O（完全燃烧）。强放热反应。烃类完全燃烧：CₙHₘ + O₂ → CO₂ + H₂O。","pt_BR":"Uma substância reage com O₂ para produzir CO₂ e H₂O (combustão completa). Altamente exotérmica. Combustão completa de hidrocarbonetos: CₙHₘ + O₂ → CO₂ + H₂O.","pt_PT":"Uma substância reage com O₂ para produzir CO₂ e H₂O (combustão completa). Altamente exotérmica. Combustão completa de hidrocarbonetos: CₙHₘ + O₂ → CO₂ + H₂O."}},
  { id: 'dc-chemistry-0096', deck_id: 'deck-chemistry', sort_order: 96, front: "Precipitation Reaction", back: "Two aqueous solutions mix and form an insoluble solid (precipitate). Determined by solubility rules. E.g., Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq)." , front_translations: {"es":"Reacción de Precipitación","de":"Fällungsreaktion","fr":"Réaction de précipitation","tr":"Çökelme Tepkimesi","nl":"Neerslaagreactie","ru":"Реакция осаждения","zh":"沉淀反应","pt_BR":"Reação de Precipitação","pt_PT":"Reação de Precipitação"}, back_translations: {"es":"Dos soluciones aquosas se misturam y forman un sólido insoluble (precipitado). Determinado por las regras de solubilidad. Ex.: Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","de":"Zwei wässrige Lösungen mischen sich und bilden einen unlöslichen Feststoff (Niederschlag). Durch Löslichkeitsregeln bestimmt. Z. B. Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","fr":"Deux solutions aqueuses se mélangent et forment un solide insoluble (précipité). Déterminé par les règles de solubilité. P. ex., Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","tr":"İki sulu çözelti karışarak çözünmez bir katı (çökelek) oluşturur. Çözünürlük kuralları ile belirlenir. Örn. Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","nl":"Twee waterige oplossingen mengen en vormen een onoplosbare vaste stof (neerslag). Bepaald door oplosbaarheidsregels. Bijv. Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","ru":"Смешивание двух водных растворов с образованием нерастворимого твёрдого вещества (осадка). Определяется правилами растворимости. Напр.: Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","zh":"两种水溶液混合后生成不溶固体（沉淀）。由溶解性规则决定。例如：Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq)。","pt_BR":"Duas soluções aquosas se misturam e formam um sólido insolúvel (precipitado). Determinado pelas regras de solubilidade. Ex.: Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq).","pt_PT":"Duas soluções aquosas misturam-se e formam um sólido insolúvel (precipitado). Determinado pelas regras de solubilidade. Ex.: Pb(NO₃)₂(aq) + 2KI(aq) → PbI₂(s) + 2KNO₃(aq)."}},
  { id: 'dc-chemistry-0097', deck_id: 'deck-chemistry', sort_order: 97, front: "Gas Laws: Dalton's Law", back: "P_total = P₁ + P₂ + P₃ + ... The total pressure of a gas mixture equals the sum of the partial pressures of each component. Each gas behaves independently." , front_translations: {"es":"Leyes de los Gases: Ley de Dalton","de":"Gasgesetze: Daltons Gesetz","fr":"Lois des gaz : Loi de Dalton","tr":"Gaz Yasaları: Dalton Yasası","nl":"Gaswetten: Wet van Dalton","ru":"Законы газов: Закон Дальтона","zh":"气体定律：道尔顿分压定律","pt_BR":"Leis dos Gases: Lei de Dalton","pt_PT":"Leis dos Gases: Lei de Dalton"}, back_translations: {"es":"P_total = P₁ + P₂ + P₃ + ... La presión total de una mistura de gases es igual a la suma de las presiones parciais de cada componente. Cada gas se comporta de forma independente.","de":"P_gesamt = P₁ + P₂ + P₃ + ... Der Gesamtdruck eines Gasgemisches ist gleich der Summe der Partialdrücke jeder Komponente. Jedes Gas verhält sich unabhängig.","fr":"P_total = P₁ + P₂ + P₃ + ... La pression totale d'un mélange de gaz est égale à la somme des pressions partielles de chaque composant. Chaque gaz se comporte de manière indépendante.","tr":"P_toplam = P₁ + P₂ + P₃ + ... Bir gaz karışımının toplam basıncı, her bileşenin kısmi basınçlarının toplamına eşittir. Her gaz bağımsız olarak davranır.","nl":"P_totaal = P₁ + P₂ + P₃ + ... De totale druk van een gasmengsel is gelijk aan de som van de partiaaldrukken van elke component. Elk gas gedraagt zich onafhankelijk.","ru":"P_общ = P₁ + P₂ + P₃ + ... Общее давление смеси газов равно сумме парциальных давлений каждого компонента. Каждый газ ведёт себя независимо.","zh":"P总 = P₁ + P₂ + P₃ + ... 混合气体的总压等于各组分分压之和。每种气体独立表现。","pt_BR":"P_total = P₁ + P₂ + P₃ + ... A pressão total de uma mistura de gases é igual à soma das pressões parciais de cada componente. Cada gás se comporta de forma independente.","pt_PT":"P_total = P₁ + P₂ + P₃ + ... A pressão total de uma mistura de gases é igual à soma das pressões parciais de cada componente. Cada gás comporta-se de forma independente."}},
  { id: 'dc-chemistry-0098', deck_id: 'deck-chemistry', sort_order: 98, front: "Van der Waals Forces", back: "Weak intermolecular attractions: London dispersion forces (temporary dipoles, all molecules), dipole-dipole (polar molecules), and hydrogen bonding. Determine boiling points and physical states." , front_translations: {"es":"Fuerzas de Van der Waals","de":"Van-der-Waals-Kräfte","fr":"Forces de Van der Waals","tr":"Van der Waals Kuvvetleri","nl":"Van der Waals-krachten","ru":"Силы Ван-дер-Ваальса","zh":"范德华力","pt_BR":"Forças de Van der Waals","pt_PT":"Forças de Van der Waals"}, back_translations: {"es":"Atraciones intermoleculares débiles: fuerzas de dispersão de London (dipolos temporários, todas las moléculas), dipolo-dipolo (moléculas polares) y enlaces de hidrógeno. Determinan los puntos de ebullición y los estados físicos.","de":"Schwache intermolekulare Anziehungskräfte: London-Dispersionskräfte (temporäre Dipole, alle Moleküle), Dipol-Dipol-Kräfte (polare Moleküle) und Wasserstoffbrückenbindungen. Bestimmen Siedepunkte und Aggregatzustände.","fr":"Attractions intermoléculaires faibles : forces de dispersion de London (dipôles temporaires, toutes les molécules), dipôle-dipôle (molécules polaires) et liaisons hydrogène. Déterminent les points d'ébullition et les états physiques.","tr":"Zayıf moleküller arası çekim kuvvetleri: London dağılım kuvvetleri (geçici dipoller, tüm moleküller), dipol-dipol (polar moleküller) ve hidrojen bağı. Kaynama noktalarını ve fiziksel halleri belirler.","nl":"Zwakke intermoleculaire aantrekkingen: London-dispersiekrachten (tijdelijke dipolen, alle moleculen), dipool-dipool (polaire moleculen) en waterstofbruggen. Bepalen kookpunten en fysieke toestanden.","ru":"Слабые межмолекулярные притяжения: силы Лондона (временные диполи, все молекулы), диполь-дипольные (полярные молекулы) и водородные связи. Определяют температуры кипения и агрегатные состояния.","zh":"弱分子间引力：伦敦色散力（瞬时偶极，所有分子）、偶极-偶极力（极性分子）和氢键。决定沸点和物质的物理状态。","pt_BR":"Atrações intermoleculares fracas: forças de dispersão de London (dipolos temporários, todas as moléculas), dipolo-dipolo (moléculas polares) e ligações de hidrogênio. Determinam os pontos de ebulição e os estados físicos.","pt_PT":"Atrações intermoleculares fracas: forças de dispersão de London (dipolos temporários, todas as moléculas), dipolo-dipolo (moléculas polares) e ligações de hidrogénio. Determinam os pontos de ebulição e os estados físicos."}},
  { id: 'dc-chemistry-0099', deck_id: 'deck-chemistry', sort_order: 99, front: "Metallic Bonding", back: "A 'sea of delocalized electrons' surrounding a lattice of metal cations. Explains metals' conductivity (electrons move freely), malleability, and luster. Strongest in small, highly charged metals." , front_translations: {"es":"Enlace Metálica","de":"Metallische Bindung","fr":"Liaison métallique","tr":"Metalik Bağ","nl":"Metallische binding","ru":"Металлическая связь","zh":"金属键","pt_BR":"Ligação Metálica","pt_PT":"Ligação Metálica"}, back_translations: {"es":"Un \"mar de electrones deslocalizados\" involucrando una red de cátions metálicos. Explica a condutividad de los metais (electrones se movem livremente), maleabilidad y brilho. Más fuerte en metais pequeños y altamente carregados.","de":"Ein \"Meer delokalisierter Elektronen\" umgibt ein Gitter aus Metallkationen. Erklärt die Leitfähigkeit (Elektronen bewegen sich frei), Formbarkeit und den Glanz von Metallen. Am stärksten in kleinen, hoch geladenen Metallen.","fr":"Une \"mer d'électrons délocalisés\" entourant un réseau de cations métalliques. Explique la conductivité des métaux (les électrons se déplacent librement), la malléabilité et l'éclat. La plus forte dans les petits métaux fortement chargés.","tr":"Metal katyon kafesini çevreleyen \"delokalize elektron denizi\". Metallerin iletkenliğini (elektronlar serbestçe hareket eder), dövülebilirliğini ve parlaklığını açıklar. Küçük, yüksek yüklü metallerde en güçlüdür.","nl":"Een \"zee van gedelokaliseerde elektronen\" rondom een rooster van metaalionen. Verklaart de geleidbaarheid van metalen (elektronen bewegen vrij), malbaarheid en glans. Het sterkst in kleine, sterk geladen metalen.","ru":"«Море делокализованных электронов» вокруг решётки металлических катионов. Объясняет проводимость металлов (электроны свободно движутся), пластичность и блеск. Наиболее прочная в малых высокозарядных металлах.","zh":"围绕金属阳离子晶格的\"离域电子海\"。解释了金属的导电性（电子自由移动）、延展性和光泽。在小而高价的金属中最强。","pt_BR":"Um \"mar de elétrons deslocalizados\" envolvendo uma rede de cátions metálicos. Explica a condutividade dos metais (elétrons se movem livremente), maleabilidade e brilho. Mais forte em metais pequenos e altamente carregados.","pt_PT":"Um \"mar de eletrões deslocalizados\" a envolver uma rede de catiões metálicos. Explica a condutividade dos metais (os eletrões movem-se livremente), a maleabilidade e o brilho. Mais forte nos metais pequenos e altamente carregados."}},
  { id: 'dc-chemistry-0100', deck_id: 'deck-chemistry', sort_order: 100, front: "Crystal Lattice", back: "A three-dimensional repeating arrangement of atoms, ions, or molecules. Types: ionic (NaCl), metallic (Cu), covalent network (diamond, SiO₂), and molecular (ice). Properties depend on bond type." , front_translations: {"es":"Red Cristalina","de":"Kristallgitter","fr":"Réseau cristallin","tr":"Kristal Kafes","nl":"Kristalrooster","ru":"Кристаллическая решётка","zh":"晶格","pt_BR":"Rede Cristalina","pt_PT":"Rede Cristalina"}, back_translations: {"es":"Un arranjo repetitivo tridimensional de átomos, iones o moléculas. Tipos: ionico (NaCl), metálico (Cu), red covalente (diamante, SiO₂) y molecular (gelo). As propiedades dependen del tipo de enlace.","de":"Eine dreidimensionale, sich wiederholende Anordnung von Atomen, Ionen oder Molekülen. Typen: ionisch (NaCl), metallisch (Cu), kovalentes Netzwerk (Diamant, SiO₂) und molekular (Eis). Eigenschaften hängen von der Bindungsart ab.","fr":"Un arrangement tridimensionnel répétitif d'atomes, d'ions ou de molécules. Types : ionique (NaCl), métallique (Cu), réseau covalent (diamant, SiO₂) et moléculaire (glace). Les propriétés dépendent du type de liaison.","tr":"Atom, iyon veya moleküllerin üç boyutlu tekrarlanan düzenlemesi. Türleri: iyonik (NaCl), metalik (Cu), kovalent ağ (elmas, SiO₂) ve moleküler (buz). Özellikler bağ türüne bağlıdır.","nl":"Een driedimensionale, herhalende rangschikking van atomen, ionen of moleculen. Typen: ionisch (NaCl), metallisch (Cu), covalent netwerk (diamant, SiO₂) en moleculair (ijs). Eigenschappen hangen af van het bindingstype.","ru":"Трёхмерное повторяющееся расположение атомов, ионов или молекул. Типы: ионная (NaCl), металлическая (Cu), ковалентная сеть (алмаз, SiO₂) и молекулярная (лёд). Свойства зависят от типа связи.","zh":"原子、离子或分子的三维重复排列。类型：离子型（NaCl）、金属型（Cu）、共价网络型（金刚石、SiO₂）和分子型（冰）。性质取决于键的类型。","pt_BR":"Um arranjo repetitivo tridimensional de átomos, íons ou moléculas. Tipos: iônico (NaCl), metálico (Cu), rede covalente (diamante, SiO₂) e molecular (gelo). As propriedades dependem do tipo de ligação.","pt_PT":"Um arranjo tridimensional repetitivo de átomos, iões ou moléculas. Tipos: iónico (NaCl), metálico (Cu), rede covalente (diamante, SiO₂) e molecular (gelo). As propriedades dependem do tipo de ligação."}},
  { id: 'dc-chemistry-0101', deck_id: 'deck-chemistry', sort_order: 101, front: "Acid Dissociation Constant (Ka)", back: "Ka = [H⁺][A⁻]/[HA]. Measures the strength of a weak acid. Stronger acids have larger Ka (smaller pKa). HCl and H₂SO₄ are strong acids and fully dissociate (Ka → ∞)." , front_translations: {"es":"Constante de Dissociación Ácida (Ka)","de":"Säuredissoziationskonstante (Ka)","fr":"Constante de dissociation acide (Ka)","tr":"Asit Ayrışma Sabiti (Ka)","nl":"Zuurdissociatieconstante (Ka)","ru":"Константа диссоциации кислоты (Ka)","zh":"酸解离常数（Ka）","pt_BR":"Constante de Dissociação Ácida (Ka)","pt_PT":"Constante de Dissociação Ácida (Ka)"}, back_translations: {"es":"Ka = [H⁺][A⁻]/[HA]. Mide a fuerza de un ácido débil. Ácidos más fuertes tienen Ka mayor (pKa menor). HCl y H₂SO₄ son ácidos fuertes y se dissociam completamente (Ka → ∞).","de":"Ka = [H⁺][A⁻]/[HA]. Misst die Stärke einer schwachen Säure. Stärkere Säuren haben größere Ka (kleineren pKa). HCl und H₂SO₄ sind starke Säuren und dissoziieren vollständig (Ka → ∞).","fr":"Ka = [H⁺][A⁻]/[HA]. Mesure la force d'un acide faible. Les acides plus forts ont un Ka plus grand (pKa plus petit). HCl et H₂SO₄ sont des acides forts et se dissocient complètement (Ka → ∞).","tr":"Ka = [H⁺][A⁻]/[HA]. Zayıf bir asidin gücünü ölçer. Daha güçlü asitler daha büyük Ka değerine (daha küçük pKa) sahiptir. HCl ve H₂SO₄ güçlü asitlerdir ve tamamen ayrışır (Ka → ∞).","nl":"Ka = [H⁺][A⁻]/[HA]. Meet de sterkte van een zwak zuur. Sterkere zuren hebben een grotere Ka (kleinere pKa). HCl en H₂SO₄ zijn sterke zuren en dissociëren volledig (Ka → ∞).","ru":"Ka = [H⁺][A⁻]/[HA]. Измеряет силу слабой кислоты. Более сильные кислоты имеют большее Ka (меньшее pKa). HCl и H₂SO₄ — сильные кислоты, полностью диссоциирующие (Ka → ∞).","zh":"Ka = [H⁺][A⁻]/[HA]。衡量弱酸的强度。酸越强，Ka越大（pKa越小）。HCl和H₂SO₄是强酸，完全解离（Ka → ∞）。","pt_BR":"Ka = [H⁺][A⁻]/[HA]. Mede a força de um ácido fraco. Ácidos mais fortes têm Ka maior (pKa menor). HCl e H₂SO₄ são ácidos fortes e se dissociam completamente (Ka → ∞).","pt_PT":"Ka = [H⁺][A⁻]/[HA]. Mede a força de um ácido fraco. Ácidos mais fortes têm Ka maior (pKa menor). HCl e H₂SO₄ são ácidos fortes e dissociam-se completamente (Ka → ∞)."}},
  { id: 'dc-chemistry-0102', deck_id: 'deck-chemistry', sort_order: 102, front: "Base Dissociation Constant (Kb)", back: "Kb = [BH⁺][OH⁻]/[B]. Measures the strength of a weak base. For conjugate acid-base pairs: Ka × Kb = Kw = 10⁻¹⁴ at 25°C. Stronger base has larger Kb." , front_translations: {"es":"Constante de Dissociación de Base (Kb)","de":"Basendissoziationskonstante (Kb)","fr":"Constante de dissociation basique (Kb)","tr":"Baz Ayrışma Sabiti (Kb)","nl":"Basedissociatieconstante (Kb)","ru":"Константа диссоциации основания (Kb)","zh":"碱解离常数（Kb）","pt_BR":"Constante de Dissociação de Base (Kb)","pt_PT":"Constante de Dissociação de Base (Kb)"}, back_translations: {"es":"Kb = [BH⁺][OH⁻]/[B]. Mide a fuerza de una base débil. Para pares ácido-base conjugados: Ka × Kb = Kw = 10⁻¹⁴ a 25 °C. Base más fuerte tiene Kb mayor.","de":"Kb = [BH⁺][OH⁻]/[B]. Misst die Stärke einer schwachen Base. Für konjugierte Säure-Base-Paare gilt: Ka × Kb = Kw = 10⁻¹⁴ bei 25 °C. Eine stärkere Base hat größeres Kb.","fr":"Kb = [BH⁺][OH⁻]/[B]. Mesure la force d'une base faible. Pour les paires acide-base conjuguées : Ka × Kb = Kw = 10⁻¹⁴ à 25 °C. Une base plus forte a un Kb plus grand.","tr":"Kb = [BH⁺][OH⁻]/[B]. Zayıf bir bazın gücünü ölçer. Konjüge asit-baz çiftleri için: Ka × Kb = Kw = 10⁻¹⁴ (25 °C'de). Daha güçlü baz daha büyük Kb değerine sahiptir.","nl":"Kb = [BH⁺][OH⁻]/[B]. Meet de sterkte van een zwakke base. Voor geconjugeerde zuur-baseparen: Ka × Kb = Kw = 10⁻¹⁴ bij 25 °C. Een sterkere base heeft een grotere Kb.","ru":"Kb = [BH⁺][OH⁻]/[B]. Измеряет силу слабого основания. Для сопряжённых кислотно-основных пар: Ka × Kb = Kw = 10⁻¹⁴ при 25 °C. Более сильное основание имеет большее Kb.","zh":"Kb = [BH⁺][OH⁻]/[B]。衡量弱碱的强度。对于共轭酸碱对：Ka × Kb = Kw = 10⁻¹⁴（25°C时）。碱越强，Kb越大。","pt_BR":"Kb = [BH⁺][OH⁻]/[B]. Mede a força de uma base fraca. Para pares ácido-base conjugados: Ka × Kb = Kw = 10⁻¹⁴ a 25 °C. Base mais forte tem Kb maior.","pt_PT":"Kb = [BH⁺][OH⁻]/[B]. Mede a força de uma base fraca. Para pares ácido-base conjugados: Ka × Kb = Kw = 10⁻¹⁴ a 25 °C. Uma base mais forte tem Kb maior."}},
  { id: 'dc-chemistry-0103', deck_id: 'deck-chemistry', sort_order: 103, front: "Water Autoionization", back: "2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ at 25°C. Pure water is both a weak acid and weak base. In neutral solution [H⁺] = [OH⁻] = 10⁻⁷ M." , front_translations: {"es":"Autoionización de la Agua","de":"Autoprotolyse des Wassers","fr":"Autoprotolyse de l'eau","tr":"Suyun Otoiyonizasyonu","nl":"Auto-ionisatie van water","ru":"Автоионизация воды","zh":"水的自电离","pt_BR":"Autoionização da Água","pt_PT":"Autoionização da Água"}, back_translations: {"es":"2H₂El ⇌ H₃El⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ a 25 °C. La agua pura es simultáneamente un ácido y una base débiles. En solución neutra [H⁺] = [OH⁻] = 10⁻⁷ M.","de":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ bei 25 °C. Reines Wasser ist sowohl eine schwache Säure als auch eine schwache Base. In neutraler Lösung gilt [H⁺] = [OH⁻] = 10⁻⁷ M.","fr":"2H₂O ⇌ H₃O⁺ + OH⁻ ; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ à 25 °C. L'eau pure est à la fois un acide et une base faibles. En solution neutre : [H⁺] = [OH⁻] = 10⁻⁷ M.","tr":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ (25 °C'de). Saf su hem zayıf bir asit hem de zayıf bir bazdır. Nötr çözeltide [H⁺] = [OH⁻] = 10⁻⁷ M.","nl":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ bij 25 °C. Zuiver water is zowel een zwak zuur als een zwakke base. In neutrale oplossing: [H⁺] = [OH⁻] = 10⁻⁷ M.","ru":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ при 25 °C. Чистая вода является одновременно слабой кислотой и слабым основанием. В нейтральном растворе [H⁺] = [OH⁻] = 10⁻⁷ М.","zh":"2H₂O ⇌ H₃O⁺ + OH⁻；Kw = [H⁺][OH⁻] = 1×10⁻¹⁴（25°C时）。纯水既是弱酸又是弱碱。在中性溶液中 [H⁺] = [OH⁻] = 10⁻⁷ M。","pt_BR":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ a 25 °C. A água pura é simultaneamente um ácido e uma base fracos. Em solução neutra [H⁺] = [OH⁻] = 10⁻⁷ M.","pt_PT":"2H₂O ⇌ H₃O⁺ + OH⁻; Kw = [H⁺][OH⁻] = 1×10⁻¹⁴ a 25 °C. A água pura é simultaneamente um ácido e uma base fracos. Em solução neutra [H⁺] = [OH⁻] = 10⁻⁷ M."}},
  { id: 'dc-chemistry-0104', deck_id: 'deck-chemistry', sort_order: 104, front: "Oxidizing Agent", back: "A substance that causes another substance to be oxidized by accepting electrons itself (it gets reduced). Common oxidizing agents: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃." , front_translations: {"es":"Agente Oxidante","de":"Oxidationsmittel","fr":"Agent oxydant","tr":"Yükseltgen (Oksitleyici Madde)","nl":"Oxidatiemiddel","ru":"Окислитель","zh":"氧化剂","pt_BR":"Agente Oxidante","pt_PT":"Agente Oxidante"}, back_translations: {"es":"Una sustancia que causa a oxidación de outra al aceitar electrones (siendo ela propia reduzida). Agentes oxidantes comuns: El₂, Cl₂, MnO₄⁻, H₂El₂, HNO₃.","de":"Eine Substanz, die eine andere Substanz oxidiert, indem sie selbst Elektronen aufnimmt (also reduziert wird). Gängige Oxidationsmittel: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","fr":"Une substance qui provoque l'oxydation d'une autre en acceptant elle-même des électrons (elle est réduite). Agents oxydants courants : O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","tr":"Başka bir maddeyi kendisi elektron kabul ederek (dolayısıyla indirgenerek) oksitleyen madde. Yaygın yükseltgenler: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","nl":"Een stof die een andere stof oxidiseert door zelf elektronen te accepteren (en dus gereduceerd wordt). Veelgebruikte oxidatiemiddelen: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","ru":"Вещество, окисляющее другое вещество путём принятия электронов (то есть само восстанавливается). Распространённые окислители: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","zh":"通过自身接受电子（即被还原）来氧化另一种物质的物质。常见氧化剂：O₂、Cl₂、MnO₄⁻、H₂O₂、HNO₃。","pt_BR":"Uma substância que causa a oxidação de outra ao aceitar elétrons (sendo ela própria reduzida). Agentes oxidantes comuns: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃.","pt_PT":"Uma substância que provoca a oxidação de outra ao aceitar eletrões (sendo ela própria reduzida). Agentes oxidantes comuns: O₂, Cl₂, MnO₄⁻, H₂O₂, HNO₃."}},
  { id: 'dc-chemistry-0105', deck_id: 'deck-chemistry', sort_order: 105, front: "Reducing Agent", back: "A substance that causes another to be reduced by donating electrons itself (it gets oxidized). Common reducing agents: H₂, metals (Na, Zn, Fe), C, CO, NaBH₄." , front_translations: {"es":"Agente Redutor","de":"Reduktionsmittel","fr":"Agent réducteur","tr":"İndirgen (Redükleyici Madde)","nl":"Reductiemiddel","ru":"Восстановитель","zh":"还原剂","pt_BR":"Agente Redutor","pt_PT":"Agente Redutor"}, back_translations: {"es":"Una sustancia que reduce outra al doar electrones (siendo ela propia oxidada). Agentes redutores comuns: H₂, metais (Na, Zn, Fe), C, CO, NaBH₄.","de":"Eine Substanz, die eine andere reduziert, indem sie selbst Elektronen abgibt (also oxidiert wird). Gängige Reduktionsmittel: H₂, Metalle (Na, Zn, Fe), C, CO, NaBH₄.","fr":"Une substance qui réduit une autre en lui cédant des électrons (elle est elle-même oxydée). Agents réducteurs courants : H₂, métaux (Na, Zn, Fe), C, CO, NaBH₄.","tr":"Başka bir maddeyi kendisi elektron vererek (dolayısıyla oksitlenerek) indirgeyen madde. Yaygın indirgenler: H₂, metaller (Na, Zn, Fe), C, CO, NaBH₄.","nl":"Een stof die een andere stof reduceert door zelf elektronen af te geven (en dus geoxideerd wordt). Veelgebruikte reductiemiddelen: H₂, metalen (Na, Zn, Fe), C, CO, NaBH₄.","ru":"Вещество, восстанавливающее другое путём отдачи электронов (само при этом окисляется). Распространённые восстановители: H₂, металлы (Na, Zn, Fe), C, CO, NaBH₄.","zh":"通过自身失去电子（即被氧化）来还原另一种物质的物质。常见还原剂：H₂、金属（Na、Zn、Fe）、C、CO、NaBH₄。","pt_BR":"Uma substância que reduz outra ao doar elétrons (sendo ela própria oxidada). Agentes redutores comuns: H₂, metais (Na, Zn, Fe), C, CO, NaBH₄.","pt_PT":"Uma substância que reduz outra ao ceder eletrões (sendo ela própria oxidada). Agentes redutores comuns: H₂, metais (Na, Zn, Fe), C, CO, NaBH₄."}},
  { id: 'dc-chemistry-0106', deck_id: 'deck-chemistry', sort_order: 106, front: "Electron Configuration", back: "Describes how electrons occupy orbitals (s, p, d, f). Follow Aufbau principle (lowest energy first), Hund's rule (maximize unpaired electrons in degenerate orbitals), and Pauli exclusion principle." , front_translations: {"es":"Configuración Electrónica","de":"Elektronenkonfiguration","fr":"Configuration électronique","tr":"Elektron Konfigürasyonu","nl":"Elektronenconfiguratie","ru":"Электронная конфигурация","zh":"电子构型","pt_BR":"Configuração Eletrônica","pt_PT":"Configuração Electrónica"}, back_translations: {"es":"Descreve como los electrones ocupam los orbitais (s, p, d, f). Seguir el principio de Aufbau (menor energía primero), a regra de Hund (maximizar electrones no emparelhados en orbitais degenerados) y el principio de exclusão de Pauli.","de":"Beschreibt, wie Elektronen Orbitale (s, p, d, f) besetzen. Nach dem Aufbauprinzip (niedrigste Energie zuerst), Hund'scher Regel (maximale Anzahl ungepaarter Elektronen in entarteten Orbitalen) und Pauli-Ausschlussprinzip.","fr":"Décrit comment les électrons occupent les orbitales (s, p, d, f). Suivre le principe d'Aufbau (énergie la plus basse d'abord), la règle de Hund (maximiser les électrons non appariés dans des orbitales dégénérées) et le principe d'exclusion de Pauli.","tr":"Elektronların orbitalleri (s, p, d, f) nasıl doldurduğunu tanımlar. Aufbau ilkesi (önce en düşük enerji), Hund kuralı (dejenere orbitallerde eşleşmemiş elektron sayısını maksimize et) ve Pauli dışlama ilkesini izler.","nl":"Beschrijft hoe elektronen orbitalen (s, p, d, f) bezetten. Volg het Aufbau-principe (laagste energie eerst), de regel van Hund (maximaliseer ongepaarde elektronen in degeneratieve orbitalen) en het uitsluitingsprincipe van Pauli.","ru":"Описывает распределение электронов по орбиталям (s, p, d, f). Следует принципу Ауфбау (заполнение с наименьшей энергии), правилу Хунда (максимизация неспаренных электронов на вырожденных орбиталях) и принципу запрета Паули.","zh":"描述电子如何占据轨道（s、p、d、f）。遵循构造原理（从最低能量开始）、洪特规则（简并轨道上未成对电子数最大）和泡利不相容原理。","pt_BR":"Descreve como os elétrons ocupam os orbitais (s, p, d, f). Seguir o princípio de Aufbau (menor energia primeiro), a regra de Hund (maximizar elétrons não emparelhados em orbitais degenerados) e o princípio de exclusão de Pauli.","pt_PT":"Descreve como os eletrões ocupam os orbitais (s, p, d, f). Seguir o princípio de Aufbau (menor energia primeiro), a regra de Hund (maximizar eletrões não emparelhados em orbitais degenerados) e o princípio de exclusão de Pauli."}},
  { id: 'dc-chemistry-0107', deck_id: 'deck-chemistry', sort_order: 107, front: "Quantum Numbers", back: "Four numbers describing each electron: n (principal shell), l (shape: s,p,d,f), m_l (orbital orientation), m_s (spin: +½ or −½). No two electrons in an atom can have identical sets." , front_translations: {"es":"Números Quanticos","de":"Quantenzahlen","fr":"Nombres quantiques","tr":"Kuantum Sayıları","nl":"Kwantumgetallen","ru":"Квантовые числа","zh":"量子数","pt_BR":"Números Quânticos","pt_PT":"Números Quânticos"}, back_translations: {"es":"Cuatro números descrevem cada electrón: n (capa principal), l (forma: s,p,d,f), m_l (orientación del orbital), m_s (spin: +½ o −½). Dos electrones en el mismo átomo no pueden ter conjuntos identicos.","de":"Vier Zahlen beschreiben jedes Elektron: n (Hauptschale), l (Form: s,p,d,f), m_l (Orbitalorientierung), m_s (Spin: +½ oder −½). Keine zwei Elektronen in einem Atom dürfen identische Sätze haben.","fr":"Quatre nombres décrivent chaque électron : n (couche principale), l (forme : s,p,d,f), m_l (orientation de l'orbitale), m_s (spin : +½ ou −½). Deux électrons dans un atome ne peuvent pas avoir des ensembles identiques.","tr":"Dört sayı her elektronu tanımlar: n (ana kabuk), l (şekil: s,p,d,f), m_l (orbital yönelimi), m_s (spin: +½ veya −½). Bir atomdaki iki elektron aynı sete sahip olamaz.","nl":"Vier getallen beschrijven elk elektron: n (hoofdschil), l (vorm: s,p,d,f), m_l (orbitaaloriëntatie), m_s (spin: +½ of −½). Geen twee elektronen in een atoom kunnen identieke sets hebben.","ru":"Четыре числа описывают каждый электрон: n (главная оболочка), l (форма: s, p, d, f), m_l (ориентация орбитали), m_s (спин: +½ или −½). Никакие два электрона в атоме не могут иметь одинаковые наборы.","zh":"四个量子数描述每个电子：n（主量子数/壳层）、l（形状：s,p,d,f）、m_l（轨道取向）、m_s（自旋：+½或−½）。同一原子中没有两个电子具有完全相同的量子数组合。","pt_BR":"Quatro números descrevem cada elétron: n (camada principal), l (forma: s,p,d,f), m_l (orientação do orbital), m_s (spin: +½ ou −½). Dois elétrons no mesmo átomo não podem ter conjuntos idênticos.","pt_PT":"Quatro números descrevem cada eletrão: n (camada principal), l (forma: s,p,d,f), m_l (orientação do orbital), m_s (spin: +½ ou −½). Dois eletrões no mesmo átomo não podem ter conjuntos idênticos."}},
  { id: 'dc-chemistry-0108', deck_id: 'deck-chemistry', sort_order: 108, front: "Hybridization: sp³", back: "One s and three p orbitals hybridize to form four sp³ orbitals arranged tetrahedrally (109.5°). Found in alkanes, water, and ammonia. Each sp³ orbital participates in a sigma bond." , front_translations: {"es":"Hibridización: sp³","de":"Hybridisierung: sp³","fr":"Hybridation : sp³","tr":"Hibridizasyon: sp³","nl":"Hybridisatie: sp³","ru":"Гибридизация: sp³","zh":"杂化：sp³","pt_BR":"Hibridização: sp³","pt_PT":"Hibridização: sp³"}, back_translations: {"es":"Un orbital s y tres orbitais p hibridizam para formar cuatro orbitais sp³ en arranjo tetraédrico (109,5°). Encontrado en alcanos, agua y amonia. Cada orbital sp³ participa de una enlace sigma.","de":"Ein s- und drei p-Orbitale hybridisieren zu vier sp³-Orbitalen in tetraedrischer Anordnung (109,5°). Zu finden in Alkanen, Wasser und Ammoniak. Jedes sp³-Orbital bildet eine Sigma-Bindung.","fr":"Un orbital s et trois orbitaux p s'hybrident pour former quatre orbitaux sp³ disposés de façon tétraédrique (109,5°). Présent dans les alcanes, l'eau et l'ammoniac. Chaque orbital sp³ participe à une liaison sigma.","tr":"Bir s ve üç p orbitali hibridize olarak dört sp³ orbitali oluşturur ve bunlar tetrahedron şeklinde düzenlenir (109,5°). Alkanlarda, suda ve amonyakta bulunur. Her sp³ orbitali sigma bağına katılır.","nl":"Één s- en drie p-orbitalen hybridiseren tot vier sp³-orbitalen in tetraëdrische opstelling (109,5°). Aanwezig in alkanen, water en ammoniak. Elk sp³-orbitaal neemt deel aan een sigma-binding.","ru":"Одна s- и три p-орбитали гибридизируются, образуя четыре sp³-орбитали в тетраэдрической геометрии (109,5°). Встречается в алканах, воде и аммиаке. Каждая sp³-орбиталь участвует в сигма-связи.","zh":"一个s轨道和三个p轨道杂化形成四个sp³杂化轨道，呈四面体排列（109.5°）。存在于烷烃、水和氨中。每个sp³轨道参与形成一个σ键。","pt_BR":"Um orbital s e três orbitais p hibridizam para formar quatro orbitais sp³ em arranjo tetraédrico (109,5°). Encontrado em alcanos, água e amônia. Cada orbital sp³ participa de uma ligação sigma.","pt_PT":"Um orbital s e três orbitais p hibridizam para formar quatro orbitais sp³ em disposição tetraédrica (109,5°). Presente em alcanos, água e amónia. Cada orbital sp³ participa numa ligação sigma."}},
  { id: 'dc-chemistry-0109', deck_id: 'deck-chemistry', sort_order: 109, front: "Hybridization: sp²", back: "One s and two p orbitals hybridize to give three sp² orbitals (120°, planar). One unhybridized p forms a π bond. Found in alkenes, benzene, and carbonyl groups." , front_translations: {"es":"Hibridización: sp²","de":"Hybridisierung: sp²","fr":"Hybridation : sp²","tr":"Hibridizasyon: sp²","nl":"Hybridisatie: sp²","ru":"Гибридизация: sp²","zh":"杂化：sp²","pt_BR":"Hibridização: sp²","pt_PT":"Hibridização: sp²"}, back_translations: {"es":"Un orbital s y de los orbitais p hibridizam para dar tres orbitais sp² (120°, planares). Un orbital p no hibridizado forma una enlace π. Encontrado en alcenos, benzeno y grupos carbonila.","de":"Ein s- und zwei p-Orbitale hybridisieren zu drei sp²-Orbitalen (120°, planar). Ein nicht hybridisiertes p bildet eine π-Bindung. Zu finden in Alkenen, Benzol und Carbonylgruppen.","fr":"Un orbital s et deux orbitaux p s'hybrident pour donner trois orbitaux sp² (120°, plan). Un orbital p non hybridé forme une liaison π. Présent dans les alcènes, le benzène et les groupes carbonyle.","tr":"Bir s ve iki p orbitali hibridize olarak üç sp² orbitali oluşturur (120°, düzlemsel). Hibridize olmayan bir p orbitali π bağı oluşturur. Alkenlerde, benzende ve karbonil gruplarında bulunur.","nl":"Één s- en twee p-orbitalen hybridiseren tot drie sp²-orbitalen (120°, planair). Één niet-gehybridiseerd p-orbitaal vormt een π-binding. Aanwezig in alkenen, benzeen en carbonylgroepen.","ru":"Одна s- и две p-орбитали гибридизируются, образуя три sp²-орбитали (120°, плоские). Одна негибридизованная p-орбиталь образует π-связь. Встречается в алкенах, бензоле и карбонильных группах.","zh":"一个s轨道和两个p轨道杂化形成三个sp²杂化轨道（120°，平面型）。一个未杂化的p轨道形成π键。存在于烯烃、苯和羰基中。","pt_BR":"Um orbital s e dois orbitais p hibridizam para dar três orbitais sp² (120°, planares). Um orbital p não hibridizado forma uma ligação π. Encontrado em alcenos, benzeno e grupos carbonila.","pt_PT":"Um orbital s e dois orbitais p hibridizam para dar três orbitais sp² (120°, planares). Um orbital p não hibridizado forma uma ligação π. Presente em alcenos, benzeno e grupos carbonilo."}},
  { id: 'dc-chemistry-0110', deck_id: 'deck-chemistry', sort_order: 110, front: "Hybridization: sp", back: "One s and one p orbital hybridize to give two sp orbitals arranged linearly (180°). Two unhybridized p orbitals form two π bonds. Found in alkynes and CO₂." , front_translations: {"es":"Hibridización: sp","de":"Hybridisierung: sp","fr":"Hybridation : sp","tr":"Hibridizasyon: sp","nl":"Hybridisatie: sp","ru":"Гибридизация: sp","zh":"杂化：sp","pt_BR":"Hibridização: sp","pt_PT":"Hibridização: sp"}, back_translations: {"es":"Un orbital s y un orbital p hibridizam para dar de los orbitais sp en disposición linear (180°). Dos orbitais p no hibridizados forman de los enlaces π. Encontrado en alcinos y CO₂.","de":"Ein s- und ein p-Orbital hybridisieren zu zwei sp-Orbitalen in linearer Anordnung (180°). Zwei nicht hybridisierte p-Orbitale bilden zwei π-Bindungen. Zu finden in Alkinen und CO₂.","fr":"Un orbital s et un orbital p s'hybrident pour donner deux orbitaux sp en disposition linéaire (180°). Deux orbitaux p non hybridés forment deux liaisons π. Présent dans les alcynes et CO₂.","tr":"Bir s ve bir p orbitali hibridize olarak iki sp orbitali oluşturur ve bunlar doğrusal şekilde düzenlenir (180°). İki hibridize olmayan p orbitali iki π bağı oluşturur. Alkinsler ve CO₂'de bulunur.","nl":"Één s- en één p-orbitaal hybridiseren tot twee sp-orbitalen in lineaire opstelling (180°). Twee niet-gehybridiseerde p-orbitalen vormen twee π-bindingen. Aanwezig in alkynen en CO₂.","ru":"Одна s- и одна p-орбиталь гибридизируются, образуя две sp-орбитали в линейной геометрии (180°). Две негибридизованные p-орбитали образуют две π-связи. Встречается в алкинах и CO₂.","zh":"一个s轨道和一个p轨道杂化形成两个sp杂化轨道，呈直线型排列（180°）。两个未杂化的p轨道形成两个π键。存在于炔烃和CO₂中。","pt_BR":"Um orbital s e um orbital p hibridizam para dar dois orbitais sp em disposição linear (180°). Dois orbitais p não hibridizados formam duas ligações π. Encontrado em alcinos e CO₂.","pt_PT":"Um orbital s e um orbital p hibridizam para dar dois orbitais sp em disposição linear (180°). Dois orbitais p não hibridizados formam duas ligações π. Presente em alcinos e CO₂."}},
  { id: 'dc-chemistry-0111', deck_id: 'deck-chemistry', sort_order: 111, front: "Titration", back: "A technique where a solution of known concentration (titrant) is added to a solution of unknown concentration until the equivalence point is reached. Used to determine acid/base or redox concentrations." , front_translations: {"es":"Titulación","de":"Titration","fr":"Titration","tr":"Titrasyon","nl":"Titratie","ru":"Титрование","zh":"滴定","pt_BR":"Titulação","pt_PT":"Titulação"}, back_translations: {"es":"Técnica en que una solución de concentración conocida (titulante) es adicionada a una solución de concentración desconhecida hasta el punto de equivalencia ser atingido. Usada para determinar concentraciones de ácido/base o redox.","de":"Eine Technik, bei der eine Lösung bekannter Konzentration (Titrant) zu einer Lösung unbekannter Konzentration hinzugegeben wird, bis der Äquivalenzpunkt erreicht ist. Wird verwendet, um Säure-/Base- oder Redoxkonzentrationen zu bestimmen.","fr":"Technique consistant à ajouter une solution de concentration connue (titrant) à une solution de concentration inconnue jusqu'au point d'équivalence. Utilisée pour déterminer les concentrations acide/base ou redox.","tr":"Bilinen konsantrasyondaki bir çözeltinin (titrant) eşdeğerlik noktasına ulaşılana kadar bilinmeyen konsantrasyondaki bir çözeltiye eklendiği bir teknik. Asit/baz veya redoks konsantrasyonlarını belirlemek için kullanılır.","nl":"Een techniek waarbij een oplossing van bekende concentratie (titrant) wordt toegevoegd aan een oplossing van onbekende concentratie totdat het equivalentiepunt is bereikt. Gebruikt om zuur/base- of redoxconcentraties te bepalen.","ru":"Метод, при котором раствор известной концентрации (титрант) добавляется к раствору неизвестной концентрации до достижения точки эквивалентности. Используется для определения концентраций кислот/оснований или редокс-систем.","zh":"将已知浓度的溶液（滴定剂）加入未知浓度的溶液中，直至到达当量点的分析技术。用于测定酸/碱或氧化还原浓度。","pt_BR":"Técnica em que uma solução de concentração conhecida (titulante) é adicionada a uma solução de concentração desconhecida até o ponto de equivalência ser atingido. Usada para determinar concentrações de ácido/base ou redox.","pt_PT":"Técnica em que uma solução de concentração conhecida (titulante) é adicionada a uma solução de concentração desconhecida até ao ponto de equivalência. Utilizada para determinar concentrações de ácido/base ou redox."}},
  { id: 'dc-chemistry-0112', deck_id: 'deck-chemistry', sort_order: 112, front: "Equivalence Point vs. Endpoint", back: "Equivalence point: stoichiometric amounts of acid and base have reacted. Endpoint: when the indicator changes color, ideally coinciding with the equivalence point. They may differ slightly." , front_translations: {"es":"Punto de Equivalencia vs. Punto Final","de":"Äquivalenzpunkt vs. Endpunkt","fr":"Point d'équivalence vs. point de fin","tr":"Eşdeğerlik Noktası ve Bitiş Noktası","nl":"Equivalentiepunt vs. eindpunt","ru":"Точка эквивалентности и конечная точка","zh":"当量点与终点","pt_BR":"Ponto de Equivalência vs. Ponto Final","pt_PT":"Ponto de Equivalência vs. Ponto Final"}, back_translations: {"es":"Punto de equivalencia: quantidades estequiométricas de ácido y base reagiram. Punto final: cuando el indicador muda de cor, idealmente coincidindo con el punto de equivalencia. Pueden diferir ligeiramente.","de":"Äquivalenzpunkt: Stöchiometrische Mengen von Säure und Base haben reagiert. Endpunkt: Wenn der Indikator die Farbe wechselt, idealerweise mit dem Äquivalenzpunkt übereinstimmend. Sie können leicht voneinander abweichen.","fr":"Point d'équivalence : les quantités stœchiométriques d'acide et de base ont réagi. Point de fin : lorsque l'indicateur change de couleur, idéalement coïncidant avec le point d'équivalence. Ils peuvent légèrement différer.","tr":"Eşdeğerlik noktası: asit ve bazın stokiyometrik miktarları reaksiyona girmiştir. Bitiş noktası: indikatörün renk değiştirdiği an; ideal olarak eşdeğerlik noktasıyla çakışır. İkisi arasında küçük fark olabilir.","nl":"Equivalentiepunt: stoichiometrische hoeveelheden zuur en base hebben gereageerd. Eindpunt: wanneer de indicator van kleur verandert, idealiter samenvallend met het equivalentiepunt. Ze kunnen licht verschillen.","ru":"Точка эквивалентности: прореагировали стехиометрические количества кислоты и основания. Конечная точка: момент изменения цвета индикатора, в идеале совпадающий с точкой эквивалентности. Они могут немного различаться.","zh":"当量点：酸和碱以化学计量比完全反应。终点：指示剂发生颜色变化的时刻，理想情况下与当量点重合。两者可能略有偏差。","pt_BR":"Ponto de equivalência: quantidades estequiométricas de ácido e base reagiram. Ponto final: quando o indicador muda de cor, idealmente coincidindo com o ponto de equivalência. Podem diferir ligeiramente.","pt_PT":"Ponto de equivalência: quantidades estequiométricas de ácido e base reagiram. Ponto final: quando o indicador muda de cor, idealmente coincidindo com o ponto de equivalência. Podem diferir ligeiramente."}},
  { id: 'dc-chemistry-0113', deck_id: 'deck-chemistry', sort_order: 113, front: "Chromatography", back: "A separation technique based on differential migration through a stationary phase by a mobile phase. Types: paper, thin-layer (TLC), gas (GC), high-performance liquid (HPLC). Rf = distance moved by solute/distance moved by solvent." , front_translations: {"es":"Cromatografia","de":"Chromatographie","fr":"Chromatographie","tr":"Kromatografi","nl":"Chromatografie","ru":"Хроматография","zh":"色谱法","pt_BR":"Cromatografia","pt_PT":"Cromatografia"}, back_translations: {"es":"Técnica de separación basada en la migración diferencial a través de una fase estacionária por una fase móvel. Tipos: papel, capa delgada (TLC), gas (GC), líquido de alta eficiencia (HPLC). Rf = distancia percorrida por el soluto / distancia percorrida por el disolvente.","de":"Eine Trenntechnik, die auf der unterschiedlichen Wanderung durch eine stationäre Phase mittels einer mobilen Phase basiert. Arten: Papier-, Dünnschicht- (DC), Gas- (GC), Hochleistungsflüssigchromatographie (HPLC). Rf = zurückgelegte Strecke des Analyten / zurückgelegte Strecke des Lösungsmittels.","fr":"Technique de séparation basée sur la migration différentielle à travers une phase stationnaire par une phase mobile. Types : papier, couche mince (CCM), gaz (GC), haute performance (HPLC). Rf = distance parcourue par le soluté / distance parcourue par le solvant.","tr":"Hareketli fazın sabit fazdan geçişindeki farklı göçe dayalı bir ayırma tekniği. Türleri: kağıt, ince tabaka (TLC), gaz (GC), yüksek performanslı sıvı (HPLC). Rf = çözünen maddenin aldığı yol / çözücünün aldığı yol.","nl":"Een scheidingstechniek gebaseerd op differentiële migratie door een stationaire fase door een mobiele fase. Typen: papier, dunnelaag (TLC), gas (GC), hogedruk vloeistof (HPLC). Rf = afgelegde afstand door opgeloste stof / afgelegde afstand door oplosmiddel.","ru":"Метод разделения, основанный на различном перемещении через неподвижную фазу при помощи подвижной фазы. Виды: бумажная, тонкослойная (ТСХ), газовая (ГХ), высокоэффективная жидкостная (ВЭЖХ). Rf = расстояние, пройденное растворённым веществом / расстояние, пройденное растворителем.","zh":"基于组分在固定相中随流动相迁移速率不同而分离的技术。类型：纸色谱、薄层色谱（TLC）、气相色谱（GC）、高效液相色谱（HPLC）。Rf = 溶质移动距离/溶剂移动距离。","pt_BR":"Técnica de separação baseada na migração diferencial através de uma fase estacionária por uma fase móvel. Tipos: papel, camada delgada (TLC), gás (GC), líquido de alta eficiência (HPLC). Rf = distância percorrida pelo soluto / distância percorrida pelo solvente.","pt_PT":"Técnica de separação baseada na migração diferencial através de uma fase estacionária por uma fase móvel. Tipos: papel, camada fina (TLC), gás (GC), líquido de alta eficiência (HPLC). Rf = distância percorrida pelo soluto / distância percorrida pelo solvente."}},
  { id: 'dc-chemistry-0114', deck_id: 'deck-chemistry', sort_order: 114, front: "Spectroscopy: Beer-Lambert Law", back: "A = εlc. Absorbance equals molar absorptivity times path length times concentration. Allows determination of concentration by measuring how much light a solution absorbs at a specific wavelength." , front_translations: {"es":"Espectroscopia: Ley de Beer-Lambert","de":"Spektroskopie: Beer-Lambert-Gesetz","fr":"Spectroscopie : Loi de Beer-Lambert","tr":"Spektroskopi: Beer-Lambert Yasası","nl":"Spectroscopie: Wet van Beer-Lambert","ru":"Спектроскопия: закон Бугера–Ламберта–Бера","zh":"光谱学：朗伯-比尔定律","pt_BR":"Espectroscopia: Lei de Beer-Lambert","pt_PT":"Espectroscopia: Lei de Beer-Lambert"}, back_translations: {"es":"La = εlc. La absorbancia es igual a la absortividad molar veces el comprimento del percurso veces a concentración. Permite determinar a concentración midiendo quanta luz una solución absorbe en un comprimento de onda específico.","de":"A = εlc. Die Absorption ist gleich dem molaren Absorptionskoeffizienten multipliziert mit der Schichtdicke und der Konzentration. Ermöglicht die Konzentrationsbestimmung durch Messung der Lichtabsorption bei einer bestimmten Wellenlänge.","fr":"A = εlc. L'absorbance est égale à l'absorptivité molaire multipliée par la longueur du trajet et la concentration. Permet de déterminer la concentration en mesurant la quantité de lumière absorbée par une solution à une longueur d'onde donnée.","tr":"A = εlc. Absorbans, molar absorbivite ile yol uzunluğu ve konsantrasyonun çarpımına eşittir. Belirli bir dalga boyunda çözeltinin ne kadar ışık absorpladığını ölçerek konsantrasyon belirlemeye olanak tanır.","nl":"A = εlc. Absorptie is gelijk aan molaire absorptiviteit maal padlengte maal concentratie. Maakt het mogelijk concentratie te bepalen door te meten hoeveel licht een oplossing absorbeert op een specifieke golflengte.","ru":"A = εlc. Оптическая плотность равна произведению молярного коэффициента поглощения, длины пути и концентрации. Позволяет определять концентрацию по измерению поглощения света раствором на заданной длине волны.","zh":"A = εlc。吸光度等于摩尔吸光系数乘以光程长度乘以浓度。通过测量溶液在特定波长下的吸光度来确定浓度。","pt_BR":"A = εlc. A absorbância é igual à absortividade molar vezes o comprimento do percurso vezes a concentração. Permite determinar a concentração medindo quanta luz uma solução absorve em um comprimento de onda específico.","pt_PT":"A = εlc. A absorbância é igual à absortividade molar vezes o comprimento do percurso vezes a concentração. Permite determinar a concentração medindo quanta luz uma solução absorve a um comprimento de onda específico."}},
  { id: 'dc-chemistry-0115', deck_id: 'deck-chemistry', sort_order: 115, front: "Nuclear Magnetic Resonance (NMR)", back: "Spectroscopic technique that uses radiofrequency radiation to probe the chemical environment of ¹H and ¹³C nuclei. Different proton environments give different chemical shifts, used to determine molecular structure." , front_translations: {"es":"Ressonancia Magnética Nuclear (RMN)","de":"Kernspinresonanz (NMR)","fr":"Résonance magnétique nucléaire (RMN)","tr":"Nükleer Manyetik Rezonans (NMR)","nl":"Kernspinresonantie (NMR)","ru":"Ядерный магнитный резонанс (ЯМР)","zh":"核磁共振（NMR）","pt_BR":"Ressonância Magnética Nuclear (RMN)","pt_PT":"Ressonância Magnética Nuclear (RMN)"}, back_translations: {"es":"Técnica espectroscópica que usa radiación de radiofrequencia para sondar el ambiente químico de los núcleos ¹H y ¹³C. Diferentes ambientes de protones proporcionan diferentes deslocamentos químicos, usados para determinar a estructura molecular.","de":"Spektroskopische Technik, die Hochfrequenzstrahlung nutzt, um die chemische Umgebung von ¹H- und ¹³C-Kernen zu untersuchen. Verschiedene Protonumgebungen liefern unterschiedliche chemische Verschiebungen, die zur Bestimmung der Molekülstruktur verwendet werden.","fr":"Technique spectroscopique qui utilise le rayonnement en radiofréquences pour sonder l'environnement chimique des noyaux ¹H et ¹³C. Différents environnements de protons donnent différents déplacements chimiques, utilisés pour déterminer la structure moléculaire.","tr":"¹H ve ¹³C çekirdeklerinin kimyasal ortamını araştırmak için radyofrekans radyasyon kullanan spektroskopik teknik. Farklı proton ortamları farklı kimyasal kaymalar verir; moleküler yapıyı belirlemek için kullanılır.","nl":"Spectroscopische techniek die radiofrequentiestraling gebruikt om de chemische omgeving van ¹H- en ¹³C-kernen te onderzoeken. Verschillende protonenomgevingen geven verschillende chemische verschuivingen, gebruikt om moleculaire structuur te bepalen.","ru":"Спектроскопический метод, использующий радиочастотное излучение для изучения химического окружения ядер ¹H и ¹³C. Разные окружения протонов дают разные химические сдвиги, применяемые для определения структуры молекул.","zh":"利用射频辐射探测¹H和¹³C核化学环境的光谱技术。不同的质子环境产生不同的化学位移，用于确定分子结构。","pt_BR":"Técnica espectroscópica que usa radiação de radiofrequência para sondar o ambiente químico dos núcleos ¹H e ¹³C. Diferentes ambientes de prótons fornecem diferentes deslocamentos químicos, usados para determinar a estrutura molecular.","pt_PT":"Técnica espectroscópica que utiliza radiação de radiofrequência para sondar o ambiente químico dos núcleos ¹H e ¹³C. Diferentes ambientes de protões fornecem diferentes desvios químicos, usados para determinar a estrutura molecular."}},
  { id: 'dc-chemistry-0116', deck_id: 'deck-chemistry', sort_order: 116, front: "Functional Group: Carboxylic Acid (-COOH)", back: "An –OH bonded to a carbonyl carbon. Weak acid; the carbonyl makes the O–H bond very polar. Forms hydrogen bonds; relatively high boiling points. Acetic acid (CH₃COOH) is the simplest example." , front_translations: {"es":"Grupo Funcional: Ácido Carboxílico (-COOH)","de":"Funktionelle Gruppe: Carbonsäure (-COOH)","fr":"Groupe fonctionnel : Acide carboxylique (-COOH)","tr":"Fonksiyonel Grup: Karboksilik Asit (-COOH)","nl":"Functionele groep: Carbonzuur (-COOH)","ru":"Функциональная группа: карбоксильная кислота (-COOH)","zh":"官能团：羧酸（-COOH）","pt_BR":"Grupo Funcional: Ácido Carboxílico (-COOH)","pt_PT":"Grupo Funcional: Ácido Carboxílico (-COOH)"}, back_translations: {"es":"Un grupo –OH ligado a un carbono carbonila. Ácido débil; a carbonila torna a enlace El–H muy polar. Forma enlaces de hidrógeno; puntos de ebullición relativamente altos. Ácido acético (CH₃COOH) es el ejemplo más simples.","de":"Eine –OH-Gruppe, die an ein Carbonylkohlenstoffatom gebunden ist. Schwache Säure; die Carbonylgruppe macht die O–H-Bindung sehr polar. Bildet Wasserstoffbrücken; relativ hohe Siedepunkte. Essigsäure (CH₃COOH) ist das einfachste Beispiel.","fr":"Un groupe –OH lié à un carbone carbonyle. Acide faible ; le carbonyle rend la liaison O–H très polaire. Forme des liaisons hydrogène ; points d'ébullition relativement élevés. L'acide acétique (CH₃COOH) est l'exemple le plus simple.","tr":"Bir karbonil karbonuna bağlı –OH grubu. Zayıf asit; karbonil grubu O–H bağını çok polar yapar. Hidrojen bağları oluşturur; görece yüksek kaynama noktaları. Asetik asit (CH₃COOH) en basit örnektir.","nl":"Een –OH gebonden aan een carbonylkoolstof. Zwak zuur; het carbonyl maakt de O–H binding zeer polair. Vormt waterstofbruggen; relatief hoge kookpunten. Azijnzuur (CH₃COOH) is het eenvoudigste voorbeeld.","ru":"Группа –OH, присоединённая к карбонильному атому углерода. Слабая кислота; карбонил делает связь O–H очень полярной. Образует водородные связи; относительно высокие температуры кипения. Уксусная кислота (CH₃COOH) — простейший пример.","zh":"连接在羰基碳上的–OH基团。弱酸；羰基使O–H键极性很强。能形成氢键；沸点相对较高。乙酸（CH₃COOH）是最简单的例子。","pt_BR":"Um grupo –OH ligado a um carbono carbonila. Ácido fraco; a carbonila torna a ligação O–H muito polar. Forma ligações de hidrogênio; pontos de ebulição relativamente altos. Ácido acético (CH₃COOH) é o exemplo mais simples.","pt_PT":"Um grupo –OH ligado a um carbono carbonilo. Ácido fraco; o carbonilo torna a ligação O–H muito polar. Forma ligações de hidrogénio; pontos de ebulição relativamente elevados. O ácido acético (CH₃COOH) é o exemplo mais simples."}},
  { id: 'dc-chemistry-0117', deck_id: 'deck-chemistry', sort_order: 117, front: "Amide Bond (Peptide Bond)", back: "Formed between a carboxylic acid and an amine with loss of water (R-CO-NH-R'). The peptide bond links amino acids in proteins. The C–N bond has partial double-bond character due to resonance." , front_translations: {"es":"Enlace Amida (Enlace Peptídica)","de":"Amidbindung (Peptidbindung)","fr":"Liaison amide (liaison peptidique)","tr":"Amid Bağı (Peptit Bağı)","nl":"Amidebinding (peptidebinding)","ru":"Амидная связь (пептидная связь)","zh":"酰胺键（肽键）","pt_BR":"Ligação Amida (Ligação Peptídica)","pt_PT":"Ligação Amida (Ligação Peptídica)"}, back_translations: {"es":"Formada entre un ácido carboxílico y una amina con perda de agua (R-CO-NH-R'). La enlace peptídica une los aminoácidos en las proteínas. La enlace C–N tiene carácter parcial de enlace dupla debido a la ressonancia.","de":"Entsteht zwischen einer Carbonsäure und einem Amin unter Wasserabspaltung (R-CO-NH-R'). Die Peptidbindung verbindet Aminosäuren in Proteinen. Die C–N-Bindung hat aufgrund von Resonanz partiellen Doppelbindungscharakter.","fr":"Formée entre un acide carboxylique et une amine avec perte d'eau (R-CO-NH-R'). La liaison peptidique relie les acides aminés dans les protéines. La liaison C–N a un caractère de double liaison partiel dû à la résonance.","tr":"Bir karboksilik asit ile bir amin arasında su kaybıyla oluşur (R-CO-NH-R'). Peptit bağı, proteinlerdeki amino asitleri birbirine bağlar. C–N bağı, rezonans nedeniyle kısmi çift bağ karakteri taşır.","nl":"Gevormd tussen een carbonzuur en een amine met verlies van water (R-CO-NH-R'). De peptidebinding verbindt aminozuren in eiwitten. De C–N binding heeft partieel dubbelobindingskarakter door resonantie.","ru":"Образуется между карбоновой кислотой и амином с выделением воды (R-CO-NH-R'). Пептидная связь соединяет аминокислоты в белках. Связь C–N имеет частичный характер двойной связи за счёт резонанса.","zh":"由羧酸和胺在失水情况下形成（R-CO-NH-R'）。肽键将蛋白质中的氨基酸连接在一起。由于共振，C–N键具有部分双键特征。","pt_BR":"Formada entre um ácido carboxílico e uma amina com perda de água (R-CO-NH-R'). A ligação peptídica une os aminoácidos nas proteínas. A ligação C–N tem carácter parcial de ligação dupla devido à ressonância.","pt_PT":"Formada entre um ácido carboxílico e uma amina com perda de água (R-CO-NH-R'). A ligação peptídica une os aminoácidos nas proteínas. A ligação C–N tem carácter parcial de ligação dupla devido à ressonância."}},
  { id: 'dc-chemistry-0118', deck_id: 'deck-chemistry', sort_order: 118, front: "Nucleophile", back: "An electron-pair donor that attacks electrophilic (electron-poor) centers. Examples: OH⁻, NH₃, CN⁻, H₂O, halide ions. Central to SN1 and SN2 reactions in organic chemistry." , front_translations: {"es":"Nucleófilo","de":"Nucleophil","fr":"Nucléophile","tr":"Nükleofil","nl":"Nucleofiel","ru":"Нуклеофил","zh":"亲核试剂","pt_BR":"Nucleófilo","pt_PT":"Nucleófilo"}, back_translations: {"es":"Un doador de par de electrones que ataca centros eletrofílicos (pobres en electrones). Ejemplos: OH⁻, NH₃, CN⁻, H₂El, iones halogeneto. Central en las reacciones SN1 y SN2 en la química orgánica.","de":"Ein Elektronenpaardonor, der elektrophile (elektronenarme) Zentren angreift. Beispiele: OH⁻, NH₃, CN⁻, H₂O, Halogenidionen. Zentral für SN1- und SN2-Reaktionen in der organischen Chemie.","fr":"Un donneur de paire d'électrons qui attaque les centres électrophiles (pauvres en électrons). Exemples : OH⁻, NH₃, CN⁻, H₂O, ions halogénures. Central pour les réactions SN1 et SN2 en chimie organique.","tr":"Elektrofilik (elektron zayıf) merkezlere saldıran elektron çifti donörü. Örnekler: OH⁻, NH₃, CN⁻, H₂O, halojenür iyonları. Organik kimyada SN1 ve SN2 reaksiyonlarının temelini oluşturur.","nl":"Een elektronenpaardonor die elektrofiele (elektronarme) centra aanvalt. Voorbeelden: OH⁻, NH₃, CN⁻, H₂O, halogenide-ionen. Centraal bij SN1- en SN2-reacties in de organische chemie.","ru":"Донор электронной пары, атакующий электрофильные (электронодефицитные) центры. Примеры: OH⁻, NH₃, CN⁻, H₂O, галогенид-ионы. Ключевое понятие в реакциях SN1 и SN2 органической химии.","zh":"提供电子对攻击亲电（缺电子）中心的物种。例子：OH⁻、NH₃、CN⁻、H₂O、卤素离子。在有机化学SN1和SN2反应中起核心作用。","pt_BR":"Um doador de par de elétrons que ataca centros eletrofílicos (pobres em elétrons). Exemplos: OH⁻, NH₃, CN⁻, H₂O, íons halogeneto. Central nas reações SN1 e SN2 na química orgânica.","pt_PT":"Um dador de par de eletrões que ataca centros electrofílicos (pobres em eletrões). Exemplos: OH⁻, NH₃, CN⁻, H₂O, iões halogeneto. Central nas reações SN1 e SN2 na química orgânica."}},
  { id: 'dc-chemistry-0119', deck_id: 'deck-chemistry', sort_order: 119, front: "Electrophile", back: "An electron-pair acceptor; an electron-deficient species that attacks nucleophiles. Examples: carbocations (R⁺), carbonyl carbon, BF₃, Br₂ (activated). Key concept in organic mechanism." , front_translations: {"es":"Eletrófilo","de":"Elektrophil","fr":"Électrophile","tr":"Elektrofil","nl":"Elektrofiel","ru":"Электрофил","zh":"亲电试剂","pt_BR":"Eletrófilo","pt_PT":"Electrófilo"}, back_translations: {"es":"Un aceitador de par de electrones; una especie deficiente en electrones que ataca nucleófilos. Ejemplos: carbocátions (R⁺), carbono carbonílico, BF₃, Br₂ (ativado). Concepto-chave en mecanismos de química orgánica.","de":"Ein Elektronenpaarakzeptor; eine elektronendefiziente Spezies, die Nucleophile angreift. Beispiele: Carbokationen (R⁺), Carbonylkohlenstoff, BF₃, Br₂ (aktiviert). Schlüsselbegriff im organischen Reaktionsmechanismus.","fr":"Un accepteur de paire d'électrons ; une espèce déficiente en électrons qui attaque les nucléophiles. Exemples : carbocations (R⁺), carbone carbonyle, BF₃, Br₂ (activé). Concept clé dans les mécanismes de la chimie organique.","tr":"Elektron çifti akseptörü; nükleofillere saldıran elektron yetersiz tür. Örnekler: karbokasyonlar (R⁺), karbonil karbonu, BF₃, Br₂ (aktive edilmiş). Organik mekanizmalarda temel kavram.","nl":"Een elektronenpaaracceptor; een elektronenarm deeltje dat nucleofielen aanvalt. Voorbeelden: carbokationen (R⁺), carbonylkoolstof, BF₃, Br₂ (geactiveerd). Sleutelbegrip in organische reactiemechanismen.","ru":"Акцептор электронной пары; электронодефицитная частица, атакующая нуклеофилы. Примеры: карбокатионы (R⁺), карбонильный углерод, BF₃, Br₂ (активированный). Ключевое понятие в механизмах органических реакций.","zh":"接受电子对的物种；缺电子的物种，攻击亲核试剂。例子：碳正离子（R⁺）、羰基碳、BF₃、Br₂（活化态）。有机反应机理中的核心概念。","pt_BR":"Um aceitador de par de elétrons; uma espécie deficiente em elétrons que ataca nucleófilos. Exemplos: carbocátions (R⁺), carbono carbonílico, BF₃, Br₂ (ativado). Conceito-chave em mecanismos de química orgânica.","pt_PT":"Um aceitador de par de eletrões; uma espécie deficiente em eletrões que ataca nucleófilos. Exemplos: carbocatiões (R⁺), carbono carbonílico, BF₃, Br₂ (ativado). Conceito-chave em mecanismos de química orgânica."}},
  { id: 'dc-chemistry-0120', deck_id: 'deck-chemistry', sort_order: 120, front: "SN2 Reaction", back: "Bimolecular nucleophilic substitution. One-step concerted mechanism; nucleophile attacks from back while leaving group departs. Best with primary alkyl halides; inversion of configuration at sp³ carbon." , front_translations: {"es":"Reacción SN2","de":"SN2-Reaktion","fr":"Réaction SN2","tr":"SN2 Reaksiyonu","nl":"SN2-reactie","ru":"Реакция SN2","zh":"SN2反应","pt_BR":"Reação SN2","pt_PT":"Reação SN2"}, back_translations: {"es":"Substituición nucleofílica bimolecular. Mecanismo concertado en una etapa; el nucleófilo ataca por la retaguarda mientras el grupo de saída parte. Mejor con haletos de alquila primários; inversão de configuración en el carbono sp³.","de":"Bimolekulare nucleophile Substitution. Einstufiger konzertierter Mechanismus; das Nucleophil greift von hinten an, während die Abgangsgruppe gleichzeitig abgeht. Am besten mit primären Alkylhalogeniden; Inversion der Konfiguration am sp³-Kohlenstoff.","fr":"Substitution nucléophile bimoléculaire. Mécanisme concerté en une étape ; le nucléophile attaque par derrière pendant que le groupe partant part. Favorisé avec les halogénoalcanes primaires ; inversion de configuration au carbone sp³.","tr":"Bimolecular nükleofilik sübstitüsyon. Tek aşamalı eşzamanlı mekanizma; nükleofil arkadan saldırırken ayrılan grup ayrılır. En iyi primer alkil halojenürlerle çalışır; sp³ karbonunda konfigurasyon inversiyonu.","nl":"Bimoleculaire nucleofiele substitutie. Eenstaps geconcerteerd mechanisme; nucleofiel valt van achteren aan terwijl de vertrekkende groep vertrekt. Het beste met primaire alkylhalogeniden; inversie van configuratie op sp³-koolstof.","ru":"Бимолекулярное нуклеофильное замещение. Одностадийный согласованный механизм: нуклеофил атакует сзади, пока уходящая группа покидает молекулу. Наилучшим образом протекает с первичными алкилгалогенидами; инверсия конфигурации на sp³-углероде.","zh":"双分子亲核取代反应。单步协同机制；亲核试剂从背面进攻，同时离去基团离去。最适合伯烷基卤化物；sp³碳处构型翻转。","pt_BR":"Substituição nucleofílica bimolecular. Mecanismo concertado em uma etapa; o nucleófilo ataca pela retaguarda enquanto o grupo de saída parte. Melhor com haletos de alquila primários; inversão de configuração no carbono sp³.","pt_PT":"Substituição nucleofílica bimolecular. Mecanismo concertado numa etapa; o nucleófilo ataca pela retaguarda enquanto o grupo de saída parte. Melhor com haletos de alquilo primários; inversão de configuração no carbono sp³."}},
  { id: 'dc-chemistry-0121', deck_id: 'deck-chemistry', sort_order: 121, front: "SN1 Reaction", back: "Unimolecular nucleophilic substitution. Two-step: leaving group departs first forming a carbocation, then nucleophile attacks. Best with tertiary alkyl halides; gives racemic product (mixture of enantiomers)." , front_translations: {"es":"Reacción SN1","de":"SN1-Reaktion","fr":"Réaction SN1","tr":"SN1 Reaksiyonu","nl":"SN1-reactie","ru":"Реакция SN1","zh":"SN1反应","pt_BR":"Reação SN1","pt_PT":"Reação SN1"}, back_translations: {"es":"Substituición nucleofílica unimolecular. Dos etapas: el grupo de saída parte primero formando un carbocátion, después el nucleófilo ataca. Mejor con haletos de alquila terciários; proporciona producto racemico (mistura de enantiomeros).","de":"Unimolekulare nucleophile Substitution. Zweistufig: Zuerst verlässt die Abgangsgruppe und bildet ein Carbokation, dann greift das Nucleophil an. Am besten mit tertiären Alkylhalogeniden; liefert racemisches Produkt (Enantiomerengemisch).","fr":"Substitution nucléophile unimoléculaire. Deux étapes : le groupe partant part d'abord en formant un carbocation, puis le nucléophile attaque. Favorisé avec les halogénoalcanes tertiaires ; donne un produit racémique (mélange d'énantiomères).","tr":"Unimolecular nükleofilik sübstitüsyon. İki aşamalı: önce ayrılan grup ayrılarak bir karbokasyon oluşturur, ardından nükleofil saldırır. En iyi tersiyer alkil halojenürlerle çalışır; rasemik ürün (enantiyomer karışımı) verir.","nl":"Unimoleculaire nucleofiele substitutie. Tweestaps: vertrekkende groep vertrekt eerst, vormt een carbokation, dan valt nucleofiel aan. Het beste met tertiaire alkylhalogeniden; geeft racemisch product (mengsel van enantiomeren).","ru":"Унимолекулярное нуклеофильное замещение. Двухстадийный механизм: сначала уходящая группа покидает молекулу, образуя карбокатион, затем нуклеофил атакует. Наилучшим образом протекает с третичными алкилгалогенидами; даёт рацемический продукт (смесь энантиомеров).","zh":"单分子亲核取代反应。两步机制：离去基团先离去形成碳正离子，然后亲核试剂进攻。最适合叔烷基卤化物；产生消旋产物（对映体混合物）。","pt_BR":"Substituição nucleofílica unimolecular. Duas etapas: o grupo de saída parte primeiro formando um carbocátion, depois o nucleófilo ataca. Melhor com haletos de alquila terciários; fornece produto racêmico (mistura de enantiômeros).","pt_PT":"Substituição nucleofílica unimolecular. Duas etapas: o grupo de saída parte primeiro formando um carbocatião, depois o nucleófilo ataca. Melhor com haletos de alquilo terciários; fornece produto racémico (mistura de enantiómeros)."}},
  { id: 'dc-chemistry-0122', deck_id: 'deck-chemistry', sort_order: 122, front: "Markovnikov's Rule", back: "In addition of H-X to an alkene, the H adds to the carbon that already has more hydrogens (forming the more stable carbocation intermediate). Predicts the major product of electrophilic addition." , front_translations: {"es":"Regra de Markovnikov","de":"Markovnikov-Regel","fr":"Règle de Markovnikov","tr":"Markovnikov Kuralı","nl":"Regel van Markovnikov","ru":"Правило Марковникова","zh":"马尔科夫尼科夫规则","pt_BR":"Regra de Markovnikov","pt_PT":"Regra de Markovnikov"}, back_translations: {"es":"Na adición de H-X a un alceno, el H se adiciona al carbono que ya possui más hidrogenios (formando el intermediário carbocátion más estable). Preve el producto principal de la adición eletrofílica.","de":"Bei der Addition von H–X an ein Alken addiert sich das H an das Kohlenstoffatom, das bereits mehr Wasserstoffatome trägt (dabei wird das stabilere Carbokation als Zwischenstufe gebildet). Sagt das Hauptprodukt der elektrophilen Addition vorher.","fr":"Lors de l'addition de H-X sur un alcène, le H s'ajoute au carbone qui possède déjà le plus d'hydrogènes (formant l'intermédiaire carbocation le plus stable). Prédit le produit majoritaire de l'addition électrophile.","tr":"Bir alkene H-X eklenmesinde, H daha fazla hidrojene sahip karbona eklenir (daha kararlı karbokasyon ara ürünü oluşturarak). Elektrofilik katılmanın ana ürününü öngörür.","nl":"Bij additie van H-X aan een alkeen wordt H toegevoegd aan het koolstofatoom met al de meeste waterstofatomen (vormt het stabielere carbokation intermediair). Voorspelt het hoofdproduct van elektrofiele additie.","ru":"При присоединении H–X к алкену атом H присоединяется к атому углерода, уже имеющему больше атомов водорода (при этом образуется более стабильный карбокатион-интермедиат). Предсказывает основной продукт электрофильного присоединения.","zh":"H-X加成到烯烃时，H加到已有更多氢的碳上（形成更稳定的碳正离子中间体）。预测亲电加成反应的主要产物。","pt_BR":"Na adição de H-X a um alceno, o H se adiciona ao carbono que já possui mais hidrogênios (formando o intermediário carbocátion mais estável). Prevê o produto principal da adição eletrofílica.","pt_PT":"Na adição de H-X a um alceno, o H adiciona-se ao carbono que já possui mais hidrogénios (formando o intermediário carbocatião mais estável). Prevê o produto principal da adição electrofílica."}},
  { id: 'dc-chemistry-0123', deck_id: 'deck-chemistry', sort_order: 123, front: "Grignard Reagent", back: "An organomagnesium halide (RMgX) formed from an alkyl halide and magnesium metal in ether. A powerful nucleophile and strong base. Reacts with carbonyl compounds to form alcohols." , front_translations: {"es":"Reactivo de Grignard","de":"Grignard-Reagenz","fr":"Réactif de Grignard","tr":"Grignard Reaktifi","nl":"Grignard-reagens","ru":"Реагент Гриньяра","zh":"格氏试剂","pt_BR":"Reagente de Grignard","pt_PT":"Reagente de Grignard"}, back_translations: {"es":"Un haleto de organomagnesio (RMgX) formado a partir de un haleto de alquila y magnésio metálico en éter. Un nucleófilo poderoso y base fuerte. Reage con compuestos carbonílicos para formar alcoóis.","de":"Ein Organomagnesiumhalogenid (RMgX), das aus einem Alkylhalogenid und Magnesiummetall in Ether gebildet wird. Ein starkes Nucleophil und eine starke Base. Reagiert mit Carbonylverbindungen unter Bildung von Alkoholen.","fr":"Un halogénure d'organoagnésium (RMgX) formé à partir d'un halogénoalcane et de magnésium métallique dans de l'éther. Un puissant nucléophile et une base forte. Réagit avec les composés carbonylés pour former des alcools.","tr":"Bir alkil halojenür ve magnezyum metalinden eter içinde oluşturulan organomagnezya halojenür (RMgX). Güçlü bir nükleofil ve güçlü bir bazdır. Karbonil bileşikleriyle reaksiyona girerek alkoller oluşturur.","nl":"Een organomagnesiumhalogenide (RMgX) gevormd uit een alkylhalogenide en magnesiummetaal in ether. Een krachtig nucleofiel en sterke base. Reageert met carbonylverbindingen om alcoholen te vormen.","ru":"Органомагниевый галогенид (RMgX), получаемый из алкилгалогенида и металлического магния в эфире. Сильный нуклеофил и сильное основание. Реагирует с карбонильными соединениями с образованием спиртов.","zh":"由烷基卤化物和金属镁在乙醚中反应制备的有机镁卤化物（RMgX）。是强亲核试剂和强碱。与羰基化合物反应生成醇。","pt_BR":"Um haleto de organomagnesio (RMgX) formado a partir de um haleto de alquila e magnésio metálico em éter. Um nucleófilo poderoso e base forte. Reage com compostos carbonílicos para formar alcoóis.","pt_PT":"Um haleto de organomagnesio (RMgX) formado a partir de um haleto de alquilo e magnésio metálico em éter. Um nucleófilo poderoso e uma base forte. Reage com compostos carbonílicos para formar álcoois."}},
  { id: 'dc-chemistry-0124', deck_id: 'deck-chemistry', sort_order: 124, front: "Carbohydrates: Monosaccharides", back: "The simplest carbohydrates; cannot be hydrolyzed further. General formula Cₙ(H₂O)ₙ. Glucose (C₆H₁₂O₆) is the primary cellular fuel. Fructose and galactose are isomers of glucose." , front_translations: {"es":"Carboidratos: Monossacarídeos","de":"Kohlenhydrate: Monosaccharide","fr":"Glucides : Monosaccharides","tr":"Karbonhidratlar: Monosakkaritler","nl":"Koolhydraten: Monosacchariden","ru":"Углеводы: моносахариды","zh":"碳水化合物：单糖","pt_BR":"Carboidratos: Monossacarídeos","pt_PT":"Hidratos de Carbono: Monossacarídeos"}, back_translations: {"es":"Los carboidratos más simples; no pueden ser hidrolisados aún más. Fórmula geral Cₙ(H₂El)ₙ. La glicose (C₆H₁₂El₆) es el combustible celular primário. Frutose y galactose son isomeros de la glicose.","de":"Die einfachsten Kohlenhydrate; können nicht weiter hydrolysiert werden. Allgemeine Formel Cₙ(H₂O)ₙ. Glucose (C₆H₁₂O₆) ist der primäre Zellbrennstoff. Fructose und Galactose sind Isomere der Glucose.","fr":"Les glucides les plus simples ; ne peuvent pas être hydrolysés davantage. Formule générale Cₙ(H₂O)ₙ. Le glucose (C₆H₁₂O₆) est le carburant cellulaire primaire. Le fructose et le galactose sont des isomères du glucose.","tr":"En basit karbonhidratlardır; daha fazla hidroliz edilemezler. Genel formül Cₙ(H₂O)ₙ. Glikoz (C₆H₁₂O₆) birincil hücresel yakıttır. Fruktoz ve galaktoz glikozun izomerleridir.","nl":"De eenvoudigste koolhydraten; kunnen niet verder worden gehydrolyseerd. Algemene formule Cₙ(H₂O)ₙ. Glucose (C₆H₁₂O₆) is de primaire cellulaire brandstof. Fructose en galactose zijn isomeren van glucose.","ru":"Простейшие углеводы; не могут быть гидролизованы дальше. Общая формула Cₙ(H₂O)ₙ. Глюкоза (C₆H₁₂O₆) — основное клеточное топливо. Фруктоза и галактоза — изомеры глюкозы.","zh":"最简单的碳水化合物；不能进一步水解。通式Cₙ(H₂O)ₙ。葡萄糖（C₆H₁₂O₆）是细胞的主要燃料。果糖和半乳糖是葡萄糖的同分异构体。","pt_BR":"Os carboidratos mais simples; não podem ser hidrolisados ainda mais. Fórmula geral Cₙ(H₂O)ₙ. A glicose (C₆H₁₂O₆) é o combustível celular primário. Frutose e galactose são isômeros da glicose.","pt_PT":"Os hidratos de carbono mais simples; não podem ser hidrolisados mais. Fórmula geral Cₙ(H₂O)ₙ. A glucose (C₆H₁₂O₆) é o combustível celular primário. A frutose e a galactose são isómeros da glucose."}},
  { id: 'dc-chemistry-0125', deck_id: 'deck-chemistry', sort_order: 125, front: "Carbohydrates: Disaccharides", back: "Two monosaccharides joined by a glycosidic bond with loss of water. Sucrose (glucose + fructose), lactose (glucose + galactose), maltose (glucose + glucose). Hydrolyzed by specific enzymes." , front_translations: {"es":"Carboidratos: Dissacarídeos","de":"Kohlenhydrate: Disaccharide","fr":"Glucides : Disaccharides","tr":"Karbonhidratlar: Disakkaritler","nl":"Koolhydraten: Disacchariden","ru":"Углеводы: дисахариды","zh":"碳水化合物：二糖","pt_BR":"Carboidratos: Dissacarídeos","pt_PT":"Hidratos de Carbono: Dissacarídeos"}, back_translations: {"es":"Dos monossacarídeos unidos por una enlace glicosídica con perda de agua. Sacarose (glicose + frutose), lactose (glicose + galactose), maltose (glicose + glicose). Hidrolisados por enzimas específicas.","de":"Zwei Monosaccharide, die durch eine glykosidische Bindung unter Wasserabspaltung verbunden sind. Saccharose (Glucose + Fructose), Lactose (Glucose + Galactose), Maltose (Glucose + Glucose). Werden durch spezifische Enzyme hydrolysiert.","fr":"Deux monosaccharides liés par une liaison glycosidique avec perte d'eau. Saccharose (glucose + fructose), lactose (glucose + galactose), maltose (glucose + glucose). Hydrolysés par des enzymes spécifiques.","tr":"Su kaybıyla glikozidik bağla birleşen iki monosakkarit. Sükroz (glikoz + fruktoz), laktoz (glikoz + galaktoz), maltoz (glikoz + glikoz). Özgün enzimler tarafından hidroliz edilir.","nl":"Twee monosacchariden verbonden door een glycosidische binding met verlies van water. Sucrose (glucose + fructose), lactose (glucose + galactose), maltose (glucose + glucose). Gehydrolyseerd door specifieke enzymen.","ru":"Два моносахарида, соединённых гликозидной связью с выделением воды. Сахароза (глюкоза + фруктоза), лактоза (глюкоза + галактоза), мальтоза (глюкоза + глюкоза). Гидролизуются специфическими ферментами.","zh":"两个单糖通过糖苷键失水连接而成。蔗糖（葡萄糖+果糖）、乳糖（葡萄糖+半乳糖）、麦芽糖（葡萄糖+葡萄糖）。由特定酶水解。","pt_BR":"Dois monossacarídeos unidos por uma ligação glicosídica com perda de água. Sacarose (glicose + frutose), lactose (glicose + galactose), maltose (glicose + glicose). Hidrolisados por enzimas específicas.","pt_PT":"Dois monossacarídeos unidos por uma ligação glicosídica com perda de água. Sacarose (glucose + frutose), lactose (glucose + galactose), maltose (glucose + glucose). Hidrolisados por enzimas específicas."}},
  { id: 'dc-chemistry-0126', deck_id: 'deck-chemistry', sort_order: 126, front: "Carbohydrates: Polysaccharides", back: "Long chains of monosaccharides. Starch and glycogen (storage polymers of glucose). Cellulose (structural polymer of glucose with β-glycosidic bonds; most animals cannot digest it)." , front_translations: {"es":"Carboidratos: Polissacarídeos","de":"Kohlenhydrate: Polysaccharide","fr":"Glucides : Polysaccharides","tr":"Karbonhidratlar: Polisakkaritler","nl":"Koolhydraten: Polysachariden","ru":"Углеводы: Полисахариды","zh":"碳水化合物：多糖","pt_BR":"Carboidratos: Polissacarídeos","pt_PT":"Hidratos de Carbono: Polissacarídeos"}, back_translations: {"es":"Largas cadeias de monossacarídeos. Amido y glicogenio (polímeros de almacenamiento de glicose). Celulose (polímero estrutural de glicose con enlaces β-glicosídicas; a maioria de los animales no consegue digeri-la).","de":"Lange Ketten aus Monosacchariden. Stärke und Glykogen (Speicherpolymere der Glucose). Cellulose (Strukturpolymer der Glucose mit β-glykosidischen Bindungen; die meisten Tiere können sie nicht verdauen).","fr":"Longues chaînes de monosaccharides. L'amidon et le glycogène (polymères de stockage du glucose). La cellulose (polymère structural du glucose avec des liaisons β-glycosidiques ; la plupart des animaux ne peuvent pas la digérer).","tr":"Monosakkaritlerin uzun zincirleri. Nişasta ve glikojen (glukozun depolama polimerleri). Selüloz (β-glikozidik bağlara sahip glukozun yapısal polimeri; çoğu hayvan sindiremez).","nl":"Lange ketens van monosacchariden. Zetmeel en glycogeen (opslagpolymeren van glucose). Cellulose (structuurpolymeer van glucose met β-glycosidische bindingen; de meeste dieren kunnen het niet verteren).","ru":"Длинные цепи моносахаридов. Крахмал и гликоген (запасные полимеры глюкозы). Целлюлоза (структурный полимер глюкозы с β-гликозидными связями; большинство животных не могут её переварить).","zh":"由单糖组成的长链。淀粉和糖原（葡萄糖的储存聚合物）。纤维素（具有β-糖苷键的葡萄糖结构聚合物；大多数动物无法消化它）。","pt_BR":"Longas cadeias de monossacarídeos. Amido e glicogênio (polímeros de armazenamento de glicose). Celulose (polímero estrutural de glicose com ligações β-glicosídicas; a maioria dos animais não consegue digeri-la).","pt_PT":"Longas cadeias de monossacarídeos. O amido e o glicogénio (polímeros de armazenamento de glicose). A celulose (polímero estrutural de glicose com ligações β-glicosídicas; a maioria dos animais não consegue digeri-la)."}},
  { id: 'dc-chemistry-0127', deck_id: 'deck-chemistry', sort_order: 127, front: "Lipids: Triglycerides", back: "Esters of glycerol with three fatty acids. Energy-rich storage molecules (9 kcal/g vs. 4 kcal/g for carbs). Saturated fats (solid) have no double bonds; unsaturated fats (liquid) have one or more C=C." , front_translations: {"es":"Lipídeos: Triglicerídeos","de":"Lipide: Triglyceride","fr":"Lipides : Triglycérides","tr":"Lipitler: Trigliseritler","nl":"Lipiden: Triglyceriden","ru":"Липиды: Триглицериды","zh":"脂质：甘油三酯","pt_BR":"Lipídeos: Triglicerídeos","pt_PT":"Lípidos: Triglicerídeos"}, back_translations: {"es":"Ésteres de glicerol con tres ácidos grasos. Moléculas de almacenamiento ricas en energía (9 kcal/g vs. 4 kcal/g para carboidratos). Gorduras saturadas (sólidas) no tienen enlaces duplas; gorduras insaturadas (líquidas) tienen una el más enlaces C=C.","de":"Ester des Glycerols mit drei Fettsäuren. Energiereiche Speichermoleküle (9 kcal/g gegenüber 4 kcal/g bei Kohlenhydraten). Gesättigte Fette (fest) haben keine Doppelbindungen; ungesättigte Fette (flüssig) haben eine oder mehrere C=C-Bindungen.","fr":"Esters du glycérol avec trois acides gras. Molécules de stockage riches en énergie (9 kcal/g contre 4 kcal/g pour les glucides). Les graisses saturées (solides) n'ont pas de doubles liaisons ; les graisses insaturées (liquides) ont une ou plusieurs liaisons C=C.","tr":"Gliserolün üç yağ asidi ile esterleri. Enerji açısından zengin depolama molekülleri (karbonhidratlara karşın 4 kcal/g'a karşı 9 kcal/g). Doymuş yağlar (katı) çift bağ içermez; doymamış yağlar (sıvı) bir veya daha fazla C=C bağı içerir.","nl":"Esters van glycerol met drie vetzuren. Energierijke opslagmoleculen (9 kcal/g vs. 4 kcal/g voor koolhydraten). Verzadigde vetten (vast) hebben geen dubbele bindingen; onverzadigde vetten (vloeibaar) hebben één of meer C=C-bindingen.","ru":"Эфиры глицерина с тремя жирными кислотами. Богатые энергией молекулы для хранения (9 ккал/г против 4 ккал/г у углеводов). Насыщенные жиры (твёрдые) не имеют двойных связей; ненасыщенные жиры (жидкие) имеют одну или несколько связей C=C.","zh":"甘油与三种脂肪酸形成的酯。富含能量的储存分子（9千卡/克，而碳水化合物为4千卡/克）。饱和脂肪（固体）没有双键；不饱和脂肪（液体）有一个或多个C=C双键。","pt_BR":"Ésteres de glicerol com três ácidos graxos. Moléculas de armazenamento ricas em energia (9 kcal/g vs. 4 kcal/g para carboidratos). Gorduras saturadas (sólidas) não têm ligações duplas; gorduras insaturadas (líquidas) têm uma ou mais ligações C=C.","pt_PT":"Ésteres do glicerol com três ácidos gordos. Moléculas de armazenamento ricas em energia (9 kcal/g vs. 4 kcal/g para hidratos de carbono). As gorduras saturadas (sólidas) não têm ligações duplas; as gorduras insaturadas (líquidas) têm uma ou mais ligações C=C."}},
  { id: 'dc-chemistry-0128', deck_id: 'deck-chemistry', sort_order: 128, front: "Amino Acids", back: "The building blocks of proteins; contain both an amino group (–NH₂) and a carboxylic acid (–COOH) group, plus a variable R group. 20 standard amino acids; differ only in their R groups." , front_translations: {"es":"Aminoácidos","de":"Aminosäuren","fr":"Acides aminés","tr":"Amino Asitler","nl":"Aminozuren","ru":"Аминокислоты","zh":"氨基酸","pt_BR":"Aminoácidos","pt_PT":"Aminoácidos"}, back_translations: {"es":"Los blocos de construcción de las proteínas; contem tanto un grupo amino (–NH₂) quanto un grupo ácido carboxílico (–COOH), além de un grupo R variable. 20 aminoácidos padrão; diferem solo en sus grupos R.","de":"Die Bausteine der Proteine; enthalten sowohl eine Aminogruppe (–NH₂) als auch eine Carbonsäuregruppe (–COOH) sowie eine variable R-Gruppe. 20 Standard-Aminosäuren; unterscheiden sich nur in ihren R-Gruppen.","fr":"Les éléments constitutifs des protéines ; contiennent à la fois un groupe aminé (–NH₂) et un groupe acide carboxylique (–COOH), ainsi qu'un groupe R variable. 20 acides aminés standard ; ils ne diffèrent que par leurs groupes R.","tr":"Proteinlerin yapı taşları; hem bir amino grubu (–NH₂) hem de bir karboksilik asit grubu (–COOH) ve değişken bir R grubu içerir. 20 standart amino asit; yalnızca R gruplarında farklılık gösterir.","nl":"De bouwstenen van eiwitten; bevatten zowel een aminogroep (–NH₂) als een carbonzuurgroep (–COOH), plus een variabele R-groep. 20 standaard aminozuren; verschillen alleen in hun R-groepen.","ru":"Строительные блоки белков; содержат как аминогруппу (–NH₂), так и карбоксильную группу (–COOH), а также переменную R-группу. 20 стандартных аминокислот; различаются только своими R-группами.","zh":"蛋白质的构建单元；同时含有氨基（–NH₂）和羧酸基团（–COOH），以及一个可变的R基团。20种标准氨基酸；仅在R基团上有所不同。","pt_BR":"Os blocos de construção das proteínas; contêm tanto um grupo amino (–NH₂) quanto um grupo ácido carboxílico (–COOH), além de um grupo R variável. 20 aminoácidos padrão; diferem apenas em seus grupos R.","pt_PT":"Os blocos de construção das proteínas; contêm tanto um grupo amino (–NH₂) como um grupo ácido carboxílico (–COOH), além de um grupo R variável. 20 aminoácidos padrão; diferem apenas nos seus grupos R."}},
  { id: 'dc-chemistry-0129', deck_id: 'deck-chemistry', sort_order: 129, front: "Chemical Equilibrium", back: "A state in which the rate of the forward reaction equals the rate of the reverse reaction; macroscopic properties remain constant. Does not mean concentrations of reactants and products are equal." , front_translations: {"es":"Equilíbrio Químico","de":"Chemisches Gleichgewicht","fr":"Équilibre chimique","tr":"Kimyasal Denge","nl":"Chemisch evenwicht","ru":"Химическое равновесие","zh":"化学平衡","pt_BR":"Equilíbrio Químico","pt_PT":"Equilíbrio Químico"}, back_translations: {"es":"Un estado en que a taxa de la reacción direta es igual a la taxa de la reacción inversa; las propiedades macroscópicas permanecen constantes. No significa que las concentraciones de reactivos y productos son iguais.","de":"Ein Zustand, bei dem die Rate der Vorwärtsreaktion gleich der Rate der Rückwärtsreaktion ist; makroskopische Eigenschaften bleiben konstant. Bedeutet nicht, dass die Konzentrationen von Edukten und Produkten gleich sind.","fr":"Un état dans lequel la vitesse de la réaction directe est égale à la vitesse de la réaction inverse ; les propriétés macroscopiques restent constantes. Cela ne signifie pas que les concentrations des réactifs et des produits sont égales.","tr":"İleri reaksiyonun hızının geri reaksiyonun hızına eşit olduğu bir durum; makroskopik özellikler sabit kalır. Reaktanların ve ürünlerin konsantrasyonlarının eşit olduğu anlamına gelmez.","nl":"Een toestand waarbij de snelheid van de voorwaartse reactie gelijk is aan de snelheid van de achterwaartse reactie; macroscopische eigenschappen blijven constant. Betekent niet dat de concentraties van reactanten en producten gelijk zijn.","ru":"Состояние, при котором скорость прямой реакции равна скорости обратной реакции; макроскопические свойства остаются постоянными. Не означает, что концентрации реагентов и продуктов равны.","zh":"正反应速率等于逆反应速率的状态；宏观性质保持不变。并不意味着反应物和生成物的浓度相等。","pt_BR":"Um estado em que a taxa da reação direta é igual à taxa da reação inversa; as propriedades macroscópicas permanecem constantes. Não significa que as concentrações de reagentes e produtos são iguais.","pt_PT":"Um estado em que a taxa da reação direta é igual à taxa da reação inversa; as propriedades macroscópicas permanecem constantes. Não significa que as concentrações de reagentes e produtos são iguais."}},
  { id: 'dc-chemistry-0130', deck_id: 'deck-chemistry', sort_order: 130, front: "Reaction Quotient (Q)", back: "Calculated the same way as Kc but using current (non-equilibrium) concentrations. If Q < K, the reaction proceeds forward; if Q > K, it proceeds in reverse; if Q = K, at equilibrium." , front_translations: {"es":"Quociente de Reacción (Q)","de":"Reaktionsquotient (Q)","fr":"Quotient de réaction (Q)","tr":"Reaksiyon Katsayısı (Q)","nl":"Reactiequotiënt (Q)","ru":"Реакционный коэффициент (Q)","zh":"反应商（Q）","pt_BR":"Quociente de Reação (Q)","pt_PT":"Quociente de Reação (Q)"}, back_translations: {"es":"Calculado de la misma forma que Kc, pero usando concentraciones atuais (de no equilíbrio). Se Q < K, a reacción prossegue para frente; se Q > K, prossegue en el sentido inverso; se Q = K, está en equilíbrio.","de":"Wird auf dieselbe Weise wie Kc berechnet, aber mit aktuellen (Nicht-Gleichgewichts-)Konzentrationen. Wenn Q < K, läuft die Reaktion vorwärts; wenn Q > K, läuft sie rückwärts; wenn Q = K, befindet sie sich im Gleichgewicht.","fr":"Calculé de la même manière que Kc mais en utilisant les concentrations actuelles (hors équilibre). Si Q < K, la réaction avance ; si Q > K, elle recule ; si Q = K, elle est à l'équilibre.","tr":"Kc ile aynı şekilde hesaplanır, ancak mevcut (denge dışı) konsantrasyonlar kullanılır. Q < K ise reaksiyon ileri gider; Q > K ise geri gider; Q = K ise dengede demektir.","nl":"Berekend op dezelfde manier als Kc, maar met huidige (niet-evenwichts)concentraties. Als Q < K verloopt de reactie voorwaarts; als Q > K in omgekeerde richting; als Q = K is er evenwicht.","ru":"Вычисляется так же, как Kc, но с использованием текущих (неравновесных) концентраций. Если Q < K, реакция идёт вперёд; если Q > K — в обратном направлении; если Q = K — в равновесии.","zh":"计算方式与Kc相同，但使用当前（非平衡）浓度。若Q < K，反应正向进行；若Q > K，反应逆向进行；若Q = K，则处于平衡状态。","pt_BR":"Calculado da mesma forma que Kc, mas usando concentrações atuais (de não equilíbrio). Se Q < K, a reação prossegue para frente; se Q > K, prossegue no sentido inverso; se Q = K, está em equilíbrio.","pt_PT":"Calculado da mesma forma que Kc, mas usando concentrações atuais (de não equilíbrio). Se Q < K, a reação avança para a frente; se Q > K, avança no sentido inverso; se Q = K, está em equilíbrio."}},
  { id: 'dc-chemistry-0131', deck_id: 'deck-chemistry', sort_order: 131, front: "Formal Charge", back: "Formal charge = valence electrons − nonbonding electrons − ½(bonding electrons). Used to assess the best Lewis structure. Structures with minimal formal charges are more stable." , front_translations: {"es":"Carga Formal","de":"Formale Ladung","fr":"Charge formelle","tr":"Biçimsel Yük","nl":"Formele lading","ru":"Формальный заряд","zh":"形式电荷","pt_BR":"Carga Formal","pt_PT":"Carga Formal"}, back_translations: {"es":"Carga formal = electrones de valencia − electrones no ligantes − ½(electrones ligantes). Usada para avaliar a mejor estructura de Lewis. Estructuras con cargas formais mínimas son más estables.","de":"Formale Ladung = Valenzelektronen − nichtbindende Elektronen − ½(bindende Elektronen). Wird verwendet, um die beste Lewis-Struktur zu bewerten. Strukturen mit minimalen formalen Ladungen sind stabiler.","fr":"Charge formelle = électrons de valence − électrons non liants − ½(électrons liants). Utilisée pour évaluer la meilleure structure de Lewis. Les structures avec des charges formelles minimales sont plus stables.","tr":"Biçimsel yük = değerlik elektronları − bağ yapmayan elektronlar − ½(bağ elektronları). En iyi Lewis yapısını değerlendirmek için kullanılır. Minimum biçimsel yüklere sahip yapılar daha kararlıdır.","nl":"Formele lading = valentie-elektronen − niet-bindende elektronen − ½(bindende elektronen). Gebruikt om de beste Lewis-structuur te beoordelen. Structuren met minimale formele ladingen zijn stabieler.","ru":"Формальный заряд = валентные электроны − несвязывающие электроны − ½(связывающие электроны). Используется для оценки наилучшей структуры Льюиса. Структуры с минимальными формальными зарядами более стабильны.","zh":"形式电荷 = 价电子数 − 非键合电子数 − ½（键合电子数）。用于评估最佳路易斯结构。形式电荷最小的结构更稳定。","pt_BR":"Carga formal = elétrons de valência − elétrons não ligantes − ½(elétrons ligantes). Usada para avaliar a melhor estrutura de Lewis. Estruturas com cargas formais mínimas são mais estáveis.","pt_PT":"Carga formal = eletrões de valência − eletrões não ligantes − ½(eletrões ligantes). Usada para avaliar a melhor estrutura de Lewis. As estruturas com cargas formais mínimas são mais estáveis."}},
  { id: 'dc-chemistry-0132', deck_id: 'deck-chemistry', sort_order: 132, front: "Resonance Structures", back: "Two or more Lewis structures that differ only in electron-pair positions, not atom positions. The real molecule is a hybrid of all resonance structures. Delocalization provides extra stability." , front_translations: {"es":"Estructuras de Ressonancia","de":"Resonanzstrukturen","fr":"Structures de résonance","tr":"Rezonans Yapıları","nl":"Resonantiestructuren","ru":"Резонансные структуры","zh":"共振结构","pt_BR":"Estruturas de Ressonância","pt_PT":"Estruturas de Ressonância"}, back_translations: {"es":"Dos el más estructuras de Lewis que diferem solo en las posiciones de los pares de electrones, no en las posiciones de los átomos. La molécula real es un híbrido de todas las estructuras de ressonancia. La deslocalización proporciona estabilidad extra.","de":"Zwei oder mehr Lewis-Strukturen, die sich nur in der Position der Elektronenpaare unterscheiden, nicht in der Atomposition. Das reale Molekül ist ein Hybrid aller Resonanzstrukturen. Delokalisierung sorgt für zusätzliche Stabilität.","fr":"Deux structures de Lewis ou plus qui ne diffèrent que par la position des paires d'électrons, et non par la position des atomes. La molécule réelle est un hybride de toutes les structures de résonance. La délocalisation apporte une stabilité supplémentaire.","tr":"Yalnızca elektron çifti konumlarında farklılık gösteren, atom konumlarında değil, iki veya daha fazla Lewis yapısı. Gerçek molekül, tüm rezonans yapılarının hibrididir. Delokalizasyon ekstra kararlılık sağlar.","nl":"Twee of meer Lewis-structuren die alleen verschillen in de positie van elektronenparen, niet in atoomposities. Het echte molecuul is een hybride van alle resonantiestructuren. Delocalisatie zorgt voor extra stabiliteit.","ru":"Две или более структуры Льюиса, которые отличаются только положением электронных пар, а не атомов. Реальная молекула является гибридом всех резонансных структур. Делокализация обеспечивает дополнительную стабильность.","zh":"两种或多种路易斯结构，仅在电子对位置上不同，而非原子位置。真实分子是所有共振结构的杂化体。离域化提供额外的稳定性。","pt_BR":"Duas ou mais estruturas de Lewis que diferem apenas nas posições dos pares de elétrons, não nas posições dos átomos. A molécula real é um híbrido de todas as estruturas de ressonância. A deslocalização fornece estabilidade extra.","pt_PT":"Duas ou mais estruturas de Lewis que diferem apenas nas posições dos pares de eletrões, não nas posições dos átomos. A molécula real é um híbrido de todas as estruturas de ressonância. A deslocalização proporciona estabilidade extra."}},
  { id: 'dc-chemistry-0133', deck_id: 'deck-chemistry', sort_order: 133, front: "Law of Conservation of Mass", back: "In a chemical reaction, mass is neither created nor destroyed. Total mass of reactants equals total mass of products. The basis for balancing chemical equations (atom counts must be equal)." , front_translations: {"es":"Ley de la Conservación de la Masa","de":"Gesetz der Massenerhaltung","fr":"Loi de conservation de la masse","tr":"Kütlenin Korunumu Yasası","nl":"Wet van behoud van massa","ru":"Закон сохранения массы","zh":"质量守恒定律","pt_BR":"Lei da Conservação da Massa","pt_PT":"Lei da Conservação da Massa"}, back_translations: {"es":"En una reacción química, a masa no es creada nem destruída. La masa total de los reactivos es igual a la masa total de los productos. La base para balancear ecuaciones químicas (las contajes de átomos devem ser iguais).","de":"Bei einer chemischen Reaktion wird Masse weder erzeugt noch vernichtet. Die Gesamtmasse der Edukte entspricht der Gesamtmasse der Produkte. Die Grundlage für das Ausbalancieren chemischer Gleichungen (Atomzahlen müssen gleich sein).","fr":"Dans une réaction chimique, la masse n'est ni créée ni détruite. La masse totale des réactifs est égale à la masse totale des produits. C'est la base de l'équilibrage des équations chimiques (le nombre d'atomes doit être égal).","tr":"Bir kimyasal reaksiyonda kütle ne yaratılır ne de yok edilir. Reaktanların toplam kütlesi ürünlerin toplam kütlesine eşittir. Kimyasal denklemleri dengelemenin temeli (atom sayıları eşit olmalıdır).","nl":"Bij een chemische reactie wordt massa niet gecreëerd of vernietigd. De totale massa van de reactanten is gelijk aan de totale massa van de producten. De basis voor het balanceren van chemische vergelijkingen (atoomaantallen moeten gelijk zijn).","ru":"В химической реакции масса не создаётся и не уничтожается. Суммарная масса реагентов равна суммарной массе продуктов. Основа для составления химических уравнений (количество атомов должно быть равным).","zh":"在化学反应中，质量既不被创造也不被消灭。反应物的总质量等于产物的总质量。这是配平化学方程式的基础（原子数必须相等）。","pt_BR":"Em uma reação química, a massa não é criada nem destruída. A massa total dos reagentes é igual à massa total dos produtos. A base para balancear equações químicas (as contagens de átomos devem ser iguais).","pt_PT":"Numa reação química, a massa não é criada nem destruída. A massa total dos reagentes é igual à massa total dos produtos. A base para balancear equações químicas (as contagens de átomos devem ser iguais)."}},
  { id: 'dc-chemistry-0134', deck_id: 'deck-chemistry', sort_order: 134, front: "Law of Definite Proportions", back: "A compound always contains its component elements in fixed mass ratios. Water is always 88.9% oxygen and 11.1% hydrogen by mass, regardless of its source." , front_translations: {"es":"Ley de las Proporciones Definidas","de":"Gesetz der konstanten Proportionen","fr":"Loi des proportions définies","tr":"Sabit Oranlar Yasası","nl":"Wet van constante verhoudingen","ru":"Закон постоянных пропорций","zh":"定比定律","pt_BR":"Lei das Proporções Definidas","pt_PT":"Lei das Proporções Definidas"}, back_translations: {"es":"Un compuesto siempre contiene sus elementos componentes en razões de masa fixas. La agua es siempre 88,9% de oxígeno y 11,1% de hidrógeno en masa, independentemente de la su fonte.","de":"Eine Verbindung enthält ihre Bestandteilselemente immer in festen Massenverhältnissen. Wasser besteht immer aus 88,9 % Sauerstoff und 11,1 % Wasserstoff nach Masse, unabhängig von seiner Herkunft.","fr":"Un composé contient toujours ses éléments constitutifs dans des proportions massiques fixes. L'eau est toujours composée de 88,9 % d'oxygène et de 11,1 % d'hydrogène en masse, quelle que soit sa source.","tr":"Bir bileşik, bileşen elementlerini her zaman sabit kütle oranlarında içerir. Su, kaynağından bağımsız olarak her zaman kütlece %88,9 oksijen ve %11,1 hidrojen içerir.","nl":"Een verbinding bevat altijd zijn samenstellende elementen in vaste massaverhoudingen. Water is altijd 88,9% zuurstof en 11,1% waterstof naar massa, ongeacht de bron.","ru":"Соединение всегда содержит составляющие его элементы в фиксированных массовых соотношениях. Вода всегда состоит из 88,9% кислорода и 11,1% водорода по массе, независимо от источника.","zh":"化合物总是以固定的质量比含有其组成元素。无论来源如何，水总是含有88.9%的氧和11.1%的氢（按质量计）。","pt_BR":"Um composto sempre contém seus elementos componentes em razões de massa fixas. A água é sempre 88,9% de oxigênio e 11,1% de hidrogênio em massa, independentemente da sua fonte.","pt_PT":"Um composto contém sempre os seus elementos componentes em proporções de massa fixas. A água é sempre 88,9% de oxigénio e 11,1% de hidrogénio em massa, independentemente da sua fonte."}},
  { id: 'dc-chemistry-0135', deck_id: 'deck-chemistry', sort_order: 135, front: "Ideal vs. Real Gas", back: "Ideal gases assume no intermolecular forces and negligible particle volume. Real gases deviate at high pressure (volume matters) and low temperature (intermolecular attractions matter). Van der Waals equation corrects for this." , front_translations: {"es":"Gas Ideal vs. Gas Real","de":"Ideales vs. reales Gas","fr":"Gaz idéal vs. gaz réel","tr":"İdeal ve Gerçek Gaz","nl":"Ideaal vs. reëel gas","ru":"Идеальный и реальный газ","zh":"理想气体与实际气体","pt_BR":"Gás Ideal vs. Gás Real","pt_PT":"Gás Ideal vs. Gás Real"}, back_translations: {"es":"Gases ideais assumem ausencia de fuerzas intermoleculares y volumen de partícula negligenciable. Gases reais desviam en alta presión (el volumen importa) y baja temperatura (las atraciones intermoleculares importam). La ecuación de Van der Waals corrige eso.","de":"Ideale Gase nehmen keine zwischenmolekularen Kräfte und vernachlässigbares Teilchenvolumen an. Reale Gase weichen bei hohem Druck (Volumen spielt eine Rolle) und niedriger Temperatur (zwischenmolekulare Anziehung spielt eine Rolle) ab. Die Van-der-Waals-Gleichung korrigiert dies.","fr":"Les gaz idéaux supposent l'absence de forces intermoléculaires et un volume de particule négligeable. Les gaz réels s'écartent à haute pression (le volume compte) et à basse température (les attractions intermoléculaires comptent). L'équation de Van der Waals corrige cela.","tr":"İdeal gazlar, moleküller arası kuvvet olmadığını ve ihmal edilebilir parçacık hacmini varsayar. Gerçek gazlar yüksek basınçta (hacim önemlidir) ve düşük sıcaklıkta (moleküller arası çekim önemlidir) sapar. Van der Waals denklemi bunu düzeltir.","nl":"Ideale gassen gaan uit van geen intermoleculaire krachten en verwaarloosbaar deeltjesvolume. Reële gassen wijken af bij hoge druk (volume telt) en lage temperatuur (intermoleculaire aantrekkingen tellen). De Van der Waals-vergelijking corrigeert hiervoor.","ru":"Идеальные газы предполагают отсутствие межмолекулярных сил и пренебрежимо малый объём частиц. Реальные газы отклоняются при высоком давлении (объём имеет значение) и низкой температуре (межмолекулярные притяжения имеют значение). Уравнение Ван-дер-Ваальса корректирует это.","zh":"理想气体假设没有分子间力且粒子体积可忽略不计。实际气体在高压（体积有影响）和低温（分子间吸引力有影响）时会偏离理想状态。范德华方程对此进行了修正。","pt_BR":"Gases ideais assumem ausência de forças intermoleculares e volume de partícula negligenciável. Gases reais desviam em alta pressão (o volume importa) e baixa temperatura (as atrações intermoleculares importam). A equação de Van der Waals corrige isso.","pt_PT":"Os gases ideais assumem a ausência de forças intermoleculares e volume de partícula negligenciável. Os gases reais desviam a alta pressão (o volume importa) e a baixa temperatura (as atrações intermoleculares importam). A equação de Van der Waals corrige isso."}},
  { id: 'dc-chemistry-0136', deck_id: 'deck-chemistry', sort_order: 136, front: "Sublimation", back: "The phase transition from solid directly to gas without passing through the liquid phase. Occurs when vapor pressure of the solid exceeds atmospheric pressure at a given temperature. E.g., dry ice (CO₂)." , front_translations: {"es":"Sublimación","de":"Sublimation","fr":"Sublimation","tr":"Süblimleşme","nl":"Sublimatie","ru":"Сублимация","zh":"升华","pt_BR":"Sublimação","pt_PT":"Sublimação"}, back_translations: {"es":"La transición de fase del sólido directamente para el gas sin passar por la fase líquida. Ocurre cuando a presión de vapor del sólido excede a presión atmosférica en una determinada temperatura. Ex.: gelo seco (CO₂).","de":"Der Phasenübergang von fest direkt zu gasförmig, ohne die flüssige Phase zu durchlaufen. Tritt auf, wenn der Dampfdruck des Feststoffs bei einer gegebenen Temperatur den Atmosphärendruck übersteigt. Z. B. Trockeneis (CO₂).","fr":"La transition de phase du solide directement en gaz sans passer par la phase liquide. Se produit lorsque la pression de vapeur du solide dépasse la pression atmosphérique à une température donnée. Ex. : glace carbonique (CO₂).","tr":"Sıvı fazdan geçmeden doğrudan katıdan gaza geçiş. Katının buhar basıncının belirli bir sıcaklıkta atmosfer basıncını aşması durumunda gerçekleşir. Örn., kuru buz (CO₂).","nl":"De faseovergang van vast stof direct naar gas zonder door de vloeibare fase te gaan. Treedt op wanneer de dampdruk van het vaste stof de atmosferische druk bij een bepaalde temperatuur overschrijdt. Bijv. droogijs (CO₂).","ru":"Фазовый переход из твёрдого состояния непосредственно в газообразное без прохождения через жидкую фазу. Происходит, когда давление пара твёрдого тела превышает атмосферное давление при данной температуре. Например, сухой лёд (CO₂).","zh":"固体直接转变为气体而不经过液态的相变过程。当固体的蒸气压在给定温度下超过大气压时发生。例如，干冰（CO₂）。","pt_BR":"A transição de fase do sólido diretamente para o gás sem passar pela fase líquida. Ocorre quando a pressão de vapor do sólido excede a pressão atmosférica em uma determinada temperatura. Ex.: gelo seco (CO₂).","pt_PT":"A transição de fase do sólido diretamente para o gás sem passar pela fase líquida. Ocorre quando a pressão de vapor do sólido excede a pressão atmosférica a uma determinada temperatura. Ex.: gelo seco (CO₂)."}},
  { id: 'dc-chemistry-0137', deck_id: 'deck-chemistry', sort_order: 137, front: "Phase Diagram", back: "A graph of temperature vs. pressure showing the phases (solid, liquid, gas) of a substance and the transitions between them. The triple point is where all three phases coexist in equilibrium." , front_translations: {"es":"Diagrama de Fase","de":"Phasendiagramm","fr":"Diagramme de phases","tr":"Faz Diyagramı","nl":"Fasediagram","ru":"Фазовая диаграмма","zh":"相图","pt_BR":"Diagrama de Fase","pt_PT":"Diagrama de Fase"}, back_translations: {"es":"Un gráfico de temperatura vs. presión mostrando las fases (sólida, líquida, gaseosa) de una sustancia y las transiciones entre elas. El punto triplo es donde las tres fases coexistem en equilíbrio.","de":"Ein Diagramm von Temperatur gegen Druck, das die Phasen (fest, flüssig, gasförmig) einer Substanz und die Übergänge zwischen ihnen zeigt. Der Tripelpunkt ist der Punkt, an dem alle drei Phasen im Gleichgewicht koexistieren.","fr":"Un graphique de la température en fonction de la pression montrant les phases (solide, liquide, gaz) d'une substance et les transitions entre elles. Le point triple est l'endroit où les trois phases coexistent en équilibre.","tr":"Bir maddenin fazlarını (katı, sıvı, gaz) ve aralarındaki geçişleri gösteren sıcaklık-basınç grafiği. Üçlü nokta, üç fazın denge halinde bir arada bulunduğu noktadır.","nl":"Een grafiek van temperatuur versus druk die de fasen (vast, vloeibaar, gas) van een stof en de overgangen daartussen weergeeft. Het tripelpunt is waar alle drie de fasen in evenwicht coëxisteren.","ru":"График зависимости температуры от давления, показывающий фазы (твёрдая, жидкая, газообразная) вещества и переходы между ними. Тройная точка — место, где все три фазы сосуществуют в равновесии.","zh":"温度与压力的关系图，显示物质的相态（固态、液态、气态）及相互之间的转变。三相点是三种相态在平衡状态下共存的点。","pt_BR":"Um gráfico de temperatura vs. pressão mostrando as fases (sólida, líquida, gasosa) de uma substância e as transições entre elas. O ponto triplo é onde as três fases coexistem em equilíbrio.","pt_PT":"Um gráfico de temperatura vs. pressão mostrando as fases (sólida, líquida, gasosa) de uma substância e as transições entre elas. O ponto triplo é onde as três fases coexistem em equilíbrio."}},
  { id: 'dc-chemistry-0138', deck_id: 'deck-chemistry', sort_order: 138, front: "Dipole Moment", back: "A measure of the polarity of a molecule: μ = qd. Arises from the vector sum of all bond dipoles. Symmetric molecules (e.g., CO₂, CCl₄) have zero net dipole moment despite polar bonds." , front_translations: {"es":"Momento de Dipolo","de":"Dipolmoment","fr":"Moment dipolaire","tr":"Dipol Momenti","nl":"Dipoolmoment","ru":"Дипольный момент","zh":"偶极矩","pt_BR":"Momento de Dipolo","pt_PT":"Momento de Dipolo"}, back_translations: {"es":"Una medida de la polaridad de una molécula: μ = qd. Surge de la suma vetorial de todos los dipolos de enlace. Moléculas simétricas (ex.: CO₂, CCl₄) tienen momento de dipolo líquido zero apesar de las enlaces polares.","de":"Ein Maß für die Polarität eines Moleküls: μ = qd. Entsteht aus der Vektorsumme aller Bindungsdipole. Symmetrische Moleküle (z. B. CO₂, CCl₄) haben trotz polarer Bindungen kein resultierendes Dipolmoment.","fr":"Une mesure de la polarité d'une molécule : μ = qd. Résulte de la somme vectorielle de tous les dipôles de liaison. Les molécules symétriques (ex. CO₂, CCl₄) ont un moment dipolaire net nul malgré des liaisons polaires.","tr":"Bir molekülün polaritesinin ölçüsü: μ = qd. Tüm bağ dipollerinin vektör toplamından kaynaklanır. Simetrik moleküller (örn. CO₂, CCl₄) polar bağlara rağmen net sıfır dipol momentine sahiptir.","nl":"Een maat voor de polariteit van een molecuul: μ = qd. Ontstaat uit de vectorsom van alle bindingsdipolen. Symmetrische moleculen (bijv. CO₂, CCl₄) hebben een netto dipoolmoment van nul ondanks polaire bindingen.","ru":"Мера полярности молекулы: μ = qd. Возникает из векторной суммы всех дипольных моментов связей. Симметричные молекулы (например, CO₂, CCl₄) имеют нулевой суммарный дипольный момент, несмотря на полярные связи.","zh":"分子极性的量度：μ = qd。由所有键偶极子的矢量和产生。对称分子（如CO₂、CCl₄）尽管有极性键，但净偶极矩为零。","pt_BR":"Uma medida da polaridade de uma molécula: μ = qd. Surge da soma vetorial de todos os dipolos de ligação. Moléculas simétricas (ex.: CO₂, CCl₄) têm momento de dipolo líquido zero apesar das ligações polares.","pt_PT":"Uma medida da polaridade de uma molécula: μ = qd. Surge da soma vetorial de todos os dipolos de ligação. Moléculas simétricas (ex.: CO₂, CCl₄) têm momento de dipolo líquido zero apesar das ligações polares."}},
  { id: 'dc-chemistry-0139', deck_id: 'deck-chemistry', sort_order: 139, front: "Coordination Compound", back: "A metal center surrounded by ligands (Lewis bases that donate electron pairs). The coordination number is the number of ligand atoms bonded to the metal. E.g., [Fe(CN)₆]⁴⁻." , front_translations: {"es":"Compuesto de Coordenación","de":"Koordinationsverbindung","fr":"Composé de coordination","tr":"Koordinasyon Bileşiği","nl":"Coördinatieverbinding","ru":"Координационное соединение","zh":"配位化合物","pt_BR":"Composto de Coordenação","pt_PT":"Composto de Coordenação"}, back_translations: {"es":"Un centro metálico rodeado por ligantes (bases de Lewis que doam pares de electrones). El número de coordenación es el número de átomos de ligante ligados al metal. Ex.: [Fe(CN)₆]⁴⁻.","de":"Ein Metallzentrum, das von Liganden umgeben ist (Lewis-Basen, die Elektronenpaare spenden). Die Koordinationszahl ist die Anzahl der Ligandatome, die an das Metall gebunden sind. Z. B. [Fe(CN)₆]⁴⁻.","fr":"Un centre métallique entouré de ligands (bases de Lewis qui donnent des paires d'électrons). Le nombre de coordination est le nombre d'atomes de ligands liés au métal. Ex. : [Fe(CN)₆]⁴⁻.","tr":"Ligandlarla (elektron çifti bağışlayan Lewis bazları) çevrili bir metal merkezi. Koordinasyon sayısı, metale bağlı ligand atomlarının sayısıdır. Örn. [Fe(CN)₆]⁴⁻.","nl":"Een metaalcentrum omgeven door liganden (Lewis-basen die elektronenparen doneren). Het coördinatiegetal is het aantal ligandatomen gebonden aan het metaal. Bijv. [Fe(CN)₆]⁴⁻.","ru":"Металлический центр, окружённый лигандами (основаниями Льюиса, донирующими электронные пары). Координационное число — это количество атомов лигандов, связанных с металлом. Например, [Fe(CN)₆]⁴⁻.","zh":"被配体（提供电子对的路易斯碱）包围的金属中心。配位数是与金属键合的配体原子数。例如，[Fe(CN)₆]⁴⁻。","pt_BR":"Um centro metálico rodeado por ligantes (bases de Lewis que doam pares de elétrons). O número de coordenação é o número de átomos de ligante ligados ao metal. Ex.: [Fe(CN)₆]⁴⁻.","pt_PT":"Um centro metálico rodeado por ligandos (bases de Lewis que doam pares de eletrões). O número de coordenação é o número de átomos de ligando ligados ao metal. Ex.: [Fe(CN)₆]⁴⁻."}},
  { id: 'dc-chemistry-0140', deck_id: 'deck-chemistry', sort_order: 140, front: "Crystal Field Theory", back: "Explains the colors and magnetic properties of coordination compounds. Ligands split d-orbital energies. Strong-field ligands (CN⁻) cause large splitting; weak-field (I⁻) cause small splitting." , front_translations: {"es":"Teoría del Campo Cristalino","de":"Kristallfeld-Theorie","fr":"Théorie du champ cristallin","tr":"Kristal Alan Teorisi","nl":"Kristalveldtheorie","ru":"Теория кристаллического поля","zh":"晶体场理论","pt_BR":"Teoria do Campo Cristalino","pt_PT":"Teoria do Campo Cristalino"}, back_translations: {"es":"Explica las cores y propiedades magnéticas de compuestos de coordenación. Los ligantes dividem las energias de los orbitais d. Ligantes de campo fuerte (CN⁻) causan grande divisão; los de campo débil (I⁻) causan pequeña divisão.","de":"Erklärt die Farben und magnetischen Eigenschaften von Koordinationsverbindungen. Liganden spalten die Energie der d-Orbitale. Starke Feldliganden (CN⁻) verursachen große Aufspaltung; schwache Feldliganden (I⁻) verursachen kleine Aufspaltung.","fr":"Explique les couleurs et les propriétés magnétiques des composés de coordination. Les ligands divisent les énergies des orbitales d. Les ligands à champ fort (CN⁻) provoquent une grande division ; les ligands à champ faible (I⁻) provoquent une petite division.","tr":"Koordinasyon bileşiklerinin renklerini ve manyetik özelliklerini açıklar. Ligandlar d-orbital enerjilerini böler. Güçlü alan ligandları (CN⁻) büyük bölünmeye neden olur; zayıf alan ligandları (I⁻) küçük bölünmeye neden olur.","nl":"Verklaart de kleuren en magnetische eigenschappen van coördinatieverbindingen. Liganden splitsen d-orbitaalenergieen. Sterkeveldliganden (CN⁻) veroorzaken grote splitsing; zwakke veldliganden (I⁻) veroorzaken kleine splitsing.","ru":"Объясняет цвета и магнитные свойства координационных соединений. Лиганды расщепляют энергии d-орбиталей. Лиганды сильного поля (CN⁻) вызывают большое расщепление; слабого поля (I⁻) — малое расщепление.","zh":"解释配位化合物的颜色和磁性。配体分裂d轨道能级。强场配体（CN⁻）引起大的分裂；弱场配体（I⁻）引起小的分裂。","pt_BR":"Explica as cores e propriedades magnéticas de compostos de coordenação. Os ligantes dividem as energias dos orbitais d. Ligantes de campo forte (CN⁻) causam grande divisão; os de campo fraco (I⁻) causam pequena divisão.","pt_PT":"Explica as cores e propriedades magnéticas de compostos de coordenação. Os ligandos dividem as energias dos orbitais d. Ligandos de campo forte (CN⁻) causam grande divisão; os de campo fraco (I⁻) causam pequena divisão."}},
  { id: 'dc-chemistry-0141', deck_id: 'deck-chemistry', sort_order: 141, front: "Thermite Reaction", back: "2Al + Fe₂O₃ → Al₂O₃ + 2Fe. A highly exothermic redox reaction. Aluminum, a stronger reducing agent, displaces iron from iron oxide. Produces temperatures up to ~2500°C. Used in welding rails." , front_translations: {"es":"Reacción Termite","de":"Thermitreaktion","fr":"Réaction thermite","tr":"Termit Reaksiyonu","nl":"Thermietreactie","ru":"Термитная реакция","zh":"铝热反应","pt_BR":"Reação Termite","pt_PT":"Reação Termite"}, back_translations: {"es":"2Al + Fe₂El₃ → Al₂El₃ + 2Fe. Una reacción redox altamente exotérmica. El alumínio, un agente redutor más fuerte, desloca el ferro del óxido de ferro. Produce temperaturas de hasta ~2500°C. Usado en la soldaje de trilhos.","de":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Eine stark exotherme Redoxreaktion. Aluminium, ein stärkeres Reduktionsmittel, verdrängt Eisen aus Eisenoxid. Erzeugt Temperaturen von bis zu ~2500°C. Wird beim Schweißen von Schienen verwendet.","fr":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Une réaction redox très exothermique. L'aluminium, un agent réducteur plus fort, déplace le fer de l'oxyde de fer. Produit des températures allant jusqu'à ~2500°C. Utilisé pour souder des rails.","tr":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Son derece ekzotermik bir redoks reaksiyonu. Daha güçlü bir indirgeyici madde olan alüminyum, demiri demir oksitten yerinden eder. ~2500°C'ye kadar sıcaklıklar üretir. Ray kaynağında kullanılır.","nl":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Een sterk exotherme redoxreactie. Aluminium, een sterkere reductor, verdringt ijzer uit ijzeroxide. Produceert temperaturen tot ~2500°C. Gebruikt bij het lassen van rails.","ru":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Высокоэкзотермическая окислительно-восстановительная реакция. Алюминий, более сильный восстановитель, вытесняет железо из оксида железа. Развивает температуры до ~2500°C. Используется при сварке рельсов.","zh":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe。高度放热的氧化还原反应。铝作为更强的还原剂，将铁从氧化铁中置换出来。产生高达约2500°C的温度。用于焊接铁轨。","pt_BR":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Uma reação redox altamente exotérmica. O alumínio, um agente redutor mais forte, desloca o ferro do óxido de ferro. Produz temperaturas de até ~2500°C. Usado na soldagem de trilhos.","pt_PT":"2Al + Fe₂O₃ → Al₂O₃ + 2Fe. Uma reação redox altamente exotérmica. O alumínio, um agente redutor mais forte, desloca o ferro do óxido de ferro. Produz temperaturas até ~2500°C. Usado na soldadura de carris."}},
  { id: 'dc-chemistry-0142', deck_id: 'deck-chemistry', sort_order: 142, front: "Haber Process", back: "N₂ + 3H₂ ⇌ 2NH₃ (high T, high P, Fe catalyst). Industrial synthesis of ammonia. ΔH = -92 kJ/mol (exothermic). A compromise between yield (low T) and rate (high T) is used (~450°C, 200 atm)." , front_translations: {"es":"Proceso Haber","de":"Haber-Bosch-Verfahren","fr":"Procédé Haber","tr":"Haber Prosesi","nl":"Haber-proces","ru":"Процесс Габера","zh":"哈伯法","pt_BR":"Processo Haber","pt_PT":"Processo Haber"}, back_translations: {"es":"N₂ + 3H₂ ⇌ 2NH₃ (alta T, alta P, catalizador Fe). Síntese industrial de amonia. ΔH = -92 kJ/mol (exotérmica). Un compromisso entre rendimento (baja T) y taxa (alta T) es usado (~450°C, 200 atm).","de":"N₂ + 3H₂ ⇌ 2NH₃ (hohe T, hoher P, Fe-Katalysator). Industrielle Synthese von Ammoniak. ΔH = -92 kJ/mol (exotherm). Ein Kompromiss zwischen Ausbeute (niedrige T) und Geschwindigkeit (hohe T) wird verwendet (~450°C, 200 atm).","fr":"N₂ + 3H₂ ⇌ 2NH₃ (T élevée, P élevée, catalyseur Fe). Synthèse industrielle de l'ammoniac. ΔH = -92 kJ/mol (exothermique). Un compromis entre le rendement (T basse) et la vitesse (T élevée) est utilisé (~450°C, 200 atm).","tr":"N₂ + 3H₂ ⇌ 2NH₃ (yüksek T, yüksek P, Fe katalizörü). Amonyağın endüstriyel sentezi. ΔH = -92 kJ/mol (ekzotermik). Verim (düşük T) ile hız (yüksek T) arasında bir uzlaşma kullanılır (~450°C, 200 atm).","nl":"N₂ + 3H₂ ⇌ 2NH₃ (hoge T, hoge P, Fe-katalysator). Industriële synthese van ammoniak. ΔH = -92 kJ/mol (exotherm). Een compromis tussen opbrengst (lage T) en snelheid (hoge T) wordt gebruikt (~450°C, 200 atm).","ru":"N₂ + 3H₂ ⇌ 2NH₃ (высокая T, высокое P, катализатор Fe). Промышленный синтез аммиака. ΔH = -92 кДж/моль (экзотермический). Используется компромисс между выходом (низкая T) и скоростью (высокая T) (~450°C, 200 атм).","zh":"N₂ + 3H₂ ⇌ 2NH₃（高温、高压、铁催化剂）。氨的工业合成。ΔH = -92 kJ/mol（放热）。在产率（低温）和速率（高温）之间取得折中（约450°C，200 atm）。","pt_BR":"N₂ + 3H₂ ⇌ 2NH₃ (alta T, alta P, catalisador Fe). Síntese industrial de amônia. ΔH = -92 kJ/mol (exotérmica). Um compromisso entre rendimento (baixa T) e taxa (alta T) é usado (~450°C, 200 atm).","pt_PT":"N₂ + 3H₂ ⇌ 2NH₃ (alta T, alta P, catalisador Fe). Síntese industrial de amoníaco. ΔH = -92 kJ/mol (exotérmica). Um compromisso entre rendimento (baixa T) e taxa (alta T) é usado (~450°C, 200 atm)."}},
  { id: 'dc-chemistry-0143', deck_id: 'deck-chemistry', sort_order: 143, front: "Contact Process", back: "Industrial production of sulfuric acid: S → SO₂ → SO₃ → H₂SO₄. SO₂ is oxidized to SO₃ over a V₂O₅ catalyst. H₂SO₄ is the world's most industrially produced chemical." , front_translations: {"es":"Proceso de Contato","de":"Kontaktverfahren","fr":"Procédé de contact","tr":"Temas Prosesi","nl":"Contactproces","ru":"Контактный процесс","zh":"接触法","pt_BR":"Processo de Contato","pt_PT":"Processo de Contacto"}, back_translations: {"es":"Producción industrial de ácido sulfúrico: S → SO₂ → SO₃ → H₂SO₄. SO₂ es oxidado a SO₃ sobre un catalizador V₂El₅. H₂SO₄ es el producto químico más producido industrialmente en el mundo.","de":"Industrielle Herstellung von Schwefelsäure: S → SO₂ → SO₃ → H₂SO₄. SO₂ wird über einem V₂O₅-Katalysator zu SO₃ oxidiert. H₂SO₄ ist die weltweit am meisten industriell produzierte Chemikalie.","fr":"Production industrielle d'acide sulfurique : S → SO₂ → SO₃ → H₂SO₄. SO₂ est oxydé en SO₃ sur un catalyseur V₂O₅. H₂SO₄ est le produit chimique le plus fabriqué industriellement dans le monde.","tr":"Sülfürik asit endüstriyel üretimi: S → SO₂ → SO₃ → H₂SO₄. SO₂, V₂O₅ katalizörü üzerinde SO₃'e yükseltgenir. H₂SO₄, dünyada en fazla endüstriyel olarak üretilen kimyasaldır.","nl":"Industriële productie van zwavelzuur: S → SO₂ → SO₃ → H₂SO₄. SO₂ wordt geoxideerd tot SO₃ over een V₂O₅-katalysator. H₂SO₄ is het meest industrieel geproduceerde chemische product ter wereld.","ru":"Промышленное производство серной кислоты: S → SO₂ → SO₃ → H₂SO₄. SO₂ окисляется до SO₃ на катализаторе V₂O₅. H₂SO₄ — наиболее промышленно производимое химическое вещество в мире.","zh":"硫酸的工业生产：S → SO₂ → SO₃ → H₂SO₄。SO₂在V₂O₅催化剂上被氧化为SO₃。H₂SO₄是世界上工业产量最大的化学品。","pt_BR":"Produção industrial de ácido sulfúrico: S → SO₂ → SO₃ → H₂SO₄. SO₂ é oxidado a SO₃ sobre um catalisador V₂O₅. H₂SO₄ é o produto químico mais produzido industrialmente no mundo.","pt_PT":"Produção industrial de ácido sulfúrico: S → SO₂ → SO₃ → H₂SO₄. SO₂ é oxidado a SO₃ sobre um catalisador V₂O₅. H₂SO₄ é o produto químico mais produzido industrialmente no mundo."}},
  { id: 'dc-chemistry-0144', deck_id: 'deck-chemistry', sort_order: 144, front: "Distillation", back: "Separation of liquid mixtures based on differences in boiling points. Fractional distillation separates components with close boiling points using a fractionating column. Used to refine crude oil." , front_translations: {"es":"Destilación","de":"Destillation","fr":"Distillation","tr":"Damıtma","nl":"Destillatie","ru":"Дистилляция","zh":"蒸馏","pt_BR":"Destilação","pt_PT":"Destilação"}, back_translations: {"es":"Separación de misturas líquidas con base en diferencias en los puntos de ebullición. La destilación fracionada separa componentes con puntos de ebullición próximos usando una columna de fracionamento. Usada para refinar petróleo bruto.","de":"Trennung von Flüssigkeitsgemischen basierend auf Unterschieden in den Siedepunkten. Fraktionierte Destillation trennt Komponenten mit ähnlichen Siedepunkten mithilfe einer Fraktionierkolonne. Wird zur Raffination von Rohöl verwendet.","fr":"Séparation de mélanges liquides basée sur les différences de points d'ébullition. La distillation fractionnée sépare les composants ayant des points d'ébullition proches à l'aide d'une colonne de fractionnement. Utilisée pour raffiner le pétrole brut.","tr":"Kaynama noktalarındaki farklılıklara dayalı sıvı karışımların ayrılması. Fraksiyonlu damıtma, yakın kaynama noktalarına sahip bileşenleri bir fraksiyonlama kolonu kullanarak ayırır. Ham petrolü rafine etmek için kullanılır.","nl":"Scheiding van vloeibare mengsels op basis van verschillen in kookpunten. Fractionele destillatie scheidt componenten met dicht bij elkaar liggende kookpunten met behulp van een fractioneerkolom. Gebruikt om ruwe olie te raffineren.","ru":"Разделение жидких смесей на основе различий в температурах кипения. Фракционная дистилляция разделяет компоненты с близкими температурами кипения с помощью ректификационной колонны. Используется для переработки сырой нефти.","zh":"根据沸点差异分离液体混合物。分馏利用分馏柱分离沸点相近的组分。用于精炼原油。","pt_BR":"Separação de misturas líquidas com base em diferenças nos pontos de ebulição. A destilação fracionada separa componentes com pontos de ebulição próximos usando uma coluna de fracionamento. Usada para refinar petróleo bruto.","pt_PT":"Separação de misturas líquidas com base em diferenças nos pontos de ebulição. A destilação fracionada separa componentes com pontos de ebulição próximos usando uma coluna de fracionamento. Usada para refinar petróleo bruto."}},
  { id: 'dc-chemistry-0145', deck_id: 'deck-chemistry', sort_order: 145, front: "Functional Group: Ether (R-O-R')", back: "An oxygen atom bonded to two carbon groups. Relatively unreactive; good solvents. Diethyl ether (Et₂O) was historically used as an anesthetic. THF is a common lab solvent." , front_translations: {"es":"Grupo Funcional: Éter (R-El-R')","de":"Funktionelle Gruppe: Ether (R-O-R')","fr":"Groupe fonctionnel : Éther (R-O-R')","tr":"Fonksiyonel Grup: Eter (R-O-R')","nl":"Functionele groep: Ether (R-O-R')","ru":"Функциональная группа: Эфир (R-O-R')","zh":"官能团：醚（R-O-R'）","pt_BR":"Grupo Funcional: Éter (R-O-R')","pt_PT":"Grupo Funcional: Éter (R-O-R')"}, back_translations: {"es":"Un átomo de oxígeno ligado a de los grupos de carbono. Relativamente inreativo; bons disolventes. El éter dietílico (Et₂El) era historicamente usado como anestésico. El THF es un disolvente comum de laboratório.","de":"Ein Sauerstoffatom, das mit zwei Kohlenstoffgruppen verbunden ist. Relativ unreaktiv; gute Lösungsmittel. Diethylether (Et₂O) wurde historisch als Anästhetikum verwendet. THF ist ein gebräuchliches Laborlösungsmittel.","fr":"Un atome d'oxygène lié à deux groupes carbonés. Relativement peu réactif ; bons solvants. L'éther diéthylique (Et₂O) était historiquement utilisé comme anesthésique. Le THF est un solvant courant en laboratoire.","tr":"İki karbon grubuna bağlı bir oksijen atomu. Görece reaktif değil; iyi çözücüler. Dietil eter (Et₂O) tarihsel olarak anestezik olarak kullanılmıştır. THF yaygın bir laboratuvar çözücüsüdür.","nl":"Een zuurstofatoom gebonden aan twee koolstofgroepen. Relatief onreactief; goede oplosmiddelen. Diethylether (Et₂O) werd historisch gebruikt als anestheticum. THF is een veelgebruikt laboratoriumoplosmiddel.","ru":"Атом кислорода, связанный с двумя углеродными группами. Относительно инертен; хорошие растворители. Диэтиловый эфир (Et₂O) исторически использовался как анестетик. ТГФ — распространённый лабораторный растворитель.","zh":"与两个碳基团相连的氧原子。相对惰性；是良好的溶剂。乙醚（Et₂O）历史上曾用作麻醉剂。四氢呋喃（THF）是常用的实验室溶剂。","pt_BR":"Um átomo de oxigênio ligado a dois grupos de carbono. Relativamente inreativo; bons solventes. O éter dietílico (Et₂O) era historicamente usado como anestésico. O THF é um solvente comum de laboratório.","pt_PT":"Um átomo de oxigénio ligado a dois grupos de carbono. Relativamente inreativo; bons solventes. O éter dietílico (Et₂O) era historicamente usado como anestésico. O THF é um solvente comum de laboratório."}},
  { id: 'dc-chemistry-0146', deck_id: 'deck-chemistry', sort_order: 146, front: "Functional Group: Aldehyde (R-CHO)", back: "A terminal carbonyl group (CHO). More reactive than ketones toward nucleophilic addition. Easily oxidized to carboxylic acids. Glucose exists partly as an open-chain aldehyde." , front_translations: {"es":"Grupo Funcional: Aldeído (R-CHO)","de":"Funktionelle Gruppe: Aldehyd (R-CHO)","fr":"Groupe fonctionnel : Aldéhyde (R-CHO)","tr":"Fonksiyonel Grup: Aldehit (R-CHO)","nl":"Functionele groep: Aldehyde (R-CHO)","ru":"Функциональная группа: Альдегид (R-CHO)","zh":"官能团：醛（R-CHO）","pt_BR":"Grupo Funcional: Aldeído (R-CHO)","pt_PT":"Grupo Funcional: Aldeído (R-CHO)"}, back_translations: {"es":"Un grupo carbonila terminal (CHO). Más reativo que cetonas para adición nucleofílica. Fácilmente oxidado a ácidos carboxílicos. La glicose existe parcialmente como un aldeído de cadeia aberta.","de":"Eine terminale Carbonylgruppe (CHO). Reaktiver als Ketone gegenüber nukleophiler Addition. Leicht zu Carbonsäuren oxidierbar. Glucose liegt teilweise als offenkettiger Aldehyd vor.","fr":"Un groupe carbonyle terminal (CHO). Plus réactif que les cétones vis-à-vis de l'addition nucléophile. Facilement oxydé en acides carboxyliques. Le glucose existe en partie sous forme d'aldéhyde à chaîne ouverte.","tr":"Terminal bir karbonil grubu (CHO). Nükleofilik katılmaya karşı ketonlardan daha reaktiftir. Karboksilik asitlere kolayca yükseltgenir. Glikoz kısmen açık zincirli aldehit olarak bulunur.","nl":"Een terminale carbonylgroep (CHO). Reactiever dan ketonen voor nucleofiele additie. Gemakkelijk geoxideerd tot carbonzuren. Glucose bestaat deels als een open-keten aldehyde.","ru":"Терминальная карбонильная группа (CHO). Более реакционноспособен, чем кетоны, по отношению к нуклеофильному присоединению. Легко окисляется до карбоновых кислот. Глюкоза частично существует в виде открытоцепного альдегида.","zh":"末端羰基（CHO）。比酮对亲核加成更有活性。易被氧化为羧酸。葡萄糖部分以开链醛的形式存在。","pt_BR":"Um grupo carbonila terminal (CHO). Mais reativo que cetonas para adição nucleofílica. Facilmente oxidado a ácidos carboxílicos. A glicose existe parcialmente como um aldeído de cadeia aberta.","pt_PT":"Um grupo carbonilo terminal (CHO). Mais reativo que cetonas para adição nucleofílica. Facilmente oxidado a ácidos carboxílicos. A glicose existe parcialmente como um aldeído de cadeia aberta."}},
  { id: 'dc-chemistry-0147', deck_id: 'deck-chemistry', sort_order: 147, front: "Functional Group: Ketone (R-CO-R')", back: "An internal carbonyl group; resistant to oxidation (no H on the carbonyl carbon). Undergo nucleophilic addition. Acetone (CH₃COCH₃) is a widely used solvent and the simplest ketone." , front_translations: {"es":"Grupo Funcional: Cetona (R-CO-R')","de":"Funktionelle Gruppe: Keton (R-CO-R')","fr":"Groupe fonctionnel : Cétone (R-CO-R')","tr":"Fonksiyonel Grup: Keton (R-CO-R')","nl":"Functionele groep: Keton (R-CO-R')","ru":"Функциональная группа: Кетон (R-CO-R')","zh":"官能团：酮（R-CO-R'）","pt_BR":"Grupo Funcional: Cetona (R-CO-R')","pt_PT":"Grupo Funcional: Cetona (R-CO-R')"}, back_translations: {"es":"Un grupo carbonila interno; resistente a la oxidación (sin H en el carbono carbonila). Sofre adición nucleofílica. La acetona (CH₃COCH₃) es un disolvente amplamente utilizado y a cetona más simples.","de":"Eine interne Carbonylgruppe; resistent gegen Oxidation (kein H am Carbonylkohlenstoff). Unterliegt nukleophiler Addition. Aceton (CH₃COCH₃) ist ein weit verbreitetes Lösungsmittel und das einfachste Keton.","fr":"Un groupe carbonyle interne ; résistant à l'oxydation (pas de H sur le carbone carbonylique). Subit une addition nucléophile. L'acétone (CH₃COCH₃) est un solvant largement utilisé et la cétone la plus simple.","tr":"İç bir karbonil grubu; oksidasyona dirençlidir (karbonil karbonunda H yoktur). Nükleofilik katılmaya uğrar. Aseton (CH₃COCH₃) yaygın olarak kullanılan bir çözücü ve en basit ketondur.","nl":"Een interne carbonylgroep; bestand tegen oxidatie (geen H op het carbonylkoolstof). Ondergaat nucleofiele additie. Aceton (CH₃COCH₃) is een veelgebruikt oplosmiddel en het eenvoudigste keton.","ru":"Внутренняя карбонильная группа; устойчива к окислению (нет H у карбонильного углерода). Вступает в нуклеофильное присоединение. Ацетон (CH₃COCH₃) — широко используемый растворитель и простейший кетон.","zh":"内部羰基；对氧化有抗性（羰基碳上无H）。发生亲核加成反应。丙酮（CH₃COCH₃）是广泛使用的溶剂，也是最简单的酮。","pt_BR":"Um grupo carbonila interno; resistente à oxidação (sem H no carbono carbonila). Sofre adição nucleofílica. A acetona (CH₃COCH₃) é um solvente amplamente utilizado e a cetona mais simples.","pt_PT":"Um grupo carbonilo interno; resistente à oxidação (sem H no carbono carbonilo). Sofre adição nucleofílica. A acetona (CH₃COCH₃) é um solvente amplamente utilizado e a cetona mais simples."}},
  { id: 'dc-chemistry-0148', deck_id: 'deck-chemistry', sort_order: 148, front: "Functional Group: Thiol (-SH)", back: "The sulfur analog of an alcohol. More acidic than alcohols; strong and unpleasant odor (e.g., garlic, skunks). In proteins, two thiol groups form a disulfide bond (R-S-S-R) important for 3D structure." , front_translations: {"es":"Grupo Funcional: Tiol (–SH)","de":"Funktionelle Gruppe: Thiol (–SH)","fr":"Groupe fonctionnel : Thiol (–SH)","tr":"Fonksiyonel Grup: Tiyol (–SH)","nl":"Functionele groep: Thiol (–SH)","ru":"Функциональная группа: Тиол (–SH)","zh":"官能团：硫醇（–SH）","pt_BR":"Grupo Funcional: Tiol (–SH)","pt_PT":"Grupo Funcional: Tiol (–SH)"}, back_translations: {"es":"El análogo de enxofre de un álcool. Más ácido que los álcoois; odor fuerte y desagradable (ex.: alho, gambá). En proteínas, de los grupos tiol forman una enlace dissulfeto (R-S-S-R) importante para a estructura 3D.","de":"Das Schwefelanalogon eines Alkohols. Saurer als Alkohole; starker und unangenehmer Geruch (z. B. Knoblauch, Stinktier). In Proteinen bilden zwei Thiolgruppen eine Disulfidbindung (R-S-S-R), die für die 3D-Struktur wichtig ist.","fr":"L'analogue soufré d'un alcool. Plus acide que les alcools ; odeur forte et désagréable (ex. ail, mouffette). Dans les protéines, deux groupes thiol forment une liaison disulfure (R-S-S-R) importante pour la structure 3D.","tr":"Bir alkolün kükürt analoğu. Alkollerden daha asidik; güçlü ve hoş olmayan koku (örn. sarımsak, skunk). Proteinlerde, iki tiyol grubu 3B yapı için önemli bir disülfit bağı (R-S-S-R) oluşturur.","nl":"Het zwavelanaloögon van een alcohol. Zuurder dan alcoholen; sterke en onaangename geur (bijv. knoflook, stinkdier). In eiwitten vormen twee thiolgroepen een disulfidebinding (R-S-S-R) die belangrijk is voor de 3D-structuur.","ru":"Серный аналог спирта. Более кислый, чем спирты; сильный и неприятный запах (например, чеснок, скунс). В белках две тиольные группы образуют дисульфидную связь (R-S-S-R), важную для трёхмерной структуры.","zh":"醇的硫类似物。比醇更具酸性；气味强烈难闻（如大蒜、臭鼬）。在蛋白质中，两个巯基形成对三维结构重要的二硫键（R-S-S-R）。","pt_BR":"O análogo de enxofre de um álcool. Mais ácido que os álcoois; odor forte e desagradável (ex.: alho, gambá). Em proteínas, dois grupos tiol formam uma ligação dissulfeto (R-S-S-R) importante para a estrutura 3D.","pt_PT":"O análogo de enxofre de um álcool. Mais ácido que os álcoois; odor forte e desagradável (ex.: alho, gambá). Em proteínas, dois grupos tiol formam uma ligação dissulfureto (R-S-S-R) importante para a estrutura 3D."}},
  { id: 'dc-chemistry-0149', deck_id: 'deck-chemistry', sort_order: 149, front: "Green Chemistry", back: "A philosophy of chemical design that minimizes waste, uses renewable feedstocks, employs safer solvents, and maximizes atom economy. Atom economy = (molecular weight of desired product / sum of all reactants) × 100%." , front_translations: {"es":"Química Verde","de":"Grüne Chemie","fr":"Chimie verte","tr":"Yeşil Kimya","nl":"Groene chemie","ru":"Зелёная химия","zh":"绿色化学","pt_BR":"Química Verde","pt_PT":"Química Verde"}, back_translations: {"es":"Una filosofia de design químico que minimiza resíduos, usa materias primas renovables, emprega disolventes más seguros y maximiza a economía atómica. Economía atómica = (peso molecular del producto desejado / suma de todos los reactivos) × 100%.","de":"Eine Philosophie des chemischen Designs, die Abfälle minimiert, erneuerbare Rohstoffe verwendet, sicherere Lösungsmittel einsetzt und die Atomeffizienz maximiert. Atomeffizienz = (Molmasse des gewünschten Produkts / Summe aller Edukte) × 100%.","fr":"Une philosophie de conception chimique qui minimise les déchets, utilise des matières premières renouvelables, emploie des solvants plus sûrs et maximise l'économie d'atomes. Économie d'atomes = (masse moléculaire du produit souhaité / somme de tous les réactifs) × 100%.","tr":"Atıkları en aza indiren, yenilenebilir hammaddeler kullanan, daha güvenli çözücüler kullanan ve atom ekonomisini maksimize eden kimyasal tasarım felsefesi. Atom ekonomisi = (istenen ürünün moleküler ağırlığı / tüm reaktanların toplamı) × %100.","nl":"Een filosofie van chemisch ontwerp die afval minimaliseert, hernieuwbare grondstoffen gebruikt, veiligere oplosmiddelen toepast en de atomaire efficiëntie maximaliseert. Atoomeconomie = (molecuulmassa van gewenst product / som van alle reactanten) × 100%.","ru":"Философия химического дизайна, минимизирующая отходы, использующая возобновляемое сырьё, применяющая более безопасные растворители и максимизирующая атомную экономию. Атомная экономия = (молекулярная масса желаемого продукта / сумма всех реагентов) × 100%.","zh":"一种化学设计理念，旨在最小化废物、使用可再生原料、采用更安全的溶剂并最大化原子经济性。原子经济性 = （所需产品的分子量 / 所有反应物之和）× 100%。","pt_BR":"Uma filosofia de design químico que minimiza resíduos, usa matérias-primas renováveis, emprega solventes mais seguros e maximiza a economia atômica. Economia atômica = (peso molecular do produto desejado / soma de todos os reagentes) × 100%.","pt_PT":"Uma filosofia de design químico que minimiza resíduos, usa matérias-primas renováveis, emprega solventes mais seguros e maximiza a economia atómica. Economia atómica = (peso molecular do produto desejado / soma de todos os reagentes) × 100%."}},
  { id: 'dc-chemistry-0150', deck_id: 'deck-chemistry', sort_order: 150, front: "Acid Rain", back: "Precipitation with pH below 5.6, caused by SO₂ and NOₓ emissions dissolving in water to form H₂SO₄ and HNO₃. Damages ecosystems, stone buildings, and metals. Reduced by scrubbers and catalytic converters." , front_translations: {"es":"Chuva Ácida","de":"Saurer Regen","fr":"Pluies acides","tr":"Asit Yağmuru","nl":"Zure regen","ru":"Кислотный дождь","zh":"酸雨","pt_BR":"Chuva Ácida","pt_PT":"Chuva Ácida"}, back_translations: {"es":"Precipitación con pH por debajo de 5,6, causada por emisiones de SO₂ y NOₓ que se dissolvem en la agua para formar H₂SO₄ y HNO₃. Danifica ecossistemas, edifícios de pedra y metais. Reduzida por lavadores y conversores catalíticos.","de":"Niederschlag mit einem pH-Wert unter 5,6, verursacht durch SO₂- und NOₓ-Emissionen, die sich in Wasser auflösen und H₂SO₄ und HNO₃ bilden. Schädigt Ökosysteme, Steingebäude und Metalle. Reduziert durch Rauchgasentschwefelung und Katalysatoren.","fr":"Des précipitations avec un pH inférieur à 5,6, causées par les émissions de SO₂ et de NOₓ se dissolvant dans l'eau pour former H₂SO₄ et HNO₃. Endommage les écosystèmes, les bâtiments en pierre et les métaux. Réduit par des épurateurs et des convertisseurs catalytiques.","tr":"pH değeri 5,6'nın altında olan yağış; SO₂ ve NOₓ emisyonlarının suda çözünerek H₂SO₄ ve HNO₃ oluşturmasından kaynaklanır. Ekosistemlere, taş binalara ve metallere zarar verir. Scrubber'lar ve katalitik konvertörlerle azaltılır.","nl":"Neerslag met een pH lager dan 5,6, veroorzaakt door SO₂- en NOₓ-emissies die in water oplossen om H₂SO₄ en HNO₃ te vormen. Beschadigt ecosystemen, stenen gebouwen en metalen. Verminderd door scrubbers en katalytische converters.","ru":"Осадки с pH ниже 5,6, вызванные выбросами SO₂ и NOₓ, растворяющимися в воде с образованием H₂SO₄ и HNO₃. Наносит ущерб экосистемам, каменным зданиям и металлам. Снижается с помощью скрубберов и каталитических нейтрализаторов.","zh":"pH低于5.6的降水，由SO₂和NOₓ排放溶于水形成H₂SO₄和HNO₃引起。损害生态系统、石质建筑和金属。通过洗涤器和催化转化器减少排放。","pt_BR":"Precipitação com pH abaixo de 5,6, causada por emissões de SO₂ e NOₓ que se dissolvem na água para formar H₂SO₄ e HNO₃. Danifica ecossistemas, edifícios de pedra e metais. Reduzida por lavadores e conversores catalíticos.","pt_PT":"Precipitação com pH abaixo de 5,6, causada por emissões de SO₂ e NOₓ que se dissolvem na água para formar H₂SO₄ e HNO₃. Danifica ecossistemas, edifícios de pedra e metais. Reduzida por depuradores e conversores catalíticos."}},
];
